// =============================================================
// BID STAGES
// =============================================================
// =============================================================
// BID STAGES --- mutable list of lifecycle stages
// Stored in state.stages so users can add/delete/rename/reorder.
// Seeded from DEFAULT_STAGES on first load.
// =============================================================
const DEFAULT_STAGES = [
  { id:'project-setup', name:'Project Setup', icon:'📋', description:'Bid/no-bid decision, document intake, estimating system setup, team assignments' },
  { id:'special-project-task', name:'Special Project Task', icon:'🌟', description:'Non-standard or unique tasks specific to this project --- anything outside the typical bid workflow' },
  { id:'document-review', name:'Document Review', icon:'🔍', description:'Drawings, specs, addenda, site walkthrough, pre-bid meeting, RFIs' },
  { id:'trade-solicitation', name:'Trade Solicitation', icon:'📨', description:'Sub/vendor outreach, RFQ packages, coverage tracking, follow-ups' },
  { id:'estimating', name:'Estimating & Takeoffs', icon:'📐', description:'Quantity takeoffs by division, self-perform pricing, unit costs, GCs' },
  { id:'scope-leveling', name:'Scope Review & Leveling', icon:'⚖️', description:'Sub bid leveling, scope gap analysis, inclusions/exclusions, qualifications' },
  { id:'bid-day-prep', name:'Bid Day Prep', icon:'🎯', description:'Final review, escalation/contingency, bid forms, proposal assembly, submission' },
  { id:'bid-day', name:'Bid Day', icon:'🏁', description:'Day-of-bid activities --- final number lock, sub call-ins, quote chasing, submission moment' },
  { id:'post-bid', name:'Post Bid', icon:'📊', description:'Debrief, lessons learned, award tracking, buyout prep, handoff' }
];

// Mutable runtime stages --- reference is stable, contents are kept in sync with state.stages.
// Using `let` so we can mutate the array in place to keep all read-references valid.
let STAGES = DEFAULT_STAGES.map(s => ({ ...s }));

// Avatar color palette --- deterministic based on name hash
const AVATAR_COLORS = ['#c8322b','#0a2540','#2563a8','#2e7d52','#d4a017','#7b4397','#00897b','#5d4037','#455a64','#e65100'];
function avatarColor(name) {
  if (!name) return '#6b7687';
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = (hash*31 + name.charCodeAt(i)) | 0;
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

// =============================================================
// STATE
// =============================================================
const STORAGE_KEY = 'sbg_precon_tracker_v3';
let state = {
  projects: [],
  templates: [],                   // saved project templates
  teamMembers: [],                 // master team roster
  masterTasks: [],                 // legacy single-template task list (preserved for backward compat; mirrored to active template)
  taskTemplates: [],               // multi-template support --- array of {id, name, description, icon, color, tasks, isDefault, createdAt, updatedAt}
  activeTemplateId: null,          // which template is currently being edited in MTT modal
  stages: [],                      // editable lifecycle stages (seeded from DEFAULT_STAGES)
  ballInCourtOptions: [],          // editable master Ball in Court list
  csiDivisions: [],                // editable master CSI Division / category list
  sourceOptions: [],               // editable master Source list (Bluebeam, Building Connected, etc.)
  milestoneTypes: [],              // editable master Key Milestone types (RFIs Due, Exec Review, etc.)
  companyLogo: null,               // base64 company logo override
  activeProjectId: null,
  activeStageId: 'all',
  activeAssignee: 'all',
  activeSource: 'all',             // Source filter when grouping=source --- value is the source name, 'unsourced', or 'all'
  activeStatus: 'all',             // Status filter when grouping=status --- value is a status id ('not-started','in-progress','blocked','pending','done') or 'all'
  secondaryAssigneeFilter: 'all',  // Cross-cutting filter applied AFTER grouping (Stage/Source/Status) --- narrows to one assignee. Hidden in Assignee grouping mode where it'd be redundant. Value is a person name, 'unassigned', or 'all'.

  // ===== GROUP BY ALERT =====
  // Fifth grouping mode that slices tasks by their active alert tier (Overdue,
  // Late Start, At Risk, Blocked, etc.). Unlike the other groupings which
  // answer "what kind / whose / where from / what status" this one answers
  // "how urgent and why." Uses ALL-TIERS overlap so a task that's both
  // Overdue AND Unacknowledged appears in both tabs (matching how the
  // Alerts strip already works).
  activeAlertTier: 'all',          // tier id: 'all', 'overdue', 'late-start', 'at-risk', 'blocked', 'imminent', 'soon', 'in-progress', 'rejected', 'unack', 'unassigned', 'pending', 'healthy', 'done'
  alertFilters: {                  // multi-filter row: applied AFTER tier filter
    assignee: 'all',
    stage: 'all',
    source: 'all'
  },

  // ===== GROUP BY MY ALERTS =====
  // Sixth grouping mode --- same tier slicing as Group by Alert but scoped
  // to the current user (assignee or support). Shows only THIS user's
  // alerts. Multi-filter is just stage + source (assignee is always "me").
  activeMyAlertTier: 'all',        // tier id, separate from activeAlertTier so switching modes doesn't lose state
  myAlertFilters: {                // two-dimensional filter row in My Alerts mode
    stage: 'all',
    source: 'all'
  },

  // ===== START BY DATE FEATURE =====
  // Optional forward-looking field on tasks. When set, fires a "Late Start"
  // alert if the date passes and the task is still 'not-started'. Helps
  // assignees plan backwards from deadlines instead of reacting at the
  // deadline. Auto-suggested with override based on per-stage default
  // durations. Globally opt-in via the firm setting below; certain
  // lead-time-critical stages are always on regardless of the global flag.
  startByGlobalEnabled: false,         // firm-level toggle --- when false, only always-on stages use Start By
  startByAlwaysOnStages: ['trade-solicitation', 'estimating', 'scope-leveling'], // stages that always use Start By (lead-time critical) regardless of global flag
  startByStageDefaults: {              // default business days BEFORE due date for each stage
    'project-setup': 2,
    'special-project-task': 2,
    'document-review': 3,
    'trade-solicitation': 5,           // RFQs need lead time so subs can respond
    'estimating': 3,
    'scope-leveling': 3,
    'bid-day-prep': 2,
    'bid-day': 1,
    'post-bid': 2
  },
  grouping: 'stage',
  viewMode: 'board',
  calMonth: new Date().toISOString().slice(0,7),
  calCursor: new Date().toISOString().slice(0,10),
  calRange: 'month',
  calAssignee: 'all',
  schedGrouping: 'stage',           // 'stage' | 'assignee' | 'scope' for the schedule view
  schedZoom: 'normal',              // 'compact' | 'normal' | 'wide' --- controls bar height + day-cell width
  schedHideDone: false,             // hide completed tasks on the schedule
  bulkSelectionMode: false,         // when true, checkboxes appear on cards and rows for bulk operations
  bulkSelectedTaskIds: [],          // array of task IDs currently selected for bulk operations
  laWindow: 7,                      // Look Ahead time window in days: 1, 2, 7, or 14
  laProjectScope: 'active',         // 'active' = current project only, 'all' = all active projects
  laAssignee: 'all',                // 'all' or specific assignee name
  laIncludeOverdue: true,           // include tasks already past due
  laHideDone: true,                 // hide tasks marked Complete
  activeAlertTier: null,            // 'overdue' | 'imminent' | 'soon' | null
  pastPursuitsExpanded: false,      // whether "Past Pursuits" section is open
  archivedExpanded: false,          // whether "Archived" section is open
  // ===== STATUS SNAPSHOT VIEW =====
  // Cross-project rollup showing what's actively being worked on, what's
  // due in the next 1-2 days, and what's at risk. Dedicated full-page view
  // accessed from the sidebar 🎯 Status Snapshot button.
  statusSnapshotView: false,        // when true, renders the snapshot page (overrides home/project view)
  statusSnapshotScope: 'all',       // 'all' (default), 'active' (current project only), 'mine' (current user only)
  statusSnapshotSectionOrder: ['atrisk', 'inprogress', 'due1', 'due2', 'allopen'], // user-reorderable
  statusSnapshotCollapsed: {},      // {atrisk: bool, inprogress: bool, due1: bool, due2: bool, allopen: bool}
  tour: {                           // Onboarding tour state --- first-time-user walkthrough
    completed: false,               // user finished the tour at least once
    dismissed: false,               // user explicitly skipped on first prompt (don't auto-show again)
    lastStep: 0                     // last step reached (for resume convenience, not strictly required)
  },
  requiredItemsCollapsed: {},       // per-mount collapsed state for the My Required Items panel ({home: bool, project: bool})
  // Global business-day calendar settings --- apply to ALL projects.
  // Used when an offset (D+N from bid start) lands on a weekend or holiday:
  // the calculated due date snaps forward to the next business day.
  // MANUALLY entered dates are NOT auto-shifted --- the user explicitly chose them.
  // The bid due date itself is NEVER auto-shifted.
  skipWeekends: false,              // when true, offset-calculated due dates skip Sat/Sun
  skipHolidays: false,              // when true, offset-calculated due dates also skip dates in state.holidays
  holidays: []                      // array of {id, name, date (yyyy-mm-dd), recurring (annual on month/day)}
};
let editingProjectId = null;
let editingTaskId = null;

function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed = JSON.parse(raw);
      state = { ...state, ...parsed };
    }
    if (!Array.isArray(state.templates)) state.templates = [];
    if (!Array.isArray(state.teamMembers)) state.teamMembers = [];
    if (!Array.isArray(state.masterTasks)) state.masterTasks = [];
    if (!Array.isArray(state.ballInCourtOptions)) state.ballInCourtOptions = [];
    if (state.ballInCourtOptions.length === 0) {
      state.ballInCourtOptions = getDefaultBallInCourtOptions();
    }
    if (!Array.isArray(state.csiDivisions)) state.csiDivisions = [];
    if (state.csiDivisions.length === 0) {
      state.csiDivisions = getDefaultCSIDivisions();
    }
    if (!Array.isArray(state.sourceOptions)) state.sourceOptions = [];
    if (state.sourceOptions.length === 0) {
      state.sourceOptions = getDefaultSourceOptions();
    }
    // Backfill icon + photo fields on existing source options that pre-date this feature.
    // Use the same emoji-from-name heuristic as new sources.
    state.sourceOptions.forEach(s => {
      if (typeof s.icon === 'undefined' || !s.icon) s.icon = suggestSourceIcon(s.name);
      if (typeof s.photo === 'undefined') s.photo = null;
    });
    // Backfill email field on existing team members that pre-date the Email Task feature.
    // Empty string = no email saved; user can fill in via Manage Team.
    if (Array.isArray(state.teamMembers)) {
      state.teamMembers.forEach(m => {
        if (typeof m.email === 'undefined') m.email = '';
      });
    }
    if (!Array.isArray(state.milestoneTypes)) state.milestoneTypes = [];
    if (state.milestoneTypes.length === 0) {
      state.milestoneTypes = getDefaultMilestoneTypes();
    }
    // One-time migration: ensure "Trade Partner Bids Due" type exists for existing users.
    // Inserted at the top of the list since it's often the most important date for preconstruction.
    if (!state.milestoneTypes.some(t => t.id === 'trade-partner-bids')) {
      state.milestoneTypes.unshift({ id: 'trade-partner-bids', name: "Trade Partner Bids Due", icon: '💼', color: '#c8322b', defaultDaysBeforeBid: 1 });
    }
    // Ensure every milestone type has a defaultDaysBeforeBid field (null = no default).
    // Pre-fill from the SBG defaults for the standard types if missing.
    const SBG_DEFAULTS = { 'trade-partner-bids': 1, 'rfi-trade': 7, 'rfi-client': 5, 'bid-leveling': 0, 'exec-review': 2 };
    state.milestoneTypes.forEach(t => {
      if (typeof t.defaultDaysBeforeBid === 'undefined') {
        t.defaultDaysBeforeBid = SBG_DEFAULTS[t.id] !== undefined ? SBG_DEFAULTS[t.id] : null;
      }
    });
    if (typeof state.tableSort === 'undefined') state.tableSort = { col: null, dir: 'asc' };
    if (typeof state.schedGrouping === 'undefined') state.schedGrouping = 'stage';
    if (typeof state.schedZoom === 'undefined') state.schedZoom = 'normal';
    if (typeof state.schedHideDone === 'undefined') state.schedHideDone = false;
    // Bulk-edit selection state --- always reset on load (selection should not persist between sessions)
    state.bulkSelectionMode = false;
    state.bulkSelectedTaskIds = [];
    if (typeof state.laWindow === 'undefined') state.laWindow = 7;
    if (typeof state.laProjectScope === 'undefined') state.laProjectScope = 'active';
    if (typeof state.laAssignee === 'undefined') state.laAssignee = 'all';
    if (typeof state.laIncludeOverdue === 'undefined') state.laIncludeOverdue = true;
    if (typeof state.laHideDone === 'undefined') state.laHideDone = true;
    if (typeof state.activeSource === 'undefined') state.activeSource = 'all';
    if (typeof state.collapsedSections === 'undefined') {
      // Default collapsed state: everything collapsed EXCEPT the bid countdown.
      // Makes the first view of a project compact --- users expand what they need.
      state.collapsedSections = { alerts: true, countdown: false, addendums: true, milestones: true };
    }
    // One-time migration: apply default-collapsed to users upgrading from versions
    // that had everything expanded by default.
    if (!state._defaultCollapseApplied) {
      state.collapsedSections = { alerts: true, countdown: false, addendums: true, milestones: true };
      state._defaultCollapseApplied = true;
    }
    if (typeof state.currentUser === 'undefined') state.currentUser = '';
    if (typeof state.sidebarCollapsed === 'undefined') state.sidebarCollapsed = false;
    if (typeof state.activeAlertTierMine === 'undefined') state.activeAlertTierMine = null;
    if (typeof state.homeView === 'undefined') state.homeView = false;
    // Per-project message boards + task-level message threads --- migrate
    state.projects.forEach(p => {
      if (!Array.isArray(p.messages)) p.messages = [];
      p.tasks.forEach(t => {
        if (!Array.isArray(t.messages)) t.messages = [];
      });
    });
    // Seed masterTasks with defaults on first load
    if (state.masterTasks.length === 0) {
      state.masterTasks = getDefaultMasterTasks();
    }
    // Multi-template migration: convert legacy single masterTasks array into taskTemplates collection
    if (!Array.isArray(state.taskTemplates)) state.taskTemplates = [];
    if (state.taskTemplates.length === 0) {
      // Seed with the user's existing masterTasks as the default "SBG Standard" template
      state.taskTemplates.push({
        id: 'tmpl-' + Date.now().toString(36),
        name: 'SBG Standard Bid Workflow',
        description: 'Default master template covering all 9 SBG bid stages --- works for most commercial pursuits',
        icon: '⭐',
        color: '#0a2540',
        tasks: state.masterTasks.map(t => ({ ...t })),
        isDefault: true,
        createdAt: Date.now(),
        updatedAt: Date.now()
      });
    }
    // Ensure exactly one template is marked default; if none, mark the first
    if (!state.taskTemplates.some(t => t.isDefault)) {
      state.taskTemplates[0].isDefault = true;
    }
    // Set active template ID for the editor --- defaults to the default template
    if (!state.activeTemplateId || !state.taskTemplates.some(t => t.id === state.activeTemplateId)) {
      const def = state.taskTemplates.find(t => t.isDefault) || state.taskTemplates[0];
      state.activeTemplateId = def.id;
    }
    // Keep state.masterTasks in sync with the active template (legacy compatibility for existing code paths)
    syncLegacyMasterTasks();

    // ===== TEMPLATE-TASK RICH FIELDS BACKFILL (v38) =====
    // Strip the legacy priority field (no longer authoritative; the per-row
    // Critical toggle replaces it) and ensure rich-field defaults are present
    // on every template task so the new editor UI never crashes on undefined.
    // Clean-slate migration per user request: existing template tasks all
    // become non-critical regardless of legacy priority value.
    if (Array.isArray(state.taskTemplates)) {
      state.taskTemplates.forEach(tmpl => {
        if (!Array.isArray(tmpl.tasks)) return;
        tmpl.tasks.forEach(t => {
          if (typeof t.critical !== 'boolean') t.critical = false;
          if (typeof t.estimatedHours === 'undefined') t.estimatedHours = null;
          if (typeof t.tips === 'undefined') t.tips = '';
          if (!Array.isArray(t.deliverables)) t.deliverables = [];
          if (!Array.isArray(t.checklist)) t.checklist = [];
          // Note: t.priority is left in place for any read sites that haven't
          // been migrated yet; the editor no longer surfaces it.
        });
      });
      // Re-sync masterTasks since we just mutated the active template's tasks
      syncLegacyMasterTasks();
    }

    // ============================================================
    // ADVANCEMENTS TRACKER --- possible program improvements list
    // Seeded on first load with the curated suggestion catalog.
    // Survives JSON export/import like any other state field.
    // ============================================================
    if (!Array.isArray(state.advancements)) state.advancements = [];
    if (state.advancements.length === 0) {
      state.advancements = getDefaultAdvancements();
    }
    // Backfill missing fields on existing entries
    state.advancements.forEach(a => {
      if (!a.id) a.id = 'adv-' + Date.now().toString(36) + '-' + Math.floor(Math.random() * 10000).toString(36);
      if (typeof a.status === 'undefined') a.status = 'open';
      if (typeof a.priority === 'undefined') a.priority = 'normal';
      if (typeof a.notes === 'undefined') a.notes = '';
      if (typeof a.addedAt === 'undefined') a.addedAt = Date.now();
      if (typeof a.implementedAt === 'undefined') a.implementedAt = null;
      if (typeof a.tier === 'undefined') a.tier = 'other';
      if (typeof a.favorite !== 'boolean') a.favorite = false;
    });
    // Favorite filter state --- defaults off so existing users see same view
    if (typeof state.advFavoritesOnly !== 'boolean') state.advFavoritesOnly = false;
    // ----------------------------------------------------------------
    // One-time migration: items shipped after the original seed list
    // need their status flipped on existing user state. Idempotent --- only
    // updates when the entry is currently 'open'.
    // ----------------------------------------------------------------
    const SHIPPED_TITLES = {
      'Onboarding tour': 'Shipped May 3, 2026 --- auto-launches on first load with a Welcome modal; sidebar "Take the Tour" button replays it on demand. Expanded May 3, 2026 to 18 spotlight steps covering Alerts, Bid Countdown, Addendums, Key Milestone Dates, Project Snapshot, action buttons, and date-mode toggle in addition to sidebar navigation, views, grouping, templates, and help.',
      'Tour - Add Alerts, Key Milestone Dates, Countdown, etc. include full list of features.': 'Shipped May 3, 2026 --- expanded the existing onboarding tour from 10 to 18 spotlight steps. New steps cover Project Header action buttons, Original/Revised date-mode toggle, the Sections Controller, 🔔 Alerts & Notifications (Project + My Alerts scopes, Alerts by Assignee), ⏱ Bid Countdown (Trade Partner + Bid Submission live timers), 📑 Addendums Log, 📅 Key Milestone Dates, and 📊 Project Snapshot. Each section-scoped step auto-expands its collapsed section before the spotlight lands so users actually see the feature being described.'
    };
    state.advancements.forEach(a => {
      if (a && SHIPPED_TITLES[a.title] && a.status === 'open') {
        a.status = 'implemented';
        a.implementedAt = a.implementedAt || Date.now();
        if (!a.notes) a.notes = SHIPPED_TITLES[a.title];
      }
    });
    // Selection set used by the Send-to-Claude flow (not persisted --- runtime only)
    if (!Array.isArray(state.advancementSelectedIds)) state.advancementSelectedIds = [];
    // Onboarding tour state --- backfill for users created before this feature shipped
    if (!state.tour || typeof state.tour !== 'object') {
      state.tour = { completed: false, dismissed: false, lastStep: 0 };
    } else {
      if (typeof state.tour.completed === 'undefined') state.tour.completed = false;
      if (typeof state.tour.dismissed === 'undefined') state.tour.dismissed = false;
      if (typeof state.tour.lastStep !== 'number') state.tour.lastStep = 0;
    }
    // Required Items panel collapsed state --- backfill for users pre-dating this feature
    if (!state.requiredItemsCollapsed || typeof state.requiredItemsCollapsed !== 'object') {
      state.requiredItemsCollapsed = {};
    }
    // Status Snapshot --- backfill for users pre-dating this feature
    if (typeof state.statusSnapshotView === 'undefined') state.statusSnapshotView = false;
    if (typeof state.statusSnapshotScope !== 'string' || !['all','active','mine'].includes(state.statusSnapshotScope)) {
      state.statusSnapshotScope = 'all';
    }
    if (!Array.isArray(state.statusSnapshotSectionOrder) || state.statusSnapshotSectionOrder.length !== 5) {
      state.statusSnapshotSectionOrder = ['atrisk', 'inprogress', 'due1', 'due2', 'allopen'];
    } else {
      // Validate all 5 keys are present (no dupes/missing) --- reset if corrupt
      const valid = ['atrisk','inprogress','due1','due2','allopen'];
      const sortedStored = [...state.statusSnapshotSectionOrder].sort().join(',');
      const sortedValid = [...valid].sort().join(',');
      if (sortedStored !== sortedValid) state.statusSnapshotSectionOrder = valid;
    }
    if (!state.statusSnapshotCollapsed || typeof state.statusSnapshotCollapsed !== 'object') {
      state.statusSnapshotCollapsed = {};
    }
    // Start By feature --- backfill for users pre-dating this feature
    if (typeof state.startByGlobalEnabled !== 'boolean') state.startByGlobalEnabled = false;
    if (!Array.isArray(state.startByAlwaysOnStages)) {
      state.startByAlwaysOnStages = ['trade-solicitation', 'estimating', 'scope-leveling'];
    }
    if (!state.startByStageDefaults || typeof state.startByStageDefaults !== 'object') {
      state.startByStageDefaults = {
        'project-setup': 2, 'special-project-task': 2, 'document-review': 3,
        'trade-solicitation': 5, 'estimating': 3, 'scope-leveling': 3,
        'bid-day-prep': 2, 'bid-day': 1, 'post-bid': 2
      };
    }
    // Hours stage defaults --- projected effort in hours per task by stage.
    // Used to auto-populate task.estimatedHours on new tasks. Calibrated from
    // typical commercial GC precon work: estimating is the heavy lift,
    // trade solicitation is mostly tracking, project setup and bid day are
    // shorter coordination tasks. User can override per-task.
    if (!state.hoursStageDefaults || typeof state.hoursStageDefaults !== 'object') {
      state.hoursStageDefaults = {
        'project-setup': 1, 'special-project-task': 2, 'document-review': 4,
        'trade-solicitation': 2, 'estimating': 8, 'scope-leveling': 4,
        'bid-day-prep': 2, 'bid-day': 1, 'post-bid': 2
      };
    }
    // Hours feature toggle --- off by default so existing users see no UI change
    // until they opt in. Auto-populate of new tasks only happens when this is on.
    if (typeof state.hoursEnabled !== 'boolean') state.hoursEnabled = false;
    // Hours rollup panel collapsed state --- preserve user's collapse choice across loads
    if (typeof state.hoursRollupCollapsed !== 'boolean') state.hoursRollupCollapsed = false;
    // Workload modal sort mode --- persists across reopens. One of:
    // 'stage' (default, groups by stage in STAGES order) | 'due' (flat list
    // sorted by due date) | 'status' (grouped by status order) | 'priority'
    // (grouped High/Medium/Low).
    if (!state.workloadModalSortMode || typeof state.workloadModalSortMode !== 'string') {
      state.workloadModalSortMode = 'stage';
    }
    if (!['stage', 'due', 'status', 'priority'].includes(state.workloadModalSortMode)) {
      state.workloadModalSortMode = 'stage';
    }
    // Critical-only filter --- global toggle in workspace toolbar
    if (typeof state.criticalFilterOnly !== 'boolean') state.criticalFilterOnly = false;
    // ===== SAVED FILTER VIEWS =====
    // Global views applied to whichever project the user is currently viewing.
    // Each view is a snapshot of view mode + grouping + stage tab + assignee
    // filter + critical-only flag + date mode. Special token 'mine' for
    // assignee filter resolves to current signed-in user at apply time.
    if (!Array.isArray(state.savedViews)) state.savedViews = [];
    // Preload sensible defaults the FIRST time (only if state.savedViews is
    // entirely empty AND the user hasn't already seen presets seeded --- so
    // deleting a preset doesn't cause it to come back next reload).
    if (state.savedViews.length === 0 && !state.savedViewsPresetsSeeded) {
      state.savedViews = [
        {
          id: 'preset-my-open',
          name: 'My Open Tasks',
          icon: '👤',
          isPreset: true,
          filters: {
            viewMode: 'board',
            grouping: 'stage',
            stageTab: 'all',
            secondaryAssigneeFilter: 'mine',
            criticalFilterOnly: false
          },
          createdAt: Date.now(),
          lastUsedAt: 0
        },
        {
          id: 'preset-critical-only',
          name: 'Critical Tasks',
          icon: '🔥',
          isPreset: true,
          filters: {
            viewMode: 'board',
            grouping: 'stage',
            stageTab: 'all',
            secondaryAssigneeFilter: 'all',
            criticalFilterOnly: true
          },
          createdAt: Date.now(),
          lastUsedAt: 0
        },
        {
          id: 'preset-overdue',
          name: 'Overdue & At Risk',
          icon: '🚨',
          isPreset: true,
          filters: {
            viewMode: 'board',
            grouping: 'alert',
            stageTab: 'all',
            secondaryAssigneeFilter: 'all',
            criticalFilterOnly: false
          },
          createdAt: Date.now(),
          lastUsedAt: 0
        },
        {
          id: 'preset-unassigned',
          name: 'Unassigned Tasks',
          icon: '❓',
          isPreset: true,
          filters: {
            viewMode: 'board',
            grouping: 'stage',
            stageTab: 'all',
            secondaryAssigneeFilter: 'unassigned',
            criticalFilterOnly: false
          },
          createdAt: Date.now(),
          lastUsedAt: 0
        },
        {
          id: 'preset-table-due',
          name: 'Table --- By Due Date',
          icon: '📅',
          isPreset: true,
          filters: {
            viewMode: 'table',
            grouping: 'stage',
            stageTab: 'all',
            secondaryAssigneeFilter: 'all',
            criticalFilterOnly: false,
            tableSort: { col: 'due', dir: 'asc' }
          },
          createdAt: Date.now(),
          lastUsedAt: 0
        }
      ];
      state.savedViewsPresetsSeeded = true;
    }
    if (typeof state.savedViewsPresetsSeeded !== 'boolean') state.savedViewsPresetsSeeded = true;
    // Active view tracking --- when a view is applied, we remember its id so
    // the toolbar can show the active view's name as a chip until any filter
    // is changed (which sets activeSavedViewId back to null).
    if (typeof state.activeSavedViewId !== 'string' && state.activeSavedViewId !== null) {
      state.activeSavedViewId = null;
    }
    // Secondary assignee filter --- backfill for users pre-dating it
    if (typeof state.secondaryAssigneeFilter !== 'string') state.secondaryAssigneeFilter = 'all';
    // Group by Alert --- backfill for users pre-dating it
    if (typeof state.activeAlertTier !== 'string') state.activeAlertTier = 'all';
    if (!state.alertFilters || typeof state.alertFilters !== 'object') {
      state.alertFilters = { assignee: 'all', stage: 'all', source: 'all' };
    } else {
      // Defensive --- make sure all three keys exist
      if (typeof state.alertFilters.assignee !== 'string') state.alertFilters.assignee = 'all';
      if (typeof state.alertFilters.stage !== 'string') state.alertFilters.stage = 'all';
      if (typeof state.alertFilters.source !== 'string') state.alertFilters.source = 'all';
    }
    // Group by My Alerts --- backfill
    if (typeof state.activeMyAlertTier !== 'string') state.activeMyAlertTier = 'all';
    if (!state.myAlertFilters || typeof state.myAlertFilters !== 'object') {
      state.myAlertFilters = { stage: 'all', source: 'all' };
    } else {
      if (typeof state.myAlertFilters.stage !== 'string') state.myAlertFilters.stage = 'all';
      if (typeof state.myAlertFilters.source !== 'string') state.myAlertFilters.source = 'all';
    }
    // Business-day calendar settings --- backfill for users pre-dating this feature.
    // Both toggles default to false so the upgrade is non-disruptive (existing
    // schedules don't shift unexpectedly). User opts in via Settings → Schedule.
    if (typeof state.skipWeekends === 'undefined') state.skipWeekends = false;
    if (typeof state.skipHolidays === 'undefined') state.skipHolidays = false;
    if (!Array.isArray(state.holidays)) state.holidays = [];
    // Seed federal US holidays on first install (or if list is empty AND user
    // has never customized --- we only seed when truly empty so an explicit
    // user-cleared list stays cleared).
    if (state.holidays.length === 0) {
      state.holidays = getDefaultHolidays();
    }
    // Defensive: if state loads with an archived project as the active one
    // (could happen if user archived from elsewhere or state was edited
    // externally), redirect to the first non-archived project. Archived
    // projects shouldn't be the "current working view."
    if (state.activeProjectId) {
      const ap = state.projects.find(x => x.id === state.activeProjectId);
      if (ap && ap.archived) {
        const fallback = state.projects.find(x => !x.archived);
        state.activeProjectId = fallback ? fallback.id : null;
        if (!fallback) state.homeView = true;
      }
    }
    // Seed stages with defaults on first load (or if existing state pre-dates this feature)
    if (!Array.isArray(state.stages) || state.stages.length === 0) {
      state.stages = DEFAULT_STAGES.map(s => ({ ...s }));
    }
    // Sync runtime STAGES array with state --- mutate in place so all
    // existing references stay valid (STAGES.find/forEach/map).
    STAGES.length = 0;
    state.stages.forEach(s => STAGES.push(s));
    state.projects.forEach(p => {
      // Bid extension fields --- initialize on existing projects
      if (typeof p.originalStartDate === 'undefined') p.originalStartDate = p.startDate || '';
      if (typeof p.originalDueDate === 'undefined') p.originalDueDate = p.dueDate || '';
      if (typeof p.revisedStartDate === 'undefined') p.revisedStartDate = '';
      if (typeof p.useRevisedDates === 'undefined') p.useRevisedDates = false;
      // Key Milestones array --- initialize with one instance per milestone type if missing
      if (!Array.isArray(p.milestones)) p.milestones = [];
      // Addenda log --- initialize empty if missing
      if (!Array.isArray(p.addenda)) p.addenda = [];
      // Activity log --- chronological event history per project. Capped at 500 entries.
      // Shape: [{id, timestamp, actor, type, action, taskId?, taskTitle?, fieldName?, oldValue?, newValue?, summary}]
      if (!Array.isArray(p.activityLog)) p.activityLog = [];
      // Default milestone offsets --- opt-in flag (defaults to false so existing projects don't auto-overwrite manual dates)
      if (typeof p.useDefaultOffsets === 'undefined') p.useDefaultOffsets = false;
      // Archive fields --- backfill for projects pre-dating the archive feature.
      // archived = soft-delete flag; project hidden from main list, all data preserved.
      // archivedAt = timestamp set on archive; cleared on restore.
      // archivedBy = user who archived the project (for audit trail).
      if (typeof p.archived === 'undefined') p.archived = false;
      if (typeof p.archivedAt === 'undefined') p.archivedAt = null;
      if (typeof p.archivedBy === 'undefined') p.archivedBy = '';

      p.tasks.forEach(t => {
        if (!t.stage) t.stage = 'project-setup';
        if (typeof t.dayOffset === 'undefined') t.dayOffset = null;
        if (typeof t.source === 'undefined') t.source = '';
        if (typeof t.support === 'undefined') t.support = '';
        // Multi-support migration: ensure every task has a supportMembers array.
        // task.support remains the "primary support" field for backward compat;
        // task.supportMembers holds additional supports beyond the primary.
        if (!Array.isArray(t.supportMembers)) t.supportMembers = [];
        // ===== MULTI-LEAD MIGRATION =====
        // task.leads is the new canonical array of Lead-tier assignees. For
        // most tasks this contains a single name (the same as task.assignee).
        // For co-Lead tasks it contains 2+ names. task.assignee is kept in
        // sync with leads[0] so the 192+ existing reads of task.assignee
        // continue working without per-call changes. Each Lead has their
        // own ack state in task.leadAck (object keyed by lowercased name →
        // { ackedAt, ackedBy }) --- same shape as bestPracticeAck.
        if (!Array.isArray(t.leads)) {
          t.leads = (t.assignee && t.assignee.trim()) ? [t.assignee.trim()] : [];
        }
        // Defensive: drop empty/duplicate entries that may have crept in
        t.leads = Array.from(new Set(t.leads.filter(n => n && String(n).trim()).map(n => String(n).trim())));
        // Sync the legacy assignee field to leads[0] so legacy code paths
        // see a consistent value. Empty leads → empty assignee.
        t.assignee = t.leads[0] || '';
        // Per-Lead ack state --- each co-Lead has their own acknowledgment
        if (!t.leadAck || typeof t.leadAck !== 'object') t.leadAck = {};
        // Per-Lead completion state --- each co-Lead can independently mark
        // their portion of the work complete. Task auto-flips to Status=Done
        // when ALL Leads have marked. Object keyed by lowercased name →
        // { completedBy, completedAt, completedByOverride? }. Same shape as leadAck.
        if (!t.leadCompletion || typeof t.leadCompletion !== 'object') t.leadCompletion = {};
        // Estimated hours --- projected effort to complete the task. Quarter-hour
        // precision (0.25, 0.5, 0.75, 1, 1.25, etc.). null = no estimate set.
        // Used for capacity planning and per-assignee workload rollups.
        if (typeof t.estimatedHours === 'undefined') t.estimatedHours = null;
        // Critical flag --- replaces the old priority field (high/medium/low).
        // Clean-slate migration: all existing tasks default to false regardless
        // of their old priority value. The priority field is left in place
        // for backward compat with legacy reads, but is no longer authoritative.
        if (typeof t.critical !== 'boolean') t.critical = false;
        // Recurrence: ensure shape exists. null means non-recurring.
        // Object shape: {pattern, interval, daysOfWeek?, dayOfMonth?, endDate?, count?, parentId?, instanceNumber?}
        if (typeof t.recurrence === 'undefined') t.recurrence = null;
        // Checklist (task subdivision) --- lightweight items inside the parent task.
        // Shape: [{id, text, done, doneBy, doneAt, required}]
        if (!Array.isArray(t.checklist)) t.checklist = [];
        // Checklist items: an array of {id, text, done, doneBy, doneAt, required} for task subdivision
        if (!Array.isArray(t.checklist)) t.checklist = [];
        // Backfill `required` flag --- default to true (legacy items become required so nothing slips).
        // Lead can untoggle individual items in the modal.
        t.checklist.forEach(ci => { if (typeof ci.required === 'undefined') ci.required = true; });
        // Deliverables --- Output/Deliverable checklist with editable description and optional file link/upload.
        // Shape: [{id, description, fileName, fileUrl, fileData, fileType, fileSize, done, doneBy, doneAt, addedAt, required}]
        if (!Array.isArray(t.deliverables)) t.deliverables = [];
        t.deliverables.forEach(d => { if (typeof d.required === 'undefined') d.required = true; });
        // Best Practice / Notes --- popup-style guidance that surfaces to the assignee on first task open.
        if (typeof t.bestPractice !== 'string') t.bestPractice = '';
        // Per-assignee acknowledgment of the best-practice popup. Object keyed by assignee name (lowercased)
        // → { ackedAt, ackedBy }. Reset whenever bestPractice text is edited so new guidance pops again.
        if (!t.bestPracticeAck || typeof t.bestPracticeAck !== 'object') t.bestPracticeAck = {};
        if (typeof t.bestPracticeUpdatedAt === 'undefined') t.bestPracticeUpdatedAt = null;
        if (typeof t.ballInCourt === 'undefined' || t.ballInCourt === '') t.ballInCourt = 'Lead';
        // Acknowledgment: existing tasks are grandfathered as already acknowledged
        if (typeof t.acknowledged === 'undefined') t.acknowledged = true;
        if (typeof t.acknowledgedBy === 'undefined') t.acknowledgedBy = '';
        if (typeof t.acknowledgedAt === 'undefined') t.acknowledgedAt = null;
        // Lead Estimator override fields --- audit trail when Lead acknowledges on assignee's behalf
        if (typeof t.acknowledgedOverrideBy === 'undefined') t.acknowledgedOverrideBy = '';
        if (typeof t.acknowledgedOverrideAt === 'undefined') t.acknowledgedOverrideAt = null;
        // Completion acknowledgment (Lead Estimator sign-off). Existing done tasks are grandfathered.
        if (typeof t.completionAcknowledged === 'undefined') t.completionAcknowledged = (t.status === 'done');
        if (typeof t.completionAcknowledgedBy === 'undefined') t.completionAcknowledgedBy = '';
        if (typeof t.completionAcknowledgedAt === 'undefined') t.completionAcknowledgedAt = null;
        // Completion rejection fields --- grandfathered as not rejected
        if (typeof t.completionRejected === 'undefined') t.completionRejected = false;
        if (typeof t.completionRejectedBy === 'undefined') t.completionRejectedBy = '';
        if (typeof t.completionRejectedAt === 'undefined') t.completionRejectedAt = null;
        if (typeof t.completionRejectionReason === 'undefined') t.completionRejectionReason = '';
        if (typeof t.completionRejectionNotes === 'undefined') t.completionRejectionNotes = '';
        if (typeof t.completionRejectionAcknowledged === 'undefined') t.completionRejectionAcknowledged = false;
        if (typeof t.completionRejectionAcknowledgedBy === 'undefined') t.completionRejectionAcknowledgedBy = '';
        if (typeof t.completionRejectionAcknowledgedAt === 'undefined') t.completionRejectionAcknowledgedAt = null;
      });
    });
  } catch(e) { console.error(e); }
}
function saveState() {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch(e){}
  scheduleApiSync();
}
// ---- Backend sync (local-first, debounced) ----
let _apiSyncTimer = null;
function scheduleApiSync() {
  if (!window.api || !window.api.enabled) return;
  if (_apiSyncTimer) clearTimeout(_apiSyncTimer);
  _apiSyncTimer = setTimeout(() => {
    _apiSyncTimer = null;
    window.api.putState(state).catch(err => {
      console.warn('Backend sync failed (keeping localStorage):', err.message);
    });
  }, 500);
}
async function syncStateFromServer() {
  if (!window.api || !window.api.enabled) return false;
  try {
    const res = await window.api.getState();
    if (res && res.state && Object.keys(res.state).length > 0) {
      const local = { ...state };
      state = { ...local, ...res.state };
      state.bulkSelectionMode = false;
      state.bulkSelectedTaskIds = [];
      return true;
    }
  } catch (err) {
    console.warn('Could not load state from backend (using local cache):', err.message);
  }
  return false;
}
function uid() { return Date.now().toString(36) + Math.random().toString(36).slice(2,8); }

// =============================================================
// DATE HELPERS
// =============================================================
function getDaysLeft(dateStr) {
  if (!dateStr) return null;
  const due = new Date(dateStr+'T00:00:00'); due.setHours(0,0,0,0);
  const today = new Date(); today.setHours(0,0,0,0);
  return Math.round((due-today)/86400000);
}
function getDueClass(dateStr, status) {
  if (!dateStr || status === 'done') return '';
  const d = getDaysLeft(dateStr);
  if (d === null) return '';
  if (d < 0) return 'overdue';
  if (d <= 3) return 'soon';
  return '';
}
function formatDate(d) { if (!d) return ''; return new Date(d+'T00:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'}); }
function formatDateShort(d) { if (!d) return ''; return new Date(d+'T00:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric'}); }

// =============================================================
// BID SUBMISSION TIME + COUNTDOWN
// =============================================================

/**
 * Returns a Date object representing the exact bid submission moment,
 * or null if the project has no due date.
 * If dueTime and dueTimezone are set, the moment is interpreted in that timezone.
 * Otherwise falls back to end-of-day in the browser's local timezone.
 */
function getBidSubmissionMoment(project) {
  if (!project || !project.dueDate) return null;
  const dateStr = project.dueDate;
  const timeStr = project.dueTime || '23:59';

  if (project.dueTimezone) {
    // Compute the Date that corresponds to `dateStr timeStr` in the project's timezone.
    // Use the Intl API to derive the timezone offset at that moment.
    try {
      const isoLocal = `${dateStr}T${timeStr}:00`;
      // Parse as if it were local, then adjust for the target timezone offset
      const asUtc = new Date(isoLocal + 'Z');
      // Determine target-tz offset for this moment
      const tzDate = new Date(asUtc.toLocaleString('en-US', { timeZone: project.dueTimezone }));
      const localDate = new Date(asUtc.toLocaleString('en-US'));
      const offsetMs = tzDate.getTime() - localDate.getTime();
      return new Date(asUtc.getTime() - offsetMs);
    } catch (e) {
      // Fallback --- treat as local
      return new Date(`${dateStr}T${timeStr}:00`);
    }
  }
  // No timezone --- interpret as browser-local
  return new Date(`${dateStr}T${timeStr}:00`);
}

/**
 * Returns a breakdown of time remaining until the bid moment.
 * { totalMs, isPast, days, hours, minutes, seconds }
 */
function getBidCountdown(project) {
  const moment = getBidSubmissionMoment(project);
  if (!moment) return null;
  const now = new Date();
  const diff = moment.getTime() - now.getTime();
  const absDiff = Math.abs(diff);
  const days = Math.floor(absDiff / 86400000);
  const hours = Math.floor((absDiff % 86400000) / 3600000);
  const minutes = Math.floor((absDiff % 3600000) / 60000);
  const seconds = Math.floor((absDiff % 60000) / 1000);
  return {
    totalMs: diff,
    isPast: diff < 0,
    days, hours, minutes, seconds
  };
}

/**
 * Formats time-of-day for display, e.g. "2:00 PM" from "14:00"
 */
function formatTimeShort(timeStr) {
  if (!timeStr) return '';
  const [h, m] = timeStr.split(':').map(Number);
  if (isNaN(h)) return timeStr;
  const period = h >= 12 ? 'PM' : 'AM';
  const h12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
  return `${h12}:${String(m || 0).padStart(2, '0')} ${period}`;
}

/**
 * Short timezone label (e.g. "CT" from "America/Chicago")
 */
function formatTimezoneShort(tz) {
  if (!tz) return '';
  const map = {
    'America/New_York': 'ET',
    'America/Chicago': 'CT',
    'America/Denver': 'MT',
    'America/Phoenix': 'MST',
    'America/Los_Angeles': 'PT',
    'America/Anchorage': 'AKT',
    'Pacific/Honolulu': 'HST'
  };
  return map[tz] || tz.split('/').pop();
}
function formatCurrency(v) {
  if (v >= 1000000) return '$'+(v/1000000).toFixed(1)+'M';
  if (v >= 1000) return '$'+(v/1000).toFixed(0)+'K';
  return '$'+v.toFixed(0);
}
function escapeHtml(s) {
  if (!s && s !== 0) return '';
  return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]);
}
function addDays(dateStr, days) {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T00:00:00');
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0,10);
}
function daysBetween(startStr, endStr) {
  if (!startStr || !endStr) return null;
  const a = new Date(startStr+'T00:00:00');
  const b = new Date(endStr+'T00:00:00');
  return Math.round((b - a) / 86400000);
}

// =============================================================
// BUSINESS-DAY CALENDAR --- weekend + holiday awareness
// =============================================================
// Seed list of federal US holidays. Most are recurring (annual on a fixed
// month/day), so we store them as `recurring: true` with month + day. Floating
// holidays (MLK, Presidents Day, Memorial Day, Labor Day, Columbus, Thanksgiving)
// are computed at runtime from a rule string.
//
// Shape: { id, name, recurring (bool), month (1-12, fixed only), day (1-31, fixed only),
//          rule (string for floating, e.g. "thanksgiving"), date (yyyy-mm-dd, one-off only),
//          enabled (bool) }
function getDefaultHolidays() {
  const now = Date.now();
  const mk = (id, name, opts) => Object.assign({ id, name, enabled: true, addedAt: now }, opts);
  return [
    mk('us-newyears',     "New Year's Day",                  { recurring: true, month: 1,  day: 1  }),
    mk('us-mlk',          'Martin Luther King Jr. Day',      { recurring: true, rule: 'mlk' }),       // 3rd Mon of Jan
    mk('us-presidents',   "Presidents' Day",                 { recurring: true, rule: 'presidents' }),// 3rd Mon of Feb
    mk('us-memorial',     'Memorial Day',                    { recurring: true, rule: 'memorial' }),  // last Mon of May
    mk('us-juneteenth',   'Juneteenth',                      { recurring: true, month: 6,  day: 19 }),
    mk('us-independence', 'Independence Day',                { recurring: true, month: 7,  day: 4  }),
    mk('us-labor',        'Labor Day',                       { recurring: true, rule: 'labor' }),     // 1st Mon of Sep
    mk('us-columbus',     'Columbus / Indigenous Peoples Day', { recurring: true, rule: 'columbus' }),// 2nd Mon of Oct
    mk('us-veterans',     'Veterans Day',                    { recurring: true, month: 11, day: 11 }),
    mk('us-thanksgiving', 'Thanksgiving',                    { recurring: true, rule: 'thanksgiving' }), // 4th Thu of Nov
    mk('us-blackfriday',  'Day After Thanksgiving',          { recurring: true, rule: 'blackfriday' }),  // 4th Thu of Nov + 1
    mk('us-christmaseve', 'Christmas Eve',                   { recurring: true, month: 12, day: 24 }),
    mk('us-christmas',    'Christmas Day',                   { recurring: true, month: 12, day: 25 })
  ];
}

// Compute the actual yyyy-mm-dd date of a recurring rule-based holiday for a given year.
// Returns '' if the rule isn't recognized.
function resolveHolidayRule(rule, year) {
  // Helper: nth weekday of a month (e.g. 3rd Monday of January)
  // weekday: 0=Sun..6=Sat; n: 1..5 (5 means "last")
  function nthWeekday(month, weekday, n) {
    const first = new Date(year, month - 1, 1);
    const firstDay = first.getDay();
    let day1 = 1 + ((weekday - firstDay + 7) % 7); // first occurrence in month
    if (n === 'last') {
      // Find last occurrence --- start from day1 and add 7 until we'd overflow
      const daysInMonth = new Date(year, month, 0).getDate();
      let d = day1;
      while (d + 7 <= daysInMonth) d += 7;
      return new Date(year, month - 1, d).toISOString().slice(0, 10);
    }
    const d = day1 + 7 * (n - 1);
    return new Date(year, month - 1, d).toISOString().slice(0, 10);
  }
  switch (rule) {
    case 'mlk':          return nthWeekday(1,  1, 3);   // 3rd Mon of Jan
    case 'presidents':   return nthWeekday(2,  1, 3);   // 3rd Mon of Feb
    case 'memorial':     return nthWeekday(5,  1, 'last'); // last Mon of May
    case 'labor':        return nthWeekday(9,  1, 1);   // 1st Mon of Sep
    case 'columbus':     return nthWeekday(10, 1, 2);   // 2nd Mon of Oct
    case 'thanksgiving': return nthWeekday(11, 4, 4);   // 4th Thu of Nov
    case 'blackfriday': {
      const thx = nthWeekday(11, 4, 4);
      return addDays(thx, 1);
    }
    default: return '';
  }
}

// Resolve all holidays for a given year into a Set of yyyy-mm-dd strings.
// Caches per-year so repeat lookups during a recalc are cheap.
const _holidaySetCache = {};
function getHolidaySetForYear(year) {
  const key = String(year);
  if (_holidaySetCache[key]) return _holidaySetCache[key];
  const out = new Set();
  if (!Array.isArray(state.holidays)) {
    _holidaySetCache[key] = out;
    return out;
  }
  state.holidays.forEach(h => {
    if (!h || h.enabled === false) return;
    if (h.recurring) {
      let iso = '';
      if (h.rule) {
        iso = resolveHolidayRule(h.rule, year);
      } else if (typeof h.month === 'number' && typeof h.day === 'number') {
        iso = `${year}-${String(h.month).padStart(2,'0')}-${String(h.day).padStart(2,'0')}`;
      }
      if (iso) out.add(iso);
    } else if (h.date) {
      // One-off holiday --- only matches its specific year
      if (h.date.startsWith(key + '-')) out.add(h.date);
    }
  });
  _holidaySetCache[key] = out;
  return out;
}
// Invalidate cache when the master list changes.
function invalidateHolidayCache() {
  Object.keys(_holidaySetCache).forEach(k => delete _holidaySetCache[k]);
}

// Is the given yyyy-mm-dd a weekend?
function isWeekend(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr + 'T00:00:00');
  const wd = d.getDay();
  return wd === 0 || wd === 6;
}

// Is the given yyyy-mm-dd a holiday in the master list?
function isHoliday(dateStr) {
  if (!dateStr) return false;
  const year = parseInt(dateStr.slice(0, 4), 10);
  if (!year) return false;
  return getHolidaySetForYear(year).has(dateStr);
}

// Returns the holiday name at the given date, or '' if not a holiday.
function getHolidayName(dateStr) {
  if (!dateStr) return '';
  const year = parseInt(dateStr.slice(0, 4), 10);
  if (!year || !Array.isArray(state.holidays)) return '';
  for (const h of state.holidays) {
    if (!h || h.enabled === false) continue;
    let iso = '';
    if (h.recurring) {
      if (h.rule) iso = resolveHolidayRule(h.rule, year);
      else if (typeof h.month === 'number' && typeof h.day === 'number') {
        iso = `${year}-${String(h.month).padStart(2,'0')}-${String(h.day).padStart(2,'0')}`;
      }
    } else if (h.date) {
      iso = h.date;
    }
    if (iso === dateStr) return h.name;
  }
  return '';
}

// Should `dateStr` be skipped according to current global settings?
// Returns the reason ('weekend', 'holiday name', or '') for messaging.
function getSkipReason(dateStr) {
  if (!dateStr) return '';
  if (state.skipWeekends && isWeekend(dateStr)) return 'weekend';
  if (state.skipHolidays && isHoliday(dateStr)) {
    const name = getHolidayName(dateStr) || 'holiday';
    return name;
  }
  return '';
}

// Snap forward to the next business day if the date hits a skip rule.
// Returns { date, shifted, reasons[] } so callers can show a "skipped X" hint.
// Stops after 60 iterations as a safety net (no infinite loops if both rules
// disabled would already short-circuit at getSkipReason).
function snapToBusinessDay(dateStr) {
  if (!dateStr) return { date: dateStr, shifted: 0, reasons: [] };
  if (!state.skipWeekends && !state.skipHolidays) return { date: dateStr, shifted: 0, reasons: [] };
  let cur = dateStr;
  let shifted = 0;
  const reasons = [];
  let safety = 60;
  while (safety-- > 0) {
    const reason = getSkipReason(cur);
    if (!reason) break;
    if (!reasons.includes(reason)) reasons.push(reason);
    cur = addDays(cur, 1);
    shifted++;
  }
  return { date: cur, shifted, reasons };
}

// Wrapper around addDays that respects business-day rules. Use this whenever
// converting an offset (D+N) into a calendar date for tasks. Manual date entry
// should NOT use this --- it's only for offset-calculated dates.
// Returns { date, shifted, reasons[] }.
function addBusinessDays(dateStr, days) {
  const raw = addDays(dateStr, days);
  return snapToBusinessDay(raw);
}

// =============================================================
// BID EXTENSION / DATE SHIFT --- master scheduling functions
// =============================================================

/**
 * Returns the "effective" bid start date for a project. This is the anchor
 * that task due dates are calculated from.
 *   - If the project has a revisedStartDate AND useRevisedDates is true, use revised
 *   - Otherwise use the project's original startDate
 * All task scheduling (dayOffset → dueDate) should call this helper.
 */
function getEffectiveBidStart(project) {
  if (!project) return '';
  if (project.useRevisedDates && project.revisedStartDate) return project.revisedStartDate;
  return project.startDate || '';
}

/**
 * When the bid due date is extended (or shortened), calculate what the bid
 * START date would need to be to preserve the same prep duration.
 * Returns an ISO date string (yyyy-mm-dd) for the revised start, or '' if
 * required anchors are missing.
 *
 * Logic: preserve the duration between original start and original due.
 *   newStart = newDue - (originalDue - originalStart)
 */
function computeRevisedBidStart(project, newDueDate) {
  if (!project || !newDueDate) return '';
  const origStart = project.originalStartDate || project.startDate || '';
  const origDue = project.originalDueDate || project.dueDate || '';
  if (!origStart || !origDue) return '';
  const duration = daysBetween(origStart, origDue);
  if (duration === null) return '';
  return addDays(newDueDate, -duration);
}

/**
 * Recalculates every task's dueDate from its dayOffset using the currently
 * effective bid start. Tasks without a dayOffset are left alone.
 * Respects global skipWeekends/skipHolidays settings --- calculated dates
 * landing on a skipped day snap forward to the next business day.
 */
function reanchorProjectTaskDates(project) {
  if (!project) return 0;
  const anchor = getEffectiveBidStart(project);
  if (!anchor) return 0;
  let changed = 0;
  project.tasks.forEach(t => {
    if (typeof t.dayOffset === 'number') {
      const result = addBusinessDays(anchor, t.dayOffset);
      const newDue = result.date;
      if (t.dueDate !== newDue) { t.dueDate = newDue; changed++; }
    }
  });
  return changed;
}

/**
 * Toggle whether the project uses the revised start date or the original.
 * Automatically reanchors all tasks and re-renders.
 */
function toggleProjectDateMode(projectId) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  // If the user is turning ON revised but there's no revised date, prompt
  if (!p.useRevisedDates && !p.revisedStartDate) {
    alert('No revised Bid Start Date is set yet. Edit the project and enter a new Bid Due Date (or manually set a Revised Bid Start).');
    return;
  }
  p.useRevisedDates = !p.useRevisedDates;
  reanchorProjectTaskDates(p);
  saveState();
  render();
}

/**
 * Manually set a revised bid start date (override the calculated one).
 * Used by the "Revised Start Override" field in the project modal.
 */
function applyRevisedStartOverride(projectId, newRevisedStart) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  p.revisedStartDate = newRevisedStart || '';
  if (p.useRevisedDates) reanchorProjectTaskDates(p);
  saveState();
  render();
}

// =============================================================
// REVISE BID DATE --- streamlined workflow for date extensions
// =============================================================
let rbdStartManuallyEdited = false;

// =============================================================
// ADDENDUMS LOG --- per-project list of architect/owner-issued document revisions
// =============================================================

// Status metadata
const ADDENDUM_STATUSES = {
  'received':     { icon: '📥', label: 'Received',                color: '#0e5b9c' },
  'reviewed':     { icon: '🔍', label: 'Reviewed',                color: '#7b4397' },
  'distributed':  { icon: '📤', label: 'Distributed to Subs',     color: '#c07f00' },
  'acknowledged': { icon: '✓',  label: 'Sub Coverage Confirmed',  color: '#2e7d52' }
};

const BID_IMPACT_LABELS = {
  'none':     { icon: '',  label: 'No bid impact',     color: 'var(--text-dim)' },
  'extends':  { icon: '⚠', label: 'Bid date extended', color: 'var(--sbg-red)' },
  'shortens': { icon: '⚠', label: 'Bid date shortened', color: 'var(--sbg-red)' },
  'tbd':      { icon: '?', label: 'Impact TBD',         color: '#c07f00' }
};

function getNextAddendumNumber(project) {
  if (!project || !Array.isArray(project.addenda) || project.addenda.length === 0) return '1';
  // Find the highest numeric addendum number used so far
  const nums = project.addenda
    .map(a => parseInt((a.number || '').replace(/[^\d]/g, ''), 10))
    .filter(n => !isNaN(n));
  if (nums.length === 0) return String(project.addenda.length + 1);
  return String(Math.max(...nums) + 1);
}

function openAddendumModal(addendumId) {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) { alert('No active project. Select one from the sidebar first.'); return; }
  if (!Array.isArray(project.addenda)) project.addenda = [];

  const isEdit = !!addendumId;
  const existing = isEdit ? project.addenda.find(a => a.id === addendumId) : null;
  if (isEdit && !existing) { alert('Addendum not found.'); return; }

  document.getElementById('addendumModalTitle').textContent = isEdit ? `📑 Edit Addendum #${existing.number || ''}`.trim() : '📑 Add Addendum';
  document.getElementById('addendumEditingId').value = addendumId || '';

  // Populate fields
  document.getElementById('addendumNumber').value      = existing ? (existing.number || '')         : getNextAddendumNumber(project);
  document.getElementById('addendumStatus').value      = existing ? (existing.status || 'received') : 'received';
  document.getElementById('addendumDateIssued').value  = existing ? (existing.dateIssued || '')     : '';
  document.getElementById('addendumDateReceived').value= existing ? (existing.dateReceived || '')   : new Date().toISOString().slice(0, 10);
  document.getElementById('addendumSubject').value     = existing ? (existing.subject || '')        : '';
  document.getElementById('addendumIssuer').value      = existing ? (existing.issuer || '')         : '';
  document.getElementById('addendumDescription').value = existing ? (existing.description || '')   : '';
  document.getElementById('addendumAffectedDocs').value= existing ? (existing.affectedDocs || '')  : '';
  document.getElementById('addendumBidImpact').value   = existing ? (existing.bidImpact || 'none') : 'none';
  document.getElementById('addendumNewBidDate').value  = existing ? (existing.newBidDate || '')    : '';
  document.getElementById('addendumAttachment').value  = existing ? (existing.attachmentName || '') : '';
  document.getElementById('addendumAttachmentUrl').value = existing ? (existing.attachmentUrl || '') : '';
  document.getElementById('addendumNotes').value       = existing ? (existing.notes || '')         : '';

  // Show delete button only on edit
  document.getElementById('addendumDeleteBtn').style.display = isEdit ? 'inline-flex' : 'none';

  document.getElementById('addendumModal').classList.add('active');
  // Scroll to top
  setTimeout(() => {
    const inner = document.querySelector('#addendumModal .modal');
    if (inner) inner.scrollTop = 0;
  }, 0);
}

function saveAddendum() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  if (!Array.isArray(project.addenda)) project.addenda = [];

  const editingId = document.getElementById('addendumEditingId').value;
  const number       = document.getElementById('addendumNumber').value.trim();
  const status       = document.getElementById('addendumStatus').value;
  const dateIssued   = document.getElementById('addendumDateIssued').value;
  const dateReceived = document.getElementById('addendumDateReceived').value;
  const subject      = document.getElementById('addendumSubject').value.trim();
  const issuer       = document.getElementById('addendumIssuer').value.trim();
  const description  = document.getElementById('addendumDescription').value.trim();
  const affectedDocs = document.getElementById('addendumAffectedDocs').value.trim();
  const bidImpact    = document.getElementById('addendumBidImpact').value;
  const newBidDate   = document.getElementById('addendumNewBidDate').value;
  const attachmentName = document.getElementById('addendumAttachment').value.trim();
  const attachmentUrl  = document.getElementById('addendumAttachmentUrl').value.trim();
  const notes        = document.getElementById('addendumNotes').value.trim();

  if (!number && !subject) {
    alert('Please enter at least an addendum number OR a subject.');
    return;
  }

  if (editingId) {
    const a = project.addenda.find(x => x.id === editingId);
    if (a) {
      a.number = number;
      a.status = status;
      a.dateIssued = dateIssued;
      a.dateReceived = dateReceived;
      a.subject = subject;
      a.issuer = issuer;
      a.description = description;
      a.affectedDocs = affectedDocs;
      a.bidImpact = bidImpact;
      a.newBidDate = newBidDate;
      a.attachmentName = attachmentName;
      a.attachmentUrl = attachmentUrl;
      a.notes = notes;
      a.updatedAt = Date.now();
      logAddendumLogged(project, a, 'edited');
    }
  } else {
    const newAddendum = {
      id: 'add-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 6),
      number, status, dateIssued, dateReceived, subject, issuer, description,
      affectedDocs, bidImpact, newBidDate, attachmentName, attachmentUrl, notes,
      createdAt: Date.now(),
      updatedAt: Date.now()
    };
    project.addenda.push(newAddendum);
    logAddendumLogged(project, newAddendum, 'created');
  }

  saveState();
  closeModal('addendumModal');

  // If user marked bid date as extended/shortened with a new date, offer to apply it
  if (!editingId && (bidImpact === 'extends' || bidImpact === 'shortens') && newBidDate) {
    setTimeout(() => {
      if (confirm(`This addendum ${bidImpact === 'extends' ? 'extends' : 'shortens'} the bid date to ${formatDate(newBidDate)}.\n\nWould you like to open Revise Bid Date now to apply this change to the project schedule?`)) {
        openReviseBidModal();
        // Pre-fill the new bid date in the revise modal
        setTimeout(() => {
          const dueInput = document.getElementById('rbdNewDue');
          if (dueInput) dueInput.value = newBidDate;
        }, 100);
      }
    }, 200);
  }

  render();
}

function deleteAddendumFromModal() {
  const editingId = document.getElementById('addendumEditingId').value;
  if (!editingId) return;
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const a = project.addenda.find(x => x.id === editingId);
  if (!a) return;
  if (!confirm(`Delete Addendum #${a.number || ''}?\n\n"${a.subject || '(no subject)'}"\n\nThis cannot be undone.`)) return;
  project.addenda = project.addenda.filter(x => x.id !== editingId);
  saveState();
  closeModal('addendumModal');
  render();
}

function deleteAddendum(addendumId, event) {
  if (event) event.stopPropagation();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const a = project.addenda.find(x => x.id === addendumId);
  if (!a) return;
  if (!confirm(`Delete Addendum #${a.number || ''}?\n\n"${a.subject || '(no subject)'}"\n\nThis cannot be undone.`)) return;
  logAddendumLogged(project, a, 'deleted');
  project.addenda = project.addenda.filter(x => x.id !== addendumId);
  saveState();
  render();
}

function quickUpdateAddendumStatus(addendumId, newStatus, event) {
  if (event) event.stopPropagation();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const a = project.addenda.find(x => x.id === addendumId);
  if (!a) return;
  a.status = newStatus;
  a.updatedAt = Date.now();
  saveState();
  render();
}

function renderAddendumsSection(project) {
  const listEl = document.getElementById('pvAddendumsList');
  const emptyEl = document.getElementById('pvAddendumsEmpty');
  const summaryEl = document.getElementById('pvAddendumsSummary');
  const headerBadgeEl = document.getElementById('pvaCountBadge');
  if (!listEl) return;

  if (!Array.isArray(project.addenda)) project.addenda = [];
  const addenda = project.addenda;

  // Update header button badge
  if (headerBadgeEl) {
    if (addenda.length > 0) {
      headerBadgeEl.textContent = ' ' + addenda.length;
      headerBadgeEl.style.display = 'inline-block';
    } else {
      headerBadgeEl.style.display = 'none';
    }
  }

  // Update section summary
  if (summaryEl) {
    if (addenda.length === 0) {
      summaryEl.textContent = '';
    } else {
      const distributedCount = addenda.filter(a => a.status === 'distributed' || a.status === 'acknowledged').length;
      const pendingCount = addenda.length - distributedCount;
      const bidImpactCount = addenda.filter(a => a.bidImpact === 'extends' || a.bidImpact === 'shortens').length;
      const parts = [`${addenda.length} total`];
      if (pendingCount > 0) parts.push(`<span style="color:var(--sbg-red);font-weight:700;">${pendingCount} pending distribution</span>`);
      if (bidImpactCount > 0) parts.push(`<span style="color:#c07f00;font-weight:700;">${bidImpactCount} affecting bid date</span>`);
      summaryEl.innerHTML = parts.join(' · ');
    }
  }

  // Empty state
  if (addenda.length === 0) {
    listEl.innerHTML = '';
    if (emptyEl) emptyEl.style.display = 'block';
    return;
  }
  if (emptyEl) emptyEl.style.display = 'none';

  // Sort: most recent first by date received (or createdAt), then by number desc
  const sorted = addenda.slice().sort((a, b) => {
    const da = a.dateReceived || (a.createdAt ? new Date(a.createdAt).toISOString().slice(0,10) : '');
    const db = b.dateReceived || (b.createdAt ? new Date(b.createdAt).toISOString().slice(0,10) : '');
    if (da !== db) return db.localeCompare(da);
    const na = parseInt((a.number || '').replace(/[^\d]/g, ''), 10) || 0;
    const nb = parseInt((b.number || '').replace(/[^\d]/g, ''), 10) || 0;
    return nb - na;
  });

  listEl.innerHTML = sorted.map(a => {
    const statusMeta = ADDENDUM_STATUSES[a.status] || ADDENDUM_STATUSES['received'];
    const impactMeta = BID_IMPACT_LABELS[a.bidImpact] || BID_IMPACT_LABELS['none'];
    const num = a.number ? `#${escapeHtml(a.number)}` : '#---';
    const dateStr = a.dateReceived ? formatDate(a.dateReceived) : (a.dateIssued ? formatDate(a.dateIssued) : '---');

    // Status dropdown for inline edit
    const statusOpts = Object.keys(ADDENDUM_STATUSES).map(k => {
      const s = ADDENDUM_STATUSES[k];
      return `<option value="${k}"${k === a.status ? ' selected' : ''}>${s.icon} ${s.label}</option>`;
    }).join('');

    const bidImpactBadge = (a.bidImpact && a.bidImpact !== 'none')
      ? `<span class="addenda-bid-impact" style="background:${impactMeta.color}15;color:${impactMeta.color};border-color:${impactMeta.color}40;">${impactMeta.icon} ${escapeHtml(impactMeta.label)}${a.newBidDate ? ` (${formatDate(a.newBidDate)})` : ''}</span>`
      : '';

    const attachmentHtml = (a.attachmentName || a.attachmentUrl)
      ? (a.attachmentUrl
          ? `<a class="addenda-attachment" href="${escapeHtml(a.attachmentUrl)}" target="_blank" rel="noopener" onclick="event.stopPropagation();" title="${escapeHtml(a.attachmentName || a.attachmentUrl)}">📎 ${escapeHtml(a.attachmentName || 'Open Link')}</a>`
          : `<span class="addenda-attachment" title="${escapeHtml(a.attachmentName)}">📎 ${escapeHtml(a.attachmentName)}</span>`)
      : '';

    return `
      <div class="addenda-row" onclick="openAddendumModal('${a.id}')">
        <div class="addenda-num">${num}</div>
        <div class="addenda-body">
          <div class="addenda-primary-row">
            <div class="addenda-subject">${escapeHtml(a.subject || '(no subject)')}</div>
            <div class="addenda-meta-right">
              ${bidImpactBadge}
              <select class="addenda-status-select" style="background:${statusMeta.color}18;color:${statusMeta.color};border-color:${statusMeta.color}40;" onclick="event.stopPropagation();" onchange="quickUpdateAddendumStatus('${a.id}', this.value, event)">
                ${statusOpts}
              </select>
            </div>
          </div>
          <div class="addenda-details-row">
            <span class="addenda-chip">📅 ${dateStr}</span>
            ${a.issuer ? `<span class="addenda-chip">🏛 ${escapeHtml(a.issuer)}</span>` : ''}
            ${a.affectedDocs ? `<span class="addenda-chip" title="Affected documents">📄 ${escapeHtml(a.affectedDocs.length > 60 ? a.affectedDocs.slice(0,57) + '...' : a.affectedDocs)}</span>` : ''}
            ${attachmentHtml}
          </div>
          ${a.description ? `<div class="addenda-desc">${escapeHtml(a.description.length > 200 ? a.description.slice(0,197) + '...' : a.description)}</div>` : ''}
        </div>
        <div class="addenda-actions">
          <button class="addenda-btn-icon" onclick="event.stopPropagation(); deleteAddendum('${a.id}', event);" title="Delete addendum">✕</button>
        </div>
      </div>
    `;
  }).join('');
}

// =============================================================
// BULK ASSIGN --- assign all tasks within a stage to one team member
// =============================================================
function openBulkAssignModal(stageId) {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) { alert('No active project.'); return; }
  const stage = STAGES.find(s => s.id === stageId);
  if (!stage) { alert('Stage not found.'); return; }

  // Snapshot of tasks in this stage
  const tasks = (project.tasks || []).filter(t => t.stage === stageId);
  if (tasks.length === 0) {
    alert(`No tasks in "${stage.name}" --- nothing to assign. Add tasks to this stage first.`);
    return;
  }

  // Compute a quick stat breakdown
  const assignedCount = tasks.filter(t => t.assignee && t.assignee.trim()).length;
  const unassignedCount = tasks.length - assignedCount;
  const doneCount = tasks.filter(t => t.status === 'done').length;
  const activeCount = tasks.length - doneCount;

  // Populate stage id + title
  document.getElementById('bulkAssignStageId').value = stageId;
  document.getElementById('bulkAssignTitle').textContent = `${stage.icon} Assign All --- ${stage.name}`;
  document.getElementById('bulkAssignDescription').innerHTML = `Bulk-assign tasks in <strong>${escapeHtml(stage.name)}</strong> to one team member. Useful when a single estimator owns this entire workflow stage.`;

  // Stats panel
  document.getElementById('bulkAssignStats').innerHTML = `
    <div class="ba-stat-row">
      <span class="ba-stat-label">Total tasks in stage:</span>
      <span class="ba-stat-value">${tasks.length}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Already assigned:</span>
      <span class="ba-stat-value" style="color:var(--green);">${assignedCount}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Unassigned:</span>
      <span class="ba-stat-value" style="color:${unassignedCount > 0 ? 'var(--sbg-red)' : 'var(--text-dim)'};">${unassignedCount}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Active (incomplete):</span>
      <span class="ba-stat-value">${activeCount}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Already complete:</span>
      <span class="ba-stat-value" style="color:var(--text-dim);">${doneCount}</span>
    </div>
  `;

  // Populate assignee dropdown from team roster
  const select = document.getElementById('bulkAssignAssignee');
  let opts = '<option value="">--- Unassigned (clear assignee) ---</option>';
  (state.teamMembers || []).forEach(m => {
    if (!m.name) return;
    const titleStr = m.title ? ` · ${m.title}` : '';
    opts += `<option value="${escapeHtml(m.name)}">${escapeHtml(m.name)}${escapeHtml(titleStr)}</option>`;
  });
  select.innerHTML = opts;
  select.value = ''; // default to unassigned

  // Reset role to assignee
  document.getElementById('bulkAssignRole').value = 'assignee';
  document.getElementById('bulkAssignSkipExisting').checked = true;
  document.getElementById('bulkAssignSkipDone').checked = true;

  document.getElementById('bulkAssignModal').classList.add('active');
}

function executeBulkAssign() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const stageId = document.getElementById('bulkAssignStageId').value;
  const stage = STAGES.find(s => s.id === stageId);
  if (!stage) return;

  const newAssignee = document.getElementById('bulkAssignAssignee').value.trim();
  const role = document.getElementById('bulkAssignRole').value; // 'assignee' or 'support'
  const skipExisting = document.getElementById('bulkAssignSkipExisting').checked;
  const skipDone = document.getElementById('bulkAssignSkipDone').checked;

  const tasks = project.tasks.filter(t => t.stage === stageId);

  // Determine which tasks to update based on filters
  const targetTasks = tasks.filter(t => {
    if (skipDone && t.status === 'done') return false;
    if (skipExisting) {
      const currentValue = role === 'assignee' ? (t.assignee || '').trim() : (t.support || '').trim();
      if (currentValue) return false;
    }
    return true;
  });

  if (targetTasks.length === 0) {
    alert(`No tasks match the current filters.\n\n• ${tasks.length} tasks total in this stage\n• ${skipExisting ? 'Skipping tasks that already have an assignee' : 'Including tasks with existing assignees'}\n• ${skipDone ? 'Skipping completed tasks' : 'Including completed tasks'}\n\nTry unchecking one of the filter options to broaden the selection.`);
    return;
  }

  // Build confirmation message
  const roleLabel = role === 'assignee' ? 'Lead Owner' : 'Support';
  const targetName = newAssignee || '(unassigned)';
  const message = `Set ${roleLabel} = "${targetName}" on ${targetTasks.length} task${targetTasks.length === 1 ? '' : 's'} in "${stage.name}"?\n\n${targetTasks.length} of ${tasks.length} stage tasks will be updated.\n\nThis cannot be easily undone.`;
  if (!confirm(message)) return;

  // Apply the change
  let updatedCount = 0;
  targetTasks.forEach(t => {
    if (role === 'assignee') {
      t.assignee = newAssignee;
      // When (re)assigning Lead Owner, also reset acknowledgment so the new owner sees it as new
      if (newAssignee) {
        t.acknowledged = false;
        t.acknowledgedBy = '';
        t.acknowledgedAt = null;
        t.acknowledgedOverrideBy = '';
        t.acknowledgedOverrideAt = null;
      } else {
        // Clearing assignee --- grandfather acknowledgment as true so it doesn't show as unacked
        t.acknowledged = true;
      }
    } else {
      t.support = newAssignee;
    }
    updatedCount++;
  });

  saveState();
  closeModal('bulkAssignModal');
  render();

  // Friendly summary
  setTimeout(() => {
    alert(`✓ ${roleLabel} set to "${targetName}" on ${updatedCount} task${updatedCount === 1 ? '' : 's'} in "${stage.name}".`);
  }, 100);
}

// =============================================================
// REASSIGN PERSON --- move every task assigned to one team member
// over to another, optionally scoped/filtered.
// =============================================================
function getTasksForPersonGrouped(personName) {
  // Returns: { byProject: [{project, leadTasks, supportTasks}], totals: {lead, support, done, active} }
  const byProject = [];
  let totalLead = 0, totalSupport = 0, totalDone = 0, totalActive = 0;
  state.projects.forEach(p => {
    const leadTasks = (p.tasks || []).filter(t => (t.assignee || '') === personName);
    const supportTasks = (p.tasks || []).filter(t => isTaskSupport(t, personName) && t.assignee !== personName);
    if (leadTasks.length === 0 && supportTasks.length === 0) return;
    byProject.push({ project: p, leadTasks, supportTasks });
    totalLead += leadTasks.length;
    totalSupport += supportTasks.length;
    leadTasks.concat(supportTasks).forEach(t => {
      if (t.status === 'done') totalDone++;
      else totalActive++;
    });
  });
  return { byProject, totals: { lead: totalLead, support: totalSupport, done: totalDone, active: totalActive } };
}

function openReassignPersonModal(personName) {
  if (!personName) { alert('No team member specified.'); return; }
  const data = getTasksForPersonGrouped(personName);

  if (data.totals.lead === 0 && data.totals.support === 0) {
    alert(`${personName} has no tasks assigned across any project. Nothing to reassign.`);
    return;
  }

  document.getElementById('reassignPersonFromName').value = personName;
  document.getElementById('reassignPersonTitle').textContent = `↻ Reassign ${personName}'s Tasks`;
  document.getElementById('reassignPersonDescription').innerHTML = `Move every task currently assigned to <strong>${escapeHtml(personName)}</strong> over to another team member. Useful for handoffs, time off, or staff changes.`;

  // Build stats panel --- total counts + per-project breakdown
  let projectBreakdown = '';
  data.byProject.forEach(b => {
    projectBreakdown += `
      <div class="ba-stat-row" style="font-size:11px;color:var(--text-dim);padding-left:10px;">
        <span class="ba-stat-label">↳ ${escapeHtml(b.project.name)}</span>
        <span class="ba-stat-value" style="font-size:10px;">${b.leadTasks.length} lead${b.supportTasks.length > 0 ? ` · ${b.supportTasks.length} support` : ''}</span>
      </div>
    `;
  });

  document.getElementById('reassignPersonStats').innerHTML = `
    <div class="ba-stat-row">
      <span class="ba-stat-label">Lead Owner of:</span>
      <span class="ba-stat-value" style="color:${data.totals.lead > 0 ? 'var(--sbg-navy)' : 'var(--text-dim)'};">${data.totals.lead} task${data.totals.lead === 1 ? '' : 's'}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Support on:</span>
      <span class="ba-stat-value" style="color:${data.totals.support > 0 ? 'var(--blue)' : 'var(--text-dim)'};">${data.totals.support} task${data.totals.support === 1 ? '' : 's'}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Active (incomplete):</span>
      <span class="ba-stat-value">${data.totals.active}</span>
    </div>
    <div class="ba-stat-row">
      <span class="ba-stat-label">Already complete:</span>
      <span class="ba-stat-value" style="color:var(--text-dim);">${data.totals.done}</span>
    </div>
    <div class="ba-stat-row" style="margin-top:6px;padding-top:8px;border-top:1px solid var(--border);">
      <span class="ba-stat-label" style="font-weight:700;">Across ${data.byProject.length} project${data.byProject.length === 1 ? '' : 's'}:</span>
      <span class="ba-stat-value"></span>
    </div>
    ${projectBreakdown}
  `;

  // Populate "Reassign To" dropdown --- exclude the source person
  const select = document.getElementById('reassignPersonToName');
  let opts = '<option value="">--- Unassigned (clear assignments) ---</option>';
  (state.teamMembers || []).forEach(m => {
    if (!m.name || m.name === personName) return;
    const titleStr = m.title ? ` · ${m.title}` : '';
    opts += `<option value="${escapeHtml(m.name)}">${escapeHtml(m.name)}${escapeHtml(titleStr)}</option>`;
  });
  select.innerHTML = opts;
  select.value = '';

  // Reset filters to defaults
  document.getElementById('reassignPersonScope').value = state.activeProjectId ? 'all' : 'all';
  document.getElementById('reassignPersonRoles').value = 'both';
  document.getElementById('reassignPersonSkipDone').checked = true;
  document.getElementById('reassignPersonResetAck').checked = true;

  document.getElementById('reassignPersonModal').classList.add('active');
}

function executeReassignPerson() {
  const fromName = document.getElementById('reassignPersonFromName').value;
  const toName = document.getElementById('reassignPersonToName').value.trim();
  const scope = document.getElementById('reassignPersonScope').value; // 'all' | 'active'
  const roles = document.getElementById('reassignPersonRoles').value; // 'both' | 'assignee' | 'support'
  const skipDone = document.getElementById('reassignPersonSkipDone').checked;
  const resetAck = document.getElementById('reassignPersonResetAck').checked;

  if (!fromName) return;
  if (fromName === toName) {
    alert('Cannot reassign tasks to the same person. Pick a different team member.');
    return;
  }

  // Determine project scope
  let scopedProjects;
  if (scope === 'active') {
    const ap = state.projects.find(p => p.id === state.activeProjectId);
    if (!ap) {
      alert('No active project --- switch to "All projects" or open a project first.');
      return;
    }
    scopedProjects = [ap];
  } else {
    scopedProjects = state.projects.slice();
  }

  // Count what will be touched
  let willUpdate = 0, leadUpdates = 0, supportUpdates = 0;
  scopedProjects.forEach(p => {
    (p.tasks || []).forEach(t => {
      if (skipDone && t.status === 'done') return;
      const isLead = (t.assignee || '') === fromName;
      const isSupport = (t.support || '') === fromName;
      const moveLead = (roles === 'both' || roles === 'assignee') && isLead;
      const moveSupport = (roles === 'both' || roles === 'support') && isSupport;
      if (moveLead) { willUpdate++; leadUpdates++; }
      if (moveSupport) { willUpdate++; supportUpdates++; }
    });
  });

  if (willUpdate === 0) {
    alert(`No tasks match the current filters.\n\n• Scope: ${scope === 'all' ? 'All projects' : 'Current project only'}\n• Roles: ${roles === 'both' ? 'Lead + Support' : (roles === 'assignee' ? 'Lead only' : 'Support only')}\n• ${skipDone ? 'Skipping completed tasks' : 'Including completed tasks'}\n\nTry broadening one of the filters.`);
    return;
  }

  // Confirmation
  const targetLabel = toName || '(unassigned)';
  const scopeLabel = scope === 'all' ? 'all projects' : 'the current project';
  const roleLabel = roles === 'both' ? 'Lead + Support assignments' : (roles === 'assignee' ? 'Lead Owner assignments' : 'Support assignments');
  let summary = `Reassign ${fromName}'s ${roleLabel} to "${targetLabel}" across ${scopeLabel}?\n\n`;
  if (leadUpdates > 0) summary += `• ${leadUpdates} Lead Owner reassignment${leadUpdates === 1 ? '' : 's'}\n`;
  if (supportUpdates > 0) summary += `• ${supportUpdates} Support reassignment${supportUpdates === 1 ? '' : 's'}\n`;
  summary += `\n${willUpdate} task field${willUpdate === 1 ? '' : 's'} total will be modified. This cannot be easily undone.`;
  if (!confirm(summary)) return;

  // Apply changes
  let actualUpdates = 0;
  scopedProjects.forEach(p => {
    (p.tasks || []).forEach(t => {
      if (skipDone && t.status === 'done') return;

      // Lead assignment
      if ((roles === 'both' || roles === 'assignee') && t.assignee === fromName) {
        t.assignee = toName;
        actualUpdates++;
        // Reset acknowledgment so the new owner sees it as new (when reassigning to someone real)
        if (resetAck && toName) {
          t.acknowledged = false;
          t.acknowledgedBy = '';
          t.acknowledgedAt = null;
          t.acknowledgedOverrideBy = '';
          t.acknowledgedOverrideAt = null;
        } else if (!toName) {
          // Clearing --- grandfather acknowledgment to true so it doesn't appear unacked
          t.acknowledged = true;
        }
      }

      // Support assignment --- handles both legacy task.support AND task.supportMembers array
      if (roles === 'both' || roles === 'support') {
        if (t.support === fromName) {
          t.support = toName;
          actualUpdates++;
        }
        if (Array.isArray(t.supportMembers)) {
          t.supportMembers = t.supportMembers.map(s => {
            if (s === fromName) {
              actualUpdates++;
              return toName;
            }
            return s;
          }).filter(s => s !== ''); // remove if toName was empty
        }
      }
    });
  });

  saveState();
  closeModal('reassignPersonModal');
  // Refresh team list if open, plus the project view
  if (document.getElementById('teamModal').classList.contains('active')) renderTeamList();
  render();

  setTimeout(() => {
    alert(`✓ Reassigned ${actualUpdates} task field${actualUpdates === 1 ? '' : 's'} from ${fromName} to ${targetLabel}${scope === 'all' ? ' across all projects' : ' in the current project'}.`);
  }, 100);
}

function openReviseBidModal() {
  const p = state.projects.find(x => x.id === state.activeProjectId);
  if (!p) { alert('No active project. Select one from the sidebar first.'); return; }

  // Build the context block showing original vs current
  const origStart = p.originalStartDate || p.startDate || '';
  const origDue = p.originalDueDate || p.dueDate || '';
  const currentStart = p.startDate || '';
  const currentDue = p.dueDate || '';
  const isCurrentlyRevised = p.useRevisedDates && p.revisedStartDate;

  const origDuration = daysBetween(origStart, origDue);
  const durationLabel = origDuration !== null ? `${origDuration} days` : '---';

  document.getElementById('rbdContext').innerHTML = `
    <div class="rbd-proj-name">${escapeHtml(p.name)}</div>
    <div class="rbd-context-grid">
      <div>
        <div class="rbd-ctx-label">Original Bid Start</div>
        <div class="rbd-ctx-value">${origStart ? formatDate(origStart) : '---'}</div>
      </div>
      <div>
        <div class="rbd-ctx-label">Original Bid Due</div>
        <div class="rbd-ctx-value">${origDue ? formatDate(origDue) : '---'}</div>
      </div>
      <div>
        <div class="rbd-ctx-label">Original Prep Window</div>
        <div class="rbd-ctx-value">${durationLabel}</div>
      </div>
      <div>
        <div class="rbd-ctx-label">Current Bid Start ${isCurrentlyRevised ? '(REV)' : ''}</div>
        <div class="rbd-ctx-value ${isCurrentlyRevised ? 'ctx-revised' : ''}">${currentStart ? formatDate(getEffectiveBidStart(p)) : '---'}</div>
      </div>
      <div>
        <div class="rbd-ctx-label">Current Bid Due ${p.originalDueDate && p.originalDueDate !== p.dueDate ? '(REV)' : ''}</div>
        <div class="rbd-ctx-value ${p.originalDueDate && p.originalDueDate !== p.dueDate ? 'ctx-revised' : ''}">${currentDue ? formatDate(currentDue) : '---'}</div>
      </div>
      <div>
        <div class="rbd-ctx-label">Active Mode</div>
        <div class="rbd-ctx-value ${isCurrentlyRevised ? 'ctx-revised' : ''}">${isCurrentlyRevised ? 'REVISED' : 'ORIGINAL'}</div>
      </div>
    </div>
  `;

  // Pre-fill new due date with current due (so user can just bump it forward)
  document.getElementById('rbdNewDueDate').value = currentDue;
  document.getElementById('rbdNewStartDate').value = '';
  document.getElementById('rbdReanchor').checked = true;
  document.getElementById('rbdUseRevised').checked = true;
  rbdStartManuallyEdited = false;

  // Show Reset button only if there's actually something to reset
  const resetBtn = document.getElementById('rbdResetBtn');
  const hasRevision = (p.originalDueDate && p.originalDueDate !== p.dueDate) ||
                      (p.revisedStartDate) ||
                      (p.useRevisedDates);
  resetBtn.style.display = hasRevision ? 'inline-flex' : 'none';

  updateReviseBidPreview();
  document.getElementById('reviseBidModal').classList.add('active');
}

function updateReviseBidPreview() {
  const p = state.projects.find(x => x.id === state.activeProjectId);
  if (!p) return;

  const newDue = document.getElementById('rbdNewDueDate').value;
  const shiftEl = document.getElementById('rbdShiftDisplay');
  const newStartEl = document.getElementById('rbdNewStartDate');
  const newDurEl = document.getElementById('rbdNewDurationDisplay');

  const origStart = p.originalStartDate || p.startDate || '';
  const origDue = p.originalDueDate || p.dueDate || '';

  if (!newDue || !origDue) {
    shiftEl.textContent = '---';
    shiftEl.className = 'bex-shift-display';
    newDurEl.textContent = '---';
    newDurEl.className = 'bex-shift-display';
    return;
  }

  // Shift from ORIGINAL due (so you get the total shift, not incremental)
  const shiftDays = daysBetween(origDue, newDue);
  if (shiftDays === 0) {
    shiftEl.textContent = 'No shift';
    shiftEl.className = 'bex-shift-display';
  } else if (shiftDays > 0) {
    shiftEl.textContent = `+${shiftDays} days (extended)`;
    shiftEl.className = 'bex-shift-display shift-positive';
  } else {
    shiftEl.textContent = `${shiftDays} days (shortened)`;
    shiftEl.className = 'bex-shift-display shift-negative';
  }

  // Auto-calculate revised start UNLESS user has manually edited it
  if (!rbdStartManuallyEdited && origStart) {
    const calcStart = addDays(origStart, shiftDays);
    newStartEl.value = calcStart;
  }

  // Show new prep window
  const effStart = newStartEl.value;
  if (effStart && newDue) {
    const newDuration = daysBetween(effStart, newDue);
    if (newDuration !== null) {
      newDurEl.textContent = `${newDuration} days`;
      newDurEl.className = 'bex-shift-display';
    }
  }
}

function applyBidRevision() {
  const p = state.projects.find(x => x.id === state.activeProjectId);
  if (!p) return;

  const newDue = document.getElementById('rbdNewDueDate').value;
  const newStart = document.getElementById('rbdNewStartDate').value;
  const reanchor = document.getElementById('rbdReanchor').checked;
  const useRevised = document.getElementById('rbdUseRevised').checked;

  if (!newDue) { alert('Enter a new Bid Due Date'); return; }

  // Preserve the original reference points if not already set
  if (!p.originalStartDate) p.originalStartDate = p.startDate || '';
  if (!p.originalDueDate) p.originalDueDate = p.dueDate || '';

  // Apply new dates
  p.dueDate = newDue;
  if (newStart) {
    p.revisedStartDate = newStart;
    if (useRevised) {
      p.useRevisedDates = true;
      // When using revised, also set startDate to the revised start so task dates align
      // (startDate is what task due dates are calculated from when useRevisedDates is false,
      //  but we want getEffectiveBidStart to return revisedStartDate when useRevised is on.)
    } else {
      p.useRevisedDates = false;
    }
  } else {
    // No revised start provided --- clear revision and keep original
    p.revisedStartDate = '';
    p.useRevisedDates = false;
  }

  // Reanchor tasks if requested
  let changedCount = 0;
  if (reanchor) {
    changedCount = reanchorProjectTaskDates(p);
  }

  // Refresh auto-dated milestones if project opted-in to default offsets
  let milestonesRefreshed = 0;
  if (p.useDefaultOffsets) {
    milestonesRefreshed = refreshAutoMilestoneDates(p);
  }

  saveState();
  closeModal('reviseBidModal');
  render();

  // Confirmation toast-style alert
  const shift = daysBetween(p.originalDueDate, newDue);
  const shiftLabel = shift > 0 ? `+${shift}` : `${shift}`;
  let msg = `✓ Bid schedule revised by ${shiftLabel} days.`;
  if (reanchor && changedCount > 0) msg += `\n${changedCount} task due date${changedCount === 1 ? '' : 's'} re-anchored to the ${useRevised ? 'revised' : 'original'} Bid Start.`;
  if (reanchor && changedCount === 0) msg += '\nNo task due dates needed updating.';
  if (milestonesRefreshed > 0) msg += `\n${milestonesRefreshed} auto-dated milestone${milestonesRefreshed === 1 ? '' : 's'} recomputed.`;
  setTimeout(() => alert(msg), 100);
}

function resetBidRevision() {
  const p = state.projects.find(x => x.id === state.activeProjectId);
  if (!p) return;
  if (!confirm(`Clear the bid revision and restore the original schedule?\n\n• Bid Start → ${p.originalStartDate ? formatDate(p.originalStartDate) : '(unchanged)'}\n• Bid Due → ${p.originalDueDate ? formatDate(p.originalDueDate) : '(unchanged)'}\n\nAll tasks with a day-offset will re-anchor to the original Bid Start.`)) return;

  if (p.originalStartDate) p.startDate = p.originalStartDate;
  if (p.originalDueDate) p.dueDate = p.originalDueDate;
  p.revisedStartDate = '';
  p.useRevisedDates = false;
  const changed = reanchorProjectTaskDates(p);
  // Also refresh auto-dated milestones to match restored bid date
  let milestonesRefreshed = 0;
  if (p.useDefaultOffsets) milestonesRefreshed = refreshAutoMilestoneDates(p);

  saveState();
  closeModal('reviseBidModal');
  render();
  let msg = `✓ Schedule restored to original.\n${changed} task due date${changed === 1 ? '' : 's'} re-anchored.`;
  if (milestonesRefreshed > 0) msg += `\n${milestonesRefreshed} auto-dated milestone${milestonesRefreshed === 1 ? '' : 's'} recomputed.`;
  setTimeout(() => alert(msg), 100);
}

// =============================================================
// IMAGE UPLOAD (resizes to max 600px, stores as base64)
// =============================================================
let pendingProjectImage = null; // holds new image while modal is open

function handleProjectImageUpload(event) {
  const file = event.target.files[0];
  if (!file) return;
  if (file.size > 10 * 1024 * 1024) { alert('Image too large --- please choose a file under 10 MB'); return; }
  const reader = new FileReader();
  reader.onload = e => {
    const img = new Image();
    img.onload = () => {
      const maxDim = 600;
      let w = img.width, h = img.height;
      if (w > maxDim || h > maxDim) {
        if (w > h) { h = Math.round(h * maxDim / w); w = maxDim; }
        else { w = Math.round(w * maxDim / h); h = maxDim; }
      }
      const canvas = document.createElement('canvas');
      canvas.width = w; canvas.height = h;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, w, h);
      const dataUrl = canvas.toDataURL('image/jpeg', 0.82);
      pendingProjectImage = dataUrl;
      renderImagePreview(dataUrl);
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
  event.target.value = '';
}

function clearProjectImage() {
  pendingProjectImage = '';  // empty string means "removed"
  renderImagePreview(null);
}

function renderImagePreview(dataUrl) {
  const preview = document.getElementById('projImagePreview');
  if (dataUrl) {
    preview.innerHTML = `<img src="${dataUrl}" alt="Project">`;
  } else {
    preview.innerHTML = '<span id="projImagePlaceholder">No image</span>';
  }
}

// =============================================================
// TEMPLATES
// =============================================================
function saveAsTemplate() {
  const p = state.projects.find(x => x.id === state.activeProjectId);
  if (!p) return;
  const name = prompt('Save project as template. Enter template name:', p.name + ' Template');
  if (!name || !name.trim()) return;
  const template = {
    id: uid(),
    name: name.trim(),
    createdAt: Date.now(),
    projectDefaults: {
      type: p.type, delivery: p.delivery,
      client: '', architect: p.architect,
      location: '', sqft: 0, value: 0,
      notes: p.notes
    },
    tasks: p.tasks.map(t => {
      // Build the template task. Always include core fields. Rich fields
      // (critical/estimatedHours/tips/deliverables/checklist) are included
      // only when they have content so the template stays clean.
      const tt = {
        title: t.title, stage: t.stage, category: t.category,
        priority: t.priority, dayOffset: t.dayOffset,
        source: t.source || '', notes: t.notes || ''
      };
      if (t.critical) tt.critical = true;
      if (typeof t.estimatedHours === 'number' && t.estimatedHours > 0) tt.estimatedHours = t.estimatedHours;
      if (t.bestPracticeNotes && t.bestPracticeNotes.trim()) tt.tips = t.bestPracticeNotes.trim();
      if (Array.isArray(t.deliverables) && t.deliverables.length > 0) {
        tt.deliverables = t.deliverables
          .map(d => (typeof d === 'string') ? d : (d && d.text ? d.text : ''))
          .filter(s => s);
      }
      if (Array.isArray(t.checklist) && t.checklist.length > 0) {
        tt.checklist = t.checklist
          .map(c => {
            if (typeof c === 'string') return { text: c, required: false };
            return { text: c.text || '', required: !!c.required };
          })
          .filter(c => c.text);
      }
      return tt;
    })
  };
  state.templates.push(template);
  saveState();
  alert(`Template "${name}" saved. It will appear as an option when creating new projects.`);
}

function duplicateProject() {
  const p = state.projects.find(x => x.id === state.activeProjectId);
  if (!p) return;
  const newName = prompt('Duplicate project. Enter name for the new project:', p.name + ' (Copy)');
  if (!newName || !newName.trim()) return;
  const copy = JSON.parse(JSON.stringify(p));
  copy.id = uid();
  copy.name = newName.trim();
  copy.createdAt = Date.now();
  copy.tasks.forEach(t => {
    t.id = uid();
    t.status = 'not-started';   // reset progress
    t.createdAt = Date.now();
  });
  state.projects.push(copy);
  state.activeProjectId = copy.id;
  state.activeStageId = 'all';
  state.activeAssignee = 'all';
  saveState();
  render();
}

function populateProjectTemplateSelect() {
  const sel = document.getElementById('projTemplateSelect');
  const section = document.getElementById('templateLoadSection');
  if (!state.templates || state.templates.length === 0) {
    section.style.display = 'none';
    return;
  }
  // Only show in new-project flow
  section.style.display = editingProjectId ? 'none' : 'block';
  sel.innerHTML = '<option value="">--- Blank Project ---</option>' +
    state.templates.map(t => `<option value="${t.id}">${escapeHtml(t.name)}</option>`).join('');
}

function applyProjectTemplate() {
  const id = document.getElementById('projTemplateSelect').value;
  if (!id) { alert('Pick a template first'); return; }
  const tpl = state.templates.find(t => t.id === id);
  if (!tpl) return;
  // Fill in defaults on the currently-open modal
  if (tpl.projectDefaults) {
    const d = tpl.projectDefaults;
    if (d.type) document.getElementById('projType').value = d.type;
    if (d.delivery) document.getElementById('projDelivery').value = d.delivery;
    if (d.architect) document.getElementById('projArchitect').value = d.architect;
    if (d.notes) document.getElementById('projNotes').value = d.notes;
  }
  // Stash template tasks for use after project is saved
  pendingTemplateTasks = tpl.tasks || [];
  alert(`Template "${tpl.name}" applied. ${pendingTemplateTasks.length} tasks will be created when you save this project.`);
}

let pendingTemplateTasks = null;

// =============================================================
// PROJECT CRUD
// =============================================================
function openProjectModal(id=null) {
  editingProjectId = id;
  pendingProjectImage = null;
  pendingTemplateTasks = null;
  const deleteBtn = document.getElementById('deleteProjBtn');
  const archiveBtn = document.getElementById('archiveProjBtn');
  const restoreBtn = document.getElementById('restoreProjBtn');
  if (id) {
    const p = state.projects.find(x=>x.id===id);
    document.getElementById('projectModalTitle').textContent = p.archived ? 'Edit Project (Archived)' : 'Edit Project';
    deleteBtn.style.display = 'inline-flex';
    // Archive vs Restore button --- swap based on current archive state
    if (archiveBtn) archiveBtn.style.display = p.archived ? 'none' : 'inline-flex';
    if (restoreBtn) restoreBtn.style.display = p.archived ? 'inline-flex' : 'none';
    document.getElementById('projName').value = p.name||'';
    document.getElementById('projType').value = p.type||'K-12 Education';
    document.getElementById('projDelivery').value = p.delivery||'CM at Risk (CMAR)';
    document.getElementById('projClient').value = p.client||'';
    document.getElementById('projArchitect').value = p.architect||'';
    document.getElementById('projLeadEstimator').value = p.leadEstimator || '';
    document.getElementById('projStartDate').value = p.startDate||'';
    document.getElementById('projDueDate').value = p.dueDate||'';
    document.getElementById('projValue').value = p.value||'';
    document.getElementById('projLocation').value = p.location||'';
    document.getElementById('projSqft').value = p.sqft||'';
    document.getElementById('projOneDriveUrl').value = p.oneDriveUrl||'';
    document.getElementById('projNotes').value = p.notes||'';
    document.getElementById('projDueTime').value = p.dueTime || '';
    document.getElementById('projDueTimezone').value = p.dueTimezone || '';
    document.getElementById('projSubmissionFormat').value = p.submissionFormat || '';
    // Bid extension fields
    document.getElementById('projOriginalStartDate').value = p.originalStartDate || p.startDate || '';
    document.getElementById('projOriginalDueDate').value = p.originalDueDate || p.dueDate || '';
    document.getElementById('projRevisedStartDate').value = p.revisedStartDate || '';
    document.getElementById('projUseRevisedDates').checked = !!p.useRevisedDates;
    updateBexModeLabels();
    recalcRevisedStartPreview();
    renderImagePreview(p.image || null);
  } else {
    document.getElementById('projectModalTitle').textContent = 'New Project';
    deleteBtn.style.display = 'none';
    if (archiveBtn) archiveBtn.style.display = 'none';
    if (restoreBtn) restoreBtn.style.display = 'none';
    ['projName','projClient','projArchitect','projLeadEstimator','projStartDate','projDueDate','projValue','projLocation','projSqft','projOneDriveUrl','projNotes','projOriginalStartDate','projOriginalDueDate','projRevisedStartDate','projDueTime'].forEach(f => {
      const el = document.getElementById(f); if (el) el.value = '';
    });
    document.getElementById('projDueTimezone').value = '';
    document.getElementById('projSubmissionFormat').value = '';
    document.getElementById('projUseRevisedDates').checked = false;
    document.getElementById('projType').value = 'K-12 Education';
    document.getElementById('projDelivery').value = 'CM at Risk (CMAR)';
    updateBexModeLabels();
    document.getElementById('bexShiftDisplay').textContent = '---';
    renderImagePreview(null);
  }
  // Wire up dynamic toggle label update
  const toggle = document.getElementById('projUseRevisedDates');
  toggle.onchange = updateBexModeLabels;
  populateProjectTemplateSelect();
  // Populate Lead Estimator datalist from team roster
  const leList = document.getElementById('leadEstimatorList');
  if (leList) {
    leList.innerHTML = state.teamMembers.map(m => {
      const label = m.title ? `${m.name} --- ${m.title}` : m.name;
      return `<option value="${escapeHtml(m.name)}">${escapeHtml(label)}</option>`;
    }).join('');
  }
  document.getElementById('projectModal').classList.add('active');
}

function updateBexModeLabels() {
  const checked = document.getElementById('projUseRevisedDates').checked;
  document.getElementById('bexModeOriginal').classList.toggle('active', !checked);
  document.getElementById('bexModeRevised').classList.toggle('active', checked);
}

function recalcRevisedStartPreview() {
  // Live preview of the shift amount + auto-fill revised start date
  const startEl = document.getElementById('projStartDate');
  const dueEl = document.getElementById('projDueDate');
  const origStartEl = document.getElementById('projOriginalStartDate');
  const origDueEl = document.getElementById('projOriginalDueDate');
  const revEl = document.getElementById('projRevisedStartDate');
  const shiftEl = document.getElementById('bexShiftDisplay');
  if (!shiftEl) return;

  const currentDue = dueEl.value;
  const origDue = origDueEl.value || currentDue;
  const origStart = origStartEl.value || startEl.value;

  if (!origDue || !currentDue || !origStart) {
    shiftEl.textContent = '---';
    shiftEl.className = 'bex-shift-display';
    return;
  }

  const shiftDays = daysBetween(origDue, currentDue);
  if (shiftDays === null) {
    shiftEl.textContent = '---';
    shiftEl.className = 'bex-shift-display';
    return;
  }

  if (shiftDays === 0) {
    shiftEl.textContent = 'No shift';
    shiftEl.className = 'bex-shift-display';
  } else if (shiftDays > 0) {
    shiftEl.textContent = `+${shiftDays} days (extended)`;
    shiftEl.className = 'bex-shift-display shift-positive';
  } else {
    shiftEl.textContent = `${shiftDays} days (shortened)`;
    shiftEl.className = 'bex-shift-display shift-negative';
  }

  // If revised start field is empty, auto-suggest the calculated value
  if (!revEl.value && shiftDays !== 0) {
    const suggested = addDays(origStart, shiftDays);
    revEl.value = suggested;
    revEl.placeholder = suggested;
  }
}
function editProject() { openProjectModal(state.activeProjectId); }
function saveProject() {
  const name = document.getElementById('projName').value.trim();
  if (!name) { alert('Project name is required'); return; }
  const oldStart = editingProjectId ? (state.projects.find(x=>x.id===editingProjectId)?.startDate || '') : '';
  const newStart = document.getElementById('projStartDate').value;
  const newDue = document.getElementById('projDueDate').value;
  const newOriginalStart = document.getElementById('projOriginalStartDate').value;
  const newOriginalDue = document.getElementById('projOriginalDueDate').value;
  const newRevisedStart = document.getElementById('projRevisedStartDate').value;
  const newUseRevised = document.getElementById('projUseRevisedDates').checked;

  const data = {
    name,
    type: document.getElementById('projType').value,
    delivery: document.getElementById('projDelivery').value,
    client: document.getElementById('projClient').value.trim(),
    architect: document.getElementById('projArchitect').value.trim(),
    leadEstimator: document.getElementById('projLeadEstimator').value.trim(),
    startDate: newStart,
    dueDate: newDue,
    originalStartDate: newOriginalStart || newStart,
    originalDueDate: newOriginalDue || newDue,
    revisedStartDate: newRevisedStart,
    useRevisedDates: newUseRevised,
    value: parseFloat(document.getElementById('projValue').value) || 0,
    location: document.getElementById('projLocation').value.trim(),
    sqft: parseInt(document.getElementById('projSqft').value) || 0,
    oneDriveUrl: document.getElementById('projOneDriveUrl').value.trim(),
    notes: document.getElementById('projNotes').value.trim(),
    dueTime: document.getElementById('projDueTime').value,
    dueTimezone: document.getElementById('projDueTimezone').value,
    submissionFormat: document.getElementById('projSubmissionFormat').value
  };

  if (editingProjectId) {
    const p = state.projects.find(x=>x.id===editingProjectId);
    // Snapshot for activity log diff
    const projectOldSnapshot = {
      name: p.name || '',
      client: p.client || '',
      dueDate: p.dueDate || '',
      startDate: p.startDate || '',
      leadEstimator: p.leadEstimator || '',
      status: p.status || '',
      location: p.location || '',
      architect: p.architect || ''
    };
    const oldUseRevised = !!p.useRevisedDates;
    const oldRevisedStart = p.revisedStartDate || '';
    const oldDue = p.dueDate || '';
    Object.assign(p, data);
    // ACTIVITY LOG: capture project edits
    logProjectEdited(p, projectOldSnapshot);
    // Image: null means "no change", empty string means "remove", string means "new image"
    if (pendingProjectImage !== null) p.image = pendingProjectImage || '';

    // Determine whether any scheduling change happened
    const startChanged = newStart && oldStart !== newStart;
    const modeChanged = oldUseRevised !== newUseRevised;
    const revisedChanged = oldRevisedStart !== newRevisedStart && newUseRevised;
    const dueChanged = oldDue !== newDue;

    // If due date changed and no revised start has been set yet, offer to compute one
    if (dueChanged && !p.revisedStartDate && p.originalDueDate && newDue !== p.originalDueDate) {
      const shift = daysBetween(p.originalDueDate, newDue);
      if (shift !== null && shift !== 0) {
        const suggested = addDays(p.originalStartDate || oldStart, shift);
        if (confirm(`Bid Due Date shifted by ${shift > 0 ? '+' : ''}${shift} days. Set Revised Bid Start to ${formatDate(suggested)} and switch to Revised dates?`)) {
          p.revisedStartDate = suggested;
          p.useRevisedDates = true;
        }
      }
    }

    // Reanchor tasks whenever the active anchor changes
    if (startChanged || modeChanged || revisedChanged) {
      const tasksWithOffset = p.tasks.filter(t => typeof t.dayOffset === 'number');
      if (tasksWithOffset.length > 0) {
        const anchor = getEffectiveBidStart(p);
        const mode = p.useRevisedDates ? 'revised' : 'original';
        if (confirm(`Scheduling changed. Recalculate due dates for ${tasksWithOffset.length} task(s) from the ${mode} Bid Start (${formatDate(anchor)})?`)) {
          tasksWithOffset.forEach(t => { t.dueDate = addBusinessDays(anchor, t.dayOffset).date; });
        }
      }
    }
    // Refresh auto-dated milestones if bid due date changed and project opted-in to default offsets
    if (dueChanged && p.useDefaultOffsets) {
      const refreshed = refreshAutoMilestoneDates(p);
      if (refreshed > 0) {
        setTimeout(() => alert(`✓ ${refreshed} auto-dated milestone${refreshed === 1 ? '' : 's'} recomputed from the new bid due date (${formatDate(newDue)}).`), 200);
      }
    }
  } else {
    const p = { id: uid(), ...data, tasks: [], image: pendingProjectImage || '', createdAt: Date.now() };
    // On new projects, seed originalStartDate / originalDueDate from the initial values
    if (!p.originalStartDate) p.originalStartDate = p.startDate || '';
    if (!p.originalDueDate) p.originalDueDate = p.dueDate || '';
    // Apply template tasks if one was picked
    if (pendingTemplateTasks && pendingTemplateTasks.length > 0) {
      const anchor = getEffectiveBidStart(p);
      pendingTemplateTasks.forEach(t => {
        const newTask = {
          id: uid(),
          title: t.title,
          stage: t.stage,
          category: t.category,
          priority: t.priority,
          status: 'not-started',
          dueDate: (anchor && typeof t.dayOffset === 'number') ? addBusinessDays(anchor, t.dayOffset).date : '',
          dayOffset: typeof t.dayOffset === 'number' ? t.dayOffset : null,
          assignee: '',
          source: t.source || '',
          notes: t.notes || '',
          createdAt: Date.now(),
          // Carry rich fields from template
          critical: !!t.critical,
          estimatedHours: (typeof t.estimatedHours === 'number' && t.estimatedHours > 0) ? t.estimatedHours : null,
          bestPracticeNotes: (t.tips || '').trim() || ''
        };
        if (Array.isArray(t.deliverables) && t.deliverables.length > 0) {
          newTask.deliverables = t.deliverables.map(d => ({
            id: uid(),
            text: (typeof d === 'string') ? d : (d.text || ''),
            completed: false
          })).filter(d => d.text);
        }
        if (Array.isArray(t.checklist) && t.checklist.length > 0) {
          newTask.checklist = t.checklist.map(c => {
            if (typeof c === 'string') return { id: uid(), text: c, required: false, completed: false };
            return { id: uid(), text: c.text || '', required: !!c.required, completed: false };
          }).filter(c => c.text);
        }
        p.tasks.push(newTask);
      });
    }
    state.projects.push(p);
    state.activeProjectId = p.id;
    state.activeStageId = 'all';
    state.activeAssignee = 'all';
  }
  pendingProjectImage = null;
  pendingTemplateTasks = null;
  saveState();
  closeModal('projectModal');
  render();
}
// =============================================================
// PROJECT ARCHIVE & DELETE
// =============================================================
// Archive = soft delete. Project hidden from main views; all data preserved.
// Delete = hard delete. Permanent. Two-step confirmation requiring name typing.

// Helper: active (non-archived) projects. Use anywhere that should NOT show
// archived projects in cross-project views (home countdowns, my tasks,
// alerts, etc.). The full state.projects array is still used by the
// sidebar project-list which renders Archived as its own dedicated section.
function getActiveProjects() {
  return state.projects.filter(p => !p.archived);
}

// Archive a project from any context. Sets archived flag, stamps actor +
// timestamp, logs to activity log. If the archived project was active,
// shifts to the first non-archived one.
function archiveProject(projectId) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  if (p.archived) {
    alert(`"${p.name}" is already archived.`);
    return;
  }
  const taskCount = (p.tasks || []).length;
  const msg = `Archive "${p.name}"?\n\n• ${taskCount} task${taskCount === 1 ? '' : 's'} and all activity history will be preserved.\n• The project will be hidden from active views (home, alerts, project list).\n• You can restore it at any time from the Archived section.\n\nThis is reversible.`;
  if (!confirm(msg)) return;
  const user = getCurrentUser() || '';
  p.archived = true;
  p.archivedAt = Date.now();
  p.archivedBy = user;
  // Activity log entry --- defensive in case logProjectEdited doesn't exist
  if (Array.isArray(p.activityLog)) {
    p.activityLog.push({
      id: 'al_' + Date.now().toString(36) + Math.floor(Math.random()*1000),
      timestamp: Date.now(),
      actor: user || 'Unknown',
      type: 'project',
      action: 'archived',
      summary: `Archived project "${p.name}"`
    });
  }
  // If this was the active project, switch to the first non-archived one
  if (state.activeProjectId === projectId) {
    const fallback = getActiveProjects()[0];
    state.activeProjectId = fallback ? fallback.id : null;
    if (!fallback) state.homeView = true; // nothing to show --- go home
  }
  saveState();
  // Close edit modal if it was open for this project
  if (editingProjectId === projectId) {
    closeModal('projectModal');
  }
  render();
  setTimeout(() => alert(`✓ Archived "${p.name}". You can restore it from the sidebar's Archived section.`), 100);
}

// Restore an archived project. Clears the archived flag and logs the event.
function restoreProject(projectId) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p || !p.archived) return;
  if (!confirm(`Restore "${p.name}" from the archive?\n\nThe project will return to the active list and appear in cross-project views again.`)) return;
  const user = getCurrentUser() || '';
  p.archived = false;
  p.archivedAt = null;
  p.archivedBy = '';
  if (Array.isArray(p.activityLog)) {
    p.activityLog.push({
      id: 'al_' + Date.now().toString(36) + Math.floor(Math.random()*1000),
      timestamp: Date.now(),
      actor: user || 'Unknown',
      type: 'project',
      action: 'restored',
      summary: `Restored project "${p.name}" from archive`
    });
  }
  saveState();
  render();
  setTimeout(() => alert(`✓ Restored "${p.name}".`), 100);
}

// Convenience wrappers used by the Edit Project modal buttons. They derive
// the project ID from the editingProjectId global so the existing modal
// markup doesn't need ID plumbing.
function archiveProjectFromModal() {
  if (!editingProjectId) return;
  archiveProject(editingProjectId);
}
function restoreProjectFromModal() {
  if (!editingProjectId) return;
  restoreProject(editingProjectId);
}

// Delete a project --- HARD delete, permanent, with two-step confirmation.
// Now requires typing the project name to confirm so accidental clicks
// don't blow away weeks of work. Surfaces task count and activity log size
// so the user knows the scope of what they're losing.
function deleteProject() {
  const id = editingProjectId;
  const p = state.projects.find(x => x.id === id);
  if (!p) return;
  const taskCount = (p.tasks || []).length;
  const msgCount = (p.tasks || []).reduce((s, t) => s + (Array.isArray(t.messages) ? t.messages.length : 0), 0);
  const logCount = Array.isArray(p.activityLog) ? p.activityLog.length : 0;
  const addCount = Array.isArray(p.addenda) ? p.addenda.length : 0;
  const summary = [
    `${taskCount} task${taskCount === 1 ? '' : 's'}`,
    msgCount > 0 ? `${msgCount} message${msgCount === 1 ? '' : 's'}` : null,
    logCount > 0 ? `${logCount} activity log entr${logCount === 1 ? 'y' : 'ies'}` : null,
    addCount > 0 ? `${addCount} addend${addCount === 1 ? 'um' : 'a'}` : null
  ].filter(Boolean).join(', ');

  // Step 1 --- soft warning, recommend archive
  const step1 = `⚠ PERMANENTLY DELETE "${p.name}"?\n\nThis will erase: ${summary || 'all project data'}.\n\nThis CANNOT be undone. Consider Archive instead --- it hides the project but keeps the data.\n\nContinue to delete?`;
  if (!confirm(step1)) return;

  // Step 2 --- type-to-confirm
  const typed = prompt(`To confirm permanent deletion, type the exact project name:\n\n${p.name}\n\n(Or click Cancel to keep the project.)`);
  if (typed === null) return; // canceled
  if (typed.trim() !== p.name.trim()) {
    alert(`Names do not match. Project NOT deleted.\n\nYou typed: "${typed}"\nExpected: "${p.name}"`);
    return;
  }

  state.projects = state.projects.filter(x => x.id !== id);
  if (state.activeProjectId === id) {
    const fallback = getActiveProjects()[0];
    state.activeProjectId = fallback ? fallback.id : null;
    if (!fallback) state.homeView = true;
  }
  saveState();
  closeModal('projectModal');
  render();
  setTimeout(() => alert(`✓ Deleted "${p.name}".`), 100);
}
function selectProject(id) {
  // If the user clicks an archived project (e.g. via global search or
  // the dedicated Archived sidebar section), open the edit modal instead
  // of switching the active view to it --- archived projects shouldn't be
  // the "current working project."
  const p = state.projects.find(x => x.id === id);
  if (p && p.archived) {
    openProjectModal(id);
    return;
  }
  state.activeProjectId = id;
  state.activeStageId = 'all';
  state.activeAssignee = 'all';
  state.homeView = false;
  state.statusSnapshotView = false;
  saveState(); render();
}

