        <div class="hi-body">
          <div class="hi-title">${escapeHtml(task.title)}</div>
          <div class="hi-meta">${stage.icon} ${escapeHtml(stage.name)} · Completed by ${escapeHtml(task.assignee || 'assignee')}</div>
        </div>
