function loadTemplate() {
  const project = state.projects.find(p=>p.id===state.activeProjectId);
  if (!project) return;
  if (!Array.isArray(state.taskTemplates) || state.taskTemplates.length === 0) {
    alert('No templates defined. Open "Manage Task Templates" to create one first.');
    return;
  }

  // If only one template exists, skip the picker and use it directly
  if (state.taskTemplates.length === 1) {
    return applyTemplateToProject(project, state.taskTemplates[0]);
  }

  // Multiple templates --- open the picker
  openTemplatePicker(project);
}

// Show a picker letting the user choose which template to load into the project
function openTemplatePicker(project) {
  const list = document.getElementById('tmplPickerList');
  if (!list) return;
  // Build template cards
  list.innerHTML = state.taskTemplates.map(t => {
    const taskCount = (t.tasks || []).length;
    const stageBreakdown = {};
    (t.tasks || []).forEach(task => {
      stageBreakdown[task.stage] = (stageBreakdown[task.stage] || 0) + 1;
    });
    const stageChips = Object.entries(stageBreakdown).slice(0, 5).map(([stageId, count]) => {
      const stage = STAGES.find(s => s.id === stageId);
      const label = stage ? stage.name : stageId;
      return `<span class="tmpl-picker-stage-chip">${count} ${escapeHtml(label)}</span>`;
    }).join('');
    return `
      <div class="tmpl-picker-card${t.isDefault ? ' is-default' : ''}" onclick="confirmApplyTemplate('${t.id}')">
        <div class="tmpl-picker-card-header" style="background:${t.color || '#0a2540'};">
          <span class="tmpl-picker-icon">${(typeof renderTemplateIconHtml === 'function') ? renderTemplateIconHtml(t.icon) : escapeHtml(t.icon || '📋')}</span>
          <span class="tmpl-picker-name">${escapeHtml(t.name)}</span>
          ${t.isDefault ? '<span class="tmpl-picker-default-badge">★ DEFAULT</span>' : ''}
        </div>
        <div class="tmpl-picker-card-body">
          ${t.description ? `<p class="tmpl-picker-desc">${escapeHtml(t.description)}</p>` : ''}
          <div class="tmpl-picker-count"><strong>${taskCount}</strong> task${taskCount === 1 ? '' : 's'}</div>
          <div class="tmpl-picker-stages">${stageChips}${Object.keys(stageBreakdown).length > 5 ? `<span class="tmpl-picker-stage-chip">+${Object.keys(stageBreakdown).length - 5} more</span>` : ''}</div>
        </div>
      </div>
    `;
  }).join('');
  document.getElementById('tmplPickerModal').classList.add('active');
}

function confirmApplyTemplate(templateId) {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const tmpl = state.taskTemplates.find(t => t.id === templateId);
  if (!tmpl) return;
  closeModal('tmplPickerModal');
  applyTemplateToProject(project, tmpl);
}

function applyTemplateToProject(project, tmpl) {
  if (!tmpl || !Array.isArray(tmpl.tasks) || tmpl.tasks.length === 0) {
    alert(`Template "${tmpl?.name || 'unknown'}" has no tasks.`);
    return;
  }
  if (!project.startDate && !project.dueDate) {
    if (!confirm(`No Bid Start or Due Date set. ${tmpl.tasks.length} tasks from "${tmpl.name}" will be added without dates. Continue?`)) return;
  } else if (!confirm(`Load "${tmpl.name}" template (${tmpl.tasks.length} tasks) with day-offsets from the Bid Start Date?`)) return;

  tmpl.tasks.forEach(x => {
    const dueDate = project.startDate ? addBusinessDays(project.startDate, x.offset).date : '';
    // Build the new project task, copying rich fields from the template.
    // Critical + estimatedHours + tips + deliverables + checklist all carry
    // through; deliverables and checklist are deep-cloned so editing the
    // project task doesn't mutate the template.
    const newTask = {
      id: uid(), title: x.title, stage: x.stage, category: x.category,
      priority: x.priority, status: 'not-started',
      dueDate, dayOffset: x.offset,
      assignee: '', support: '', supportMembers: [], ballInCourt: 'Lead',
      source: x.source || '',
      notes: '', createdAt: Date.now(),
      // Critical flag --- copied from template (defaults to false if not set)
      critical: !!x.critical,
      // Estimated hours --- copied if template set a number, else null
      estimatedHours: (typeof x.estimatedHours === 'number' && x.estimatedHours > 0) ? x.estimatedHours : null,
      // Tips / best-practice notes --- string carried straight through
      bestPracticeNotes: (x.tips || '').trim() || ''
    };
    // Deliverables list --- deep-cloned with new ids so each project task gets
    // independent deliverable objects (state/check status is per-project).
    if (Array.isArray(x.deliverables) && x.deliverables.length > 0) {
      newTask.deliverables = x.deliverables.map(d => ({
        id: uid(),
        text: (typeof d === 'string') ? d : (d.text || ''),
        completed: false
      })).filter(d => d.text);
    }
    // Checklist list --- deep-cloned with new ids; preserves required-flag from template.
    if (Array.isArray(x.checklist) && x.checklist.length > 0) {
      newTask.checklist = x.checklist.map(c => {
        if (typeof c === 'string') return { id: uid(), text: c, required: false, completed: false };
        return { id: uid(), text: c.text || '', required: !!c.required, completed: false };
      }).filter(c => c.text);
    }
    project.tasks.push(newTask);
  });
  saveState();
  render();
  setTimeout(() => alert(`✓ Loaded ${tmpl.tasks.length} tasks from "${tmpl.name}".`), 100);
}

function closeModal(id) { document.getElementById(id).classList.remove('active'); }

// =============================================================
// VIEW MODE & GROUPING
// =============================================================
function setViewMode(mode) {
  state.viewMode = mode;
  if (typeof clearActiveSavedView === 'function') clearActiveSavedView();
  saveState();
  document.querySelectorAll('[data-viewmode]').forEach(b => b.classList.toggle('active', b.dataset.viewmode === mode));
  render();
}
function setGrouping(g) {
  state.grouping = g;
  if (g === 'stage') state.activeStageId = 'all';
  else if (g === 'assignee') state.activeAssignee = 'all';
  else if (g === 'source') state.activeSource = 'all';
  else if (g === 'status') state.activeStatus = 'all';
  else if (g === 'alert') state.activeAlertTier = 'all';
  else if (g === 'my-alert') state.activeMyAlertTier = 'all';
  if (typeof clearActiveSavedView === 'function') clearActiveSavedView();
  saveState();
  document.querySelectorAll('[data-grouping]').forEach(b => b.classList.toggle('active', b.dataset.grouping === g));
  render();
}

// Secondary filter --- narrows whatever the current grouping is to a single
// assignee (or 'unassigned'). Applied AFTER the primary group filter so a
// user can do things like "show me Blocked tasks assigned to John" or
// "Project Setup tasks assigned to Sarah." Hidden in Assignee grouping
// where it'd be redundant (the grouping already does this).
function setSecondaryAssigneeFilter(value) {
  state.secondaryAssigneeFilter = value || 'all';
  if (typeof clearActiveSavedView === 'function') clearActiveSavedView();
  saveState();
  render();
}

// Multi-filter setter for Group by Alert mode. `dim` is one of
// 'assignee' | 'stage' | 'source'.
function setAlertFilter(dim, value) {
  if (!state.alertFilters) state.alertFilters = { assignee: 'all', stage: 'all', source: 'all' };
  state.alertFilters[dim] = value || 'all';
  saveState();
  render();
}

// One-click reset for all three filters
function clearAllAlertFilters() {
  state.alertFilters = { assignee: 'all', stage: 'all', source: 'all' };
  saveState();
  render();
}

// === MY-ALERT FILTERS ===
function setMyAlertFilter(dim, value) {
  if (!state.myAlertFilters) state.myAlertFilters = { stage: 'all', source: 'all' };
  state.myAlertFilters[dim] = value || 'all';
  saveState();
  render();
}

function clearAllMyAlertFilters() {
  state.myAlertFilters = { stage: 'all', source: 'all' };
  saveState();
  render();
}

// Render the My Alerts multi-filter row. Two dropdowns --- stage + source ---
// (assignee is fixed to "me" so omitted). Counts within the active tier
// scoped to the current user.
function renderMyAlertMultiFilter() {
  const row = document.getElementById('myAlertFilterRow');
  if (!row) return;
  if (state.grouping !== 'my-alert') {
    row.style.display = 'none';
    return;
  }
  row.style.display = 'flex';

  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) {
    row.style.display = 'none';
    return;
  }

  // Tier-filtered tasks scoped to the current user (BEFORE the multi-filter)
  const tierTasks = filterTasksByAlertTierScoped(project, state.activeMyAlertTier, 'my');

  // === STAGE DROPDOWN ===
  const stageSel = document.getElementById('myAlertFilterStage');
  if (stageSel) {
    const current = (state.myAlertFilters && state.myAlertFilters.stage) || 'all';
    const opts = [`<option value="all"${current === 'all' ? ' selected' : ''}>All Stages</option>`];
    STAGES.forEach(s => {
      const count = tierTasks.filter(t => t.stage === s.id).length;
      if (count === 0) return;
      opts.push(`<option value="${escapeAttr(s.id)}"${current === s.id ? ' selected' : ''}>${s.icon} ${escapeHtml(s.name)} (${count})</option>`);
    });
    stageSel.innerHTML = opts.join('');
    if (current !== 'all') {
      const stillExists = Array.from(stageSel.options).some(o => o.value === current);
      if (!stillExists) stageSel.value = 'all';
    }
  }

  // === SOURCE DROPDOWN ===
  const sourceSel = document.getElementById('myAlertFilterSource');
  if (sourceSel) {
    const current = (state.myAlertFilters && state.myAlertFilters.source) || 'all';
    const sourceMap = new Map();
    tierTasks.forEach(t => {
      const s = (t.source || '').trim();
      if (!s) return;
      sourceMap.set(s, (sourceMap.get(s) || 0) + 1);
    });
    const unsourcedCount = tierTasks.filter(t => !t.source || !t.source.trim()).length;
    const opts = [`<option value="all"${current === 'all' ? ' selected' : ''}>All Sources</option>`];
    if (unsourcedCount > 0) {
      opts.push(`<option value="unsourced"${current === 'unsourced' ? ' selected' : ''}>--- Unsourced --- (${unsourcedCount})</option>`);
    }
    Array.from(sourceMap.keys()).sort().forEach(name => {
      opts.push(`<option value="${escapeAttr(name)}"${current === name ? ' selected' : ''}>${escapeHtml(name)} (${sourceMap.get(name)})</option>`);
    });
    sourceSel.innerHTML = opts.join('');
    if (current !== 'all' && current !== 'unsourced') {
      const stillExists = Array.from(sourceSel.options).some(o => o.value === current);
      if (!stillExists) sourceSel.value = 'all';
    }
  }

  // === META + CLEAR-ALL ===
  const f = state.myAlertFilters || {};
  const anyActive = (f.stage && f.stage !== 'all') || (f.source && f.source !== 'all');
  row.classList.toggle('afr-active', anyActive);
  const clearBtn = document.getElementById('myAfrClearBtn');
  if (clearBtn) clearBtn.style.display = anyActive ? 'inline-flex' : 'none';

  const meta = document.getElementById('myAfrMeta');
  if (meta) {
    if (anyActive) {
      const filtered = getFilteredTasks(project).length;
      const parts = [];
      if (f.stage && f.stage !== 'all') {
        const stage = STAGES.find(s => s.id === f.stage);
        if (stage) parts.push(stage.name);
      }
      if (f.source && f.source !== 'all') parts.push(f.source === 'unsourced' ? 'unsourced' : f.source);
      meta.textContent = `→ ${filtered} of your task${filtered === 1 ? '' : 's'} matching ${parts.join(' · ')}`;
    } else {
      meta.textContent = `${tierTasks.length} of your task${tierTasks.length === 1 ? '' : 's'} in this tier`;
    }
  }
}

// Render the multi-filter row used in Group by Alert. Three dropdowns ---
// assignee, stage, source --- with live counts within the active alert tier
// so users see "Trent (5)" reflecting just the at-risk tasks Trent owns,
// not his entire workload.
function renderAlertMultiFilter() {
  const row = document.getElementById('alertFilterRow');
  if (!row) return;
  // Hide unless we're in alert grouping mode
  if (state.grouping !== 'alert') {
    row.style.display = 'none';
    return;
  }
  row.style.display = 'flex';

  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) {
    row.style.display = 'none';
    return;
  }

  // Compute the tier-filtered task pool (BEFORE multi-filter is applied)
  // so the dropdown counts reflect "within the active tier" not "total."
  const tierTasks = filterTasksByAlertTier(project, state.activeAlertTier);

  // === ASSIGNEE DROPDOWN ===
  const assigneeSel = document.getElementById('alertFilterAssignee');
  if (assigneeSel) {
    const rosterNames = (state.teamMembers || []).map(m => m.name);
    const taskNames = project.tasks.map(t => t.assignee).filter(Boolean);
    const supportNames = [];
    project.tasks.forEach(t => {
      const all = (typeof getAllSupportMembers === 'function') ? getAllSupportMembers(t) : [];
      all.forEach(name => supportNames.push(name));
    });
    const allPeople = Array.from(new Set([...rosterNames, ...taskNames, ...supportNames])).sort();

    const unassignedCount = tierTasks.filter(t => !t.assignee || !t.assignee.trim()).length;
    const current = (state.alertFilters && state.alertFilters.assignee) || 'all';
    const opts = [`<option value="all"${current === 'all' ? ' selected' : ''}>All Assignees</option>`];
    if (unassignedCount > 0) {
      opts.push(`<option value="unassigned"${current === 'unassigned' ? ' selected' : ''}>--- Unassigned --- (${unassignedCount})</option>`);
    }
    allPeople.forEach(n => {
      const count = tierTasks.filter(t => (t.assignee||'').trim() === n || isTaskSupport(t, n)).length;
      if (count === 0) return;
      opts.push(`<option value="${escapeAttr(n)}"${current === n ? ' selected' : ''}>${escapeHtml(n)} (${count})</option>`);
    });
    assigneeSel.innerHTML = opts.join('');
    if (current !== 'all' && current !== 'unassigned') {
      const stillExists = Array.from(assigneeSel.options).some(o => o.value === current);
      if (!stillExists) assigneeSel.value = 'all';
    }
  }

  // === STAGE DROPDOWN ===
  const stageSel = document.getElementById('alertFilterStage');
  if (stageSel) {
    const current = (state.alertFilters && state.alertFilters.stage) || 'all';
    const opts = [`<option value="all"${current === 'all' ? ' selected' : ''}>All Stages</option>`];
    STAGES.forEach(s => {
      const count = tierTasks.filter(t => t.stage === s.id).length;
      if (count === 0) return;
      opts.push(`<option value="${escapeAttr(s.id)}"${current === s.id ? ' selected' : ''}>${s.icon} ${escapeHtml(s.name)} (${count})</option>`);
    });
    stageSel.innerHTML = opts.join('');
    if (current !== 'all') {
      const stillExists = Array.from(stageSel.options).some(o => o.value === current);
      if (!stillExists) stageSel.value = 'all';
    }
  }

  // === SOURCE DROPDOWN ===
  const sourceSel = document.getElementById('alertFilterSource');
  if (sourceSel) {
    const current = (state.alertFilters && state.alertFilters.source) || 'all';
    const sourceMap = new Map();
    tierTasks.forEach(t => {
      const s = (t.source || '').trim();
      if (!s) return;
      sourceMap.set(s, (sourceMap.get(s) || 0) + 1);
    });
    const unsourcedCount = tierTasks.filter(t => !t.source || !t.source.trim()).length;
    const opts = [`<option value="all"${current === 'all' ? ' selected' : ''}>All Sources</option>`];
    if (unsourcedCount > 0) {
      opts.push(`<option value="unsourced"${current === 'unsourced' ? ' selected' : ''}>--- Unsourced --- (${unsourcedCount})</option>`);
    }
    Array.from(sourceMap.keys()).sort().forEach(name => {
      opts.push(`<option value="${escapeAttr(name)}"${current === name ? ' selected' : ''}>${escapeHtml(name)} (${sourceMap.get(name)})</option>`);
    });
    sourceSel.innerHTML = opts.join('');
    if (current !== 'all' && current !== 'unsourced') {
      const stillExists = Array.from(sourceSel.options).some(o => o.value === current);
      if (!stillExists) sourceSel.value = 'all';
    }
  }

  // === META + CLEAR-ALL ===
  const f = state.alertFilters || {};
  const anyActive = (f.assignee && f.assignee !== 'all') || (f.stage && f.stage !== 'all') || (f.source && f.source !== 'all');
  row.classList.toggle('afr-active', anyActive);
  const clearBtn = document.getElementById('afrClearBtn');
  if (clearBtn) clearBtn.style.display = anyActive ? 'inline-flex' : 'none';

  const meta = document.getElementById('afrMeta');
  if (meta) {
    if (anyActive) {
      const filtered = getFilteredTasks(project).length;
      const parts = [];
      if (f.assignee && f.assignee !== 'all') parts.push(f.assignee === 'unassigned' ? 'unassigned' : f.assignee);
      if (f.stage && f.stage !== 'all') {
        const stage = STAGES.find(s => s.id === f.stage);
        if (stage) parts.push(stage.name);
      }
      if (f.source && f.source !== 'all') parts.push(f.source === 'unsourced' ? 'unsourced' : f.source);
      meta.textContent = `→ ${filtered} task${filtered === 1 ? '' : 's'} matching ${parts.join(' · ')}`;
    } else {
      meta.textContent = `${tierTasks.length} task${tierTasks.length === 1 ? '' : 's'} in this tier`;
    }
  }
}

// Build the assignee dropdown for the secondary filter row. Pulls from team
// roster + any task assignees not yet in roster + support members, matching
// how populateAssigneeDatalist works for the task modal. Includes special
// 'unassigned' bucket since unassigned-but-overdue tasks are a common
// "needs Lead attention" pattern.
function renderSecondaryAssigneeFilter() {
  const row = document.getElementById('secondaryFilterRow');
  const select = document.getElementById('secondaryAssigneeFilterSelect');
  const meta = document.getElementById('sfrMeta');
  const clearBtn = document.getElementById('sfrClearBtn');
  if (!row || !select) return;

  // Hide entirely in Assignee grouping mode --- would be redundant
  // Also hide in Alert / My Alerts grouping modes --- they use their own filter rows
  if (state.grouping === 'assignee' || state.grouping === 'alert' || state.grouping === 'my-alert') {
    row.style.display = 'none';
    return;
  }
  row.style.display = 'flex';

  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) {
    row.style.display = 'none';
    return;
  }

  // Build the option list --- same union as the task modal's assignee datalist
  const rosterNames = (state.teamMembers || []).map(m => m.name);
  const taskNames = project.tasks.map(t => t.assignee).filter(Boolean);
  const supportNames = [];
  project.tasks.forEach(t => {
    const all = (typeof getAllSupportMembers === 'function') ? getAllSupportMembers(t) : [];
    all.forEach(name => supportNames.push(name));
  });
  const all = Array.from(new Set([...rosterNames, ...taskNames, ...supportNames])).sort();

  // Count tasks per person within the CURRENT primary group, so the dropdown
  // shows live counts ("John (12)" etc.) that reflect the active grouping
  const tasksInGroup = getTasksInPrimaryGroup(project);
  const countFor = (name) => {
    if (name === 'unassigned') return tasksInGroup.filter(t => !t.assignee || !t.assignee.trim()).length;
    return tasksInGroup.filter(t => (t.assignee||'').trim() === name || isTaskSupport(t, name)).length;
  };

  // Always include 'unassigned' if there are any unassigned tasks in the group
  const unassignedCount = tasksInGroup.filter(t => !t.assignee || !t.assignee.trim()).length;

  const current = state.secondaryAssigneeFilter || 'all';
  const opts = [`<option value="all">All Assignees · ${tasksInGroup.length} task${tasksInGroup.length === 1 ? '' : 's'}</option>`];
  if (unassignedCount > 0) {
    opts.push(`<option value="unassigned"${current === 'unassigned' ? ' selected' : ''}>--- Unassigned --- (${unassignedCount})</option>`);
  }
  all.forEach(n => {
    const count = countFor(n);
    if (count === 0) return; // skip people with no tasks in current group
    opts.push(`<option value="${escapeAttr(n)}"${current === n ? ' selected' : ''}>${escapeHtml(n)} (${count})</option>`);
  });
  select.innerHTML = opts.join('');
  // If the previously-selected name has zero tasks in the new group, the
  // dropdown won't include it --- make sure 'all' is shown selected
  if (current !== 'all' && current !== 'unassigned') {
    const stillExists = Array.from(select.options).some(o => o.value === current);
    if (!stillExists) select.value = 'all';
  }

  // Active-state styling and meta
  const isFiltered = current !== 'all';
  row.classList.toggle('sfr-active', isFiltered);
  if (clearBtn) clearBtn.style.display = isFiltered ? 'inline-flex' : 'none';
  if (meta) {
    if (isFiltered) {
      const filtered = getFilteredTasks(project).length;
      const label = current === 'unassigned' ? 'unassigned' : current;
      meta.textContent = `→ ${filtered} task${filtered === 1 ? '' : 's'} for ${label}`;
    } else {
      meta.textContent = '';
    }
  }
}

// Returns the tasks within the CURRENT primary group, BEFORE the secondary
// assignee filter is applied. Used so the assignee dropdown can show
// per-person counts within the active group, and so the meta line can
// compare "filtered vs. group total" honestly.
function getTasksInPrimaryGroup(project) {
  if (state.grouping === 'stage') {
    if (state.activeStageId === 'all') return project.tasks.slice();
    return project.tasks.filter(t => t.stage === state.activeStageId);
  } else if (state.grouping === 'source') {
    if (state.activeSource === 'all') return project.tasks.slice();
    if (state.activeSource === 'unsourced') return project.tasks.filter(t => !t.source || !t.source.trim());
    return project.tasks.filter(t => (t.source || '').trim() === state.activeSource);
  } else if (state.grouping === 'status') {
    if (state.activeStatus === 'all') return project.tasks.slice();
    return project.tasks.filter(t => t.status === state.activeStatus);
  }
  // For 'assignee' grouping, fall back to all tasks (filter row is hidden anyway)
  return project.tasks.slice();
}

// =============================================================
// PRINT / SAVE AS PDF
// =============================================================
function printView() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) { alert('Select a project first'); return; }

  // Populate print header meta
  const viewLabels = { board: 'Board View', table: 'Table View', calendar: 'Calendar View' };
  const calRangeLabels = { day: 'Day', week: 'Week', '2week': '2-Week Look Ahead', month: 'Month' };

  const total = project.tasks.length;
  const done = project.tasks.filter(t => t.status === 'done').length;
  const overdueCount = project.tasks.filter(t => isTaskOverdue(t)).length;
  const pct = total > 0 ? Math.round((done/total)*100) : 0;

  let viewTag = viewLabels[state.viewMode] || 'View';
  if (state.viewMode === 'calendar') {
    viewTag = `Calendar · ${calRangeLabels[state.calRange] || ''}`;
  }

  let groupTag = '';
  if (state.viewMode !== 'calendar') {
    if (state.grouping === 'stage') {
      const stage = STAGES.find(s => s.id === state.activeStageId);
      groupTag = state.activeStageId === 'all' ? 'All Stages' : (stage ? stage.name : '');
    } else if (state.grouping === 'source') {
      groupTag = state.activeSource === 'all' ? 'All Sources' :
                 state.activeSource === 'unsourced' ? 'No Source' : state.activeSource;
    } else if (state.grouping === 'status') {
      const statusLabels = {
        'all': 'All Statuses',
        'not-started': 'Not Started',
        'in-progress': 'In Progress',
        'blocked': 'Blocked',
        'pending': 'Pending',
        'done': 'Done'
      };
      groupTag = statusLabels[state.activeStatus] || state.activeStatus;
    } else {
      groupTag = state.activeAssignee === 'all' ? 'All Team' :
                 state.activeAssignee === 'unassigned' ? 'Unassigned' : state.activeAssignee;
    }
  } else if (state.calAssignee && state.calAssignee !== 'all') {
    groupTag = state.calAssignee === 'unassigned' ? 'Unassigned' : state.calAssignee;
  }

  const meta = [
    `<strong>${escapeHtml(project.name)}</strong>`,
    project.client ? `Owner: ${escapeHtml(project.client)}` : '',
    project.dueDate ? `Bid Due: ${formatDate(project.dueDate)}` : '',
    `Progress: ${done}/${total} (${pct}%)`,
    overdueCount > 0 ? `<span style="color:#c8322b;font-weight:700;">Overdue: ${overdueCount}</span>` : '',
    `View: ${viewTag}${groupTag ? ' · ' + escapeHtml(groupTag) : ''}`,
    `Printed: ${new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}`
  ].filter(Boolean).join(' &nbsp;|&nbsp; ');

  document.getElementById('printHeaderMeta').innerHTML = meta;

  // For calendar "all stages" board view would be too sparse; ensure we render the current state first
  // Render ensures DOM is up to date
  render();

  // Small delay allows browser to apply classes then open print dialog
  setTimeout(() => window.print(), 150);
}

// =============================================================
// MAIN RENDER
// =============================================================
function render() {
  renderSidebar();
  renderHeaderStats();
  renderHomeSidebarBtn();
  renderCurrentUserChip();
  // Refresh the snapshot sidebar badge regardless of which view is active
  if (typeof refreshSnapshotSidebarBadge === 'function') {
    try { refreshSnapshotSidebarBadge(); } catch(err) { /* defensive */ }
  }

  // Status Snapshot view --- takes precedence over home/project view when active
  const snapshotEl = document.getElementById('statusSnapshotView');
  const homeViewEl = document.getElementById('homeView');
  const projectViewEl = document.getElementById('projectView');
  const emptyEl = document.getElementById('emptyProjects');
  if (state.statusSnapshotView) {
    if (emptyEl) emptyEl.classList.add('hidden');
    if (projectViewEl) projectViewEl.classList.add('hidden');
    if (homeViewEl) homeViewEl.classList.add('hidden');
    if (snapshotEl) snapshotEl.classList.remove('hidden');
    // Hide sticky countdown bar --- cross-project view, no single bid applies
    const _scbBar = document.getElementById('stickyCountdownBar');
    const _scbMain = document.querySelector('.main');
    if (_scbBar) _scbBar.style.display = 'none';
    if (_scbMain) _scbMain.classList.remove('has-sticky-countdown');
    renderStatusSnapshot();
    applySidebarState();
    return;
  }
  if (snapshotEl) snapshotEl.classList.add('hidden');

  // Home/Today view takes precedence over project view
  if (state.homeView) {
    if (emptyEl) emptyEl.classList.add('hidden');
    if (projectViewEl) projectViewEl.classList.add('hidden');
    if (homeViewEl) homeViewEl.classList.remove('hidden');
    // Hide sticky countdown bar --- Home is cross-project, no countdown applies
    const _scbBarH = document.getElementById('stickyCountdownBar');
    const _scbMainH = document.querySelector('.main');
    if (_scbBarH) _scbBarH.style.display = 'none';
    if (_scbMainH) _scbMainH.classList.remove('has-sticky-countdown');
    renderHomeView();
    applySidebarState();
    return;
  }
  if (homeViewEl) homeViewEl.classList.add('hidden');

  const project = state.projects.find(p=>p.id===state.activeProjectId);
  if (!project) {
    document.getElementById('emptyProjects').classList.remove('hidden');
    document.getElementById('projectView').classList.add('hidden');
    return;
  }
  document.getElementById('emptyProjects').classList.add('hidden');
  document.getElementById('projectView').classList.remove('hidden');
  renderProjectHeader(project);
  renderProjectRequiredItems();
  renderProjectHoursRollup();
  renderBidCountdown(project);
  renderTradePartnerCountdown(project);
  // Sticky compact countdown bar --- replaces the dashboard accordion section
  // as the primary always-visible countdown surface.
  if (typeof renderStickyCountdownBar === 'function') renderStickyCountdownBar(project);
  renderMilestonesStrip(project);
  renderAddendumsSection(project);
  startCountdownTimer();
  renderAlertStrip(project);
  renderAssigneeAlertsStrip(project);
  renderSectionSummaries(project);
  renderActivityLog();
  applySectionStates();
  applySidebarState();
  renderAckAllButtons(project);
  // Critical filter pill --- sync active state + count chip with current project
  if (typeof refreshCriticalFilterPill === 'function') refreshCriticalFilterPill(project);
  // Saved Views button label --- show active view name when one is applied
  if (typeof refreshSavedViewsButtonLabel === 'function') refreshSavedViewsButtonLabel();
  // Sticky workspace controls --- IntersectionObserver pinned to .main scroll
  // container. Re-runs each render so observer rebinds if the panel was
  // re-rendered. Idempotent: tears down previous observer first.
  if (typeof setupPvWorkspaceStickyObserver === 'function') {
    setupPvWorkspaceStickyObserver();
  }
  renderMessagesButtonBadge(project);
  checkForNewInboundMessages(project);

  // View mode buttons
  document.querySelectorAll('[data-viewmode]').forEach(b => b.classList.toggle('active', b.dataset.viewmode === state.viewMode));
  document.querySelectorAll('[data-grouping]').forEach(b => b.classList.toggle('active', b.dataset.grouping === state.grouping));

  // Show/hide view panels
  document.getElementById('boardView').classList.toggle('hidden', state.viewMode !== 'board');
  document.getElementById('tableView').classList.toggle('hidden', state.viewMode !== 'table');
  document.getElementById('calendarView').classList.toggle('hidden', state.viewMode !== 'calendar');
  const schedView = document.getElementById('scheduleView');
  if (schedView) schedView.classList.toggle('hidden', state.viewMode !== 'schedule');
  const laView = document.getElementById('lookaheadView');
  if (laView) laView.classList.toggle('hidden', state.viewMode !== 'lookahead');

  // Grouping nav + section header only for board & table --- calendar, schedule, and lookahead have their own controls
  const hideTopControls = state.viewMode === 'calendar' || state.viewMode === 'schedule' || state.viewMode === 'lookahead';
  document.getElementById('groupingSection').classList.toggle('hidden', hideTopControls);
  document.getElementById('sectionHeader').classList.toggle('hidden', hideTopControls);

  if (state.viewMode === 'calendar') {
    renderCalendar(project);
  } else if (state.viewMode === 'schedule') {
    renderScheduleView(project);
  } else if (state.viewMode === 'lookahead') {
    renderLookAheadView(project);
  } else {
    renderTabNav(project);
    renderSectionHeader(project);
    renderSecondaryAssigneeFilter();
    renderAlertMultiFilter();
    renderMyAlertMultiFilter();
    if (state.viewMode === 'board') renderBoardView(project);
    else if (state.viewMode === 'table') renderTableView(project);
  }

  // Update bulk action bar visibility (shows when in selection mode)
  updateBulkActionBar();
  updateBulkSelectToggleBtn();
}

function renderSidebar() {
  const list = document.getElementById('projectList');
  if (state.projects.length === 0) {
    list.innerHTML = '<div style="color:var(--text-dim);font-size:12px;padding:12px;text-align:center;">No projects yet</div>';
    return;
  }

  // Split projects into three buckets:
  //   Currently Bidding = no due date OR due date is today/future (and not archived)
  //   Past Pursuits     = due date has passed (regardless of completion, not archived)
  //   Archived          = soft-deleted, hidden from main views
  const currentlyBidding = [];
  const pastPursuits = [];
  const archived = [];
  state.projects.forEach(p => {
    if (p.archived) { archived.push(p); return; }
    const d = getDaysLeft(p.dueDate);
    if (d === null || d >= 0) currentlyBidding.push(p);
    else pastPursuits.push(p);
  });

  // Sort each bucket sensibly:
  //   Currently Bidding: most urgent first (fewest days left), null dates at the bottom
  //   Past Pursuits: most recent (least overdue) first
  //   Archived: most recently archived first
  currentlyBidding.sort((a, b) => {
    const da = getDaysLeft(a.dueDate);
    const db = getDaysLeft(b.dueDate);
    if (da === null && db === null) return a.name.localeCompare(b.name);
    if (da === null) return 1;
    if (db === null) return -1;
    return da - db;
  });
  pastPursuits.sort((a, b) => {
    const da = getDaysLeft(a.dueDate);
    const db = getDaysLeft(b.dueDate);
    return db - da;  // least overdue first (closest to today)
  });
  archived.sort((a, b) => {
    const aa = a.archivedAt || 0;
    const ab = b.archivedAt || 0;
    return ab - aa; // most recent first
  });

  const renderProjectItem = (p, opts) => {
    opts = opts || {};
    const daysLeft = getDaysLeft(p.dueDate);
    const cls = daysLeft===null?'':daysLeft<0?'urgent':daysLeft<=3?'urgent':daysLeft<=7?'warning':'ok';
    const dayText = daysLeft===null?'---':daysLeft<0?`${Math.abs(daysLeft)}d late`:`${daysLeft}d`;
    const total = p.tasks.length;
    const done = p.tasks.filter(t=>t.status==='done').length;
    const pct = total>0 ? Math.round((done/total)*100) : 0;
    const initials = p.name.split(/\s+/).map(w=>w[0]).join('').slice(0,2).toUpperCase();
    const thumb = p.image
      ? `<div class="project-item-thumb"><img src="${p.image}" alt=""></div>`
      : `<div class="project-item-thumb">${escapeHtml(initials)}</div>`;
    const oneDriveBtn = p.oneDriveUrl
      ? `<a href="${escapeHtml(p.oneDriveUrl)}" target="_blank" rel="noopener" class="project-item-od" onclick="event.stopPropagation()" title="Open OneDrive folder">☁</a>`
      : '';
    // Small REV pill if this project's due date has been revised
    const hasDueShift = p.originalDueDate && p.dueDate && p.originalDueDate !== p.dueDate;
    const revPill = hasDueShift
      ? `<span class="sidebar-rev-pill" title="Bid Due Date has been revised from ${formatDateShort(p.originalDueDate)}">REV</span>`
      : '';
    // Inline kebab menu --- Edit / Archive / Delete (or Restore / Delete for archived).
    // Surfaces the most-common project actions one click away from the
    // project list rather than buried in the modal. Stops click propagation
    // so opening the menu doesn't also navigate into the project.
    const isArchived = !!p.archived;
    const menuItems = isArchived
      ? `<button class="pi-menu-item" onclick="event.stopPropagation();openProjectModal('${p.id}');document.getElementById('pim_${p.id}').classList.remove('open')">✎ Edit Details</button>
         <button class="pi-menu-item pi-menu-restore" onclick="event.stopPropagation();restoreProject('${p.id}');document.getElementById('pim_${p.id}').classList.remove('open')">↩ Restore</button>
         <button class="pi-menu-item pi-menu-delete" onclick="event.stopPropagation();editingProjectId='${p.id}';deleteProject();document.getElementById('pim_${p.id}').classList.remove('open')">🗑 Delete Permanently</button>`
      : `<button class="pi-menu-item" onclick="event.stopPropagation();openProjectModal('${p.id}');document.getElementById('pim_${p.id}').classList.remove('open')">✎ Edit Details</button>
         <button class="pi-menu-item pi-menu-archive" onclick="event.stopPropagation();archiveProject('${p.id}');document.getElementById('pim_${p.id}').classList.remove('open')">📁 Archive</button>
         <button class="pi-menu-item pi-menu-delete" onclick="event.stopPropagation();editingProjectId='${p.id}';deleteProject();document.getElementById('pim_${p.id}').classList.remove('open')">🗑 Delete Permanently</button>`;
    const actionMenu = `
      <div class="project-item-actions">
        <button class="pi-kebab" onclick="event.stopPropagation();togglePIMenu('${p.id}')" title="Project actions">⋯</button>
        <div class="pi-menu" id="pim_${p.id}">
          ${menuItems}
        </div>
      </div>`;
    // Archived projects: badge + faded styling, click opens edit modal (NOT
    // selectProject, since we don't want to switch to a hidden project)
    const archBadge = isArchived
      ? `<span class="pi-archived-badge" title="Archived ${p.archivedAt ? formatDateShort(new Date(p.archivedAt).toISOString().slice(0,10)) : ''}${p.archivedBy ? ' by ' + escapeHtml(p.archivedBy) : ''}">ARCHIVED</span>`
      : '';
    const clickHandler = isArchived
      ? `openProjectModal('${p.id}')`
      : `selectProject('${p.id}')`;
    return `
      <div class="project-item ${p.id===state.activeProjectId?'active':''} ${isArchived?'project-item-archived':''}" onclick="${clickHandler}" title="${escapeHtml(p.name)}">
        <div class="project-item-layout">
          ${thumb}
          <div class="project-item-body">
            <div class="name">${escapeHtml(p.name)}${oneDriveBtn}${archBadge}</div>
            <div class="meta">
              <span class="task-count"><span class="done">${done}</span> / ${total} tasks</span>
              <span class="bid-days ${cls}">${dayText}${revPill}</span>
            </div>
            <div class="mini-progress"><div class="mini-progress-fill" style="width:${pct}%"></div></div>
          </div>
          ${actionMenu}
        </div>
      </div>
    `;
  };

  const sections = [];

  // --- Currently Bidding section ---
  sections.push(`
    <div class="project-section">
      <div class="project-section-header">
        <span class="ps-dot ps-dot-active"></span>
        <span class="ps-title">Currently Bidding</span>
        <span class="ps-count">${currentlyBidding.length}</span>
      </div>
      <div class="project-section-body">
        ${currentlyBidding.length > 0
          ? currentlyBidding.map(p => renderProjectItem(p)).join('')
          : '<div class="project-section-empty">No active bids. Click + New Project to start one.</div>'
        }
      </div>
    </div>
  `);

  // --- Past Pursuits section (collapsible, hidden by default) ---
  if (pastPursuits.length > 0) {
    const expanded = state.pastPursuitsExpanded;
    sections.push(`
      <div class="project-section project-section-past ${expanded ? 'expanded' : 'collapsed'}">
        <div class="project-section-header clickable" onclick="togglePastPursuits()">
          <span class="ps-dot ps-dot-past"></span>
          <span class="ps-title">Past Pursuits</span>
          <span class="ps-count">${pastPursuits.length}</span>
          <span class="ps-chevron">${expanded ? '▾' : '▸'}</span>
        </div>
        ${expanded ? `
          <div class="project-section-body">
            ${pastPursuits.map(p => renderProjectItem(p)).join('')}
          </div>
        ` : ''}
      </div>
    `);
  }

  // --- Archived section (collapsible, hidden by default) ---
  if (archived.length > 0) {
    const expanded = state.archivedExpanded;
    sections.push(`
      <div class="project-section project-section-archived ${expanded ? 'expanded' : 'collapsed'}">
        <div class="project-section-header clickable" onclick="toggleArchived()">
          <span class="ps-dot ps-dot-archived"></span>
          <span class="ps-title">Archived</span>
          <span class="ps-count">${archived.length}</span>
          <span class="ps-chevron">${expanded ? '▾' : '▸'}</span>
        </div>
        ${expanded ? `
          <div class="project-section-body">
            ${archived.map(p => renderProjectItem(p)).join('')}
          </div>
        ` : ''}
      </div>
    `);
  }

  list.innerHTML = sections.join('');
}

// Collapse / expand the Archived section in the sidebar
function toggleArchived() {
  state.archivedExpanded = !state.archivedExpanded;
  saveState();
  renderSidebar();
}

// Open / close the inline project-item kebab menu. Closes any other open
// menus first so only one is visible at a time.
function togglePIMenu(projectId) {
  const target = document.getElementById('pim_' + projectId);
  if (!target) return;
  const isOpen = target.classList.contains('open');
  // Close all other menus
  document.querySelectorAll('.pi-menu.open').forEach(m => {
    if (m !== target) m.classList.remove('open');
  });
  // Toggle this one
  target.classList.toggle('open', !isOpen);
  // Close on next outside click
  if (!isOpen) {
    setTimeout(() => {
      const handler = (e) => {
        if (!target.contains(e.target) && !e.target.classList.contains('pi-kebab')) {
          target.classList.remove('open');
          document.removeEventListener('click', handler);
        }
      };
      document.addEventListener('click', handler);
    }, 10);
  }
}

function togglePastPursuits() {
  state.pastPursuitsExpanded = !state.pastPursuitsExpanded;
  saveState();
  renderSidebar();
}

function renderHeaderStats() {
  document.getElementById('statActive').textContent = state.projects.filter(p => {
    if (p.archived) return false;
    const d = getDaysLeft(p.dueDate); return d === null || d >= 0;
  }).length;

  let totalTasks = 0, doneTasks = 0;
  state.projects.forEach(p => {
    if (p.archived) return; // exclude archived from header stats
    totalTasks += p.tasks.length;
    doneTasks += p.tasks.filter(t=>t.status==='done').length;
  });
  document.getElementById('statTasks').textContent = `${doneTasks} / ${totalTasks}`;

  const weekFromNow = new Date(); weekFromNow.setDate(weekFromNow.getDate()+7); weekFromNow.setHours(23,59,59,999);
  const today = new Date(); today.setHours(0,0,0,0);
  let dueCount = 0;
  state.projects.forEach(p => {
    if (p.archived) return; // exclude archived from "due this week" count
    p.tasks.forEach(t => {
      if (t.status === 'done' || !t.dueDate) return;
      const d = new Date(t.dueDate+'T00:00:00');
      if (d <= weekFromNow && d >= today) dueCount++;
    });
  });
  document.getElementById('statDue').textContent = dueCount;

  const total = state.projects.reduce((s,p) => s + (p.value||0), 0);
  document.getElementById('statValue').textContent = formatCurrency(total);
}

// =============================================================
// BID COUNTDOWN --- live ticking clock
// =============================================================
let countdownTimer = null;

function renderBidCountdown(project) {
  const card = document.getElementById('pvCountdownCard');
  if (!card) return;

  // Only show the card when we have a due date. Even without a time, show day-level countdown.
  if (!project || !project.dueDate) {
    card.style.display = 'none';
    return;
  }

  card.style.display = 'grid';

  // Moment & format labels
  const momentEl = document.getElementById('bccMoment');
  const formatEl = document.getElementById('bccFormat');
  const dueDateLabel = formatDate(project.dueDate);
  const timeLabel = project.dueTime ? formatTimeShort(project.dueTime) : '11:59 PM';
  const tzLabel = project.dueTimezone ? formatTimezoneShort(project.dueTimezone) : '';
  momentEl.innerHTML = `${dueDateLabel} · ${timeLabel}${tzLabel ? ` <span style="opacity:0.75;font-weight:600;font-size:14px;">${tzLabel}</span>` : ''}`;

  const formatParts = [];
  if (project.submissionFormat) formatParts.push(`📤 ${project.submissionFormat}`);
  if (!project.dueTime) formatParts.push('No time set --- defaulting to end of day');
  formatEl.textContent = formatParts.join(' · ');

  // Tick once immediately so numbers aren't blank
  tickBidCountdown(project);
}

// Track which audio alerts have fired for each project so we don't spam
let audioAlertState = {}; // { [projectId]: { fired2h: bool, fired1h: bool } }

function playCountdownBeep(frequency, durationMs) {
  // Web Audio API beep --- works without any asset files.
  // Will silently no-op if the browser blocks audio before a user gesture.
  try {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return;
    if (!window._countdownAudioCtx) window._countdownAudioCtx = new AudioCtx();
    const ctx = window._countdownAudioCtx;
    // If the context is suspended (pre-user-gesture), try to resume but don't block
    if (ctx.state === 'suspended') { try { ctx.resume(); } catch(e){} }
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.value = frequency;
    osc.connect(gain);
    gain.connect(ctx.destination);
    // Quick fade-in, hold, fade-out to avoid clicks
    const now = ctx.currentTime;
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(0.35, now + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + (durationMs / 1000));
    osc.start(now);
    osc.stop(now + (durationMs / 1000) + 0.02);
  } catch (e) {
    // Silent fail --- audio isn't critical
  }
}

function playCountdownAlertSequence(tier) {
  // Different patterns so you can distinguish 2h vs 1h by ear
  if (tier === '2h') {
    // Three medium beeps --- "heads up"
    playCountdownBeep(660, 200);
    setTimeout(() => playCountdownBeep(660, 200), 300);
    setTimeout(() => playCountdownBeep(660, 200), 600);
  } else if (tier === '1h') {
    // Four urgent higher beeps --- "final hour"
    playCountdownBeep(880, 220);
    setTimeout(() => playCountdownBeep(880, 220), 280);
    setTimeout(() => playCountdownBeep(1100, 220), 560);
    setTimeout(() => playCountdownBeep(1100, 400), 840);
  }
}

function tickBidCountdown(project) {
  const card = document.getElementById('pvCountdownCard');
  if (!card || !project || !project.dueDate) return;

  const cd = getBidCountdown(project);
  if (!cd) return;

  // Apply state class based on urgency --- removes all prior tier classes first
  card.classList.remove(
    'countdown-past', 'countdown-critical', 'countdown-imminent',
    'countdown-warning', 'countdown-attention', 'countdown-approaching'
  );
  const statusEl = document.getElementById('bccStatus');

  // Initialize project-specific audio-fired tracking
  const pid = project.id;
  if (!audioAlertState[pid]) audioAlertState[pid] = { fired2h: false, fired1h: false };
  const audioState = audioAlertState[pid];

  // 5-tier urgency scale (past → critical → imminent → warning → attention → approaching → normal)
  if (cd.isPast) {
    card.classList.add('countdown-past');
    statusEl.textContent = '⏱ Submission window closed';
    // Reset audio fired flags --- if the date gets revised in the future, we want new alerts
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else if (cd.totalMs < 3600000) {
    // < 1 HOUR: CRITICAL --- pulsing bright red + audio
    card.classList.add('countdown-critical');
    statusEl.textContent = '🚨 FINAL HOUR --- SUBMIT NOW';
    if (!audioState.fired1h) {
      playCountdownAlertSequence('1h');
      audioState.fired1h = true;
      audioState.fired2h = true; // Definitely past 2h threshold too
    }
  } else if (cd.totalMs < 2 * 3600000) {
    // < 2 HOURS: IMMINENT --- pulsing red + audio (fires once)
    card.classList.add('countdown-imminent');
    statusEl.textContent = '🚨 Under 2 hours --- submit now';
    if (!audioState.fired2h) {
      playCountdownAlertSequence('2h');
      audioState.fired2h = true;
    }
  } else if (cd.totalMs < 24 * 3600000) {
    // < 1 DAY: WARNING --- amber
    card.classList.add('countdown-warning');
    statusEl.textContent = '⚠ Under 24 hours to bid';
    // Reset audio flags so they can fire again if we cross back down
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else if (cd.totalMs < 2 * 86400000) {
    // < 2 DAYS: ATTENTION --- soft amber
    card.classList.add('countdown-attention');
    statusEl.textContent = '⚠ Under 2 days --- final push';
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else if (cd.totalMs < 5 * 86400000) {
    // < 5 DAYS: APPROACHING --- light accent
    card.classList.add('countdown-approaching');
    statusEl.textContent = '⏰ Under 5 days out';
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else {
    statusEl.textContent = '';
    audioState.fired2h = false;
    audioState.fired1h = false;
  }

  // Update the clock numbers
  const pad = n => String(n).padStart(2, '0');
  document.getElementById('bccDays').textContent = cd.isPast ? `-${cd.days}` : cd.days;
  document.getElementById('bccHours').textContent = pad(cd.hours);
  document.getElementById('bccMinutes').textContent = pad(cd.minutes);
  document.getElementById('bccSeconds').textContent = pad(cd.seconds);
}

// =============================================================
// TRADE PARTNER BIDS COUNTDOWN
// Pulls its date/time from the Key Milestone with id "trade-partner-bids".
// Mirrors the main Bid Countdown's 5-tier urgency scheme + audio alerts.
// =============================================================
function getTradePartnerMilestoneInstance(project) {
  if (!project || !Array.isArray(project.milestones)) return null;
  return project.milestones.find(m => m.typeId === 'trade-partner-bids' && m.date) || null;
}

function renderTradePartnerCountdown(project) {
  const card = document.getElementById('pvTradePartnerCountdownCard');
  const nudge = document.getElementById('pvTradePartnerNudge');
  if (!card) return;

  const inst = getTradePartnerMilestoneInstance(project);
  if (!inst) {
    card.style.display = 'none';
    // Nudge: only shown if the Trade Partner Bids type exists in milestoneTypes and the project has a main bid date
    const tpTypeExists = state.milestoneTypes && state.milestoneTypes.some(t => t.id === 'trade-partner-bids');
    if (nudge) nudge.style.display = (tpTypeExists && project && project.dueDate) ? 'flex' : 'none';
    return;
  }
  if (nudge) nudge.style.display = 'none';
  card.style.display = 'grid';

  const momentEl = document.getElementById('tpccMoment');
  const formatEl = document.getElementById('tpccFormat');
  const dateLabel = formatDate(inst.date);
  const timeLabel = inst.time ? formatTimeShort(inst.time) : '5:00 PM';
  const tzLabel = inst.timezone ? formatTimezoneShort(inst.timezone) : '';
  momentEl.innerHTML = `${dateLabel} · ${timeLabel}${tzLabel ? ` <span style="opacity:0.75;font-weight:600;font-size:14px;">${tzLabel}</span>` : ''}`;

  const parts = [];
  if (!inst.time) parts.push('No time set --- defaulting to 5:00 PM');
  if (inst.notes) parts.push(inst.notes);
  formatEl.textContent = parts.join(' · ');

  tickTradePartnerCountdown(project);
}

// Separate per-project audio state for the Trade Partner countdown (independent of main bid clock)
let tpAudioAlertState = {};

function tickTradePartnerCountdown(project) {
  const card = document.getElementById('pvTradePartnerCountdownCard');
  if (!card) return;
  const inst = getTradePartnerMilestoneInstance(project);
  if (!inst) return;
  const cd = getMilestoneCountdown(inst);
  if (!cd) return;

  card.classList.remove(
    'countdown-past', 'countdown-critical', 'countdown-imminent',
    'countdown-warning', 'countdown-attention', 'countdown-approaching'
  );
  const statusEl = document.getElementById('tpccStatus');

  const pid = project.id;
  if (!tpAudioAlertState[pid]) tpAudioAlertState[pid] = { fired2h: false, fired1h: false };
  const audioState = tpAudioAlertState[pid];

  if (cd.isPast) {
    card.classList.add('countdown-past');
    statusEl.textContent = '⏱ Trade partner deadline passed';
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else if (cd.totalMs < 3600000) {
    card.classList.add('countdown-critical');
    statusEl.textContent = '🚨 FINAL HOUR --- TRADES SUBMITTING NOW';
    if (!audioState.fired1h) {
      playCountdownAlertSequence('1h');
      audioState.fired1h = true;
      audioState.fired2h = true;
    }
  } else if (cd.totalMs < 2 * 3600000) {
    card.classList.add('countdown-imminent');
    statusEl.textContent = '🚨 Under 2 hours --- trade partner bids arriving';
    if (!audioState.fired2h) {
      playCountdownAlertSequence('2h');
      audioState.fired2h = true;
    }
  } else if (cd.totalMs < 24 * 3600000) {
    card.classList.add('countdown-warning');
    statusEl.textContent = '⚠ Under 24 hours --- final subcontractor follow-ups';
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else if (cd.totalMs < 2 * 86400000) {
    card.classList.add('countdown-attention');
    statusEl.textContent = '⚠ Under 2 days --- chase coverage gaps';
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else if (cd.totalMs < 5 * 86400000) {
    card.classList.add('countdown-approaching');
    statusEl.textContent = '⏰ Under 5 days out for trade partners';
    audioState.fired2h = false;
    audioState.fired1h = false;
  } else {
    statusEl.textContent = '';
    audioState.fired2h = false;
    audioState.fired1h = false;
  }

  const pad = n => String(n).padStart(2, '0');
  document.getElementById('tpccDays').textContent = cd.isPast ? `-${cd.days}` : cd.days;
  document.getElementById('tpccHours').textContent = pad(cd.hours);
  document.getElementById('tpccMinutes').textContent = pad(cd.minutes);
  document.getElementById('tpccSeconds').textContent = pad(cd.seconds);
}

let milestoneTickCounter = 0;

function startCountdownTimer() {
  // Stop any existing timer first to avoid leaks when switching projects
  stopCountdownTimer();
  milestoneTickCounter = 0;
  countdownTimer = setInterval(() => {
    const project = state.projects.find(p => p.id === state.activeProjectId);
    if (!project) {
      stopCountdownTimer();
      return;
    }
    const hasBid = !!project.dueDate;
    const hasMilestones = Array.isArray(project.milestones) && project.milestones.some(m => m.date);
    const hasTradePartner = !!getTradePartnerMilestoneInstance(project);
    if (!hasBid && !hasMilestones) {
      stopCountdownTimer();
      return;
    }
    if (hasBid) tickBidCountdown(project);
    if (hasTradePartner) tickTradePartnerCountdown(project);
    // Always tick the sticky bar --- it handles its own empty-state display
    if (typeof tickStickyCountdownBar === 'function') tickStickyCountdownBar(project);
    // Milestone cards: refresh every 10 seconds (save perf --- they show min/hr granularity)
    milestoneTickCounter++;
    if (hasMilestones && milestoneTickCounter % 10 === 0) {
      renderMilestonesStrip(project);
    }
  }, 1000);
}

function stopCountdownTimer() {
  if (countdownTimer) {
    clearInterval(countdownTimer);
    countdownTimer = null;
  }
}

// =============================================================
// STICKY COUNTDOWN BAR --- fixed top-of-viewport always-visible compact display.
// Replaces the dashboard accordion section as the primary surface for live
// countdown awareness. Renders both Trade Partner Bids Due and Bid Submission
// in a stacked dual-row layout. Hidden on Home view (no project context).
// =============================================================

function renderStickyCountdownBar(project) {
  const bar = document.getElementById('stickyCountdownBar');
  const main = document.querySelector('.main');
  if (!bar) return;
  // Hide bar entirely when not on a project view
  if (!project || state.homeView) {
    bar.style.display = 'none';
    if (main) main.classList.remove('has-sticky-countdown');
    return;
  }
  // Show bar --- Tick will populate values; if no dates set we show empty state
  bar.style.display = 'block';
  if (main) main.classList.add('has-sticky-countdown');
  // Initial tick to populate values immediately (before next 1-second interval)
  tickStickyCountdownBar(project);
}

function tickStickyCountdownBar(project) {
  if (!project) return;
  // ===== TRADE PARTNER row =====
  const tpRow = document.getElementById('scbRowTp');
  // Trade Partner data comes from milestone instance, not a standalone fn
  const tpInst = (typeof getTradePartnerMilestoneInstance === 'function') ? getTradePartnerMilestoneInstance(project) : null;
  const tpcd = (tpInst && typeof getMilestoneCountdown === 'function') ? getMilestoneCountdown(tpInst) : null;
  if (tpRow) {
    tpRow.classList.remove('scb-empty', 'scb-past', 'scb-critical', 'scb-imminent', 'scb-warning', 'scb-attention');
    if (!tpcd) {
      // Empty / unconfigured state
      tpRow.classList.add('scb-empty');
      const statusEl = document.getElementById('scbTpStatus');
      const momentEl = document.getElementById('scbTpMoment');
      if (statusEl) statusEl.textContent = '💡 Trade Partner Bids Due not configured --- click to set date';
      if (momentEl) momentEl.textContent = '';
    } else {
      // Apply urgency tier class --- same thresholds as the original card
      if (tpcd.isPast) tpRow.classList.add('scb-past');
      else if (tpcd.totalMs < 3600000) tpRow.classList.add('scb-critical');
      else if (tpcd.totalMs < 2 * 3600000) tpRow.classList.add('scb-imminent');
      else if (tpcd.totalMs < 24 * 3600000) tpRow.classList.add('scb-warning');
      else if (tpcd.totalMs < 2 * 86400000) tpRow.classList.add('scb-attention');

      // Status text
      let statusText = '';
      if (tpcd.isPast) statusText = '⏱ Trade partner window closed';
      else if (tpcd.totalMs < 3600000) statusText = '🚨 FINAL HOUR for trade partners';
      else if (tpcd.totalMs < 2 * 3600000) statusText = '🚨 Under 2 hours for trade partners';
      else if (tpcd.totalMs < 24 * 3600000) statusText = '⚠ Under 24 hours for trade partners';
      else if (tpcd.totalMs < 2 * 86400000) statusText = '⚠ Under 2 days for trade partners';
      else if (tpcd.totalMs < 5 * 86400000) statusText = '⏰ Under 5 days out for trade partners';
      else statusText = 'On track';
      const statusEl = document.getElementById('scbTpStatus');
      if (statusEl) statusEl.textContent = statusText;

      // Clock
      const pad = n => String(n).padStart(2, '0');
      const daysEl = document.getElementById('scbTpDays');
      const hoursEl = document.getElementById('scbTpHours');
      const minsEl = document.getElementById('scbTpMinutes');
      const secsEl = document.getElementById('scbTpSeconds');
      if (daysEl) daysEl.textContent = tpcd.isPast ? `-${tpcd.days}` : tpcd.days;
      if (hoursEl) hoursEl.textContent = pad(tpcd.hours);
      if (minsEl) minsEl.textContent = pad(tpcd.minutes);
      if (secsEl) secsEl.textContent = pad(tpcd.seconds);

      // Moment string
      const momentEl = document.getElementById('scbTpMoment');
      if (momentEl && tpInst) {
        try {
          const dateLabel = (typeof formatDate === 'function') ? formatDate(tpInst.date) : tpInst.date;
          const timeLabel = tpInst.time ? ((typeof formatTimeShort === 'function') ? formatTimeShort(tpInst.time) : tpInst.time) : '5:00 PM';
          momentEl.textContent = dateLabel + ' · ' + timeLabel;
        } catch (e) { momentEl.textContent = ''; }
      }
    }
  }

  // ===== BID SUBMISSION row =====
  const bidRow = document.getElementById('scbRowBid');
  const bcd = (typeof getBidCountdown === 'function') ? getBidCountdown(project) : null;
  if (bidRow) {
    bidRow.classList.remove('scb-empty', 'scb-past', 'scb-critical', 'scb-imminent', 'scb-warning', 'scb-attention');
    if (!bcd) {
      bidRow.classList.add('scb-empty');
      const statusEl = document.getElementById('scbBidStatus');
      const momentEl = document.getElementById('scbBidMoment');
      if (statusEl) statusEl.textContent = '💡 Bid submission date not set --- click to configure';
      if (momentEl) momentEl.textContent = '';
    } else {
      if (bcd.isPast) bidRow.classList.add('scb-past');
      else if (bcd.totalMs < 3600000) bidRow.classList.add('scb-critical');
      else if (bcd.totalMs < 2 * 3600000) bidRow.classList.add('scb-imminent');
      else if (bcd.totalMs < 24 * 3600000) bidRow.classList.add('scb-warning');
      else if (bcd.totalMs < 2 * 86400000) bidRow.classList.add('scb-attention');

      let statusText = '';
      if (bcd.isPast) statusText = '⏱ Submission window closed';
      else if (bcd.totalMs < 3600000) statusText = '🚨 FINAL HOUR --- SUBMIT NOW';
      else if (bcd.totalMs < 2 * 3600000) statusText = '🚨 Under 2 hours --- submit now';
      else if (bcd.totalMs < 24 * 3600000) statusText = '⚠ Under 24 hours to bid';
      else if (bcd.totalMs < 2 * 86400000) statusText = '⚠ Under 2 days --- final push';
      else if (bcd.totalMs < 5 * 86400000) statusText = '⏰ Under 5 days out';
      else statusText = 'On track';
      const statusEl = document.getElementById('scbBidStatus');
      if (statusEl) statusEl.textContent = statusText;

      const pad = n => String(n).padStart(2, '0');
      const daysEl = document.getElementById('scbBidDays');
      const hoursEl = document.getElementById('scbBidHours');
      const minsEl = document.getElementById('scbBidMinutes');
      const secsEl = document.getElementById('scbBidSeconds');
      if (daysEl) daysEl.textContent = bcd.isPast ? `-${bcd.days}` : bcd.days;
      if (hoursEl) hoursEl.textContent = pad(bcd.hours);
      if (minsEl) minsEl.textContent = pad(bcd.minutes);
      if (secsEl) secsEl.textContent = pad(bcd.seconds);

      const momentEl = document.getElementById('scbBidMoment');
      if (momentEl && project.dueDate) {
        try {
          const dueDate = (typeof getProjectDueDate === 'function') ? getProjectDueDate(project) : project.dueDate;
          const dateLabel = (typeof formatDate === 'function') ? formatDate(dueDate) : dueDate;
          let timeLabel = '8:00 AM';
          if (project.dueTime && typeof formatTimeShort === 'function') {
            timeLabel = formatTimeShort(project.dueTime);
          } else if (project.dueTime) {
            timeLabel = project.dueTime;
          }
          momentEl.textContent = dateLabel + ' · ' + timeLabel;
        } catch (e) { momentEl.textContent = ''; }
      }
    }
  }
}

// =============================================================
// KEY MILESTONES --- main page rendering
// =============================================================
function renderMilestonesStrip(project) {
  const strip = document.getElementById('pvMilestonesStrip');
  const grid = document.getElementById('pvMilestonesGrid');
  if (!strip || !grid) return;

  if (!project || !state.milestoneTypes || state.milestoneTypes.length === 0) {
    strip.style.display = 'none';
    return;
  }
  strip.style.display = 'block';

  const milestones = getProjectMilestones(project);
  grid.innerHTML = milestones.map(({ type, instance }) => {
    const hasDate = !!instance.date;
    const cd = hasDate ? getMilestoneCountdown(instance) : null;

    let stateClass = '';
    let countdownHtml = '';
    let momentHtml = '';

    if (!hasDate) {
      stateClass = 'missing';
      momentHtml = `<div class="mc-moment"><span class="mc-missing-alert">⚠ MISSING --- SET DATE</span></div>`;
      countdownHtml = `<div class="mc-countdown" style="color:var(--text-faint);font-style:italic;font-size:12px;">Click to set date & time</div>`;
    } else {
      // Format moment
      const dateLabel = formatDate(instance.date);
      const timeLabel = instance.time ? formatTimeShort(instance.time) : '5:00 PM';
      const tzLabel = instance.timezone ? formatTimezoneShort(instance.timezone) : '';
      momentHtml = `<div class="mc-moment">${dateLabel} · ${timeLabel}${tzLabel ? ' ' + tzLabel : ''}</div>`;

      // State
      if (cd.isPast) {
        stateClass = 'past';
        countdownHtml = `<div class="mc-countdown"><span>⏱ Past due · ${cd.days}d ${cd.hours}h ago</span></div>`;
      } else if (cd.totalMs < 2 * 3600000) {
        stateClass = 'imminent';
        countdownHtml = `
          <div class="mc-countdown">
            <span class="mc-num">${cd.hours}</span><span class="mc-unit">hr</span>
            <span class="mc-num">${String(cd.minutes).padStart(2,'0')}</span><span class="mc-unit">min</span>
          </div>`;
      } else if (cd.totalMs < 24 * 3600000) {
        stateClass = 'warning';
        countdownHtml = `
          <div class="mc-countdown">
            <span class="mc-num">${cd.hours}</span><span class="mc-unit">hr</span>
            <span class="mc-num">${cd.minutes}</span><span class="mc-unit">min</span>
          </div>`;
      } else if (cd.totalMs < 72 * 3600000) {
        stateClass = 'warning';
        countdownHtml = `
          <div class="mc-countdown">
            <span class="mc-num">${cd.days}</span><span class="mc-unit">d</span>
            <span class="mc-num">${cd.hours}</span><span class="mc-unit">hr</span>
          </div>`;
      } else {
        countdownHtml = `
          <div class="mc-countdown">
            <span class="mc-num">${cd.days}</span><span class="mc-unit">days</span>
            <span class="mc-num">${cd.hours}</span><span class="mc-unit">hr</span>
          </div>`;
      }
    }

    return `
      <div class="milestone-card ${stateClass}" onclick="openMilestonesModal()" style="border-left-color:${type.color || 'var(--sbg-navy)'};">
        <div class="mc-header">
          <span class="mc-icon">${type.icon || '🎯'}</span>
          <span class="mc-name">${escapeHtml(type.name)}</span>
        </div>
        ${momentHtml}
        ${countdownHtml}
      </div>
    `;
  }).join('');
}

// =============================================================
// KEY MILESTONES --- modal editor
// =============================================================
function openMilestonesModal() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) { alert('No active project.'); return; }
  renderMilestonesEditor();
  document.getElementById('milestonesModal').classList.add('active');
}

function renderMilestonesEditor() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const list = document.getElementById('milestonesList');
  const milestones = getProjectMilestones(project);

  // Default offsets opt-in panel --- only show if at least one milestone type has a default
  const panel = document.getElementById('milestonesDefaultOffsetsPanel');
  const toggle = document.getElementById('useDefaultOffsetsToggle');
  const dopActions = document.getElementById('dopActions');
  const dopAutoStatus = document.getElementById('dopAutoStatus');
  const hasAnyDefaults = state.milestoneTypes.some(t => typeof t.defaultDaysBeforeBid === 'number');
  if (panel && toggle) {
    panel.style.display = hasAnyDefaults ? 'block' : 'none';
    toggle.checked = !!project.useDefaultOffsets;
    if (dopActions) dopActions.style.display = project.useDefaultOffsets ? 'flex' : 'none';
    if (dopAutoStatus) {
      const autoCount = (project.milestones || []).filter(m => m.defaultOffsetApplied).length;
      const dueLabel = project.dueDate ? `bid due ${formatDate(project.dueDate)}` : 'NO BID DATE';
      dopAutoStatus.textContent = project.useDefaultOffsets
        ? (autoCount > 0 ? `${autoCount} milestone${autoCount === 1 ? '' : 's'} auto-dated from ${dueLabel}` : `Ready to auto-date from ${dueLabel}`)
        : '';
      if (!project.dueDate) {
        dopAutoStatus.style.color = 'var(--sbg-red)';
      } else {
        dopAutoStatus.style.color = 'var(--text-dim)';
      }
    }
  }

  if (milestones.length === 0) {
    list.innerHTML = '<div style="padding:20px;text-align:center;color:var(--text-faint);font-style:italic;">No milestone types defined. Click "Manage Milestone Types" below to add some.</div>';
    return;
  }

  const tzOptions = `
    <option value="">Local</option>
    <option value="America/New_York">ET</option>
    <option value="America/Chicago">CT</option>
    <option value="America/Denver">MT</option>
    <option value="America/Phoenix">MST</option>
    <option value="America/Los_Angeles">PT</option>
    <option value="America/Anchorage">AKT</option>
    <option value="Pacific/Honolulu">HST</option>
  `;

  list.innerHTML = `
    <div style="display:grid;grid-template-columns:30px 1.5fr 1fr 1fr 1.5fr auto;gap:8px;padding:6px 10px;background:var(--sbg-navy);color:#fff;font-family:'Barlow Condensed',sans-serif;font-size:10px;text-transform:uppercase;letter-spacing:0.1em;font-weight:700;margin-bottom:6px;">
      <div></div><div>Milestone</div><div>Date</div><div>Time</div><div>Timezone / Notes</div><div style="text-align:right;">Status</div>
    </div>
  ` + milestones.map(({ type, instance }) => {
    const cd = instance.date ? getMilestoneCountdown(instance) : null;
    let preview = '---';
    let previewCls = '';
    if (!instance.date) { preview = '⚠ MISSING'; previewCls = 'missing'; }
    else if (cd.isPast) { preview = `Past by ${cd.days}d`; previewCls = 'past'; }
    else if (cd.totalMs < 24 * 3600000) preview = `${cd.hours}h ${cd.minutes}m`;
    else preview = `${cd.days}d ${cd.hours}h`;

    // Auto-date indicator: show a small badge if this milestone has a default offset
    // and the project has opted in to use it.
    const isAutoDated = project.useDefaultOffsets && instance.defaultOffsetApplied && typeof type.defaultDaysBeforeBid === 'number';
    const hasDefaultOffset = typeof type.defaultDaysBeforeBid === 'number';
    let nameDisplay = escapeHtml(type.name);
    if (isAutoDated) {
      nameDisplay += ` <span class="m-auto-tag" title="Auto-computed from bid due date - ${type.defaultDaysBeforeBid} days. Editing the date will switch this to manual.">🔗 ${type.defaultDaysBeforeBid}d</span>`;
    } else if (hasDefaultOffset && project.useDefaultOffsets) {
      nameDisplay += ` <span class="m-default-available" title="Default offset available: ${type.defaultDaysBeforeBid} days before bid. Click Re-Apply Defaults to use it.">↺ ${type.defaultDaysBeforeBid}d</span>`;
    } else if (hasDefaultOffset) {
      nameDisplay += ` <span class="m-default-disabled" title="Default offset of ${type.defaultDaysBeforeBid} days set, but this project has default offsets disabled.">${type.defaultDaysBeforeBid}d</span>`;
    }

    return `
      <div class="milestone-edit-row${isAutoDated ? ' has-auto-date' : ''}">
        <div class="mer-icon">${type.icon || '🎯'}</div>
        <div class="mer-name">${nameDisplay}</div>
        <input type="date" value="${instance.date || ''}" onchange="updateMilestoneField('${type.id}', 'date', this.value, true)">
        <input type="time" value="${instance.time || ''}" step="60" onchange="updateMilestoneField('${type.id}', 'time', this.value)">
        <div style="display:flex;gap:4px;">
          <select onchange="updateMilestoneField('${type.id}', 'timezone', this.value)" style="width:90px;">
            ${tzOptions.replace(`value="${instance.timezone || ''}"`, `value="${instance.timezone || ''}" selected`)}
          </select>
          <input type="text" placeholder="Notes" value="${escapeHtml(instance.notes || '')}" onchange="updateMilestoneField('${type.id}', 'notes', this.value)" style="flex:1;">
        </div>
        <div style="display:flex;align-items:center;gap:6px;">
          <button class="btn-icon-cal" onclick="event.stopPropagation(); openMilestoneCalendarDialog('${type.id}')" title="${instance.date ? 'Add this milestone to your calendar (Outlook Web or .ics download)' : 'Set a date first to enable calendar invite'}" ${!instance.date ? 'disabled' : ''}>📅</button>
          <div class="mer-preview ${previewCls}">${preview}</div>
        </div>
      </div>
    `;
  }).join('');
}

function updateMilestoneField(typeId, field, value, isManualDateEdit) {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  if (!Array.isArray(project.milestones)) project.milestones = [];
  let inst = project.milestones.find(m => m.typeId === typeId);
  if (!inst) {
    inst = { typeId, date:'', time:'', timezone:'', notes:'' };
    project.milestones.push(inst);
  }
  inst[field] = value || '';
  // If the user manually edits the Date field, mark this instance as no longer auto-dated.
  // The user has taken ownership of this date --- bid date changes won't recompute it.
  if (isManualDateEdit && field === 'date') {
    inst.defaultOffsetApplied = false;
  }
  saveState();
  renderMilestonesEditor();
  render();
}

// Toggle whether this project uses default offsets from milestone settings.
// On opt-in, prompt to apply defaults now (overwriting existing dates) or just enable for future bid date changes.
function toggleProjectDefaultOffsets(checked) {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  project.useDefaultOffsets = !!checked;

  if (checked) {
    if (!project.dueDate) {
      alert('⚠ This project has no bid due date set. Default offsets need a bid due date to compute from.\n\nSet a bid due date in Edit Project, then return here to apply defaults.');
      saveState();
      renderMilestonesEditor();
      render();
      return;
    }
    // Count what's currently set vs. blank
    const milestones = getProjectMilestones(project);
    const typesWithDefaults = state.milestoneTypes.filter(t => typeof t.defaultDaysBeforeBid === 'number');
    const filled = typesWithDefaults.filter(t => {
      const inst = (project.milestones || []).find(m => m.typeId === t.id);
      return inst && inst.date;
    }).length;

    let message = `Enable default offsets for this project?\n\nThis will auto-compute milestone dates from the bid due date (${formatDate(project.dueDate)}).\n\n`;
    let overwrite = false;
    if (filled > 0) {
      message += `⚠ ${filled} milestone${filled === 1 ? '' : 's'} already ${filled === 1 ? 'has' : 'have'} a date set.\n\nClick OK to OVERWRITE existing dates with computed defaults.\nClick Cancel to keep existing dates and only auto-fill blank ones.`;
      overwrite = confirm(message);
    } else {
      message += 'OK to apply defaults to all empty milestones.';
      if (!confirm(message)) {
        // User cancelled enabling --- toggle back off
        project.useDefaultOffsets = false;
        saveState();
        renderMilestonesEditor();
        render();
        return;
      }
    }

    const applied = applyDefaultOffsetsToProject(project, overwrite);
    saveState();
    setTimeout(() => {
      alert(`✓ Default offsets enabled. ${applied} milestone${applied === 1 ? '' : 's'} auto-dated from bid due date.`);
    }, 100);
  } else {
    // Opt-out: keep existing dates, but no longer auto-refresh on bid date changes
    saveState();
  }
  renderMilestonesEditor();
  render();
}

function manuallyApplyDefaultOffsets() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  if (!project.useDefaultOffsets) {
    alert('Default offsets are not enabled for this project. Toggle the checkbox above first.');
    return;
  }
  if (!project.dueDate) {
    alert('⚠ This project has no bid due date set. Set one in Edit Project first.');
    return;
  }
  const typesWithDefaults = state.milestoneTypes.filter(t => typeof t.defaultDaysBeforeBid === 'number');
  if (typesWithDefaults.length === 0) {
    alert('No default offsets are configured in Milestone Types Manager. Open it (⚙ Manage Milestone Types) and set "Days Before Bid" values.');
    return;
  }

  if (!confirm(`Re-apply default offsets to ${typesWithDefaults.length} milestone${typesWithDefaults.length === 1 ? '' : 's'}?\n\nThis will OVERWRITE all current milestone dates with computed values from the bid due date (${formatDate(project.dueDate)}).\n\nManually edited dates will be replaced.`)) return;

  const applied = applyDefaultOffsetsToProject(project, true);
  saveState();
  renderMilestonesEditor();
  render();
  setTimeout(() => {
    alert(`✓ ${applied} milestone${applied === 1 ? '' : 's'} re-dated from bid due date.`);
  }, 100);
}

// =============================================================
// MILESTONE TYPES MANAGER
// =============================================================
function openMilestoneTypesModal() {
  document.getElementById('mtypeNewIcon').value = '';
  document.getElementById('mtypeNewName').value = '';
  document.getElementById('mtypeNewColor').value = '#2e7d52';
  const daysBeforeEl = document.getElementById('mtypeNewDaysBefore');
  if (daysBeforeEl) daysBeforeEl.value = '';
  renderMilestoneTypesList();
  document.getElementById('milestoneTypesModal').classList.add('active');
}

function addMilestoneType() {
  const name = document.getElementById('mtypeNewName').value.trim();
  if (!name) { alert('Enter a milestone name'); return; }
  if (state.milestoneTypes.some(t => t.name.toLowerCase() === name.toLowerCase())) {
    alert('A milestone type with that name already exists'); return;
  }
  const icon = document.getElementById('mtypeNewIcon').value.trim() || '🎯';
  const color = document.getElementById('mtypeNewColor').value || '#2e7d52';
  const daysBeforeRaw = document.getElementById('mtypeNewDaysBefore').value;
  const defaultDaysBeforeBid = (daysBeforeRaw === '' || daysBeforeRaw === null) ? null : parseInt(daysBeforeRaw, 10);
  const id = 'custom-' + Date.now().toString(36);
  state.milestoneTypes.push({ id, name, icon, color, defaultDaysBeforeBid: isNaN(defaultDaysBeforeBid) ? null : defaultDaysBeforeBid });
  saveState();
  document.getElementById('mtypeNewIcon').value = '';
  document.getElementById('mtypeNewName').value = '';
  document.getElementById('mtypeNewDaysBefore').value = '';
  renderMilestoneTypesList();
  renderMilestonesEditor();
  render();
}

function updateMilestoneTypeField(typeId, field, value) {
  const t = state.milestoneTypes.find(x => x.id === typeId);
  if (!t) return;
  t[field] = value;
  saveState();
  renderMilestonesEditor();
  render();
}

function removeMilestoneType(typeId) {
  const t = state.milestoneTypes.find(x => x.id === typeId);
  if (!t) return;
  // Count how many projects have an instance for this type
  let usage = 0;
  state.projects.forEach(p => {
    if (Array.isArray(p.milestones) && p.milestones.some(m => m.typeId === typeId)) usage++;
  });
  const msg = usage > 0
    ? `Remove "${t.name}" from the milestone types list?\n\nThis will also clear it from ${usage} project(s) that have dates assigned.`
    : `Remove "${t.name}" from the milestone types list?`;
  if (!confirm(msg)) return;
  state.milestoneTypes = state.milestoneTypes.filter(x => x.id !== typeId);
  // Also remove instances from every project
  state.projects.forEach(p => {
    if (Array.isArray(p.milestones)) {
      p.milestones = p.milestones.filter(m => m.typeId !== typeId);
    }
  });
  saveState();
  renderMilestoneTypesList();
  renderMilestonesEditor();
  render();
}

function moveMilestoneType(typeId, direction) {
  const idx = state.milestoneTypes.findIndex(x => x.id === typeId);
  if (idx < 0) return;
  const newIdx = direction === 'up' ? idx - 1 : idx + 1;
  if (newIdx < 0 || newIdx >= state.milestoneTypes.length) return;
  const [item] = state.milestoneTypes.splice(idx, 1);
  state.milestoneTypes.splice(newIdx, 0, item);
  saveState();
  renderMilestoneTypesList();
  render();
}

function resetMilestoneTypes() {
  if (!confirm('Reset to the 4 default milestone types?\n\nYour custom types will be removed. Date/time data on projects will be kept only for the 4 default types.')) return;
  state.milestoneTypes = getDefaultMilestoneTypes();
  saveState();
  renderMilestoneTypesList();
  renderMilestonesEditor();
  render();
}

function renderMilestoneTypesList() {
  const list = document.getElementById('milestoneTypesList');
  if (!list) return;
  if (state.milestoneTypes.length === 0) {
    list.innerHTML = '<div style="padding:30px;text-align:center;color:var(--text-faint);font-style:italic;">No milestone types defined. Add one above or click Reset.</div>';
    return;
  }
  // Header row showing column labels
  const header = `
    <div class="mtype-row mtype-header-row">
      <div></div>
      <div style="font-family:'Barlow Condensed',sans-serif;font-size:9px;text-transform:uppercase;letter-spacing:0.1em;font-weight:700;color:var(--text-dim);">Name</div>
      <div style="font-family:'Barlow Condensed',sans-serif;font-size:9px;text-transform:uppercase;letter-spacing:0.1em;font-weight:700;color:var(--text-dim);text-align:center;">Color</div>
      <div style="font-family:'Barlow Condensed',sans-serif;font-size:9px;text-transform:uppercase;letter-spacing:0.1em;font-weight:700;color:var(--text-dim);text-align:center;" title="Days before bid due date --- used when projects opt-in to default offsets">Days Before Bid</div>
      <div></div>
    </div>
  `;
  list.innerHTML = header + state.milestoneTypes.map((t, i) => {
    const daysBefore = (typeof t.defaultDaysBeforeBid === 'number') ? t.defaultDaysBeforeBid : '';
    return `
    <div class="mtype-row">
      <input type="text" class="mtype-icon-input" value="${escapeHtml(t.icon || '🎯')}" maxlength="2" onchange="updateMilestoneTypeField('${t.id}', 'icon', this.value)">
      <input type="text" value="${escapeHtml(t.name)}" onchange="updateMilestoneTypeField('${t.id}', 'name', this.value)">
      <input type="color" value="${t.color || '#2e7d52'}" onchange="updateMilestoneTypeField('${t.id}', 'color', this.value)">
      <input type="number" class="mtype-days-input" value="${daysBefore}" placeholder="---" min="-30" max="120" onchange="updateMilestoneTypeDaysBefore('${t.id}', this.value)" title="Days before bid due date (leave blank for no default)">
      <div style="display:flex;gap:2px;">
        <button class="btn btn-sm" title="Move up" onclick="moveMilestoneType('${t.id}', 'up')" ${i === 0 ? 'disabled' : ''} style="padding:3px 7px;">↑</button>
        <button class="btn btn-sm" title="Move down" onclick="moveMilestoneType('${t.id}', 'down')" ${i === state.milestoneTypes.length - 1 ? 'disabled' : ''} style="padding:3px 7px;">↓</button>
        <button class="mtt-remove-btn" onclick="removeMilestoneType('${t.id}')" title="Remove">✕</button>
      </div>
    </div>
  `;
  }).join('');
}

// Update defaultDaysBeforeBid for a milestone type. Empty string clears it (sets to null).
function updateMilestoneTypeDaysBefore(typeId, value) {
  const t = state.milestoneTypes.find(x => x.id === typeId);
  if (!t) return;
  if (value === '' || value === null || value === undefined) {
    t.defaultDaysBeforeBid = null;
  } else {
    const n = parseInt(value, 10);
    t.defaultDaysBeforeBid = isNaN(n) ? null : n;
  }
  saveState();
  // Refresh active project's auto-computed dates if the project opts-in
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project && project.useDefaultOffsets) {
    refreshAutoMilestoneDates(project);
    saveState();
  }
  renderMilestoneTypesList();
  if (project) renderMilestonesStrip(project);
}

function renderProjectHeader(p) {
  document.getElementById('pvName').textContent = p.name;
  // Subtitle shows key identity info
  const subParts = [];
  if (p.type) subParts.push(p.type);
  if (p.delivery) subParts.push(p.delivery);
  if (p.client) subParts.push(`Owner: ${p.client}`);
  document.getElementById('pvSubtitle').textContent = subParts.join(' · ');

  // Lead Estimator banner chip --- prominent display at the top of the project header
  const leChip = document.getElementById('pvLeadEstimatorChip');
  const leChipAvatar = document.getElementById('plecAvatar');
  const leChipName = document.getElementById('plecName');
  if (leChip && leChipAvatar && leChipName) {
    const lead = (p.leadEstimator || '').trim();
    const currentUser = getCurrentUser();
    const isMe = currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();

    if (lead) {
      // Configured: show navy chip + avatar. If it's the current user, add YOU badge.
      leChip.style.display = 'inline-flex';
      leChip.classList.remove('missing');
      leChip.classList.toggle('is-me', !!isMe);
      // Click opens the workload modal scoped to this Lead --- same shape as
      // the team strip avatars. Edit Project is still reachable via the
      // Edit Project button in the action row.
      leChip.onclick = () => openTeamMemberWorkload(lead);
      leChip.style.cursor = 'pointer';
      leChip.title = isMe
        ? 'View your workload on this project'
        : `View ${lead}'s workload on this project`;
      leChipName.textContent = lead;

      const photo = getMemberPhoto(lead);
      const initials = lead.split(/\s+/).map(x => x[0]).join('').slice(0, 2).toUpperCase();
      const color = avatarColor(lead);
      if (photo) {
        leChipAvatar.innerHTML = `<img src="${photo}" alt="">`;
        leChipAvatar.style.background = 'transparent';
      } else {
        leChipAvatar.innerHTML = escapeHtml(initials);
        leChipAvatar.style.background = color;
      }
    } else {
      // Missing: show the red dashed-border "Assign Lead" prompt
      leChip.style.display = 'inline-flex';
      leChip.classList.add('missing');
      leChip.classList.remove('is-me');
      leChip.onclick = () => editProject();
      leChip.style.cursor = 'pointer';
      leChip.title = 'No Lead Estimator assigned --- click to edit project and set one';
      leChipAvatar.innerHTML = '?';
      leChipAvatar.style.background = '';
      leChipName.textContent = '--- No Lead Assigned ---';
    }
  }

  const bannerImg = document.getElementById('pvBannerImage');
  if (p.image) {
    bannerImg.innerHTML = `<img src="${p.image}" alt="${escapeHtml(p.name)}">`;
  } else {
    const initials = p.name.split(/\s+/).map(w=>w[0]).join('').slice(0,2).toUpperCase();
    bannerImg.innerHTML = `<div class="placeholder">${escapeHtml(initials)}</div>`;
  }

  // Compact secondary meta row (architect, location, sqft, OneDrive link)
  // Lead Estimator is intentionally NOT included here --- it's already shown as a prominent chip
  // in the top header next to the Signed In chip, so repeating it on the dashboard adds noise.
  const compactMeta = document.getElementById('pvCompactMeta');
  const items = [];
  if (p.architect) items.push(`<div class="cm-item"><span class="cm-label">Architect</span><span class="cm-value">${escapeHtml(p.architect)}</span></div>`);
  if (p.location) items.push(`<div class="cm-item"><span class="cm-label">Location</span><span class="cm-value">${escapeHtml(p.location)}</span></div>`);
  if (p.sqft) items.push(`<div class="cm-item"><span class="cm-label">Sq Ft</span><span class="cm-value">${p.sqft.toLocaleString()}</span></div>`);
  compactMeta.innerHTML = items.join('');
  compactMeta.style.display = items.length > 0 ? 'flex' : 'none';

  // OneDrive button in the action row
  const oneDriveBtn = document.getElementById('pvOneDriveBtn');
  if (p.oneDriveUrl) {
    oneDriveBtn.href = p.oneDriveUrl;
    oneDriveBtn.style.display = 'inline-flex';
  } else {
    oneDriveBtn.style.display = 'none';
  }

  // Date Mode chip --- show only when a revised start is set (so toggling makes sense)
  const modeChip = document.getElementById('pvDateModeChip');
  if (modeChip) {
    const hasRevised = !!p.revisedStartDate;
    const hasExtensionInfo = p.originalStartDate && p.originalDueDate &&
      (p.originalStartDate !== p.startDate || p.originalDueDate !== p.dueDate || hasRevised);
    if (hasRevised || hasExtensionInfo) {
      const activeAnchor = getEffectiveBidStart(p);
      const modeLabel = p.useRevisedDates ? 'Revised Dates' : 'Original Dates';
      modeChip.innerHTML = `${modeLabel} · ${formatDateShort(activeAnchor)}`;
      modeChip.className = 'date-mode-chip ' + (p.useRevisedDates ? 'mode-revised' : 'mode-original');
      modeChip.onclick = () => toggleProjectDateMode(p.id);
      modeChip.title = p.useRevisedDates
        ? `Click to switch to Original (${formatDateShort(p.originalStartDate)})`
        : (hasRevised ? `Click to switch to Revised (${formatDateShort(p.revisedStartDate)})` : 'Edit project to set a Revised Bid Start');
      modeChip.style.display = 'inline-flex';
    } else {
      modeChip.style.display = 'none';
    }
  }

  // Determine if this project has a bid extension active (due date differs from original, OR revised start set, OR toggle on)
  const hasDueShift = p.originalDueDate && p.dueDate && p.originalDueDate !== p.dueDate;
  const hasStartShift = p.originalStartDate && p.startDate && p.originalStartDate !== p.startDate;
  const isRevised = p.useRevisedDates && p.revisedStartDate;
  const shiftDays = hasDueShift ? daysBetween(p.originalDueDate, p.dueDate) : 0;

  // ========== BID START CARD ==========
  // Show the ACTIVE anchor. If using revised dates, show the revised Bid Start with a REV badge
  // and a small line underneath noting the original.
  const startEl = document.getElementById('pvStartDate');
  if (isRevised) {
    startEl.innerHTML = `
      ${formatDate(p.revisedStartDate)}
      <span class="rev-badge" title="Task due dates are calculated from this revised Bid Start">REV</span>
      <div class="orig-ref">was ${formatDate(p.originalStartDate || p.startDate)}</div>
    `;
  } else if (hasStartShift) {
    startEl.innerHTML = `
      ${formatDate(p.startDate)}
      <div class="orig-ref">orig. ${formatDate(p.originalStartDate)}</div>
    `;
  } else {
    startEl.textContent = p.startDate ? formatDate(p.startDate) : 'Not set';
  }

  // ========== BID DUE CARD ==========
  // Always show the CURRENT (possibly revised) due date prominently. If it shifted, add a REV badge
  // and a small note showing the original due date + shift amount.
  const dueEl = document.getElementById('pvDueDate');
  if (hasDueShift) {
    const shiftLabel = shiftDays > 0 ? `+${shiftDays}d extended` : `${shiftDays}d shortened`;
    const shiftColor = shiftDays > 0 ? 'var(--green)' : 'var(--sbg-red)';
    dueEl.innerHTML = `
      ${formatDate(p.dueDate)}
      <span class="rev-badge" title="Bid Due Date has been revised from the original">REV</span>
      <div class="orig-ref">was ${formatDate(p.originalDueDate)} · <span style="color:${shiftColor};font-weight:700;">${shiftLabel}</span></div>
    `;
  } else {
    dueEl.textContent = p.dueDate ? formatDate(p.dueDate) : 'Not set';
  }

  // ========== DAYS LEFT CARD ==========
  // Countdown is always based on the CURRENT (possibly revised) due date --- this matches the
  // actual bid submission deadline.
  const daysLeft = getDaysLeft(p.dueDate);
  const daysEl = document.getElementById('pvDaysLeft');
  const revTag = hasDueShift
    ? `<span class="rev-badge" style="margin-left:6px;" title="Countdown based on revised Bid Due Date">REV</span>`
    : '';
  if (daysLeft === null) {
    daysEl.innerHTML = '---';
    daysEl.style.color = '';
  } else if (daysLeft < 0) {
    daysEl.innerHTML = `${Math.abs(daysLeft)}d overdue${revTag}`;
    daysEl.style.color = 'var(--red)';
  } else {
    daysEl.innerHTML = `${daysLeft} days${revTag}`;
    daysEl.style.color = daysLeft<=3?'var(--red)':daysLeft<=7?'var(--yellow)':'var(--green)';
  }
  document.getElementById('pvValue').textContent = p.value ? formatCurrency(p.value) : '---';

  const total = p.tasks.length;
  const done = p.tasks.filter(t=>t.status==='done').length;
  const pct = total>0 ? Math.round((done/total)*100) : 0;
  const remaining = total - done;
  document.getElementById('pvTaskCount').innerHTML = `${done} <span class="sub">/ ${total}</span>`;
  document.getElementById('pvPercent').innerHTML = `${pct}% <span class="sub">· ${remaining} left</span>`;
  document.getElementById('pvProgress').style.width = `${pct}%`;

  // Notes card
  const notesCard = document.getElementById('pvNotesCard');
  const notesEl = document.getElementById('pvNotes');
  if (p.notes && p.notes.trim()) {
    notesCard.style.display = 'block';
    notesEl.textContent = p.notes;
  } else {
    notesCard.style.display = 'none';
  }
  // Team strip --- additional members on this project (excludes Lead Estimator)
  if (typeof renderProjectTeamStrip === 'function') renderProjectTeamStrip(p);
}

// =============================================================
// PROJECT TEAM STRIP --- collects everyone who is a Lead OR Support on at least
// one task on this project, excludes the Lead Estimator (already shown in the
// global header chip), and renders a row of avatars below the action buttons.
// Click an avatar to open the team-member workload modal scoped to this
// project. Avatars are sorted by total task count descending.
// =============================================================

// Returns an array of { name, leadCount, supportCount, totalCount } for every
// person who appears as a Lead or Support on any task in the project,
// excluding the project's Lead Estimator.
function getProjectTeamMembers(project) {
  if (!project || !Array.isArray(project.tasks)) return [];
  const leadEstimator = (project.leadEstimator || '').trim().toLowerCase();
  const map = {};
  project.tasks.forEach(t => {
    if (!t) return;
    // Lead-tier members (multi-Lead aware via getTaskLeads)
    const leads = (typeof getTaskLeads === 'function')
      ? getTaskLeads(t)
      : (t.assignee && t.assignee.trim() ? [t.assignee.trim()] : []);
    leads.forEach(name => {
      if (!name) return;
      const lc = name.toLowerCase();
      if (lc === leadEstimator) return; // exclude Lead Estimator
      if (!map[lc]) map[lc] = { name: name, leadCount: 0, supportCount: 0, totalCount: 0 };
      map[lc].leadCount++;
      map[lc].totalCount++;
    });
    // Support-tier members (multi-support aware via getAllSupportMembers)
    const supports = (typeof getAllSupportMembers === 'function')
      ? getAllSupportMembers(t)
      : ((t.support && t.support.trim()) ? [t.support.trim()] : []);
    supports.forEach(name => {
      if (!name) return;
      const lc = name.toLowerCase();
      if (lc === leadEstimator) return; // exclude Lead Estimator
      if (!map[lc]) map[lc] = { name: name, leadCount: 0, supportCount: 0, totalCount: 0 };
      map[lc].supportCount++;
      map[lc].totalCount++;
    });
  });
  // Sort by total task involvement (most involved first)
  return Object.values(map).sort((a, b) => b.totalCount - a.totalCount);
}

function renderProjectTeamStrip(project) {
  const strip = document.getElementById('pvTeamStrip');
  if (!strip) return;
  const members = getProjectTeamMembers(project);
  if (!members.length) {
    strip.style.display = 'none';
    strip.innerHTML = '';
    return;
  }
  // Show up to 8 avatars; overflow becomes a "+N" pill listing the rest in tooltip
  const VISIBLE = 8;
  const visible = members.slice(0, VISIBLE);
  const overflow = members.slice(VISIBLE);
  const avatarHtmlOf = (m) => {
    const photo = (typeof getMemberPhoto === 'function') ? getMemberPhoto(m.name) : '';
    const initials = m.name.split(/\s+/).map(x => x[0]).join('').slice(0, 2).toUpperCase();
    const color = (typeof avatarColor === 'function') ? avatarColor(m.name) : '#6b7687';
    const tooltip = `${m.name} --- ${m.leadCount} as Lead${m.leadCount === 1 ? '' : 's'}, ${m.supportCount} as Support`;
    const avatarInner = photo
      ? `<img src="${photo}" alt="">`
      : `<span class="pvts-initials">${escapeHtml(initials)}</span>`;
    // Only show role badge if member is exclusively one role; mixed roles get no badge
    let roleBadge = '';
    if (m.leadCount > 0 && m.supportCount === 0) {
      roleBadge = '<span class="pvts-role-badge pvts-role-lead" title="Lead-only on this project">L</span>';
    } else if (m.supportCount > 0 && m.leadCount === 0) {
      roleBadge = '<span class="pvts-role-badge pvts-role-support" title="Support-only on this project">S</span>';
    }
    return `
      <button class="pvts-avatar" onclick="openTeamMemberWorkload('${escapeAttr(m.name)}')" title="${escapeAttr(tooltip)}" style="background:${color};">
        ${avatarInner}
        <span class="pvts-name">${escapeHtml(m.name)}</span>
        <span class="pvts-count" title="Total tasks involved">${m.totalCount}</span>
        ${roleBadge}
      </button>
    `;
  };
  let overflowChip = '';
  if (overflow.length) {
    const overflowNames = overflow.map(m => `${m.name} (${m.totalCount})`).join(', ');
    overflowChip = `<span class="pvts-overflow" title="${escapeAttr(overflowNames)}">+${overflow.length}</span>`;
  }
  strip.style.display = 'flex';
  strip.innerHTML = `
    <span class="pvts-label">👥 Team</span>
    <div class="pvts-avatars">
      ${visible.map(avatarHtmlOf).join('')}
      ${overflowChip}
    </div>
  `;
}

// =============================================================
// STICKY WORKSPACE CONTROLS --- fixed-position-on-scroll strategy.
// position:sticky doesn't work because the panel sits 6 levels deep inside
// .main > #projectView > .project-header > .project-header-banner > .banner-body
// which prevents browser-native sticky behavior. Instead we use a scroll
// listener on .main: when the panel's natural top position scrolls above
// the .main viewport top, we switch the panel to position:fixed and add a
// same-height placeholder so the layout doesn't jump. When scrolled back,
// we revert to position:relative and hide the placeholder.
// =============================================================
let _pvWcScrollHandler = null;
let _pvWcResizeHandler = null;

function setupPvWorkspaceStickyObserver() {
  // Tear down previous handlers (safe to call repeatedly across renders)
  const scrollRoot = document.querySelector('.main');
  if (_pvWcScrollHandler && scrollRoot) {
    try { scrollRoot.removeEventListener('scroll', _pvWcScrollHandler); } catch (e) {}
  }
  if (_pvWcResizeHandler) {
    try { window.removeEventListener('resize', _pvWcResizeHandler); } catch (e) {}
  }
  _pvWcScrollHandler = null;
  _pvWcResizeHandler = null;

  const panel = document.getElementById('pvWorkspaceControls');
  if (!panel || !scrollRoot) return;

  // Lazily create the placeholder element once per panel; it sits right
  // before the panel and adopts the panel's height when stuck.
  let placeholder = panel.previousElementSibling;
  if (!placeholder || !placeholder.classList || !placeholder.classList.contains('pv-wc-placeholder')) {
    placeholder = document.createElement('div');
    placeholder.className = 'pv-wc-placeholder';
    panel.parentNode.insertBefore(placeholder, panel);
  }

  // The natural top offset of the panel relative to .main scroll container.
  // We capture this fresh each time the user crosses the threshold OR on
  // resize, since project-header content can change (banner image, addenda count).
  function measureNaturalTop() {
    // If panel is currently stuck, temporarily un-stick to measure natural position
    const wasStuck = panel.classList.contains('is-stuck');
    if (wasStuck) {
      panel.classList.remove('is-stuck');
      placeholder.classList.remove('is-active');
      placeholder.style.height = '';
      panel.style.left = '';
      panel.style.width = '';
    }
    // Now measure natural top offset relative to scrollRoot
    const panelRect = panel.getBoundingClientRect();
    const rootRect = scrollRoot.getBoundingClientRect();
    // Natural top in the scroll-content coordinate space
    const naturalTopInScroll = panelRect.top - rootRect.top + scrollRoot.scrollTop;
    // Restore stuck state if it was on
    if (wasStuck) {
      // Re-apply stuck immediately if still scrolled past
      const shouldStillBeStuck = scrollRoot.scrollTop >= naturalTopInScroll;
      if (shouldStillBeStuck) {
        applyStuck(panelRect.height);
      }
    }
    return naturalTopInScroll;
  }

  function applyStuck(panelHeight) {
    placeholder.style.height = panelHeight + 'px';
    placeholder.classList.add('is-active');
    // Position the fixed panel at the top of .main scroll container
    const rootRect = scrollRoot.getBoundingClientRect();
    panel.style.top = rootRect.top + 'px';
    panel.style.left = rootRect.left + 'px';
    panel.style.width = rootRect.width + 'px';
    panel.classList.add('is-stuck');
  }

  function clearStuck() {
    panel.classList.remove('is-stuck');
    placeholder.classList.remove('is-active');
    placeholder.style.height = '';
    panel.style.top = '';
    panel.style.left = '';
    panel.style.width = '';
  }

  // Cache natural top; recompute only on resize OR when not currently stuck
  let cachedNaturalTop = null;
  function getNaturalTop() {
    if (cachedNaturalTop === null || !panel.classList.contains('is-stuck')) {
      cachedNaturalTop = measureNaturalTop();
    }
    return cachedNaturalTop;
  }

  _pvWcScrollHandler = function () {
    if (!panel.parentNode) return; // panel was removed (different view active)
    const isCurrentlyStuck = panel.classList.contains('is-stuck');
    const naturalTop = getNaturalTop();
    const scrollTop = scrollRoot.scrollTop;
    if (scrollTop >= naturalTop && !isCurrentlyStuck) {
      // Capture height BEFORE going fixed (since fixed elements have no
      // contribution to flow-based height of placeholder)
      const h = panel.getBoundingClientRect().height;
      applyStuck(h);
    } else if (scrollTop < naturalTop && isCurrentlyStuck) {
      clearStuck();
      cachedNaturalTop = null; // force re-measure on next scroll-down
    }
  };

  _pvWcResizeHandler = function () {
    cachedNaturalTop = null;
    // Re-evaluate stuck state at new dimensions
    if (panel.classList.contains('is-stuck')) {
      // Reposition the fixed panel to match new viewport
      const rootRect = scrollRoot.getBoundingClientRect();
      panel.style.top = rootRect.top + 'px';
      panel.style.left = rootRect.left + 'px';
      panel.style.width = rootRect.width + 'px';
    }
    // Trigger scroll handler to reconcile state
    if (_pvWcScrollHandler) _pvWcScrollHandler();
  };

  scrollRoot.addEventListener('scroll', _pvWcScrollHandler, { passive: true });
  window.addEventListener('resize', _pvWcResizeHandler);

  // Run once to set initial state in case user is already scrolled past
  // (e.g., switching projects while scrolled deep)
  _pvWcScrollHandler();
}

// =============================================================
// TEAM MEMBER WORKLOAD MODAL --- opens when an avatar in the team strip is
// clicked. Shows all tasks on the current project where the member is a
// Lead or Support, grouped by stage, with summary stats.
// =============================================================

function openTeamMemberWorkload(memberName) {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project || !memberName) return;
  // Build the modal lazily on first open since most users won't use it
  ensureTeamWorkloadModal();
  // Cache the active member on the modal element so setWorkloadSortMode
  // can re-render after the user picks a different sort. Avoids needing
  // to thread state through additional globals.
  const modalEl = document.getElementById('teamWorkloadModal');
  if (modalEl) modalEl.setAttribute('data-member-name', memberName);
  // Render with this person + project
  renderTeamMemberWorkload(project, memberName);
  modalEl.classList.add('active');
}

function ensureTeamWorkloadModal() {
  if (document.getElementById('teamWorkloadModal')) return;
  const div = document.createElement('div');
  div.className = 'modal-backdrop';
  div.id = 'teamWorkloadModal';
  div.innerHTML = `
    <div class="modal" style="max-width:920px;">
      <button class="modal-close" onclick="closeModal('teamWorkloadModal')" title="Close">×</button>
      <h3 id="teamWorkloadTitle" style="margin-bottom:6px;">Team Member Workload</h3>
      <p id="teamWorkloadSubtitle" style="color:var(--text-dim);font-size:13px;margin-bottom:14px;">---</p>
      <div id="teamWorkloadStats" class="tw-stats"></div>
      <div id="teamWorkloadBody" class="tw-body"></div>
      <div class="modal-actions" style="margin-top:18px;">
        <button class="btn btn-dark" onclick="closeModal('teamWorkloadModal')">Done</button>
      </div>
    </div>
  `;
  document.body.appendChild(div);
}

function renderTeamMemberWorkload(project, memberName) {
  const titleEl = document.getElementById('teamWorkloadTitle');
  const subtitleEl = document.getElementById('teamWorkloadSubtitle');
  const statsEl = document.getElementById('teamWorkloadStats');
  const bodyEl = document.getElementById('teamWorkloadBody');
  if (!titleEl || !subtitleEl || !statsEl || !bodyEl) return;

  // Find tasks where this person is Lead or Support
  const lc = (memberName || '').toLowerCase();
  const tasks = (project.tasks || []).filter(t => {
    if (!t) return false;
    const isLead = (typeof isTaskLead === 'function') ? isTaskLead(t, memberName)
      : ((t.assignee || '').toLowerCase() === lc);
    if (isLead) return true;
    const isSupport = (typeof isTaskSupport === 'function') && isTaskSupport(t, memberName);
    return !!isSupport;
  });

  // Header
  titleEl.innerHTML = `👤 ${escapeHtml(memberName)} <span style="color:var(--text-dim);font-size:13px;font-weight:400;">--- Workload on ${escapeHtml(project.name)}</span>`;
  if (!tasks.length) {
    subtitleEl.textContent = 'No tasks found for this team member on this project.';
    statsEl.innerHTML = '';
    bodyEl.innerHTML = '<div class="tw-empty">Nothing assigned.</div>';
    return;
  }

  // Stats
  const open = tasks.filter(t => t.status !== 'done');
  const done = tasks.filter(t => t.status === 'done');
  const overdue = tasks.filter(t => (typeof isTaskOverdue === 'function') && isTaskOverdue(t));
  const blocked = tasks.filter(t => t.status === 'blocked');
  let leadCount = 0, supportCount = 0;
  tasks.forEach(t => {
    const isL = (typeof isTaskLead === 'function') ? isTaskLead(t, memberName) : ((t.assignee || '').toLowerCase() === lc);
    if (isL) leadCount++;
    const isS = (typeof isTaskSupport === 'function') && isTaskSupport(t, memberName);
    if (isS) supportCount++;
  });

  // Hours rollup if feature enabled --- multi-Lead aware
  let hoursOpen = 0, hoursDone = 0;
  if (state.hoursEnabled) {
    tasks.forEach(t => {
      if (typeof t.estimatedHours !== 'number' || t.estimatedHours <= 0) return;
      const isL = (typeof isTaskLead === 'function') ? isTaskLead(t, memberName) : false;
      let share = 0;
      if (isL) {
        const leads = (typeof getTaskLeads === 'function') ? getTaskLeads(t) : [];
        share = leads.length > 0 ? t.estimatedHours / leads.length : t.estimatedHours;
      }
      // Support contribution doesn't add to hours (matches existing rollup logic)
      if (t.status === 'done') hoursDone += share;
      else hoursOpen += share;
    });
  }

  subtitleEl.textContent = `${tasks.length} total task${tasks.length === 1 ? '' : 's'} · ${leadCount} as Lead · ${supportCount} as Support`;

  const statHtml = (label, val, cls) => `
    <div class="tw-stat${cls ? ' ' + cls : ''}">
      <div class="tw-stat-num">${val}</div>
      <div class="tw-stat-label">${label}</div>
    </div>
  `;
  statsEl.innerHTML = `
    ${statHtml('Total tasks', tasks.length, '')}
    ${statHtml('Open', open.length, 'tw-open')}
    ${statHtml('Done', done.length, 'tw-done')}
    ${statHtml('Overdue', overdue.length, 'tw-overdue')}
    ${statHtml('Blocked', blocked.length, 'tw-blocked')}
    ${state.hoursEnabled ? statHtml('Hrs remaining', (typeof formatHours === 'function' ? formatHours(hoursOpen) : hoursOpen.toFixed(1) + 'h'), 'tw-hours') : ''}
  `;

  // Group tasks by stage
  // Build a single task row --- used by all sort modes
  const buildRow = (t) => {
    const isL = (typeof isTaskLead === 'function') ? isTaskLead(t, memberName) : false;
    const roleLabel = isL ? '<span class="tw-role-badge tw-role-lead">LEAD</span>' : '<span class="tw-role-badge tw-role-support">SUPPORT</span>';
    const statusLabels = {
      'not-started': 'Not Started', 'in-progress': 'In Progress', 'blocked': 'Blocked',
      'pending': 'Pending', 'done': 'Done'
    };
    const status = statusLabels[t.status] || t.status || '---';
    const dueText = t.dueDate ? formatDate(t.dueDate) : '---';
    const isOverdueCls = ((typeof isTaskOverdue === 'function') && isTaskOverdue(t)) ? ' tw-row-overdue' : '';
    const hoursText = (state.hoursEnabled && typeof t.estimatedHours === 'number' && t.estimatedHours > 0)
      ? `<span class="tw-hours-cell">⏱ ${escapeHtml(typeof formatHours === 'function' ? formatHours(t.estimatedHours) : t.estimatedHours + 'h')}</span>`
      : '';
    return `
      <div class="tw-row${isOverdueCls}" onclick="openTaskFromWorkloadModal('${escapeAttr(t.id)}')">
        ${roleLabel}
        <span class="tw-row-title">${escapeHtml(t.title || '(untitled)')}</span>
        <span class="tw-row-status tw-status-${escapeAttr(t.status || 'not-started')}">${escapeHtml(status)}</span>
        <span class="tw-row-due">${escapeHtml(dueText)}</span>
        ${hoursText}
      </div>
    `;
  };

  // Build a section header --- used by grouped sort modes (stage / status / priority)
  const buildSectionHeader = (label, count) => `
    <div class="tw-stage-header">${escapeHtml(label)} <span class="tw-stage-count">${count}</span></div>
  `;

  // ===== SORT MODE =====
  // The toolbar buttons set state.workloadModalSortMode. Each mode shapes
  // the body differently: stage/status/priority use grouped sections;
  // due uses a single flat list sorted earliest-first.
  const sortMode = state.workloadModalSortMode || 'stage';

  // Toolbar at top of body --- sort buttons. Active button gets cyan background.
  const sortToolbar = `
    <div class="tw-sort-toolbar">
      <span class="tw-sort-label">Sort:</span>
      <button class="tw-sort-btn${sortMode === 'stage' ? ' active' : ''}" onclick="setWorkloadSortMode('stage')" title="Group tasks by stage in bid lifecycle order">📋 Stage</button>
      <button class="tw-sort-btn${sortMode === 'due' ? ' active' : ''}" onclick="setWorkloadSortMode('due')" title="Flat list sorted by due date, earliest first">📅 Due Date</button>
      <button class="tw-sort-btn${sortMode === 'status' ? ' active' : ''}" onclick="setWorkloadSortMode('status')" title="Group tasks by status (Not Started, In Progress, Blocked, Pending, Done)">⏷ Status</button>
      <button class="tw-sort-btn${sortMode === 'priority' ? ' active' : ''}" onclick="setWorkloadSortMode('priority')" title="Critical tasks first, then everything else">🔥 Critical First</button>
    </div>
  `;

  let groupedHtml = '';

  if (sortMode === 'due') {
    // FLAT LIST sorted by due date earliest-first; tasks without dates sink
    // to bottom. Overdue rows still get the existing overdue styling.
    const sortedTasks = tasks.slice().sort((a, b) => {
      const aDate = a.dueDate ? new Date(a.dueDate + 'T00:00:00').getTime() : Infinity;
      const bDate = b.dueDate ? new Date(b.dueDate + 'T00:00:00').getTime() : Infinity;
      return aDate - bDate;
    });
    const datedTasks = sortedTasks.filter(t => t.dueDate);
    const undatedTasks = sortedTasks.filter(t => !t.dueDate);
    let dueHtml = '';
    if (datedTasks.length) {
      dueHtml += `<div class="tw-stage-section"><div class="tw-stage-rows">${datedTasks.map(buildRow).join('')}</div></div>`;
    }
    if (undatedTasks.length) {
      dueHtml += `<div class="tw-stage-section">${buildSectionHeader('No due date', undatedTasks.length)}<div class="tw-stage-rows">${undatedTasks.map(buildRow).join('')}</div></div>`;
    }
    groupedHtml = dueHtml;
  } else if (sortMode === 'status') {
    // Grouped by status in canonical order: not-started → in-progress →
    // blocked → pending → done
    const statusOrder = ['not-started', 'in-progress', 'blocked', 'pending', 'done'];
    const statusLabelsLong = {
      'not-started': '⬜ Not Started', 'in-progress': '⏳ In Progress', 'blocked': '🚫 Blocked',
      'pending': '⏸ Pending', 'done': '✅ Done'
    };
    const byStatus = {};
    tasks.forEach(t => {
      const s = t.status || 'not-started';
      if (!byStatus[s]) byStatus[s] = [];
      byStatus[s].push(t);
    });
    groupedHtml = statusOrder
      .filter(s => byStatus[s] && byStatus[s].length)
      .map(s => `
        <div class="tw-stage-section tw-status-section tw-status-section-${s}">
          ${buildSectionHeader(statusLabelsLong[s] || s, byStatus[s].length)}
          <div class="tw-stage-rows">${byStatus[s].map(buildRow).join('')}</div>
        </div>
      `).join('');
  } else if (sortMode === 'priority') {
    // Critical-first sort --- replaced the old high/medium/low priority sort
    // since the priority field was removed in v33. Two sections: 🔥 Critical
    // (tasks with critical:true) and Normal (everything else).
    const byPriority = { 'critical': [], 'normal': [] };
    tasks.forEach(t => {
      if (t.critical) byPriority.critical.push(t);
      else byPriority.normal.push(t);
    });
    const priorityOrder = ['critical', 'normal'];
    const priorityLabels = {
      'critical': '🔥 Critical',
      'normal': '--- Normal'
    };
    groupedHtml = priorityOrder
      .filter(p => byPriority[p] && byPriority[p].length)
      .map(p => `
        <div class="tw-stage-section tw-priority-section tw-priority-section-${p}">
          ${buildSectionHeader(priorityLabels[p] || p, byPriority[p].length)}
          <div class="tw-stage-rows">${byPriority[p].map(buildRow).join('')}</div>
        </div>
      `).join('');
  } else {
    // DEFAULT --- group by stage in STAGES order
    const byStage = {};
    tasks.forEach(t => {
      const sId = t.stage || 'unknown';
      if (!byStage[sId]) byStage[sId] = [];
      byStage[sId].push(t);
    });
    const stageOrder = (typeof STAGES !== 'undefined' && Array.isArray(STAGES))
      ? STAGES.map(s => s.id) : Object.keys(byStage);
    const stageKeys = stageOrder.filter(k => byStage[k]).concat(Object.keys(byStage).filter(k => !stageOrder.includes(k)));
    groupedHtml = stageKeys.map(stageId => {
      const stageDef = (typeof STAGES !== 'undefined') ? STAGES.find(s => s.id === stageId) : null;
      const stageName = stageDef ? `${stageDef.icon || ''} ${stageDef.name}`.trim() : stageId;
      const stageTasks = byStage[stageId];
      return `
        <div class="tw-stage-section">
          ${buildSectionHeader(stageName, stageTasks.length)}
          <div class="tw-stage-rows">${stageTasks.map(buildRow).join('')}</div>
        </div>
      `;
    }).join('');
  }

  bodyEl.innerHTML = sortToolbar + groupedHtml;
}

// Set the workload modal sort mode and re-render. Persists to state so the
// modal opens in the same mode next time.
function setWorkloadSortMode(mode) {
  if (!['stage', 'due', 'status', 'priority'].includes(mode)) return;
  state.workloadModalSortMode = mode;
  saveState();
  // Re-render the modal with the same person/project --- pull the active
  // member name from the modal title element since it's already there
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  // Cached on the modal via a data attribute set by openTeamMemberWorkload
  const modal = document.getElementById('teamWorkloadModal');
  if (!modal) return;
  const memberName = modal.getAttribute('data-member-name');
  if (!memberName) return;
  renderTeamMemberWorkload(project, memberName);
}

// Open a task from inside the workload modal --- closes the modal first, then
// opens the task modal so the user can drill in.
function openTaskFromWorkloadModal(taskId) {
  const wlModal = document.getElementById('teamWorkloadModal');
  if (wlModal) wlModal.classList.remove('active');
  if (typeof openTaskModal === 'function') openTaskModal(null, taskId);
}


// =============================================================
// TAB NAV (Stage or Assignee)
// =============================================================
function renderTabNav(project) {
  const nav = document.getElementById('tabNav');
  const totalAll = project.tasks.length;
  const doneAll = project.tasks.filter(t=>t.status==='done').length;

  // Determine the "all" label and the active key based on grouping mode
  let allLabel = 'Stages';
  let activeKey = state.activeStageId;
  if (state.grouping === 'assignee') { allLabel = 'People'; activeKey = state.activeAssignee; }
  else if (state.grouping === 'source') { allLabel = 'Sources'; activeKey = state.activeSource; }
  else if (state.grouping === 'status') { allLabel = 'Statuses'; activeKey = state.activeStatus; }
  else if (state.grouping === 'alert') { allLabel = 'Tasks'; activeKey = state.activeAlertTier; }
  else if (state.grouping === 'my-alert') { allLabel = 'My Tasks'; activeKey = state.activeMyAlertTier; }

  // For alert / my-alert grouping the buckets array already includes an
  // "All" entry as its first element, so we skip the auto-prepended All
  // pill to avoid a duplicate.
  let tabs = [];
  if (state.grouping !== 'alert' && state.grouping !== 'my-alert') {
    tabs.push(`
      <button class="pill-tab ${activeKey==='all'?'active':''}" onclick="selectTab('all')">
        <span class="icon">🗂️</span>All ${allLabel}
        <span class="count"><span class="done-num">${doneAll}</span>/${totalAll}</span>
      </button>
    `);
  }

  if (state.grouping === 'stage') {
    STAGES.forEach(s => {
      const tasks = project.tasks.filter(t=>t.stage===s.id);
      const done = tasks.filter(t=>t.status==='done').length;
      tabs.push(`
        <button class="pill-tab ${state.activeStageId===s.id?'active':''}" onclick="selectTab('${s.id}')">
          <span class="icon">${(typeof renderStageIconHtml === 'function') ? renderStageIconHtml(s) : escapeHtml(s.icon || '🎯')}</span>${s.name}
          <span class="count"><span class="done-num">${done}</span>/${tasks.length}</span>
        </button>
      `);
    });
  } else if (state.grouping === 'assignee') {
    // Group by assignee - with progress bars + %
    const assignees = getAssigneeBuckets(project);
    assignees.forEach(a => {
      const initials = a.name === 'unassigned' ? '?' : a.name.split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
      const color = a.name === 'unassigned' ? '#9ba4b0' : avatarColor(a.name);
      const photo = a.name === 'unassigned' ? null : getMemberPhoto(a.name);
      const pct = a.total > 0 ? Math.round((a.done / a.total) * 100) : 0;
      const displayName = a.name === 'unassigned' ? 'Unassigned' : a.name;
      const avatarMarkup = photo
        ? `<span class="mini-avatar has-photo" style="overflow:hidden;padding:0;"><img src="${photo}" alt="" style="width:100%;height:100%;object-fit:cover;"></span>`
        : `<span class="mini-avatar" style="background:${color};">${escapeHtml(initials)}</span>`;

      // Compute all alert counts for this assignee's tasks
      let overdueN = 0, imminentN = 0, soonN = 0, unackN = 0, pendingN = 0, completionN = 0;
      if (a.name !== 'unassigned') {
        project.tasks.forEach(t => {
          if (t.assignee !== a.name) return; // only count tasks assigned as Lead
          if (t.status !== 'done' && t.dueDate && isTaskOverdue(t)) overdueN++;
          else if (t.status !== 'done' && t.dueDate && isTaskDueImminent(t)) imminentN++;
          else if (t.status !== 'done' && t.dueDate && isTaskDueSoon(t)) soonN++;
          if (t.status !== 'done' && !t.acknowledged) unackN++;
          if (t.status === 'pending') pendingN++;
          if (t.status === 'done' && !t.completionAcknowledged) completionN++;
        });
      }
      const totalAlerts = overdueN + imminentN + soonN + unackN + pendingN + completionN;

      // Build the inline dot strip --- one colored dot per alert type that applies
      const dots = [];
      if (overdueN > 0) dots.push(`<span class="assignee-alert-dot ad-overdue" title="${overdueN} overdue">${overdueN}</span>`);
      if (imminentN > 0) dots.push(`<span class="assignee-alert-dot ad-imminent" title="${imminentN} due today/tomorrow">${imminentN}</span>`);
      if (soonN > 0) dots.push(`<span class="assignee-alert-dot ad-soon" title="${soonN} due in 2 days">${soonN}</span>`);
      if (unackN > 0) dots.push(`<span class="assignee-alert-dot ad-unack" title="${unackN} awaiting acknowledgment">${unackN}</span>`);
      if (pendingN > 0) dots.push(`<span class="assignee-alert-dot ad-pending" title="${pendingN} pending">${pendingN}</span>`);
      if (completionN > 0) dots.push(`<span class="assignee-alert-dot ad-completion" title="${completionN} awaiting Lead sign-off">${completionN}</span>`);
      const dotsHtml = dots.length ? `<div class="assignee-alert-dots">${dots.join('')}</div>` : '';

      // Kept for backward compat --- the pulsing NEW badge by the name stays
      const newBadge = unackN > 0
        ? `<span class="assignee-new-badge" title="${unackN} new task${unackN===1?'':'s'} awaiting acknowledgment">${unackN} NEW</span>`
        : '';

      // Determine tab severity class for progress-bar coloring
      let tabSeverity = '';
      if (overdueN > 0) tabSeverity = 'has-critical-alerts';
      else if (imminentN > 0 || unackN > 0) tabSeverity = 'has-alerts';
      else if (soonN > 0 || pendingN > 0 || completionN > 0) tabSeverity = 'has-warning-alerts';

      // Alert-border indicator positioned over the progress bar
      const alertCountPill = totalAlerts > 0
        ? `<span class="pill-alert-count" title="${totalAlerts} active alert${totalAlerts===1?'':'s'}">⚠ ${totalAlerts}</span>`
        : '';

      tabs.push(`
        <button class="pill-tab assignee-tab ${tabSeverity} ${state.activeAssignee===a.name?'active':''}" onclick="selectTab('${escapeHtml(a.name)}')">
          <div class="pill-top">
            ${avatarMarkup}
            <span style="flex:1;text-align:left;">${escapeHtml(displayName)}${newBadge}</span>
            <span class="count"><span class="done-num">${a.done}</span>/${a.total} · ${pct}%</span>
          </div>
          ${dotsHtml}
          <div class="pill-progress">
            <div class="pill-progress-fill" style="width:${pct}%"></div>
            ${alertCountPill}
          </div>
        </button>
      `);
    });
  } else if (state.grouping === 'source') {
    // Group by Source --- a tab per source, each showing the source icon/photo + task count
    const buckets = getSourceBuckets(project);
    buckets.forEach(b => {
      const meta = getSourceMeta(b.name);
      const displayName = b.name === 'unsourced' ? '--- No Source ---' : b.name;
      const pct = b.total > 0 ? Math.round((b.done / b.total) * 100) : 0;
      const iconMarkup = (b.name !== 'unsourced' && meta.photo)
        ? `<span class="mini-avatar has-photo" style="overflow:hidden;padding:0;"><img src="${meta.photo}" alt="" style="width:100%;height:100%;object-fit:cover;"></span>`
        : `<span class="icon">${escapeHtml(meta.icon)}</span>`;
      tabs.push(`
        <button class="pill-tab source-tab ${state.activeSource===b.name?'active':''}" onclick="selectTab('${escapeHtml(b.name).replace(/'/g, "\\'")}')">
          <div class="pill-top">
            ${iconMarkup}
            <span style="flex:1;text-align:left;">${escapeHtml(displayName)}</span>
            <span class="count"><span class="done-num">${b.done}</span>/${b.total} · ${pct}%</span>
          </div>
          <div class="pill-progress">
            <div class="pill-progress-fill" style="width:${pct}%"></div>
          </div>
        </button>
      `);
    });
  } else if (state.grouping === 'status') {
    // Group by Status --- one tab per status with its dot color, count, and
    // percent of project. Order matches the workflow: Not Started → In
    // Progress → Blocked → Pending → Done.
    const buckets = getStatusBuckets(project);
    buckets.forEach(b => {
      const pct = b.total > 0 ? Math.round((b.done / b.total) * 100) : 0;
      // For non-done statuses the "done" concept doesn't apply --- show count instead
      // For 'done' status the count *is* the done count --- show as is
      const countDisplay = b.id === 'done'
        ? `${b.total} done`
        : `${b.total} task${b.total === 1 ? '' : 's'}`;
      const isActive = state.activeStatus === b.id;
      tabs.push(`
        <button class="pill-tab status-tab status-tab-${b.id} ${isActive ? 'active' : ''}" onclick="selectTab('${b.id}')">
          <div class="pill-top">
            <span class="status-tab-dot dot-${b.id}"></span>
            <span style="flex:1;text-align:left;">${escapeHtml(b.label)}</span>
            <span class="count">${countDisplay}</span>
          </div>
        </button>
      `);
    });
  } else if (state.grouping === 'alert') {
    // Group by Alert --- one tab per alert tier in urgency order. Each tab
    // shows live count of tasks matching that tier (all-tiers overlap, so
    // a task can appear in multiple). Tab styling mirrors the project
    // Alerts strip so visual language stays consistent.
    const buckets = getAlertBuckets(project);
    buckets.forEach(b => {
      // Hide empty tabs for non-special tiers to keep the row tidy. ALWAYS
      // show 'healthy' and 'done' so the team can navigate to "settled work"
      // or "no-fire-drill work" even when those buckets happen to be empty.
      if (b.count === 0 && b.id !== 'healthy' && b.id !== 'done') return;
      const isActive = state.activeAlertTier === b.id;
      const countDisplay = `${b.count} task${b.count === 1 ? '' : 's'}`;
      tabs.push(`
        <button class="pill-tab alert-tier-tab alert-tier-${b.id} ${isActive ? 'active' : ''}" onclick="selectTab('${b.id}')" title="${escapeAttr(b.title)}">
          <div class="pill-top">
            <span class="atr-icon">${b.icon}</span>
            <span style="flex:1;text-align:left;">${escapeHtml(b.label)}</span>
            <span class="count">${countDisplay}</span>
          </div>
        </button>
      `);
    });
  } else if (state.grouping === 'my-alert') {
    // Group by My Alerts --- same tier slicing as Group by Alert but scoped
    // to current user. Uses the .alert-tier-mine modifier class so styling
    // can pick up a subtle gold accent that distinguishes it visually
    // from the project-wide Alert grouping.
    const buckets = getMyAlertBuckets(project);
    buckets.forEach(b => {
      if (b.count === 0 && b.id !== 'healthy' && b.id !== 'done') return;
      const isActive = state.activeMyAlertTier === b.id;
      const countDisplay = `${b.count} task${b.count === 1 ? '' : 's'}`;
      tabs.push(`
        <button class="pill-tab alert-tier-tab alert-tier-mine alert-tier-${b.id} ${isActive ? 'active' : ''}" onclick="selectTab('${b.id}')" title="${escapeAttr(b.title)}">
          <div class="pill-top">
            <span class="atr-icon">${b.icon}</span>
            <span style="flex:1;text-align:left;">${escapeHtml(b.label)}</span>
            <span class="count">${countDisplay}</span>
          </div>
        </button>
      `);
    });
  }
  nav.innerHTML = tabs.join('');
}

// Group tasks by status. Returns an array of { id, label, total, done }
// in workflow order (not-started → in-progress → blocked → pending → done).
// Always includes all five statuses even when empty so users see the full
// pipeline at a glance, matching how Stages render even when empty.
function getStatusBuckets(project) {
  const order = [
    { id: 'not-started', label: '○ Not Started' },
    { id: 'in-progress', label: '⚙ In Progress' },
    { id: 'blocked',     label: '⛔ Blocked / RFI' },
    { id: 'pending',     label: '⏳ Pending' },
    { id: 'done',        label: '✓ Done' }
  ];
  return order.map(spec => {
    const tasks = project.tasks.filter(t => t.status === spec.id);
    const done = tasks.filter(t => t.status === 'done').length;
    return { id: spec.id, label: spec.label, total: tasks.length, done };
  });
}

// Returns alert-tier buckets in urgency order for Group by Alert mode.
// All-tiers overlap: a task that's both Overdue AND Unacknowledged
// contributes to BOTH counts. Order intentionally puts the most urgent
// tiers first (Overdue → Late Start → At Risk → Blocked → Imminent →
// Soon → In Progress → Rejected → Unack → Unassigned → Pending → Healthy
// → Done) so the user reads urgency left-to-right.
function getAlertBuckets(project) {
  const order = [
    { id: 'all',         icon: '🗂',  label: 'All',          title: 'Every task in the project (no tier filter applied)' },
    { id: 'overdue',     icon: '🚨', label: 'Overdue',      title: 'Tasks past their due date and not yet done' },
    { id: 'late-start',  icon: '⏰', label: 'Late Start',   title: 'Tasks past their Start By date and still not started' },
    { id: 'at-risk',     icon: '⚠',  label: 'At Risk',      title: 'Tasks overdue OR due within 2 days but still not started or with required items open' },
    { id: 'blocked',     icon: '⛔', label: 'Blocked',      title: 'Tasks with status Blocked / RFI' },
    { id: 'imminent',    icon: '⏱',  label: 'Imminent',     title: 'Tasks due in the next 24 hours' },
    { id: 'soon',        icon: '📅', label: 'Due Soon',     title: 'Tasks due in the next 2 days' },
    { id: 'in-progress', icon: '⚙',  label: 'In Progress',  title: 'Tasks currently being worked on' },
    { id: 'rejected',    icon: '✗',  label: 'Rejected',     title: 'Tasks with a rejection notice from the Lead Estimator' },
    { id: 'unack',       icon: '🔔', label: 'Unack',        title: 'Tasks assigned but not yet acknowledged by the assignee' },
    { id: 'unassigned',  icon: '👤', label: 'Unassigned',   title: 'Tasks with no Lead assignee' },
    { id: 'pending',     icon: '⏳', label: 'Pending',      title: 'Tasks with status Pending (waiting on something)' },
    { id: 'healthy',     icon: '✅', label: 'Healthy',      title: 'Tasks with no active alerts and not yet done --- on track' },
    { id: 'done',        icon: '✓',  label: 'Done',         title: 'Completed tasks' }
  ];
  return order.map(spec => {
    const tasks = filterTasksByAlertTier(project, spec.id);
    return { id: spec.id, icon: spec.icon, label: spec.label, title: spec.title, count: tasks.length };
  });
}

// Same as getAlertBuckets but counts are scoped to the current user
// (Lead OR support member). Powers the Group by My Alerts pill tabs.
function getMyAlertBuckets(project) {
  const order = [
    { id: 'all',         icon: '🗂',  label: 'All My Tasks', title: 'Every task assigned to or supporting you' },
    { id: 'overdue',     icon: '🚨', label: 'Overdue',      title: 'Your tasks past their due date and not yet done' },
    { id: 'late-start',  icon: '⏰', label: 'Late Start',   title: 'Your tasks past their Start By date and still not started' },
    { id: 'at-risk',     icon: '⚠',  label: 'At Risk',      title: 'Your tasks overdue OR due within 2 days but still not started or with required items open' },
    { id: 'blocked',     icon: '⛔', label: 'Blocked',      title: 'Your tasks with status Blocked / RFI' },
    { id: 'imminent',    icon: '⏱',  label: 'Imminent',     title: 'Your tasks due in the next 24 hours' },
    { id: 'soon',        icon: '📅', label: 'Due Soon',     title: 'Your tasks due in the next 2 days' },
    { id: 'in-progress', icon: '⚙',  label: 'In Progress',  title: 'Your tasks currently being worked on' },
    { id: 'rejected',    icon: '✗',  label: 'Rejected',     title: 'Your tasks with a rejection notice from the Lead Estimator' },
    { id: 'unack',       icon: '🔔', label: 'Unack',        title: 'Your assigned tasks not yet acknowledged' },
    { id: 'pending',     icon: '⏳', label: 'Pending',      title: 'Your tasks with status Pending' },
    { id: 'healthy',     icon: '✅', label: 'Healthy',      title: 'Your tasks with no active alerts and not yet done --- comfortably on track' },
    { id: 'done',        icon: '✓',  label: 'Done',         title: 'Your completed tasks' }
    // Note: 'unassigned' tier is not included in My scope (it's tasks WITHOUT an assignee, by definition not yours)
  ];
  return order.map(spec => {
    const tasks = filterTasksByAlertTierScoped(project, spec.id, 'my');
    return { id: spec.id, icon: spec.icon, label: spec.label, title: spec.title, count: tasks.length };
  });
}

function getAssigneeBuckets(project) {
  const map = new Map();
  project.tasks.forEach(t => {
    // Primary (Lead) assignment
    const leadKey = (t.assignee && t.assignee.trim()) ? t.assignee.trim() : 'unassigned';
    if (!map.has(leadKey)) map.set(leadKey, { name: leadKey, tasks: [], total: 0, done: 0, leadCount: 0, supportCount: 0 });
    const lead = map.get(leadKey);
    lead.tasks.push({ ...t, _role: 'lead' });
    lead.total++;
    lead.leadCount++;
    if (t.status === 'done') lead.done++;

    // Support assignment --- iterate every support member (primary + additional),
    // each contributes a "support" role row to that person's tasks.
    getAllSupportMembers(t).forEach(supportName => {
      const supportKey = supportName.trim();
      if (!supportKey || supportKey === leadKey) return;
      if (!map.has(supportKey)) map.set(supportKey, { name: supportKey, tasks: [], total: 0, done: 0, leadCount: 0, supportCount: 0 });
      const sup = map.get(supportKey);
      sup.tasks.push({ ...t, _role: 'support' });
      sup.total++;
      sup.supportCount++;
      if (t.status === 'done') sup.done++;
    });
  });
  // Sort: real names alphabetical, 'unassigned' last
  return Array.from(map.values()).sort((a,b) => {
    if (a.name === 'unassigned') return 1;
    if (b.name === 'unassigned') return -1;
    return a.name.localeCompare(b.name);
  });
}

// Group tasks by their source value (Bluebeam, Building Connected, Email, etc.).
// Tasks without a source land in the 'unsourced' bucket. Returns an array of
// { name, tasks, total, done } sorted alphabetically with 'unsourced' last.
function getSourceBuckets(project) {
  const map = new Map();
  project.tasks.forEach(t => {
    const sourceKey = (t.source && t.source.trim()) ? t.source.trim() : 'unsourced';
    if (!map.has(sourceKey)) map.set(sourceKey, { name: sourceKey, tasks: [], total: 0, done: 0 });
    const bucket = map.get(sourceKey);
    bucket.tasks.push(t);
    bucket.total++;
    if (t.status === 'done') bucket.done++;
  });
  // Also include sources from state.sourceOptions that have NO tasks yet --- so the user
  // can see all configured sources, not just the ones with actual tasks. This matches
  // how stages render even when empty.
  (state.sourceOptions || []).forEach(s => {
    if (!map.has(s.name)) {
      map.set(s.name, { name: s.name, tasks: [], total: 0, done: 0 });
    }
  });
  // Sort: real names alphabetical, 'unsourced' last
  return Array.from(map.values()).sort((a,b) => {
    if (a.name === 'unsourced') return 1;
    if (b.name === 'unsourced') return -1;
    return a.name.localeCompare(b.name);
  });
}

// Look up a source's icon and photo from the master sourceOptions list.
// Returns { icon, photo } --- both may be null if source isn't in the master list.
function getSourceMeta(sourceName) {
  if (!sourceName || sourceName === 'unsourced') return { icon: '📥', photo: null };
  const found = (state.sourceOptions || []).find(s => s.name === sourceName);
  if (!found) return { icon: '📥', photo: null };
  return { icon: found.icon || '📥', photo: found.photo || null };
}

// =============================================================
// SECTION HEADER
// =============================================================
function renderSectionHeader(project) {
  const titleEl = document.getElementById('sectionTitle');
  const descEl = document.getElementById('sectionDescription');

  if (state.grouping === 'stage') {
    if (state.activeStageId === 'all') {
      titleEl.innerHTML = `🗂️ All Stages <span class="count-badge"><span class="done-num">${project.tasks.filter(t=>t.status==='done').length}</span> / ${project.tasks.length} complete</span>`;
      descEl.textContent = 'Overview of every bid stage. Click a stage tab above to focus.';
    } else {
      const stage = STAGES.find(s=>s.id===state.activeStageId);
      const tasks = project.tasks.filter(t=>t.stage===stage.id);
      const done = tasks.filter(t=>t.status==='done').length;
      const bulkAssignBtn = tasks.length > 0
        ? ` <button class="bulk-assign-btn" onclick="openBulkAssignModal('${stage.id}')" title="Assign all tasks in this stage to one team member">👥 Assign All</button>`
        : '';
      titleEl.innerHTML = `${stage.icon} ${stage.name} <span class="count-badge"><span class="done-num">${done}</span> / ${tasks.length} complete</span>${bulkAssignBtn}`;
      descEl.textContent = stage.description;
    }
  } else if (state.grouping === 'assignee') {
    if (state.activeAssignee === 'all') {
      titleEl.innerHTML = `👥 All Team Members <span class="count-badge"><span class="done-num">${project.tasks.filter(t=>t.status==='done').length}</span> / ${project.tasks.length} complete</span>`;
      descEl.textContent = 'Workload across the estimating team. Click a person above to focus on their tasks.';
    } else {
      const tasks = getFilteredTasks(project);
      const done = tasks.filter(t=>t.status==='done').length;
      const remaining = tasks.length - done;
      const pct = tasks.length > 0 ? Math.round((done / tasks.length) * 100) : 0;
      const label = state.activeAssignee === 'unassigned' ? 'Unassigned Tasks' : state.activeAssignee;
      const title = state.activeAssignee === 'unassigned' ? '' : getMemberTitle(state.activeAssignee);
      const titleLabel = title ? ` <span style="font-family:'Barlow Condensed',sans-serif;font-size:13px;color:var(--text-dim);letter-spacing:0.08em;font-weight:600;">· ${escapeHtml(title)}</span>` : '';
      const pctColor = pct === 100 ? 'var(--green)' : pct >= 50 ? 'var(--sbg-navy)' : pct > 0 ? 'var(--yellow)' : 'var(--text-dim)';
      const pctBadge = `<span style="font-family:'JetBrains Mono',monospace;font-size:20px;font-weight:800;color:${pctColor};margin-left:8px;">${pct}%</span>`;
      titleEl.innerHTML = `👤 ${escapeHtml(label)}${titleLabel}${pctBadge} <span class="count-badge"><span class="done-num">${done}</span> / ${tasks.length} complete · ${remaining} remaining</span>`;
      descEl.textContent = state.activeAssignee === 'unassigned' ? 'Tasks with no assignee --- needs ownership.' : `All bid tasks assigned to ${state.activeAssignee}.`;
    }
  } else if (state.grouping === 'source') {
    if (state.activeSource === 'all') {
      titleEl.innerHTML = `🗂️ All Sources <span class="count-badge"><span class="done-num">${project.tasks.filter(t=>t.status==='done').length}</span> / ${project.tasks.length} complete</span>`;
      descEl.textContent = 'Tasks grouped by where they originated --- Bluebeam markups, Building Connected ITBs, emails, etc. Click a source above to focus.';
    } else {
      const tasks = getFilteredTasks(project);
      const done = tasks.filter(t=>t.status==='done').length;
      const remaining = tasks.length - done;
      const pct = tasks.length > 0 ? Math.round((done / tasks.length) * 100) : 0;
      const label = state.activeSource === 'unsourced' ? '--- No Source ---' : state.activeSource;
      const meta = getSourceMeta(state.activeSource);
      const iconHtml = (state.activeSource !== 'unsourced' && meta.photo)
        ? `<img src="${meta.photo}" alt="" style="width:24px;height:24px;border-radius:3px;vertical-align:middle;margin-right:4px;">`
        : `<span style="font-size:18px;margin-right:4px;">${escapeHtml(meta.icon)}</span>`;
      const pctColor = pct === 100 ? 'var(--green)' : pct >= 50 ? 'var(--sbg-navy)' : pct > 0 ? 'var(--yellow)' : 'var(--text-dim)';
      const pctBadge = `<span style="font-family:'JetBrains Mono',monospace;font-size:20px;font-weight:800;color:${pctColor};margin-left:8px;">${pct}%</span>`;
      titleEl.innerHTML = `${iconHtml}${escapeHtml(label)}${pctBadge} <span class="count-badge"><span class="done-num">${done}</span> / ${tasks.length} complete · ${remaining} remaining</span>`;
      descEl.textContent = state.activeSource === 'unsourced'
        ? 'Tasks with no Source set --- origin uncategorized.'
        : `All tasks originating from ${state.activeSource}.`;
    }
  } else if (state.grouping === 'status') {
    if (state.activeStatus === 'all') {
      titleEl.innerHTML = `🗂️ All Statuses <span class="count-badge"><span class="done-num">${project.tasks.filter(t=>t.status==='done').length}</span> / ${project.tasks.length} complete</span>`;
      descEl.textContent = 'Tasks grouped by their workflow status. Click a status above to see only those tasks.';
    } else {
      const tasks = getFilteredTasks(project);
      const total = tasks.length;
      const statusMeta = {
        'not-started': { label: '○ Not Started',   desc: 'Tasks queued and not yet picked up.' },
        'in-progress': { label: '⚙ In Progress',   desc: 'Tasks currently being worked on by the team.' },
        'blocked':     { label: '⛔ Blocked / RFI', desc: 'Tasks waiting on RFI response or external dependency.' },
        'pending':     { label: '⏳ Pending',      desc: 'Tasks awaiting external response or clarification.' },
        'done':        { label: '✓ Done',          desc: 'Tasks completed (some may be awaiting Lead sign-off).' }
      };
      const meta = statusMeta[state.activeStatus] || { label: state.activeStatus, desc: '' };
      titleEl.innerHTML = `${escapeHtml(meta.label)} <span class="count-badge">${total} task${total === 1 ? '' : 's'}</span>`;
      descEl.textContent = meta.desc;
    }
  } else if (state.grouping === 'alert') {
    // Alert grouping --- title reflects the active tier, count is post-filter
    const alertMeta = {
      'all':         { icon: '🗂',  label: 'All Tasks',         desc: 'Every task in the project. Use the filters below to slice by assignee, stage, or source.' },
      'overdue':     { icon: '🚨', label: 'Overdue',           desc: 'Tasks past their due date and not yet done --- most urgent tier.' },
      'late-start':  { icon: '⏰', label: 'Late Start',        desc: 'Tasks past their Start By date and still not started --- planning failure that needs attention.' },
      'at-risk':     { icon: '⚠',  label: 'At Risk',           desc: 'Tasks overdue OR due within 2 days but still not started, plus tasks with required items still open.' },
      'blocked':     { icon: '⛔', label: 'Blocked / RFI',     desc: 'Tasks with status Blocked --- usually awaiting RFI response or sub callback.' },
      'imminent':    { icon: '⏱',  label: 'Imminent',          desc: 'Tasks due in the next 24 hours.' },
      'soon':        { icon: '📅', label: 'Due Soon',          desc: 'Tasks due in the next 2 days.' },
      'in-progress': { icon: '⚙',  label: 'In Progress',       desc: 'Tasks currently being worked on by the team.' },
      'rejected':    { icon: '✗',  label: 'Rejected',          desc: 'Tasks rejected by the Lead Estimator and awaiting rework.' },
      'unack':       { icon: '🔔', label: 'Unacknowledged',    desc: 'Tasks assigned but not yet acknowledged by the assignee --- they may not know they have it.' },
      'unassigned':  { icon: '👤', label: 'Unassigned',        desc: 'Tasks with no Lead --- needs ownership before work can start.' },
      'pending':     { icon: '⏳', label: 'Pending',           desc: 'Tasks awaiting external response, clarification, or sub bid.' },
      'healthy':     { icon: '✅', label: 'Healthy',           desc: 'Tasks with no active alerts and not yet done --- comfortably on track.' },
      'done':        { icon: '✓',  label: 'Done',              desc: 'Completed tasks --- may include some awaiting Lead sign-off.' }
    };
    const tier = state.activeAlertTier || 'all';
    const meta = alertMeta[tier] || alertMeta['all'];
    const tasks = getFilteredTasks(project);
    titleEl.innerHTML = `${meta.icon} ${escapeHtml(meta.label)} <span class="count-badge">${tasks.length} task${tasks.length === 1 ? '' : 's'}</span>`;
    descEl.textContent = meta.desc;
  } else if (state.grouping === 'my-alert') {
    // Group by My Alerts --- same alertMeta but with "My" prefix in title
    const myAlertMeta = {
      'all':         { icon: '👤', label: 'All My Tasks',     desc: 'Every task assigned to you OR where you are a support member.' },
      'overdue':     { icon: '🚨', label: 'My Overdue',       desc: 'Your tasks past their due date and not yet done --- most urgent.' },
      'late-start':  { icon: '⏰', label: 'My Late Start',    desc: 'Your tasks past their Start By date and still not started.' },
      'at-risk':     { icon: '⚠',  label: 'My At Risk',       desc: 'Your tasks overdue OR due within 2 days but still not started, plus tasks with required items still open.' },
      'blocked':     { icon: '⛔', label: 'My Blocked / RFI', desc: 'Your tasks with status Blocked --- usually awaiting RFI response or sub callback.' },
      'imminent':    { icon: '⏱',  label: 'My Imminent',      desc: 'Your tasks due in the next 24 hours.' },
      'soon':        { icon: '📅', label: 'My Due Soon',      desc: 'Your tasks due in the next 2 days.' },
      'in-progress': { icon: '⚙',  label: 'My In Progress',   desc: 'Your tasks currently being worked on.' },
      'rejected':    { icon: '✗',  label: 'My Rejected',      desc: 'Your tasks rejected by the Lead Estimator and awaiting rework.' },
      'unack':       { icon: '🔔', label: 'My Unacknowledged',desc: 'Your assigned tasks not yet acknowledged.' },
      'pending':     { icon: '⏳', label: 'My Pending',       desc: 'Your tasks awaiting external response, clarification, or sub bid.' },
      'healthy':     { icon: '✅', label: 'My Healthy',       desc: 'Your tasks with no active alerts and not yet done --- comfortably on track.' },
      'done':        { icon: '✓',  label: 'My Done',          desc: 'Your completed tasks --- may include some awaiting Lead sign-off.' }
    };
    const tier = state.activeMyAlertTier || 'all';
    const meta = myAlertMeta[tier] || myAlertMeta['all'];
    const tasks = getFilteredTasks(project);
    titleEl.innerHTML = `${meta.icon} ${escapeHtml(meta.label)} <span class="count-badge">${tasks.length} of your task${tasks.length === 1 ? '' : 's'}</span>`;
    descEl.textContent = meta.desc;
  }
}

function getFilteredTasks(project) {
  let tasks;
  if (state.grouping === 'stage') {
    if (state.activeStageId === 'all') tasks = project.tasks.slice();
    else tasks = project.tasks.filter(t => t.stage === state.activeStageId);
  } else if (state.grouping === 'assignee') {
    if (state.activeAssignee === 'all') tasks = project.tasks.slice();
    else if (state.activeAssignee === 'unassigned') tasks = project.tasks.filter(t => {
      const leads = (typeof getTaskLeads === 'function') ? getTaskLeads(t) : [];
      return leads.length === 0 && (!t.assignee || !t.assignee.trim());
    });
    else {
      // Include tasks where the person is any Lead (co-Leads count) OR any Support
      const name = state.activeAssignee;
      tasks = project.tasks.filter(t => {
        if (typeof isTaskLead === 'function' && isTaskLead(t, name)) return true;
        if (typeof isTaskSupport === 'function' && isTaskSupport(t, name)) return true;
        // Legacy fallback in case helpers aren't loaded for some reason
        return (t.assignee||'').trim() === name;
      });
    }
  } else if (state.grouping === 'source') {
    if (state.activeSource === 'all') tasks = project.tasks.slice();
    else if (state.activeSource === 'unsourced') tasks = project.tasks.filter(t => !t.source || !t.source.trim());
    else tasks = project.tasks.filter(t => (t.source || '').trim() === state.activeSource);
  } else if (state.grouping === 'status') {
    if (state.activeStatus === 'all') tasks = project.tasks.slice();
    else tasks = project.tasks.filter(t => t.status === state.activeStatus);
  } else if (state.grouping === 'alert') {
    // Alert grouping --- filter to tasks that match the active alert tier
    tasks = filterTasksByAlertTier(project, state.activeAlertTier);
    // Apply the multi-filter row (assignee + stage + source) AFTER tier filter
    const f = state.alertFilters || {};
    if (f.assignee && f.assignee !== 'all') {
      if (f.assignee === 'unassigned') {
        tasks = tasks.filter(t => !t.assignee || !t.assignee.trim());
      } else {
        tasks = tasks.filter(t => (t.assignee||'').trim() === f.assignee || isTaskSupport(t, f.assignee));
      }
    }
    if (f.stage && f.stage !== 'all') {
      tasks = tasks.filter(t => t.stage === f.stage);
    }
    if (f.source && f.source !== 'all') {
      if (f.source === 'unsourced') tasks = tasks.filter(t => !t.source || !t.source.trim());
      else tasks = tasks.filter(t => (t.source||'').trim() === f.source);
    }
    return tasks;
  } else if (state.grouping === 'my-alert') {
    // Group by My Alerts --- same as Group by Alert but pre-scoped to the
    // current user. Reuses the same filterTasksByAlertTier logic with the
    // 'my' scope passed via filterTasksByAlertTierScoped (see below).
    tasks = filterTasksByAlertTierScoped(project, state.activeMyAlertTier, 'my');
    // Two-dim filter row --- stage + source only (assignee is fixed to "me")
    const f = state.myAlertFilters || {};
    if (f.stage && f.stage !== 'all') {
      tasks = tasks.filter(t => t.stage === f.stage);
    }
    if (f.source && f.source !== 'all') {
      if (f.source === 'unsourced') tasks = tasks.filter(t => !t.source || !t.source.trim());
      else tasks = tasks.filter(t => (t.source||'').trim() === f.source);
    }
    return tasks;
  } else {
    tasks = project.tasks.slice();
  }

  // Apply secondary assignee filter on top of the primary group filter.
  // Only fires when grouping is NOT assignee (where filter is redundant)
  // and NOT alert/my-alert (which have their own filter rows), and when the
  // secondary filter is set to something other than 'all'.
  const sec = state.secondaryAssigneeFilter || 'all';
  if (state.grouping !== 'assignee' && state.grouping !== 'alert' && state.grouping !== 'my-alert' && sec !== 'all') {
    if (sec === 'unassigned') {
      tasks = tasks.filter(t => !t.assignee || !t.assignee.trim());
    } else {
      tasks = tasks.filter(t => (t.assignee||'').trim() === sec || isTaskSupport(t, sec));
    }
  }
  // Critical-only filter --- global toggle from workspace toolbar pill.
  // Applied after all other filters so it composes with grouping/assignee/alert.
  if (state.criticalFilterOnly) {
    tasks = tasks.filter(t => !!t.critical);
  }
  return tasks;
}

// Returns tasks in `project` matching the given alert tier id. Reuses the
// existing per-tier logic from getTasksByAlertTier where possible; adds two
// new "tiers" for the grouping UI: 'all' (every task), 'healthy' (no active
// alerts AND not done), and 'done' (status === 'done'). All-tiers overlap:
// a task that's both Overdue AND Unacknowledged appears under both tabs.
function filterTasksByAlertTier(project, tier) {
  if (!tier || tier === 'all') return project.tasks.slice();
  if (tier === 'done') return project.tasks.filter(t => t.status === 'done');
  if (tier === 'healthy') {
    // Healthy = not done AND not in any active alert tier
    return project.tasks.filter(t => {
      if (t.status === 'done') return false;
      if (typeof isTaskOverdue === 'function' && isTaskOverdue(t)) return false;
      if (typeof isStartByEnabledForStage === 'function' && isStartByEnabledForStage(t.stage)
          && typeof isTaskLateStart === 'function' && isTaskLateStart(t)) return false;
      // At Risk inline check (avoid full getTasksByAlertTier for performance)
      if (t.dueDate) {
        const due = new Date(t.dueDate + 'T23:59:59');
        const now = new Date();
        const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const day2End = new Date(todayStart.getTime() + 3 * 86400000);
        const dueWithin2 = due < day2End;
        const readiness = (typeof getTaskReadiness === 'function') ? getTaskReadiness(t) : { isReady: true };
        if (dueWithin2 && (t.status === 'not-started' || !readiness.isReady)) return false;
      }
      if (t.status === 'blocked' || t.status === 'pending') return false;
      if (t.assignee && t.assignee.trim() && !t.acknowledged) return false;
      if (!t.assignee || !t.assignee.trim()) return false;
      if (t.rejected) return false;
      return true;
    });
  }
  // For all other tiers, delegate to getTasksByAlertTier
  if (typeof getTasksByAlertTier === 'function') {
    // Map UI tier ids to getTasksByAlertTier ids where they differ
    const tierMap = {
      'unack': 'unacknowledged',
      'imminent': 'imminent',
      'soon': 'soon',
      'overdue': 'overdue',
      'late-start': 'late-start',
      'at-risk': 'at-risk',
      'blocked': 'blocked',
      'in-progress': 'in-progress',
      'rejected': 'rejected',
      'unassigned': 'unassigned',
      'pending': 'pending'
    };
    const apiTier = tierMap[tier] || tier;
    return getTasksByAlertTier(project, apiTier, 'project');
  }
  return [];
}

// Same as filterTasksByAlertTier but applies the 'my' (current user) scope
// when dispatching to getTasksByAlertTier. For the synthetic tiers ('all',
// 'healthy', 'done') we apply the same "is mine" predicate inline so the
// scoping is consistent across the project + my modes.
function filterTasksByAlertTierScoped(project, tier, scope) {
  if (scope !== 'my') return filterTasksByAlertTier(project, tier);
  const currentUser = (typeof getCurrentUser === 'function') ? (getCurrentUser() || '') : '';
  if (!currentUser) return []; // no current user → nothing is "mine"
  const lc = currentUser.toLowerCase();

  // Helper: returns true if `t` belongs to the current user (Lead OR support)
  const isMine = (t) => {
    if (t.assignee && t.assignee.trim().toLowerCase() === lc) return true;
    if (typeof isTaskSupport === 'function' && isTaskSupport(t, currentUser)) return true;
    return false;
  };

  if (!tier || tier === 'all') {
    return project.tasks.filter(isMine);
  }
  if (tier === 'done') {
    return project.tasks.filter(t => t.status === 'done' && isMine(t));
  }
  if (tier === 'healthy') {
    // Reuse the same healthy predicate from filterTasksByAlertTier but
    // additionally require isMine. Inline check keeps it fast.
    return project.tasks.filter(t => {
      if (!isMine(t)) return false;
      if (t.status === 'done') return false;
      if (typeof isTaskOverdue === 'function' && isTaskOverdue(t)) return false;
      if (typeof isStartByEnabledForStage === 'function' && isStartByEnabledForStage(t.stage)
          && typeof isTaskLateStart === 'function' && isTaskLateStart(t)) return false;
      if (t.dueDate) {
        const due = new Date(t.dueDate + 'T23:59:59');
        const now = new Date();
        const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const day2End = new Date(todayStart.getTime() + 3 * 86400000);
        const dueWithin2 = due < day2End;
        const readiness = (typeof getTaskReadiness === 'function') ? getTaskReadiness(t) : { isReady: true };
        if (dueWithin2 && (t.status === 'not-started' || !readiness.isReady)) return false;
      }
      if (t.status === 'blocked' || t.status === 'pending') return false;
      if (t.assignee && t.assignee.trim() && !t.acknowledged) return false;
      // For "mine" scope, "unassigned" never applies (it's mine because I'm
      // support, but if there's no Lead the task is also unassigned).
      // Healthy still requires a Lead to be assigned to count as healthy.
      if (!t.assignee || !t.assignee.trim()) return false;
      if (t.rejected) return false;
      return true;
    });
  }
  // Standard tiers --- delegate to getTasksByAlertTier with 'my' scope
  if (typeof getTasksByAlertTier === 'function') {
    const tierMap = {
      'unack': 'unacknowledged',
      'imminent': 'imminent',
      'soon': 'soon',
      'overdue': 'overdue',
      'late-start': 'late-start',
      'at-risk': 'at-risk',
      'blocked': 'blocked',
      'in-progress': 'in-progress',
      'rejected': 'rejected',
      'unassigned': 'unassigned',
      'pending': 'pending'
    };
    const apiTier = tierMap[tier] || tier;
    return getTasksByAlertTier(project, apiTier, 'my');
  }
  return [];
}

// =============================================================
// START BY DATE --- forward-looking field that fires a "Late Start" alert
// when the date passes and the task is still 'not-started'. Auto-suggested
// based on per-stage default duration; user can override or clear.
// =============================================================

// Returns true if the Start By feature applies to this stage. Always-on
// stages (trade-solicitation, estimating, scope-leveling --- lead-time
// critical) get it regardless of the global flag; other stages only when
// the firm-level toggle is on.
function isStartByEnabledForStage(stageId) {
  const alwaysOn = state.startByAlwaysOnStages || [];
  if (alwaysOn.includes(stageId)) return true;
  return !!state.startByGlobalEnabled;
}

// Returns the suggested Start By date for a task --- `dueDate` minus the
// stage's default duration in business days. Honors the user's existing
// skipWeekends / skipHolidays preference via subtractBusinessDays. Returns
// null if there's no due date or no usable stage default.
function getSuggestedStartByDate(task) {
  if (!task || !task.dueDate) return null;
  const stageId = task.stage;
  const defaults = state.startByStageDefaults || {};
  const days = (typeof defaults[stageId] === 'number' && defaults[stageId] > 0) ? defaults[stageId] : 2;
  return subtractBusinessDays(task.dueDate, days);
}

// Subtract N business days from a YYYY-MM-DD string. Honors the same
// skipWeekends / skipHolidays preferences as the additive equivalent so
// suggestions agree with how the rest of the schedule was computed.
function subtractBusinessDays(dateStr, days) {
  if (!dateStr || !days) return dateStr;
  let d = new Date(dateStr + 'T12:00:00');
  let remaining = days;
  while (remaining > 0) {
    d.setDate(d.getDate() - 1);
    if (state.skipWeekends && (d.getDay() === 0 || d.getDay() === 6)) continue;
    const iso = d.toISOString().slice(0, 10);
    if (state.skipHolidays && Array.isArray(state.holidays) && state.holidays.includes(iso)) continue;
    remaining--;
  }
  return d.toISOString().slice(0, 10);
}

// Returns true if the task is "Late Start" --- has a Start By date that's
// already passed AND status is still 'not-started'. Once a task is in
// progress, the Start By has been satisfied so the alert clears.
function isTaskLateStart(task) {
  if (!task) return false;
  if (task.status !== 'not-started') return false;
  if (!task.startByDate) return false;
  const today = new Date();
  const todayStart = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  const startBy = new Date(task.startByDate + 'T00:00:00');
  return startBy < todayStart;
}

// Returns true if the task's Start By is "imminent" --- within 2 business
// days of today AND the task hasn't started yet. Drives the gold/warning
// chip color on task cards (vs. red for already-passed Late Start).
function isTaskStartByImminent(task) {
  if (!task) return false;
  if (task.status !== 'not-started') return false;
  if (!task.startByDate) return false;
  const today = new Date();
  const todayStart = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  const startBy = new Date(task.startByDate + 'T00:00:00');
  if (startBy < todayStart) return false; // already late, different tier
  const diffDays = Math.round((startBy.getTime() - todayStart.getTime()) / 86400000);
  return diffDays <= 2;
}

// =============================================================
// DUE ALERT TIERS
// =============================================================
function getTasksByAlertTier(project, tier, scope) {
  // tier: 'overdue' | 'imminent' | 'soon' | 'unassigned' | 'unacknowledged'
  //     | 'completed' | 'not-started' | 'pending' | 'rejected'
  //     | 'in-progress' | 'blocked' | 'at-risk' | 'late-start'
  // scope: 'project' (all tasks) | 'my' (filtered to current user's relevance)
  const currentUser = (scope === 'my') ? getCurrentUser() : null;
  const lead = (project.leadEstimator || '').trim();
  const isCurrentUserLead = scope === 'my' && currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();

  return project.tasks.filter(t => {
    // ===== SCOPE FILTER (for 'my' alerts) =====
    if (scope === 'my' && currentUser) {
      // For 'my' scope, a task is relevant if I'm the assignee OR support OR
      // if I'm the Lead Estimator (for tiers that matter to me as Lead).
      const isMine = (typeof isTaskMember === 'function')
        ? isTaskMember(t, currentUser)
        : ((t.assignee && t.assignee.toLowerCase() === currentUser.toLowerCase()) || isTaskSupport(t, currentUser));
      // Lead cares about these tiers for ALL tasks (even not assigned to them)
      const leadRelevantTiers = ['completed', 'unassigned', 'rejected'];
      const leadShouldSee = isCurrentUserLead && leadRelevantTiers.includes(tier);
      if (!isMine && !leadShouldSee) return false;
    }

    // ===== TIER FILTER =====
    if (tier === 'unassigned') {
      // Multi-Lead aware: a task is unassigned only if it has NO Leads
      const leads = (typeof getTaskLeads === 'function') ? getTaskLeads(t) : [];
      if (leads.length > 0) return false;
      return t.status !== 'done' && (!t.assignee || !t.assignee.trim());
    }
    if (tier === 'completed') {
      return t.status === 'done' && !t.completionAcknowledged;
    }
    if (tier === 'not-started') return t.status === 'not-started';
    if (tier === 'pending') return t.status === 'pending';
    if (tier === 'in-progress') return t.status === 'in-progress';
    if (tier === 'blocked') return t.status === 'blocked';
    if (tier === 'late-start') {
      // Late Start = task is not-started AND has a passed Start By date
      // AND the Start By feature is enabled for this stage (so disabling
      // the feature globally also clears the alerts).
      if (!isStartByEnabledForStage(t.stage)) return false;
      return isTaskLateStart(t);
    }
    if (tier === 'at-risk') {
      // At Risk = open task that is overdue OR (due within 2 days AND not started)
      // OR (due within 2 days AND has unfinished required items)
      // OR (Late Start --- Start By date passed and still not started).
      if (t.status === 'done') return false;
      // Late Start tasks are always at-risk regardless of due date proximity
      if (isStartByEnabledForStage(t.stage) && isTaskLateStart(t)) return true;
      if (!t.dueDate) return false;
      const due = new Date(t.dueDate + 'T23:59:59');
      const now = new Date();
      const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const day2End = new Date(todayStart.getTime() + 3 * 86400000);
      const isOverdue = due < now && !isSameDay(due, now);
      const dueWithin2 = due < day2End;
      const isNotStarted = t.status === 'not-started';
      const readiness = (typeof getTaskReadiness === 'function') ? getTaskReadiness(t) : { isReady: true };
      const hasOpenRequired = !readiness.isReady;
      return isOverdue || (dueWithin2 && (isNotStarted || hasOpenRequired));
    }
    if (tier === 'rejected') return t.completionRejected;
    if (tier === 'unacknowledged') {
      return t.status !== 'done'
        && t.assignee && t.assignee.trim()
        && !t.acknowledged;
    }
    // Date-based tiers --- skip done and no-due-date
    if (t.status === 'done' || !t.dueDate) return false;
    if (tier === 'overdue') return isTaskOverdue(t);
    if (tier === 'imminent') return !isTaskOverdue(t) && isTaskDueImminent(t);
    if (tier === 'soon') return !isTaskOverdue(t) && !isTaskDueImminent(t) && isTaskDueSoon(t);
    return false;
  });
}

function renderAlertStrip(project) {
  // Render two scoped alert strips: Project Alerts (all tasks) and My Alerts (current user).
  renderScopedAlertStrip(project, 'project', 'alertStripProject');
  renderScopedAlertStrip(project, 'my', 'alertStripMine');
}

function renderScopedAlertStrip(project, scope, stripElementId) {
  const strip = document.getElementById(stripElementId);
  if (!strip) return;

  const activeStateKey = scope === 'project' ? 'activeAlertTier' : 'activeAlertTierMine';
  const activeTier = state[activeStateKey];

  const overdue = getTasksByAlertTier(project, 'overdue', scope);
  const imminent = getTasksByAlertTier(project, 'imminent', scope);
  const soon = getTasksByAlertTier(project, 'soon', scope);
  const unassigned = getTasksByAlertTier(project, 'unassigned', scope);
  const unacknowledged = getTasksByAlertTier(project, 'unacknowledged', scope);
  const completed = getTasksByAlertTier(project, 'completed', scope);
  const notStarted = getTasksByAlertTier(project, 'not-started', scope);
  const pending = getTasksByAlertTier(project, 'pending', scope);
  const inProgress = getTasksByAlertTier(project, 'in-progress', scope);
  const blocked = getTasksByAlertTier(project, 'blocked', scope);
  const atRisk = getTasksByAlertTier(project, 'at-risk', scope);
  const lateStart = getTasksByAlertTier(project, 'late-start', scope);

  const currentUser = getCurrentUser();
  const tabs = [];

  // For 'my' scope, gate the strip --- if no user signed in, show a prompt
  if (scope === 'my' && !currentUser) {
    strip.innerHTML = `
      <div class="alert-strip-empty">
        <span class="ase-icon">👤</span>
        <span class="ase-text">Sign in to see your personal alerts. Click the user chip in the top-right to sign in.</span>
      </div>
    `;
    return;
  }

  // Overdue tab --- only visible when there are overdue tasks
  if (overdue.length > 0) {
    const active = activeTier === 'overdue' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-overdue${active}" onclick="toggleAlertPanelScoped('overdue','${scope}')" title="${overdue.length} task(s) past due date">
      🚨 Overdue <span class="alert-count">${overdue.length}</span>
    </button>`);
  }
  // At Risk --- overdue OR due within 2 days AND not-started/required-open.
  // Placed near Overdue because both signal urgent attention. Excludes the
  // tasks that are already in the Overdue tab visually but the bucket
  // overlap is tracked in collectSnapshotBuckets --- here we surface anything
  // that earned the "at risk" label.
  if (atRisk.length > 0) {
    const active = activeTier === 'at-risk' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-atrisk${active}" onclick="toggleAlertPanelScoped('at-risk','${scope}')" title="Open tasks that are overdue, OR due within 2 days but still not started or have unfinished required items">
      ⚠ At Risk <span class="alert-count">${atRisk.length}</span>
    </button>`);
  }
  // Late Start --- Start By date has passed and task is still 'not-started'.
  // Sits next to At Risk because the underlying message is similar
  // ("you needed to start this already") but the trigger is forward-looking
  // not deadline-driven.
  if (lateStart.length > 0) {
    const active = activeTier === 'late-start' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-latestart${active}" onclick="toggleAlertPanelScoped('late-start','${scope}')" title="Tasks past their Start By date and still not started">
      ⏰ Late Start <span class="alert-count">${lateStart.length}</span>
    </button>`);
  }
  if (imminent.length > 0) {
    const active = activeTier === 'imminent' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-imminent${active}" onclick="toggleAlertPanelScoped('imminent','${scope}')" title="Tasks due today or tomorrow">
      1-Day Alert <span class="alert-count">${imminent.length}</span>
    </button>`);
  }
  if (soon.length > 0) {
    const active = activeTier === 'soon' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-soon${active}" onclick="toggleAlertPanelScoped('soon','${scope}')" title="Tasks due in 2 days">
      2-Day Alert <span class="alert-count">${soon.length}</span>
    </button>`);
  }
  if (unassigned.length > 0) {
    const active = activeTier === 'unassigned' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-unassigned${active}" onclick="toggleAlertPanelScoped('unassigned','${scope}')" title="Open tasks without a Lead assignee">
      👤 Unassigned <span class="alert-count">${unassigned.length}</span>
    </button>`);
  }
  if (unacknowledged.length > 0) {
    const active = activeTier === 'unacknowledged' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-unacknowledged${active}" onclick="toggleAlertPanelScoped('unacknowledged','${scope}')" title="Newly-assigned tasks awaiting assignee acknowledgment">
      🔔 Unacknowledged <span class="alert-count">${unacknowledged.length}</span>
    </button>`);
  }
  // Messages and receipts are inherently "mine" --- only shown in the My Alerts strip
  if (scope === 'my' && currentUser) {
    const unreadMessages = getUnreadMessagesForUser(project, currentUser);
    if (unreadMessages.length > 0) {
      tabs.push(`<button class="alert-tab tab-messages" onclick="openMessageBoard()" title="${unreadMessages.length} unread message(s)">
        📩 Messages <span class="alert-count">${unreadMessages.length}</span>
      </button>`);
    }
    const receipts = getUnseenReceiptsForSender(project, currentUser);
    if (receipts.length > 0) {
      tabs.push(`<button class="alert-tab tab-receipts" onclick="openMessageBoardReceipts()" title="${receipts.length} message acknowledgment receipt(s) --- your messages have been seen">
        ✉✓ Receipts <span class="alert-count">${receipts.length}</span>
      </button>`);
    }
  }
  // Rejected completions
  const rejected = scope === 'my'
    ? project.tasks.filter(t => {
        if (!t.completionRejected) return false;
        const isMine = (t.assignee && currentUser && t.assignee.toLowerCase() === currentUser.toLowerCase())
                    || (currentUser && isTaskSupport(t, currentUser));
        const lead = (project.leadEstimator || '').trim();
        const isLead = currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();
        return isMine || isLead;
      })
    : project.tasks.filter(t => t.completionRejected);
  if (rejected.length > 0) {
    const active = activeTier === 'rejected' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-rejected${active}" onclick="toggleAlertPanelScoped('rejected','${scope}')" title="${rejected.length} completion(s) rejected by Lead Estimator --- assignee action required">
      ✗ Rejected <span class="alert-count">${rejected.length}</span>
    </button>`);
  }
  // Status-based tabs
  if (inProgress.length > 0) {
    const active = activeTier === 'in-progress' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-inprogress${active}" onclick="toggleAlertPanelScoped('in-progress','${scope}')" title="Tasks actively being worked on">
      ⚙ In Progress <span class="alert-count">${inProgress.length}</span>
    </button>`);
  }
  if (blocked.length > 0) {
    const active = activeTier === 'blocked' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-blocked${active}" onclick="toggleAlertPanelScoped('blocked','${scope}')" title="Tasks blocked or awaiting RFI response">
      ⛔ Blocked / RFI <span class="alert-count">${blocked.length}</span>
    </button>`);
  }
  if (pending.length > 0) {
    const active = activeTier === 'pending' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-pending${active}" onclick="toggleAlertPanelScoped('pending','${scope}')" title="Tasks awaiting external response or clarification">
      ⏳ Pending <span class="alert-count">${pending.length}</span>
    </button>`);
  }
  if (notStarted.length > 0) {
    const active = activeTier === 'not-started' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-notstarted${active}" onclick="toggleAlertPanelScoped('not-started','${scope}')" title="Tasks not yet started">
      ○ Not Started <span class="alert-count">${notStarted.length}</span>
    </button>`);
  }
  if (completed.length > 0) {
    const active = activeTier === 'completed' ? ' active' : '';
    tabs.push(`<button class="alert-tab tab-completed${active}" onclick="toggleAlertPanelScoped('completed','${scope}')" title="Completed tasks awaiting Lead Estimator sign-off">
      ✓ Completions <span class="alert-count">${completed.length}</span>
    </button>`);
  }

  // Empty state for each scope
  if (tabs.length === 0) {
    strip.innerHTML = `
      <div class="alert-strip-empty">
        <span class="ase-icon">✓</span>
        <span class="ase-text">${scope === 'my' ? "You're all caught up --- no personal alerts right now." : 'No active project alerts.'}</span>
      </div>
    `;
    return;
  }

  // Append the expanded panel (if any tier is active for this scope)
  let panelHtml = '';
  if (activeTier) {
    const tier = activeTier;
    const tierTasks = tier === 'rejected'
      ? rejected
      : getTasksByAlertTier(project, tier, scope);
    if (tierTasks.length === 0) {
      state[activeStateKey] = null;
    } else {
      const titles = {
        'overdue': '🚨 Overdue Tasks',
        'imminent': '⚠ Due Today or Tomorrow (1-Day Alert)',
        'soon': '⚠ Due in 2 Days (2-Day Alert)',
        'unassigned': '👤 Unassigned Tasks --- Needs Ownership',
        'unacknowledged': '🔔 Newly Assigned --- Awaiting Assignee Acknowledgment',
        'pending': '⏳ Pending Tasks --- Awaiting Response',
        'not-started': '○ Not Yet Started',
        'in-progress': '⚙ In Progress --- Actively Being Worked On',
        'blocked': '⛔ Blocked / Awaiting RFI Response',
        'at-risk': '⚠ At Risk --- Overdue or Due Soon Without Progress',
        'late-start': '⏰ Late Start --- Past Start-By Date, Still Not Started',
        'completed': '✓ Completions Awaiting Lead Estimator Sign-Off',
        'rejected': '✗ Rejected Completions --- Assignee Action Required'
      };
      const leadName = (project.leadEstimator || '').trim();
      const scopeLabel = scope === 'my' ? ' · Filtered to your tasks' : '';
      const completionHeader = tier === 'completed' ? `
        <div class="completion-panel-notice">
          ${leadName
            ? `<div class="cpn-lead">
                 <span class="cpn-label">Sign-Off Authority:</span>
                 <strong>${escapeHtml(leadName)}</strong>
                 <span class="cpn-sub">Lead Estimator for this project</span>
               </div>`
            : `<div class="cpn-lead cpn-missing">
                 <span>⚠ No Lead Estimator set --- configure one in Edit Project to enable sign-offs</span>
               </div>`
          }
          ${leadName && tierTasks.length > 1
            ? `<button class="ack-all-btn" onclick="acknowledgeAllCompletions()" title="Sign off on all ${tierTasks.length} completions at once">✓ Sign Off All (${tierTasks.length})</button>`
            : ''}
        </div>
      ` : '';

      let unackHeader = '';
      if (tier === 'unacknowledged' && tierTasks.length > 0) {
        const myUnacked = currentUser
          ? tierTasks.filter(t => (typeof isTaskLead === 'function') ? isTaskLead(t, currentUser) : (t.assignee && t.assignee.toLowerCase() === currentUser.toLowerCase())).length
          : 0;
        const isLead = currentUser && leadName && currentUser.toLowerCase() === leadName.toLowerCase();
        const othersUnacked = tierTasks.length - myUnacked;
        const buttons = [];
        if (myUnacked > 0) {
          buttons.push(`<button class="ack-all-btn" onclick="acknowledgeAllMyTasks()" title="Acknowledge all tasks assigned to you">✓ Acknowledge All Mine (${myUnacked})</button>`);
        }
        if (isLead && othersUnacked > 0) {
          buttons.push(`<button class="ack-all-btn ack-override-all-btn" onclick="overrideAcknowledgeAll()" title="Lead override --- acknowledge on behalf of all assignees">⚡ Override All (${tierTasks.length})</button>`);
        }
        if (buttons.length > 0 || currentUser) {
          unackHeader = `
            <div class="completion-panel-notice">
              <div class="cpn-lead">
                ${currentUser
                  ? `<span class="cpn-label">Signed in:</span><strong>${escapeHtml(currentUser)}</strong>${isLead ? `<span class="cpn-sub">Lead Estimator --- can override</span>` : `<span class="cpn-sub">${myUnacked} task${myUnacked===1?'':'s'} awaiting your acknowledgment</span>`}`
                  : `<span>⚠ No user signed in --- click the user chip in the header to sign in</span>`
                }
              </div>
              ${buttons.join('')}
            </div>
          `;
        }
      }

      panelHtml = `
        <div class="alert-panel panel-${tier}">
          <div class="alert-panel-header">
            <div class="alert-panel-title">${titles[tier]} · ${tierTasks.length} task${tierTasks.length===1?'':'s'}${scopeLabel}</div>
            <button class="alert-panel-close" onclick="closeAlertPanelScoped('${scope}')" title="Close">✕</button>
          </div>
          ${completionHeader}
          ${unackHeader}
          <div class="alert-list">
            ${tierTasks.slice().sort((a,b) => {
              const nonDateTiers = ['unassigned', 'unacknowledged', 'completed', 'not-started', 'pending'];
              if (nonDateTiers.includes(tier)) {
                const stageOrder = {};
                STAGES.forEach((s,i) => stageOrder[s.id] = i);
                const sa = stageOrder[a.stage] ?? 99;
                const sb = stageOrder[b.stage] ?? 99;
                if (sa !== sb) return sa - sb;
                return (a.title||'').localeCompare(b.title||'');
              }
              const da = a.dueDate ? new Date(a.dueDate+'T00:00:00').getTime() : Infinity;
              const db = b.dueDate ? new Date(b.dueDate+'T00:00:00').getTime() : Infinity;
              return da - db;
            }).map(t => renderAlertItem(t, tier)).join('')}
          </div>
        </div>
      `;
    }
  }

  strip.innerHTML = tabs.join('') + panelHtml;
}

// Scoped versions of toggle/close --- each scope has its own activeAlertTier state key.
function toggleAlertPanelScoped(tier, scope) {
  const key = scope === 'project' ? 'activeAlertTier' : 'activeAlertTierMine';
  state[key] = state[key] === tier ? null : tier;
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) {
    renderAlertStrip(project);
    renderAssigneeAlertsStrip(project);
  }
}

function closeAlertPanelScoped(scope) {
  const key = scope === 'project' ? 'activeAlertTier' : 'activeAlertTierMine';
  state[key] = null;
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) {
    renderAlertStrip(project);
    renderAssigneeAlertsStrip(project);
  }
}

function renderAlertItem(t, tier) {
  const stage = STAGES.find(s => s.id === t.stage) || STAGES[0];
  const initials = (t.assignee || '?').split(/\s+/).map(x => x[0]).join('').slice(0,2).toUpperCase();
  const color = t.assignee ? avatarColor(t.assignee) : '#9ba4b0';
  const photo = t.assignee ? getMemberPhoto(t.assignee) : null;
  const avatar = t.assignee
    ? (photo
        ? `<span class="avatar has-photo" style="width:22px;height:22px;font-size:10px;"><img src="${photo}" alt=""></span>`
        : `<span class="avatar" style="background:${color};width:22px;height:22px;font-size:10px;">${escapeHtml(initials)}</span>`)
    : `<span class="avatar" style="background:#9ba4b0;width:22px;height:22px;font-size:10px;">?</span>`;

  const daysLeft = getDaysLeft(t.dueDate);
  let flagLabel, flagCls;

  if (tier === 'unassigned') {
    flagLabel = 'NEEDS LEAD';
    flagCls = 'badge-unassigned';
  } else if (tier === 'unacknowledged') {
    flagLabel = 'NEW --- NOT ACKNOWLEDGED';
    flagCls = 'badge-unacknowledged';
  } else if (tier === 'rejected') {
    // Rejected completions --- flag shows the rejection reason word so it's
    // visible at a glance even before the user expands the detail panel.
    const reason = (t.completionRejectionReason || '').trim();
    flagLabel = reason ? `✗ ${reason.toUpperCase()}` : '✗ REJECTED';
    flagCls = 'badge-rejected';
  } else if (tier === 'completed') {
    flagLabel = '✓ DONE';
    flagCls = 'badge-status-completed';
  } else if (tier === 'not-started') {
    flagLabel = '○ NOT STARTED';
    flagCls = 'badge-status-notstarted';
  } else if (tier === 'pending') {
    flagLabel = '⏳ PENDING';
    flagCls = 'badge-status-pending';
  } else if (tier === 'in-progress') {
    flagLabel = '⚙ IN PROGRESS';
    flagCls = 'badge-status-inprogress';
  } else if (tier === 'blocked') {
    flagLabel = '⛔ BLOCKED';
    flagCls = 'badge-status-blocked';
  } else if (tier === 'at-risk') {
    // At-risk badge surfaces WHY it's at risk (overdue / not-started / required-open)
    if (daysLeft !== null && daysLeft < 0) {
      flagLabel = `${Math.abs(daysLeft)}d OVERDUE`;
    } else if (t.status === 'not-started') {
      flagLabel = '⚠ AT RISK · NOT STARTED';
    } else {
      flagLabel = '⚠ AT RISK · REQ OPEN';
    }
    flagCls = 'badge-atrisk';
  } else if (tier === 'late-start') {
    // Late-start badge shows how many days past the Start By date the task is.
    let daysPast = 0;
    if (t.startByDate) {
      const sb = new Date(t.startByDate + 'T00:00:00');
      const today = new Date();
      const todayStart = new Date(today.getFullYear(), today.getMonth(), today.getDate());
      daysPast = Math.round((todayStart.getTime() - sb.getTime()) / 86400000);
    }
    flagLabel = daysPast > 0 ? `⏰ ${daysPast}d LATE START` : '⏰ LATE START';
    flagCls = 'badge-latestart';
  } else if (tier === 'overdue') {
    flagLabel = `${Math.abs(daysLeft)}d OVERDUE`;
    flagCls = 'badge-overdue';
  } else if (daysLeft === 0) {
    flagLabel = 'TODAY';
    flagCls = 'badge-imminent';
  } else if (daysLeft === 1) {
    flagLabel = 'TOMORROW';
    flagCls = 'badge-imminent';
  } else if (daysLeft === null) {
    flagLabel = 'NO DUE DATE';
    flagCls = 'badge-unassigned';
  } else {
    flagLabel = `${daysLeft} DAYS`;
    flagCls = 'badge-soon';
  }

  const dueText = t.dueDate ? formatDate(t.dueDate) : '---';
  const assigneeLabel = t.assignee || 'Unassigned';
  const flagIcon = (tier === 'unassigned' || tier === 'unacknowledged' || tier === 'completed' || tier === 'not-started' || tier === 'pending' || tier === 'rejected' || tier === 'in-progress' || tier === 'blocked' || tier === 'at-risk' || tier === 'late-start') ? '' : '⚠ ';

  // Completed tier: add sign-off + reject buttons (Lead-Estimator-only)
  let signoffButton = '';
  if (tier === 'completed') {
    const project = state.projects.find(p => p.id === state.activeProjectId);
    const hasLead = project && project.leadEstimator && project.leadEstimator.trim();
    if (hasLead) {
      signoffButton = `<button class="ai-signoff-btn" onclick="acknowledgeCompletion('${t.id}', event)" title="Sign off --- Lead Estimator only">✓ Sign Off</button><button class="ai-reject-btn" onclick="openRejectCompletionModal('${t.id}', event)" title="Reject completion and send back to assignee">✗ Reject</button>`;
    } else {
      signoffButton = `<button class="ai-signoff-btn disabled" onclick="event.stopPropagation(); alert('No Lead Estimator is set for this project. Click Edit Project to assign one.');" title="No Lead Estimator assigned --- set one in Edit Project">⚠ No Lead</button>`;
    }
  }

  // Unacknowledged tier: assignee can acknowledge from the alert list; Lead can override
  let ackInlineBtn = '';
  if (tier === 'unacknowledged') {
    const project = state.projects.find(p => p.id === state.activeProjectId);
    const lead = project?.leadEstimator?.trim();
    const currentUser = getCurrentUser();
    const isCurrentUserAssignee = currentUser && t.assignee && currentUser.toLowerCase() === t.assignee.toLowerCase();
    const isCurrentUserLead = currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();
    ackInlineBtn = `<button class="ai-ack-btn" onclick="acknowledgeTask('${t.id}', event)" title="Mark this task as acknowledged by ${escapeHtml(t.assignee || 'assignee')}">✓ Acknowledge</button>`;
    // Lead override button --- only shown to the Lead Estimator, and only when the current user isn't the assignee
    if (isCurrentUserLead && !isCurrentUserAssignee && lead) {
      ackInlineBtn += `<button class="ai-override-btn" onclick="overrideAcknowledge('${t.id}', event)" title="Lead override --- acknowledge on behalf of ${escapeHtml(t.assignee || 'assignee')}">⚡ Override</button>`;
    }
  }

  // ===== Secondary metadata row --- build chips for category, priority, BIC, source, support, notes =====
  const detailChips = [];

  // Priority chip (colored by severity)
  if (t.priority) {
    const priorityColors = { high: '#c8322b', medium: '#d4a017', low: '#9ba4b0' };
    const priorityIcons = { high: '🔥', medium: '●', low: '○' };
    const pc = priorityColors[t.priority] || '#9ba4b0';
    detailChips.push(`<span class="ai-chip ai-chip-priority" style="background:${pc}15;color:${pc};border-color:${pc}40;" title="Priority: ${t.priority}">${priorityIcons[t.priority] || '●'} ${t.priority.toUpperCase()}</span>`);
  }

  // Category / CSI tag
  if (t.category && t.category.trim() && t.category !== 'General') {
    detailChips.push(`<span class="ai-chip ai-chip-category" title="Category: ${escapeHtml(t.category)}">🏷 ${escapeHtml(t.category)}</span>`);
  }

  // Ball in Court chip (uses same master-list color as the board card)
  if (t.ballInCourt) {
    detailChips.push(`<span class="ai-chip ai-chip-bic bic-color-${bicColorFor(t.ballInCourt)}" title="Ball in Court: ${escapeHtml(t.ballInCourt)}">🏀 ${escapeHtml(t.ballInCourt)}</span>`);
  }

  // Source chip
  if (t.source && t.source.trim()) {
    detailChips.push(`<span class="ai-chip ai-chip-source" title="Source: ${escapeHtml(t.source)}">📥 ${escapeHtml(t.source)}</span>`);
  }

  // Support member (if different from assignee)
  if (t.support && t.support.trim() && t.support !== t.assignee) {
    const sInitials = t.support.split(/\s+/).map(x => x[0]).join('').slice(0,2).toUpperCase();
    const sColor = avatarColor(t.support);
    const sPhoto = getMemberPhoto(t.support);
    const sAvatar = sPhoto
      ? `<span class="ai-support-avatar"><img src="${sPhoto}" alt=""></span>`
      : `<span class="ai-support-avatar" style="background:${sColor};">${escapeHtml(sInitials)}</span>`;
    detailChips.push(`<span class="ai-chip ai-chip-support" title="Support: ${escapeHtml(t.support)}">+ ${sAvatar}${escapeHtml(t.support)}</span>`);
  }

  // Day offset
  if (typeof t.dayOffset === 'number') {
    detailChips.push(`<span class="ai-chip ai-chip-offset" title="Day offset from bid start">D+${t.dayOffset}</span>`);
  }

  // Message count indicator (if task has thread)
  if (Array.isArray(t.messages) && t.messages.length > 0) {
    detailChips.push(`<span class="ai-chip ai-chip-messages" title="${t.messages.length} message${t.messages.length === 1 ? '' : 's'} on this task">💬 ${t.messages.length}</span>`);
  }

  // Notes preview (truncated if long, but shown inline rather than hidden)
  let notesPreview = '';
  if (t.notes && t.notes.trim()) {
    const notesText = t.notes.replace(/\s+/g, ' ').trim();
    const trimmed = notesText.length > 240 ? notesText.slice(0, 237) + '...' : notesText;
    notesPreview = `<div class="ai-notes" title="${escapeHtml(notesText)}">📝 ${escapeHtml(trimmed)}</div>`;
  }

  // Combine chips + notes into a secondary row (hidden if both empty)
  const hasDetails = detailChips.length > 0 || notesPreview;
  const detailsRow = hasDetails
    ? `<div class="ai-details-row">
         ${detailChips.length > 0 ? `<div class="ai-chips-row">${detailChips.join('')}</div>` : ''}
         ${notesPreview}
       </div>`
    : '';

  // ===== Rejection detail block (rejected tier only) =====
  // Surfaces *why* a completion was rejected directly inside the alert
  // dropdown so the assignee doesn't have to open the task to find out.
  // Includes: who rejected, when, the reason chip (icon + label), the
  // additional notes from the Lead, an Open Task button, and a quick
  // Acknowledge-Rejection action when the assignee hasn't yet acked it.
  let rejectionBlock = '';
  if (tier === 'rejected') {
    const reason = (t.completionRejectionReason || '').trim();
    const notes = (t.completionRejectionNotes || '').trim();
    const rejectedBy = (t.completionRejectedBy || '').trim();
    const rejectedAt = t.completionRejectedAt;
    const ackedBy = (t.completionRejectionAcknowledgedBy || '').trim();
    // Map the 5 known reasons to icon + descriptive subtext (matches the modal)
    const reasonMeta = {
      'Incomplete':       { icon: '⊘', desc: 'Missing required items or scope' },
      'Reverify':         { icon: '🔍', desc: 'Double-check numbers or sources' },
      'Start Over':       { icon: '↻', desc: 'Redo from scratch --- issues are systemic' },
      'Resubmit':         { icon: '↺', desc: 'Minor fixes needed, then resubmit' },
      'Schedule Meeting': { icon: '📅', desc: 'Discuss before moving forward' }
    };
    const meta = reasonMeta[reason] || { icon: '✗', desc: '' };
    const whenStr = rejectedAt ? formatDateTime(rejectedAt) : '';
    const whoLine = rejectedBy
      ? `Rejected by <strong>${escapeHtml(rejectedBy)}</strong>${whenStr ? ` · <span class="ai-rj-when">${whenStr}</span>` : ''}`
      : 'Rejected --- sender unknown';

    // Action buttons --- primary "Open & [verb]" button for edit-action reasons,
    // plus the inline Acknowledge action for the assignee/support members.
    // The primary button is reason-aware: each rejection reason maps to a
    // verb that matches the next action the assignee should take. It
    // dispatches to openAndResolveRejection(), which opens the task modal,
    // flips status from done→in-progress, and scrolls into the rejection
    // notice so the next-steps and notes are visible immediately.
    const currentUser = getCurrentUser();
    const isAssignee = currentUser && ((typeof isTaskLead === 'function')
      ? isTaskLead(t, currentUser)
      : (t.assignee && t.assignee.toLowerCase() === currentUser.toLowerCase()));
    const isSupport = currentUser && (typeof isTaskSupport === 'function') && isTaskSupport(t, currentUser);
    const editActionVerbs = {
      'Resubmit':         { label: 'Open & Fix',     title: 'Open the task in edit mode, status will revert to In Progress so you can apply fixes and resubmit',  cls: 'ai-rj-edit-btn-resubmit' },
      'Reverify':         { label: 'Open & Verify',  title: 'Open the task in edit mode, status will revert to In Progress so you can re-check numbers and sources', cls: 'ai-rj-edit-btn-reverify' },
      'Incomplete':       { label: 'Open & Complete', title: 'Open the task in edit mode, status will revert to In Progress so you can finish missing items',         cls: 'ai-rj-edit-btn-incomplete' },
      'Start Over':       { label: 'Open & Restart', title: 'Open the task in edit mode, status will revert to In Progress for a fresh redo',                          cls: 'ai-rj-edit-btn-startover' }
      // Note: 'Schedule Meeting' intentionally has NO edit verb --- the next
      // action there is coordination, not editing. Falls through to plain
      // "Open Task" button below.
    };
    const editVerb = editActionVerbs[reason];
    const canEdit = isAssignee || isSupport;
    let primaryAction = '';
    if (editVerb && canEdit) {
      primaryAction = `<button class="ai-rj-edit-btn ${editVerb.cls}" onclick="event.stopPropagation();openAndResolveRejection('${t.id}')" title="${escapeAttr(editVerb.title)}">→ ${escapeHtml(editVerb.label)}</button>`;
    } else if (!editVerb && canEdit) {
      // Schedule Meeting (or any unmapped reason) --- give a plain Open Task button
      // for completeness, since the assignee still needs to navigate in.
      primaryAction = `<button class="ai-rj-edit-btn ai-rj-edit-btn-meeting" onclick="event.stopPropagation();openAndResolveRejection('${t.id}', { keepStatus: true })" title="Open the task to coordinate next steps">→ Open Task</button>`;
    }
    let rejectionActions = '';
    if (!t.completionRejectionAcknowledged && (isAssignee || isSupport)) {
      rejectionActions = `${primaryAction}<button class="ai-rj-ack-btn" onclick="event.stopPropagation();acknowledgeRejectionFromAlert('${t.id}')" title="Mark this rejection as seen without changing status --- clears the alert from your list">✓ Acknowledge</button>`;
    } else if (t.completionRejectionAcknowledged && ackedBy) {
      rejectionActions = `${primaryAction}<span class="ai-rj-acked" title="Rejection acknowledged by ${escapeHtml(ackedBy)} on ${formatDateTime(t.completionRejectionAcknowledgedAt)}">✓ Acknowledged by ${escapeHtml(ackedBy)}</span>`;
    }

    rejectionBlock = `
      <div class="ai-rejection-block">
        <div class="ai-rj-header">
          <span class="ai-rj-reason-chip" title="${escapeAttr(meta.desc || 'Rejection reason')}">
            <span class="ai-rj-reason-icon">${meta.icon}</span>
            <span class="ai-rj-reason-label">${escapeHtml(reason || 'Rejected')}</span>
          </span>
          <span class="ai-rj-who">${whoLine}</span>
        </div>
        ${meta.desc ? `<div class="ai-rj-desc">${escapeHtml(meta.desc)}</div>` : ''}
        ${notes ? `
          <div class="ai-rj-notes">
            <div class="ai-rj-notes-label">Notes from ${escapeHtml(rejectedBy || 'Lead')}</div>
            <div class="ai-rj-notes-body">${escapeHtml(notes)}</div>
          </div>` : `<div class="ai-rj-notes-empty">No additional notes provided. Open the task for full context.</div>`}
        ${rejectionActions ? `<div class="ai-rj-actions">${rejectionActions}</div>` : ''}
      </div>`;
  }

  // Hours pill for the alert row --- small inline indicator.
  // Shows when feature is on AND task has an estimate. Hidden otherwise.
  let aiHoursPill = '';
  if (state.hoursEnabled && typeof t.estimatedHours === 'number' && t.estimatedHours > 0) {
    const fH = (typeof formatHours === 'function') ? formatHours(t.estimatedHours) : (t.estimatedHours + 'h');
    aiHoursPill = `<span class="ai-hours" title="Projected effort: ${escapeAttr(fH)}">⏱ ${escapeHtml(fH)}</span>`;
  }

  return `
    <div class="alert-item${tier === 'completed' ? ' alert-item-completion' : ''}${tier === 'unacknowledged' ? ' alert-item-unack' : ''}${tier === 'rejected' ? ' alert-item-rejected' : ''}" onclick="openTaskModal(null, '${t.id}')">
      <div class="ai-primary-row">
        <span class="ai-stage" title="${escapeHtml(stage.name)}">${stage.icon} ${escapeHtml(stage.name)}</span>
        <span class="ai-title" title="${escapeHtml(t.title)}">${escapeHtml(t.title)}</span>
        <span class="ai-assignee">${avatar}${escapeHtml(assigneeLabel)}</span>
        <span class="ai-due">${dueText}</span>
        ${aiHoursPill}
        <span class="ai-flag ${flagCls}">${flagIcon}${flagLabel}</span>
        <div class="ai-actions">${signoffButton}${ackInlineBtn}</div>
      </div>
      ${rejectionBlock}
      ${detailsRow}
    </div>
  `;
}

function toggleAlertPanel(tier) {
  state.activeAlertTier = state.activeAlertTier === tier ? null : tier;
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) {
    renderAlertStrip(project);
    renderAssigneeAlertsStrip(project);
  }
}

function closeAlertPanel() {
  state.activeAlertTier = null;
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) {
    renderAlertStrip(project);
    renderAssigneeAlertsStrip(project);
  }
}

// =============================================================
// COLLAPSIBLE SIDEBAR
// =============================================================
// =============================================================
// GLOBAL SEARCH --- search across projects, tasks, messages, addenda, scope packages
// Live results dropdown as the user types. Searches everything in state regardless
// of which project is currently active. Click a result to jump to it.
// =============================================================

let globalSearchSelectedIndex = -1; // for keyboard navigation
let globalSearchResultsCache = []; // most recent result list, used by Enter handler

// Highlight matching text in a result label by wrapping the matched substring in <mark>
function highlightSearchMatch(text, query) {
  if (!text || !query) return escapeHtml(text || '');
  const escaped = escapeHtml(text);
  const lowerText = text.toLowerCase();
  const lowerQuery = query.toLowerCase();
  const idx = lowerText.indexOf(lowerQuery);
  if (idx === -1) return escaped;
  // Find the matching range in the escaped string --- escapeHtml may have shifted positions
  // due to & → &amp; etc. Easiest: re-do the highlight on the original then escape segments.
  const before = text.substring(0, idx);
  const match = text.substring(idx, idx + query.length);
  const after = text.substring(idx + query.length);
  return `${escapeHtml(before)}<mark class="gs-mark">${escapeHtml(match)}</mark>${escapeHtml(after)}`;
}

// Truncate a long string and place ellipsis around the match if possible
function snippetAroundMatch(text, query, maxLen) {
  if (!text) return '';
  const len = text.length;
  if (len <= maxLen) return text;
  const lower = text.toLowerCase();
  const q = (query || '').toLowerCase();
  const idx = q ? lower.indexOf(q) : -1;
  if (idx === -1) return text.substring(0, maxLen) + '...';
  // Center the snippet around the match
  const halfWindow = Math.floor((maxLen - q.length) / 2);
  const start = Math.max(0, idx - halfWindow);
  const end = Math.min(len, idx + q.length + halfWindow);
  let snippet = text.substring(start, end);
  if (start > 0) snippet = '...' + snippet;
  if (end < len) snippet = snippet + '...';
  return snippet;
}

function performGlobalSearch(query) {
  const trimmed = (query || '').trim();
  const resultsEl = document.getElementById('globalSearchResults');
  const clearBtn = document.getElementById('gsClearBtn');

  if (clearBtn) clearBtn.style.display = trimmed ? 'flex' : 'none';

  if (!trimmed || trimmed.length < 2) {
    if (resultsEl) {
      resultsEl.style.display = 'none';
      resultsEl.innerHTML = '';
    }
    globalSearchResultsCache = [];
    globalSearchSelectedIndex = -1;
    return;
  }

  const q = trimmed.toLowerCase();
  const results = [];
  const MAX_RESULTS = 30;

  // 1. Projects --- match name, client, location, architect
  (state.projects || []).forEach(p => {
    const fields = [
      { val: p.name, label: 'name' },
      { val: p.client, label: 'owner' },
      { val: p.location, label: 'location' },
      { val: p.architect, label: 'architect' },
      { val: p.type, label: 'type' }
    ];
    for (const f of fields) {
      if (f.val && String(f.val).toLowerCase().includes(q)) {
        results.push({
          type: 'project',
          icon: '📁',
          label: p.name,
          context: f.label === 'name'
            ? [p.client, p.location].filter(Boolean).join(' · ')
            : `${f.label}: ${f.val}`,
          projectId: p.id,
          taskId: null,
          rank: f.label === 'name' ? 1 : 2
        });
        return; // one hit per project
      }
    }
  });

  // 2. Tasks --- match title, notes, category, assignee, support
  (state.projects || []).forEach(p => {
    (p.tasks || []).forEach(t => {
      let matchedField = null;
      let matchedText = null;
      if (t.title && t.title.toLowerCase().includes(q)) {
        matchedField = 'title';
        matchedText = t.title;
      } else if (t.notes && t.notes.toLowerCase().includes(q)) {
        matchedField = 'notes';
        matchedText = t.notes;
      } else if (t.category && t.category.toLowerCase().includes(q)) {
        matchedField = 'category';
        matchedText = t.category;
      } else if (t.assignee && t.assignee.toLowerCase().includes(q)) {
        matchedField = 'assignee';
        matchedText = t.assignee;
      } else if ((t.support || '').toLowerCase().includes(q) ||
                 (Array.isArray(t.supportMembers) && t.supportMembers.some(s => (s || '').toLowerCase().includes(q)))) {
        matchedField = 'support';
        const allSupports = getAllSupportMembers(t);
        matchedText = allSupports.find(s => s.toLowerCase().includes(q)) || allSupports.join(', ');
      } else if (Array.isArray(t.checklist) && t.checklist.some(item => (item.text || '').toLowerCase().includes(q))) {
        matchedField = 'checklist';
        const matchingItem = t.checklist.find(item => (item.text || '').toLowerCase().includes(q));
        matchedText = matchingItem ? matchingItem.text : '';
      }

      if (matchedField) {
        const stage = STAGES.find(s => s.id === t.stage);
        const stageLabel = stage ? stage.name : t.stage;
        let context;
        if (matchedField === 'title') {
          context = `${stageLabel} · ${p.name}`;
        } else if (matchedField === 'notes') {
          context = `Notes: "${snippetAroundMatch(t.notes, trimmed, 80)}" · ${p.name}`;
        } else if (matchedField === 'checklist') {
          context = `Checklist: "${snippetAroundMatch(matchedText, trimmed, 80)}" · ${p.name}`;
        } else {
          context = `${matchedField}: ${matchedText} · ${p.name}`;
        }
        results.push({
          type: 'task',
          icon: '✓',
          label: t.title,
          context,
          projectId: p.id,
          taskId: t.id,
          rank: matchedField === 'title' ? 3 : 4
        });
      }
    });
  });

  // 3. Project-level messages
  (state.projects || []).forEach(p => {
    (p.messages || []).forEach(m => {
      const body = m.body || m.text || '';
      if (body.toLowerCase().includes(q)) {
        const author = m.author || 'Unknown';
        results.push({
          type: 'message',
          icon: '💬',
          label: `${author}: "${snippetAroundMatch(body, trimmed, 80)}"`,
          context: `Project message · ${p.name}`,
          projectId: p.id,
          taskId: null,
          rank: 5
        });
      }
    });
  });

  // 4. Task-level messages
  (state.projects || []).forEach(p => {
    (p.tasks || []).forEach(t => {
      (t.messages || []).forEach(m => {
        const body = m.body || m.text || '';
        if (body.toLowerCase().includes(q)) {
          const author = m.author || 'Unknown';
          results.push({
            type: 'task-message',
            icon: '💬',
            label: `${author}: "${snippetAroundMatch(body, trimmed, 80)}"`,
            context: `Message on "${t.title}" · ${p.name}`,
            projectId: p.id,
            taskId: t.id,
            rank: 5
          });
        }
      });
    });
  });

  // 5. Addendum log entries
  (state.projects || []).forEach(p => {
    (p.addenda || []).forEach(a => {
      const fieldsToCheck = [a.title, a.summary, a.notes, a.number].filter(Boolean);
      const matched = fieldsToCheck.find(v => String(v).toLowerCase().includes(q));
      if (matched) {
        results.push({
          type: 'addendum',
          icon: '📑',
          label: `Addendum #${a.number || '?'}: ${a.title || '(untitled)'}`,
          context: `${snippetAroundMatch(String(matched), trimmed, 80)} · ${p.name}`,
          projectId: p.id,
          taskId: null,
          rank: 6
        });
      }
    });
  });

  // 6. Scope packages
  (state.projects || []).forEach(p => {
    (p.scopePackages || []).forEach(s => {
      if ((s.name || '').toLowerCase().includes(q) || (s.description || '').toLowerCase().includes(q)) {
        results.push({
          type: 'scope',
          icon: s.icon || '📦',
          label: s.name || '(unnamed scope)',
          context: `Scope package · ${p.name}`,
          projectId: p.id,
          taskId: null,
          rank: 7,
          scopePackageId: s.id
        });
      }
    });
  });

  // 7. Team members --- jumping to a member shows tasks assigned to them
  (state.teamMembers || []).forEach(m => {
    if (!m.name) return;
    if (m.name.toLowerCase().includes(q) || (m.title || '').toLowerCase().includes(q) || (m.email || '').toLowerCase().includes(q)) {
      results.push({
        type: 'team',
        icon: '👤',
        label: m.name,
        context: `${m.title || 'Team Member'}${m.email ? ' · ' + m.email : ''}`,
        projectId: null,
        taskId: null,
        memberName: m.name,
        rank: 8
      });
    }
  });

  // Sort by rank, then alphabetically by label
  results.sort((a, b) => {
    if (a.rank !== b.rank) return a.rank - b.rank;
    return (a.label || '').localeCompare(b.label || '');
  });

  // Trim to max
  const truncated = results.slice(0, MAX_RESULTS);
  const totalCount = results.length;
  globalSearchResultsCache = truncated;
  globalSearchSelectedIndex = -1;

  // Render results dropdown
  if (truncated.length === 0) {
    resultsEl.innerHTML = `<div class="gs-no-results">No results for "<strong>${escapeHtml(trimmed)}</strong>"</div>`;
    resultsEl.style.display = 'block';
    return;
  }

  // Group by type for visual sectioning
  const grouped = new Map();
  const typeLabels = {
    'project': 'Projects',
    'task': 'Tasks',
    'message': 'Project Messages',
    'task-message': 'Task Messages',
    'addendum': 'Addenda',
    'scope': 'Scope Packages',
    'team': 'Team Members'
  };
  truncated.forEach(r => {
    if (!grouped.has(r.type)) grouped.set(r.type, []);
    grouped.get(r.type).push(r);
  });

  let html = '';
  let runningIdx = 0;
  // Iterate in the same order as sort rank
  ['project', 'task', 'message', 'task-message', 'addendum', 'scope', 'team'].forEach(type => {
    const items = grouped.get(type);
    if (!items || items.length === 0) return;
    html += `<div class="gs-group-header">${typeLabels[type]} <span class="gs-group-count">${items.length}</span></div>`;
    items.forEach(r => {
      const idx = runningIdx++;
      html += `
        <div class="gs-result" data-idx="${idx}" onclick="jumpToSearchResult(${idx})" onmouseenter="setGlobalSearchSelected(${idx})">
          <span class="gs-result-icon">${escapeHtml(r.icon)}</span>
          <div class="gs-result-body">
            <div class="gs-result-label">${highlightSearchMatch(r.label, trimmed)}</div>
            <div class="gs-result-context">${highlightSearchMatch(r.context || '', trimmed)}</div>
          </div>
        </div>
      `;
    });
  });

  if (totalCount > MAX_RESULTS) {
    html += `<div class="gs-truncate-note">Showing top ${MAX_RESULTS} of ${totalCount} matches --- refine your search to narrow further.</div>`;
  }

  resultsEl.innerHTML = html;
  resultsEl.style.display = 'block';
}

function setGlobalSearchSelected(idx) {
  globalSearchSelectedIndex = idx;
  document.querySelectorAll('.gs-result').forEach(el => {
    el.classList.toggle('selected', parseInt(el.dataset.idx, 10) === idx);
  });
}

function handleGlobalSearchKey(e) {
  const items = globalSearchResultsCache;
  if (e.key === 'Escape') {
    e.preventDefault();
    clearGlobalSearch();
    e.target.blur();
  } else if (e.key === 'ArrowDown') {
    e.preventDefault();
    if (items.length === 0) return;
    globalSearchSelectedIndex = Math.min(items.length - 1, globalSearchSelectedIndex + 1);
    setGlobalSearchSelected(globalSearchSelectedIndex);
    // Scroll selected into view
    const sel = document.querySelector('.gs-result.selected');
    if (sel) sel.scrollIntoView({ block: 'nearest' });
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    if (items.length === 0) return;
    globalSearchSelectedIndex = Math.max(0, globalSearchSelectedIndex - 1);
    setGlobalSearchSelected(globalSearchSelectedIndex);
    const sel = document.querySelector('.gs-result.selected');
    if (sel) sel.scrollIntoView({ block: 'nearest' });
  } else if (e.key === 'Enter') {
    e.preventDefault();
    if (items.length === 0) return;
    const target = globalSearchSelectedIndex >= 0 ? globalSearchSelectedIndex : 0;
    jumpToSearchResult(target);
  }
}

function jumpToSearchResult(idx) {
  const result = globalSearchResultsCache[idx];
  if (!result) return;

  // Close the dropdown
  clearGlobalSearch();

  // Switch to the project if specified
  if (result.projectId && state.activeProjectId !== result.projectId) {
    state.activeProjectId = result.projectId;
    saveState();
  }

  // Type-specific routing
  if (result.type === 'project') {
    state.homeView = false;
    saveState();
    render();
  } else if (result.type === 'task' || result.type === 'task-message') {
    state.homeView = false;
    saveState();
    render();
    // Open the task modal
    setTimeout(() => openTaskModal(null, result.taskId), 100);
  } else if (result.type === 'message') {
    state.homeView = false;
    saveState();
    render();
    // Open the project messages thread if available
    setTimeout(() => {
      if (typeof openProjectMessages === 'function') openProjectMessages();
    }, 100);
  } else if (result.type === 'addendum') {
    state.homeView = false;
    saveState();
    render();
    // Scroll to the addendum log section if it exists
    setTimeout(() => {
      const addendaSection = document.getElementById('addendaSection') || document.querySelector('.addenda-log');
      if (addendaSection) addendaSection.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 200);
  } else if (result.type === 'scope') {
    state.homeView = false;
    saveState();
    render();
    // Optionally filter to that scope package --- for now just open the project
  } else if (result.type === 'team') {
    // Switch grouping to assignee + filter to this person, in the active project
    if (state.projects.length > 0) {
      state.grouping = 'assignee';
      state.activeAssignee = result.memberName;
      state.homeView = false;
      saveState();
      render();
    }
  }
}

function clearGlobalSearch() {
  const input = document.getElementById('globalSearchInput');
  const resultsEl = document.getElementById('globalSearchResults');
  const clearBtn = document.getElementById('gsClearBtn');
  if (input) input.value = '';
  if (resultsEl) {
    resultsEl.style.display = 'none';
    resultsEl.innerHTML = '';
  }
  if (clearBtn) clearBtn.style.display = 'none';
  globalSearchResultsCache = [];
  globalSearchSelectedIndex = -1;
}

function onGlobalSearchFocus() {
  // If there's already text in the input, re-show the results dropdown
  const input = document.getElementById('globalSearchInput');
  if (input && input.value.trim()) {
    performGlobalSearch(input.value);
  }
}

// Close the search dropdown when clicking outside the search wrapper
document.addEventListener('click', function(e) {
  const wrapper = document.getElementById('globalSearchWrapper');
  if (!wrapper) return;
  if (!wrapper.contains(e.target)) {
    const resultsEl = document.getElementById('globalSearchResults');
    if (resultsEl) resultsEl.style.display = 'none';
  }
});

// Keyboard shortcut --- `/` or Cmd/Ctrl+K to focus the search bar from anywhere
document.addEventListener('keydown', function(e) {
  // Skip if the user is typing in an input/textarea/contenteditable element already
  const activeTag = document.activeElement ? document.activeElement.tagName : '';
  const isEditing = activeTag === 'INPUT' || activeTag === 'TEXTAREA' || activeTag === 'SELECT' ||
                    (document.activeElement && document.activeElement.isContentEditable);

  // Helper: expand sidebar if collapsed, then focus search
  const focusSearchBar = () => {
    if (state.sidebarCollapsed) {
      state.sidebarCollapsed = false;
      saveState();
      const sidebar = document.getElementById('appSidebar');
      if (sidebar) sidebar.classList.remove('collapsed');
    }
    const input = document.getElementById('globalSearchInput');
    if (input) {
      input.focus();
      input.select();
    }
  };

  // `/` shortcut --- only when not already typing
  if (e.key === '/' && !isEditing && !e.metaKey && !e.ctrlKey && !e.altKey) {
    e.preventDefault();
    focusSearchBar();
    return;
  }

  // Cmd/Ctrl+K --- works even when typing in another input
  if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
    e.preventDefault();
    focusSearchBar();
  }
});

// =============================================================
// BULK TASK EDITING --- selection mode + multi-task operations
// User toggles selection mode → checkboxes appear on cards/rows →
// click to select tasks → floating action bar at bottom shows operations.
// All operations open a generic dialog (bulkEditModal) configured per-op.
// =============================================================

let pendingBulkOperation = null; // {type, ...config} while bulk dialog is open

// Toggle bulk selection mode on/off
function toggleBulkSelectionMode() {
  state.bulkSelectionMode = !state.bulkSelectionMode;
  // Always clear selection when toggling mode
  state.bulkSelectedTaskIds = [];
  updateBulkSelectToggleBtn();
  updateBulkActionBar();
  render();
}

function updateBulkSelectToggleBtn() {
  const btn = document.getElementById('bulkSelectToggleBtn');
  if (!btn) return;
  if (state.bulkSelectionMode) {
    btn.innerHTML = '✕ Exit Selection';
    btn.classList.add('bulk-mode-active');
  } else {
    btn.innerHTML = '☐ Select Multiple';
    btn.classList.remove('bulk-mode-active');
  }
}

// Toggle a task's selection state
function toggleTaskSelection(event, taskId) {
  if (event) {
    event.stopPropagation();
    event.preventDefault();
  }
  if (!state.bulkSelectionMode) return;
  const idx = state.bulkSelectedTaskIds.indexOf(taskId);
  if (idx === -1) {
    state.bulkSelectedTaskIds.push(taskId);
  } else {
    state.bulkSelectedTaskIds.splice(idx, 1);
  }
  updateBulkActionBar();
  // Update only the affected card/row class, no full re-render needed
  document.querySelectorAll(`[data-task-id="${taskId}"]`).forEach(el => {
    el.classList.toggle('bulk-selected', state.bulkSelectedTaskIds.includes(taskId));
  });
  document.querySelectorAll(`.bulk-checkbox[data-task-id="${taskId}"]`).forEach(cb => {
    cb.checked = state.bulkSelectedTaskIds.includes(taskId);
  });
}

function isTaskSelected(taskId) {
  return state.bulkSelectedTaskIds.includes(taskId);
}

// Select every task currently visible (respects active filters/grouping/view)
function bulkSelectAllVisible() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const visibleTasks = getFilteredTasks(project);
  state.bulkSelectedTaskIds = visibleTasks.map(t => t.id);
  updateBulkActionBar();
  render();
}

function bulkClearSelection() {
  state.bulkSelectedTaskIds = [];
  updateBulkActionBar();
  render();
}

function updateBulkActionBar() {
  const bar = document.getElementById('bulkActionBar');
  if (!bar) return;
  const count = state.bulkSelectedTaskIds.length;
  if (state.bulkSelectionMode) {
    bar.style.display = 'flex';
    bar.classList.toggle('has-selection', count > 0);
  } else {
    bar.style.display = 'none';
  }
  const countEl = document.getElementById('bulkSelectedCount');
  if (countEl) countEl.textContent = count;
}

// Returns the live array of selected task objects from the active project
function getSelectedTasks() {
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return [];
  return state.bulkSelectedTaskIds
    .map(id => project.tasks.find(t => t.id === id))
    .filter(Boolean);
}

// Configure and open the generic bulk-edit modal for a given operation
function openBulkEditDialog(config) {
  if (state.bulkSelectedTaskIds.length === 0) {
    alert('Select at least one task first.');
    return;
  }
  pendingBulkOperation = config;

  document.getElementById('bulkEditTitle').textContent = config.title;
  document.getElementById('bulkEditDescription').textContent = config.description || '';

  // Render summary --- list of selected tasks (truncated if many)
  const tasks = getSelectedTasks();
  const summaryEl = document.getElementById('bulkEditSummary');
  const maxShow = 6;
  const visible = tasks.slice(0, maxShow);
  const overflow = tasks.length - visible.length;
  summaryEl.innerHTML = `
    <div class="bes-header">${tasks.length} task${tasks.length === 1 ? '' : 's'} selected:</div>
    <ul class="bes-list">
      ${visible.map(t => {
        const stage = STAGES.find(s => s.id === t.stage);
        const stageLabel = stage ? `${stage.icon} ${stage.name}` : '';
        return `<li><strong>${escapeHtml(t.title)}</strong> <span class="bes-meta">${escapeHtml(stageLabel)}${t.dueDate ? ' · Due ' + formatDate(t.dueDate) : ''}</span></li>`;
      }).join('')}
      ${overflow > 0 ? `<li class="bes-overflow">...and ${overflow} more</li>` : ''}
    </ul>
  `;

  document.getElementById('bulkEditFieldArea').innerHTML = config.fieldHtml || '';
  document.getElementById('bulkEditApplyCount').textContent = tasks.length;

  // Run optional post-render hook (for binding events, populating dropdowns, etc.)
  if (typeof config.afterRender === 'function') {
    setTimeout(config.afterRender, 0);
  }

  document.getElementById('bulkEditModal').classList.add('active');
}

// Apply the pending bulk operation by running its handler against each selected task
function applyBulkEdit() {
  if (!pendingBulkOperation) return;
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const tasks = getSelectedTasks();

  // Validate via op handler (op may show its own error and return false)
  if (typeof pendingBulkOperation.validate === 'function') {
    const valid = pendingBulkOperation.validate(tasks);
    if (!valid) return;
  }

  // Reset the per-run blocked-task list before applying
  window._bulkBlockedTaskTitles = [];

  let successCount = 0;
  let skipCount = 0;
  tasks.forEach(t => {
    const result = pendingBulkOperation.applyToTask(t, project);
    if (result === false) skipCount++;
    else successCount++;
  });

  // ACTIVITY LOG: log the bulk operation
  if (successCount > 0) {
    logBulkOperation(project, pendingBulkOperation.type || 'edit', successCount, pendingBulkOperation.title || '');
  }

  saveState();
  closeModal('bulkEditModal');
  pendingBulkOperation = null;
  render();

  // Confirmation toast
  setTimeout(() => {
    let msg = `✓ Updated ${successCount} task${successCount === 1 ? '' : 's'}.`;
    const blocked = window._bulkBlockedTaskTitles || [];
    if (blocked.length > 0) {
      msg += `\n\n🚫 ${blocked.length} task${blocked.length === 1 ? '' : 's'} blocked from being marked Complete due to unfinished required items:`;
      blocked.slice(0, 5).forEach(title => msg += `\n   • ${title}`);
      if (blocked.length > 5) msg += `\n   ... and ${blocked.length - 5} more`;
      msg += `\n\nFinish required checklist items + deliverables on those tasks first, or have the Lead untoggle the REQ flag on items that aren't truly required.`;
    } else if (skipCount > 0) {
      msg += `\n${skipCount} skipped (already at target value or not eligible).`;
    }
    window._bulkBlockedTaskTitles = [];
    alert(msg);
  }, 100);
}

// =============================================================
// BULK OPERATION DEFINITIONS
// Each operation configures the generic dialog with title, description,
// field HTML, validators, and a per-task apply handler.
// =============================================================

function openBulkStatusDialog() {
  openBulkEditDialog({
    type: 'status',
    title: '🔄 Change Status',
    description: 'Set the status for all selected tasks.',
    fieldHtml: `
      <div class="form-group">
        <label>New Status</label>
        <select id="bulkEditStatus">
          <option value="not-started">Not Started</option>
          <option value="in-progress">In Progress</option>
          <option value="blocked">Blocked / RFI</option>
          <option value="pending">Pending</option>
          <option value="done">Complete</option>
        </select>
      </div>
    `,
    applyToTask: (t) => {
      const newStatus = document.getElementById('bulkEditStatus').value;
      if (t.status === newStatus) return false;
      const oldStatus = t.status;
      // ===== GUARDRAIL: silently skip tasks that would be blocked =====
      // For bulk operations we don't show the modal per-task --- instead we
      // skip blocked tasks and let the bulk-runner aggregate the count.
      if (newStatus === 'done' && oldStatus !== 'done') {
        const r = getTaskReadiness(t);
        if (!r.isReady) {
          if (!window._bulkBlockedTaskTitles) window._bulkBlockedTaskTitles = [];
          window._bulkBlockedTaskTitles.push(t.title || '(untitled)');
          return false;
        }
      }
      t.status = newStatus;
      // Reset completion ack when transitioning to/from done
      if (newStatus === 'done' && oldStatus !== 'done') {
        t.completionAcknowledged = false;
        t.completionAcknowledgedBy = '';
        t.completionAcknowledgedAt = null;
      } else if (oldStatus === 'done' && newStatus !== 'done') {
        t.completionAcknowledged = false;
        t.completionAcknowledgedBy = '';
        t.completionAcknowledgedAt = null;
        delete t._recurrenceSpawned;
      }
      return true;
    }
  });
}

function openBulkAssigneeDialog() {
  // Build a roster dropdown
  const rosterOptions = ['<option value="">--- Unassigned ---</option>'];
  (state.teamMembers || []).forEach(m => {
    rosterOptions.push(`<option value="${escapeHtml(m.name)}">${escapeHtml(m.name)}${m.title ? ' (' + escapeHtml(m.title) + ')' : ''}</option>`);
  });

  openBulkEditDialog({
    type: 'assignee',
    title: '👤 Reassign Lead Owner',
    description: 'Set a new Lead Owner for all selected tasks. Existing acknowledgments will be cleared (the new assignee will need to re-acknowledge).',
    fieldHtml: `
      <div class="form-group">
        <label>New Lead Owner</label>
        <select id="bulkEditAssignee">${rosterOptions.join('')}</select>
      </div>
    `,
    applyToTask: (t) => {
      const newAssignee = document.getElementById('bulkEditAssignee').value;
      if ((t.assignee || '') === newAssignee) return false;
      t.assignee = newAssignee;
      // Reset acknowledgment so the new assignee gets prompted to ack
      t.acknowledged = !newAssignee; // auto-ack if unassigned
      t.acknowledgedBy = '';
      t.acknowledgedAt = null;
      return true;
    }
  });
}

function openBulkSupportDialog() {
  // Build options
  const rosterOptions = [];
  (state.teamMembers || []).forEach(m => {
    rosterOptions.push(`<option value="${escapeHtml(m.name)}">${escapeHtml(m.name)}${m.title ? ' (' + escapeHtml(m.title) + ')' : ''}</option>`);
  });

  openBulkEditDialog({
    type: 'support',
    title: '👥 Bulk Support Members',
    description: 'Add or remove support members across all selected tasks.',
    fieldHtml: `
      <div class="form-group">
        <label>Action</label>
        <select id="bulkEditSupportAction" onchange="document.getElementById('bulkEditSupportPerson').disabled = this.value === 'clear-all';">
          <option value="add">Add a person as support</option>
          <option value="remove">Remove a person from support</option>
          <option value="clear-all">Clear all support members</option>
        </select>
      </div>
      <div class="form-group">
        <label>Team Member</label>
        <select id="bulkEditSupportPerson">${rosterOptions.join('')}</select>
        <div class="hint-inline">Ignored when "Clear all support members" is selected.</div>
      </div>
    `,
    applyToTask: (t) => {
      const action = document.getElementById('bulkEditSupportAction').value;
      const name = document.getElementById('bulkEditSupportPerson').value;
      if (action === 'clear-all') {
        if (!t.support && (!t.supportMembers || t.supportMembers.length === 0)) return false;
        t.support = '';
        t.supportMembers = [];
        return true;
      }
      if (!name) return false;
      // Ignore if person is the Lead
      if ((t.assignee || '').toLowerCase() === name.toLowerCase()) return false;

      const all = getAllSupportMembers(t);
      const isCurrentlySupport = all.some(s => s.toLowerCase() === name.toLowerCase());

      if (action === 'add') {
        if (isCurrentlySupport) return false; // already there
        if (!t.support) {
          t.support = name;
        } else {
          if (!Array.isArray(t.supportMembers)) t.supportMembers = [];
          t.supportMembers.push(name);
        }
        return true;
      } else if (action === 'remove') {
        if (!isCurrentlySupport) return false;
        if ((t.support || '').toLowerCase() === name.toLowerCase()) {
          // Promote first additional support to primary, or clear
          if (Array.isArray(t.supportMembers) && t.supportMembers.length > 0) {
            t.support = t.supportMembers.shift();
          } else {
            t.support = '';
          }
        } else if (Array.isArray(t.supportMembers)) {
          t.supportMembers = t.supportMembers.filter(s => s.toLowerCase() !== name.toLowerCase());
        }
        return true;
      }
      return false;
    }
  });
}

