function openBulkDueDateDialog() {
  openBulkEditDialog({
    type: 'duedate',
    title: '📅 Change Due Dates',
    description: 'Shift or set due dates on all selected tasks. Pick an action below.',
    fieldHtml: `
      <div class="form-group">
        <label>Action</label>
        <select id="bulkEditDueAction" onchange="updateBulkDueFieldVisibility()">
          <option value="set">Set all to a specific date</option>
          <option value="shift-days">Shift by N days (positive = later, negative = earlier)</option>
          <option value="clear">Clear all due dates</option>
        </select>
      </div>
      <div class="form-group" id="bulkEditDueDateGroup">
        <label>Date</label>
        <input type="date" id="bulkEditDueDate">
      </div>
      <div class="form-group" id="bulkEditDueShiftGroup" style="display:none;">
        <label>Shift By</label>
        <div style="display:flex;align-items:center;gap:8px;">
          <input type="number" id="bulkEditDueShift" placeholder="e.g., 7 or -3" style="width:120px;">
          <span style="color:var(--text-dim);font-size:12px;">days</span>
        </div>
        <div class="hint-inline">Tasks without a due date will be skipped.</div>
      </div>
    `,
    afterRender: () => updateBulkDueFieldVisibility(),
    applyToTask: (t) => {
      const action = document.getElementById('bulkEditDueAction').value;
      if (action === 'set') {
        const newDate = document.getElementById('bulkEditDueDate').value;
        if (!newDate) return false;
        if (t.dueDate === newDate) return false;
        t.dueDate = newDate;
        // Clear day offset if it was set --- explicit date overrides offset
        t.dayOffset = null;
        return true;
      }
      if (action === 'shift-days') {
        const shift = parseInt(document.getElementById('bulkEditDueShift').value, 10);
        if (isNaN(shift) || shift === 0) return false;
        if (!t.dueDate) return false; // skip tasks without dates
        t.dueDate = addDays(t.dueDate, shift);
        // If task had a day offset, also update it
        if (typeof t.dayOffset === 'number') {
          t.dayOffset += shift;
        }
        return true;
      }
      if (action === 'clear') {
        if (!t.dueDate) return false;
        t.dueDate = '';
        t.dayOffset = null;
        return true;
      }
      return false;
    }
  });
}

function updateBulkDueFieldVisibility() {
  const action = document.getElementById('bulkEditDueAction').value;
  document.getElementById('bulkEditDueDateGroup').style.display = action === 'set' ? 'block' : 'none';
  document.getElementById('bulkEditDueShiftGroup').style.display = action === 'shift-days' ? 'block' : 'none';
}

