// Bulk delete --- confirmation only, no separate dialog
function bulkDelete() {
  const tasks = getSelectedTasks();
  if (tasks.length === 0) {
    alert('Select at least one task first.');
    return;
  }
  const titles = tasks.slice(0, 5).map(t => '• ' + t.title).join('\n');
  const overflow = tasks.length > 5 ? `\n...and ${tasks.length - 5} more` : '';
  if (!confirm(`Delete ${tasks.length} task${tasks.length === 1 ? '' : 's'}?\n\n${titles}${overflow}\n\nThis cannot be undone.`)) return;

  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (!project) return;
  const idsToDelete = new Set(state.bulkSelectedTaskIds);
  // ACTIVITY LOG: log the bulk delete with task titles for audit trail
  const taskTitleSummary = tasks.slice(0, 3).map(t => t.title).join(', ') + (tasks.length > 3 ? ` +${tasks.length - 3} more` : '');
  logBulkOperation(project, 'delete', tasks.length, taskTitleSummary);
  project.tasks = project.tasks.filter(t => !idsToDelete.has(t.id));
  state.bulkSelectedTaskIds = [];
  saveState();
  render();
  setTimeout(() => alert(`✓ Deleted ${tasks.length} task${tasks.length === 1 ? '' : 's'}.`), 100);
}

