// =============================================================
// COLLAPSIBLE SECTIONS (Alerts, Countdown, Milestones)
// =============================================================
function getSectionCollapsed(key) {
  if (!state.collapsedSections) state.collapsedSections = {};
  return !!state.collapsedSections[key];
}

function toggleSection(key) {
  if (!state.collapsedSections) state.collapsedSections = {};
  state.collapsedSections[key] = !state.collapsedSections[key];
  saveState();
  applySectionStates();
}

function applySectionStates() {
  const mapping = { snapshot: 'pvSectionSnapshot', alerts: 'pvSectionAlerts', countdown: 'pvSectionCountdown', addendums: 'pvSectionAddendums', milestones: 'pvSectionMilestones' };
  Object.keys(mapping).forEach(key => {
    const el = document.getElementById(mapping[key]);
    if (!el) return;
    el.classList.toggle('collapsed', getSectionCollapsed(key));
  });
}

function collapseAllSections() {
  if (!state.collapsedSections) state.collapsedSections = {};
  state.collapsedSections.snapshot = true;
  state.collapsedSections.alerts = true;
  state.collapsedSections.countdown = true;
  state.collapsedSections.addendums = true;
  state.collapsedSections.milestones = true;
  saveState();
  applySectionStates();
}

function expandAllSections() {
  if (!state.collapsedSections) state.collapsedSections = {};
  state.collapsedSections.snapshot = false;
  state.collapsedSections.alerts = false;
  state.collapsedSections.countdown = false;
  state.collapsedSections.addendums = false;
  state.collapsedSections.milestones = false;
  saveState();
  applySectionStates();
}

function renderSectionSummaries(project) {
  // Update My Alerts scope label with the current user's name
  const ascMyLabel = document.getElementById('ascMyLabel');
  if (ascMyLabel) {
    const u = getCurrentUser();
    ascMyLabel.textContent = u ? `Filtered to ${u}` : 'Sign in to see your personal alerts';
  }

  // ===== Alerts summary =====
  const alertsSummaryEl = document.getElementById('pvAlertsSummary');
  const alertsEmptyEl = document.getElementById('pvAlertsEmpty');
  const alertsSection = document.getElementById('pvSectionAlerts');
  if (alertsSummaryEl && project) {
    // ----- Project-wide totals -----
    const overdue = getTasksByAlertTier(project, 'overdue').length;
    const imminent = getTasksByAlertTier(project, 'imminent').length;
    const soon = getTasksByAlertTier(project, 'soon').length;
    const unassigned = getTasksByAlertTier(project, 'unassigned').length;
    const unack = getTasksByAlertTier(project, 'unacknowledged').length;
    const pending = getTasksByAlertTier(project, 'pending').length;
    const completed = getTasksByAlertTier(project, 'completed').length;
    const rejectedCount = getTasksByAlertTier(project, 'rejected').length;
    const inProgress = getTasksByAlertTier(project, 'in-progress').length;
    const blocked = getTasksByAlertTier(project, 'blocked').length;
    const atRisk = getTasksByAlertTier(project, 'at-risk').length;
    const lateStart = getTasksByAlertTier(project, 'late-start').length;
    const projectTotal = overdue + imminent + soon + unassigned + unack + pending + completed + rejectedCount + inProgress + blocked + atRisk + lateStart;

    // ----- "Mine" totals (scoped to current user) -----
    const currentUser2 = getCurrentUser();
    let mineTotal = 0;
    let myOverdue = 0, myImminent = 0, myUnack = 0, myUnreadMsgs = 0, myRejected = 0;
    let myReceipts = 0;
    let myInProgress = 0, myBlocked = 0, myAtRisk = 0, myLateStart = 0;
    if (currentUser2) {
      myOverdue = getTasksByAlertTier(project, 'overdue', 'my').length;
      myImminent = getTasksByAlertTier(project, 'imminent', 'my').length;
      const mySoon = getTasksByAlertTier(project, 'soon', 'my').length;
      const myUnassigned = getTasksByAlertTier(project, 'unassigned', 'my').length;
      myUnack = getTasksByAlertTier(project, 'unacknowledged', 'my').length;
      const myPending = getTasksByAlertTier(project, 'pending', 'my').length;
      const myCompleted = getTasksByAlertTier(project, 'completed', 'my').length;
      myInProgress = getTasksByAlertTier(project, 'in-progress', 'my').length;
      myBlocked = getTasksByAlertTier(project, 'blocked', 'my').length;
      myAtRisk = getTasksByAlertTier(project, 'at-risk', 'my').length;
      myLateStart = getTasksByAlertTier(project, 'late-start', 'my').length;
      myUnreadMsgs = getUnreadMessagesForUser(project, currentUser2).length;
      myReceipts = getUnseenReceiptsForSender(project, currentUser2).length;
      // Rejected scoped to current user --- same logic as in renderScopedAlertStrip
      const lead = (project.leadEstimator || '').trim();
      const isLead = lead && currentUser2.toLowerCase() === lead.toLowerCase();
      myRejected = project.tasks.filter(t => {
        if (!t.completionRejected) return false;
        const isMine = (typeof isTaskMember === 'function')
          ? isTaskMember(t, currentUser2)
          : ((t.assignee && t.assignee.toLowerCase() === currentUser2.toLowerCase()) || isTaskSupport(t, currentUser2));
        return isMine || isLead;
      }).length;
      mineTotal = myOverdue + myImminent + mySoon + myUnassigned + myUnack + myPending + myCompleted + myUnreadMsgs + myReceipts + myRejected + myInProgress + myBlocked + myAtRisk + myLateStart;
    }

    // Build chip content for each scope. Order: urgency first (overdue,
    // at-risk, imminent), then status (blocked, unassigned, etc.), then info.
    const buildChips = (o, i, s, un, ua, p, co, re, msg, rc, ip, bl, ar, ls) => {
      const c = [];
      if (o) c.push(`<span class="ss-chip">🚨 ${o}</span>`);
      if (ar) c.push(`<span class="ss-chip ss-warn">⚠ AR ${ar}</span>`);
      if (ls) c.push(`<span class="ss-chip ss-warn">⏰ LS ${ls}</span>`);
      if (i) c.push(`<span class="ss-chip ss-warn">⚠ ${i}</span>`);
      if (s) c.push(`<span class="ss-chip ss-warn">⚠ ${s}</span>`);
      if (bl) c.push(`<span class="ss-chip">⛔ ${bl}</span>`);
      if (un) c.push(`<span class="ss-chip ss-info">👤 ${un}</span>`);
      if (ua) c.push(`<span class="ss-chip">🔔 ${ua}</span>`);
      if (msg) c.push(`<span class="ss-chip">📩 ${msg}</span>`);
      if (rc) c.push(`<span class="ss-chip ss-green">✉✓ ${rc}</span>`);
      if (re) c.push(`<span class="ss-chip">✗ ${re}</span>`);
      if (ip) c.push(`<span class="ss-chip ss-cyan">⚙ ${ip}</span>`);
      if (p) c.push(`<span class="ss-chip ss-info">⏳ ${p}</span>`);
      if (co) c.push(`<span class="ss-chip ss-green">✓ ${co}</span>`);
      return c.join('');
    };
    const projectChips = buildChips(overdue, imminent, soon, unassigned, unack, pending, completed, rejectedCount, 0, 0, inProgress, blocked, atRisk, lateStart);
    const mineChips = currentUser2
      ? buildChips(myOverdue, myImminent, 0, 0, myUnack, 0, 0, myRejected, myUnreadMsgs, myReceipts, myInProgress, myBlocked, myAtRisk, myLateStart)
      : '';

    // Compose the two-scope summary line
    if (projectTotal > 0 || mineTotal > 0) {
      const scopeParts = [];
      if (projectTotal > 0) {
        scopeParts.push(`<span class="ss-scope-group"><span class="ss-scope-label">PROJECT:</span>${projectChips || `<span class="ss-chip ss-info">${projectTotal}</span>`}</span>`);
      }
      if (currentUser2 && mineTotal > 0) {
        scopeParts.push(`<span class="ss-scope-group ss-scope-mine"><span class="ss-scope-label">MINE:</span>${mineChips || `<span class="ss-chip ss-info">${mineTotal}</span>`}</span>`);
      }
      alertsSummaryEl.innerHTML = scopeParts.join('<span class="ss-scope-sep">·</span>');
      if (alertsEmptyEl) alertsEmptyEl.style.display = 'none';
    } else {
      alertsSummaryEl.innerHTML = `<span class="ss-chip ss-green">✓ All clear</span>`;
      if (alertsEmptyEl) alertsEmptyEl.style.display = 'block';
    }

    // Section severity glow
    if (alertsSection) {
      alertsSection.classList.toggle('has-critical', overdue > 0 || imminent > 0 || unack > 0 || myUnreadMsgs > 0 || rejectedCount > 0 || atRisk > 0 || blocked > 0 || lateStart > 0);
      alertsSection.classList.toggle('has-warning', overdue === 0 && imminent === 0 && unack === 0 && myUnreadMsgs === 0 && rejectedCount === 0 && atRisk === 0 && blocked === 0 && lateStart === 0 && (soon > 0 || pending > 0 || completed > 0 || inProgress > 0));
      alertsSection.classList.toggle('critical-pulse', overdue > 0 || myUnreadMsgs > 0 || rejectedCount > 0 || atRisk > 0 || lateStart > 0);
    }
  }

  // ===== Countdown summary =====
  const countdownSummaryEl = document.getElementById('pvCountdownSummary');
  const countdownEmptyEl = document.getElementById('pvCountdownEmpty');
  const countdownCard = document.getElementById('pvCountdownCard');
  const countdownSection = document.getElementById('pvSectionCountdown');

  // Helper: format a countdown object as a compact chip
  const _cdChip = (cd, prefix) => {
    if (!cd) return '';
    if (cd.isPast) return `<span class="ss-chip">${prefix}⏱ PAST</span>`;
    if (cd.totalMs < 3600000) return `<span class="ss-chip">${prefix}🚨 ${cd.minutes}m ${cd.seconds}s</span>`;
    if (cd.totalMs < 2 * 3600000) return `<span class="ss-chip">${prefix}🚨 ${cd.hours}h ${cd.minutes}m</span>`;
    if (cd.totalMs < 24 * 3600000) return `<span class="ss-chip ss-warn">${prefix}⚠ ${cd.hours}h ${cd.minutes}m</span>`;
    if (cd.totalMs < 2 * 86400000) return `<span class="ss-chip ss-warn">${prefix}⚠ ${cd.days}d ${cd.hours}h</span>`;
    if (cd.totalMs < 5 * 86400000) return `<span class="ss-chip ss-warn">${prefix}⚠ ${cd.days}d ${cd.hours}h</span>`;
    return `<span class="ss-chip ss-info">${prefix}${cd.days}d ${cd.hours}h</span>`;
  };
  // Helper: evaluate urgency flags for a countdown
  const _cdFlags = (cd) => {
    if (!cd) return { critical: false, warning: false, pulse: false };
    if (cd.isPast) return { critical: true, warning: false, pulse: true };
    if (cd.totalMs < 2 * 3600000) return { critical: true, warning: false, pulse: true };
    if (cd.totalMs < 5 * 86400000) return { critical: false, warning: true, pulse: false };
    return { critical: false, warning: false, pulse: false };
  };

  if (countdownSummaryEl && project) {
    const tpInst = getTradePartnerMilestoneInstance(project);
    const tpCd = tpInst ? getMilestoneCountdown(tpInst) : null;
    const bidCd = project.dueDate ? getBidCountdown(project) : null;

    if (!bidCd && !tpCd) {
      countdownSummaryEl.innerHTML = `<span class="ss-chip ss-info">No due date</span>`;
      if (countdownEmptyEl) countdownEmptyEl.style.display = 'block';
      if (countdownCard) countdownCard.style.display = 'none';
      if (countdownSection) {
        countdownSection.classList.remove('has-critical','has-warning','critical-pulse');
      }
    } else {
      if (countdownEmptyEl) countdownEmptyEl.style.display = 'none';
      const chips = [];
      if (tpCd) chips.push(_cdChip(tpCd, '💼 TP: '));
      if (bidCd) chips.push(_cdChip(bidCd, '📤 Bid: '));
      countdownSummaryEl.innerHTML = chips.join(' ');

      // Compute overall section urgency --- the more-urgent of the two wins
      const tpFlags = _cdFlags(tpCd);
      const bidFlags = _cdFlags(bidCd);
      const hasCritical = tpFlags.critical || bidFlags.critical;
      const hasWarning = !hasCritical && (tpFlags.warning || bidFlags.warning);
      const pulse = tpFlags.pulse || bidFlags.pulse;
      countdownSection?.classList.toggle('has-critical', hasCritical);
      countdownSection?.classList.toggle('has-warning', hasWarning);
      countdownSection?.classList.toggle('critical-pulse', pulse);
    }
  }

  // ===== Milestones summary =====
  const milestonesSummaryEl = document.getElementById('pvMilestonesSummary');
  const milestonesSection = document.getElementById('pvSectionMilestones');
  if (milestonesSummaryEl && project) {
    const milestones = getProjectMilestones(project);
    let missing = 0, imminent = 0, warning = 0, past = 0, normal = 0;
    milestones.forEach(({ instance }) => {
      if (!instance.date) { missing++; return; }
      const cd = getMilestoneCountdown(instance);
      if (!cd) return;
      if (cd.isPast) past++;
      else if (cd.totalMs < 2 * 3600000) imminent++;
      else if (cd.totalMs < 72 * 3600000) warning++;
      else normal++;
    });
    const chips = [];
    if (missing) chips.push(`<span class="ss-chip">⚠ ${missing} missing</span>`);
    if (imminent) chips.push(`<span class="ss-chip">🚨 ${imminent}</span>`);
    if (warning) chips.push(`<span class="ss-chip ss-warn">⚠ ${warning}</span>`);
    if (past) chips.push(`<span class="ss-chip">⏱ ${past}</span>`);
    const total = milestones.length;
    milestonesSummaryEl.innerHTML = total > 0
      ? `${total} milestone${total===1?'':'s'}${chips.length ? ' ' + chips.join('') : ''}`
      : `<span class="ss-chip ss-info">No types defined</span>`;
    if (milestonesSection) {
      milestonesSection.classList.toggle('has-critical', missing > 0 || imminent > 0);
      milestonesSection.classList.toggle('has-warning', missing === 0 && imminent === 0 && warning > 0);
    }
  }
}

// =============================================================
// BY-ASSIGNEE ALERTS STRIP
// Shows a per-assignee alert summary (only renders if any alerts exist)
// =============================================================
function renderAssigneeAlertsStrip(project) {
  const strip = document.getElementById('assigneeAlertsStrip');
  if (!strip) return;

  if (!project) {
    strip.classList.remove('active');
    strip.innerHTML = '';
    return;
  }

  // Collect per-assignee alert counts across all alert tiers
  const map = new Map();
  const ensure = (name) => {
    if (!map.has(name)) {
      map.set(name, {
        name,
        overdue: 0,
        imminent: 0,
        soon: 0,
        unacknowledged: 0,
        pending: 0,
        completion: 0   // done but awaiting Lead sign-off
      });
    }
    return map.get(name);
  };

  project.tasks.forEach(t => {
    const assignee = (t.assignee || '').trim();
    if (!assignee) return; // Unassigned tasks are handled by the main Unassigned alert tab, not here

    // Overdue (non-done with past due date)
    if (t.status !== 'done' && t.dueDate && isTaskOverdue(t)) ensure(assignee).overdue++;
    // Imminent (today/tomorrow, not overdue, not done)
    else if (t.status !== 'done' && t.dueDate && isTaskDueImminent(t)) ensure(assignee).imminent++;
    // Soon (exactly 2 days out)
    else if (t.status !== 'done' && t.dueDate && isTaskDueSoon(t)) ensure(assignee).soon++;

    // Unacknowledged (newly assigned, not yet ack'd)
    if (t.status !== 'done' && !t.acknowledged) ensure(assignee).unacknowledged++;

    // Pending status
    if (t.status === 'pending') ensure(assignee).pending++;

    // Completed but awaiting Lead Estimator sign-off
    if (t.status === 'done' && !t.completionAcknowledged) ensure(assignee).completion++;
  });

  // Filter out assignees with zero alerts
  const rows = Array.from(map.values()).filter(r =>
    r.overdue + r.imminent + r.soon + r.unacknowledged + r.pending + r.completion > 0
  );

  if (rows.length === 0) {
    strip.classList.remove('active');
    strip.innerHTML = '';
    return;
  }

  // Sort: most total alerts first, then name
  rows.sort((a, b) => {
    const totalA = a.overdue + a.imminent + a.soon + a.unacknowledged + a.pending + a.completion;
    const totalB = b.overdue + b.imminent + b.soon + b.unacknowledged + b.pending + b.completion;
    if (totalA !== totalB) return totalB - totalA;
    return a.name.localeCompare(b.name);
  });

  const totalAlerts = rows.reduce((sum, r) =>
    sum + r.overdue + r.imminent + r.soon + r.unacknowledged + r.pending + r.completion, 0);

  const cards = rows.map(r => {
    const initials = r.name.split(/\s+/).map(x => x[0]).join('').slice(0,2).toUpperCase();
    const color = avatarColor(r.name);
    const photo = getMemberPhoto(r.name);
    const avatar = photo
      ? `<span class="aac-avatar"><img src="${photo}" alt=""></span>`
      : `<span class="aac-avatar" style="background:${color};">${escapeHtml(initials)}</span>`;

    const badges = [];
    if (r.overdue > 0) badges.push(`<span class="aac-badge b-overdue" title="${r.overdue} overdue task(s)">🚨 ${r.overdue}</span>`);
    if (r.imminent > 0) badges.push(`<span class="aac-badge b-imminent" title="${r.imminent} due today/tomorrow">⚠ ${r.imminent}</span>`);
    if (r.soon > 0) badges.push(`<span class="aac-badge b-soon" title="${r.soon} due in 2 days">⚠ ${r.soon}</span>`);
    if (r.unacknowledged > 0) badges.push(`<span class="aac-badge b-unack" title="${r.unacknowledged} newly assigned, awaiting acknowledgment">🔔 ${r.unacknowledged}</span>`);
    if (r.pending > 0) badges.push(`<span class="aac-badge b-pending" title="${r.pending} pending task(s)">⏳ ${r.pending}</span>`);
    if (r.completion > 0) badges.push(`<span class="aac-badge b-completion" title="${r.completion} completion(s) awaiting Lead sign-off">✓ ${r.completion}</span>`);

    const isActive = state.grouping === 'assignee' && state.activeAssignee === r.name;
    return `
      <div class="assignee-alert-card ${isActive ? 'active' : ''}"
           onclick="jumpToAssigneeAlerts('${escapeHtml(r.name)}')"
           title="Click to view ${escapeHtml(r.name)}'s tasks in Group by Assignee">
        ${avatar}
        <span class="aac-name">${escapeHtml(r.name)}</span>
        <span class="aac-badges">${badges.join('')}</span>
      </div>
    `;
  }).join('');

  strip.innerHTML = `
    <div class="assignee-alerts-header">
      <span class="assignee-alerts-title">👥 Alerts by Assignee · ${rows.length} team member${rows.length===1?'':'s'} · ${totalAlerts} alert${totalAlerts===1?'':'s'}</span>
    </div>
    <div class="assignee-alerts-grid">${cards}</div>
  `;
  strip.classList.add('active');
}

function jumpToAssigneeAlerts(name) {
  // Switch to Group by Assignee view and focus on this person
  state.grouping = 'assignee';
  state.activeAssignee = name;
  state.activeStageId = 'all';
  saveState();
  render();
  // Smoothly scroll to the task board
  const el = document.getElementById('stageBoard') || document.getElementById('allStagesView');
  if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

// =============================================================
// BOARD VIEW
// =============================================================
function renderBoardView(project) {
  // When "all stages" is selected AND grouping=stage, show stage panels
  if (state.grouping === 'stage' && state.activeStageId === 'all') {
    document.getElementById('stageBoard').classList.add('hidden');
    document.getElementById('allStagesView').classList.remove('hidden');
    renderAllStages(project);
    return;
  }
  // When "all people" is selected AND grouping=assignee, show assignee panels
  if (state.grouping === 'assignee' && state.activeAssignee === 'all') {
    document.getElementById('stageBoard').classList.add('hidden');
    document.getElementById('allStagesView').classList.remove('hidden');
    renderAllAssignees(project);
    return;
  }
  // When "all sources" is selected AND grouping=source, show source panels
  if (state.grouping === 'source' && state.activeSource === 'all') {
    document.getElementById('stageBoard').classList.add('hidden');
    document.getElementById('allStagesView').classList.remove('hidden');
    renderAllSources(project);
    return;
  }
  document.getElementById('stageBoard').classList.remove('hidden');
  document.getElementById('allStagesView').classList.add('hidden');

  const tasks = getFilteredTasks(project);
  const statuses = ['not-started','in-progress','blocked','pending','done'];
  statuses.forEach(status => {
    const list = document.querySelector(`[data-list="${status}"]`);
    const countEl = document.querySelector(`[data-count="${status}"]`);
    const t = tasks.filter(x => x.status === status);
    countEl.textContent = t.length;
    t.sort(sortTasks);
    list.innerHTML = t.map(renderTaskCard).join('');
  });
  attachDragHandlers();
}

function sortTasks(a, b) {
  const pri = {high:0,medium:1,low:2};
  if (pri[a.priority] !== pri[b.priority]) return pri[a.priority]-pri[b.priority];
  if (a.dueDate && b.dueDate) return new Date(a.dueDate)-new Date(b.dueDate);
  if (a.dueDate) return -1;
  if (b.dueDate) return 1;
  return 0;
}

function renderAllStages(project) {
  const container = document.getElementById('allStagesView');
  container.innerHTML = STAGES.map(stage => {
    const tasks = project.tasks.filter(t=>t.stage===stage.id);
    const done = tasks.filter(t=>t.status==='done').length;
    const pct = tasks.length>0 ? Math.round((done/tasks.length)*100) : 0;
    return `
      <div class="stage-panel">
        <div class="stage-panel-header" onclick="selectTab('${stage.id}')">
          <div class="stage-panel-title">
            <span>${stage.icon}</span><span>${stage.name}</span>
            <span class="stage-count"><span class="done-num">${done}</span>/${tasks.length}</span>
          </div>
          <div class="stage-panel-stats">
            ${tasks.length > 0 ? `<button class="bulk-assign-btn bulk-assign-btn-sm" onclick="event.stopPropagation(); openBulkAssignModal('${stage.id}')" title="Assign all tasks in ${escapeHtml(stage.name)} to one team member">👥 Assign All</button>` : ''}
            <div class="stage-mini-progress"><div class="stage-mini-progress-fill" style="width:${pct}%"></div></div>
            <span>${pct}%</span>
          </div>
        </div>
        ${tasks.length === 0
          ? `<div class="stage-empty">No tasks in this stage yet</div>`
          : `<div class="stage-task-grid">${tasks.slice().sort(sortTasks).map(renderTaskCard).join('')}</div>`
        }
      </div>
    `;
  }).join('');
  attachDragHandlers();
}

function renderAllAssignees(project) {
  const container = document.getElementById('allStagesView');
  const buckets = getAssigneeBuckets(project);
  if (buckets.length === 0) {
    container.innerHTML = '<div class="stage-empty">No tasks yet</div>';
    return;
  }
  container.innerHTML = buckets.map(b => {
    const label = b.name === 'unassigned' ? 'Unassigned' : b.name;
    const initials = b.name === 'unassigned' ? '?' : b.name.split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
    const color = b.name === 'unassigned' ? '#9ba4b0' : avatarColor(b.name);
    const photo = b.name === 'unassigned' ? null : getMemberPhoto(b.name);
    const title = b.name === 'unassigned' ? '' : getMemberTitle(b.name);
    const pct = b.total>0 ? Math.round((b.done/b.total)*100) : 0;
    const remaining = b.total - b.done;
    const avatarMarkup = photo
      ? `<span class="avatar has-photo" style="width:36px;height:36px;overflow:hidden;padding:0;"><img src="${photo}" alt="" style="width:100%;height:100%;object-fit:cover;"></span>`
      : `<span class="avatar" style="background:${color};width:36px;height:36px;font-size:13px;">${escapeHtml(initials)}</span>`;
    // Color-coded % based on progress
    const pctColor = pct === 100 ? 'var(--green)' : pct >= 50 ? 'var(--sbg-navy)' : pct > 0 ? 'var(--yellow)' : 'var(--text-dim)';
    // Count unacknowledged tasks for this assignee
    const unackCount = b.name === 'unassigned' ? 0 : b.tasks.filter(t => !t.acknowledged && t.assignee === b.name).length;
    const ackAllBtn = unackCount > 0
      ? `<button class="ack-all-btn" onclick="event.stopPropagation(); acknowledgeAllForAssignee('${escapeHtml(b.name)}')" title="Mark all ${unackCount} new task${unackCount===1?'':'s'} as acknowledged">✓ Acknowledge All (${unackCount})</button>`
      : '';
    return `
      <div class="stage-panel ${unackCount > 0 ? 'has-new-tasks' : ''}">
        <div class="stage-panel-header" onclick="selectTab('${escapeHtml(b.name)}')">
          <div class="stage-panel-title">
            ${avatarMarkup}
            <span style="display:flex;flex-direction:column;line-height:1.2;">
              <span>${escapeHtml(label)}${unackCount > 0 ? `<span class="assignee-new-badge" style="animation:none;">${unackCount} NEW</span>` : ''}</span>
              ${title ? `<span style="font-family:'Barlow Condensed',sans-serif;font-size:10px;text-transform:uppercase;letter-spacing:0.12em;color:var(--text-dim);font-weight:600;">${escapeHtml(title)}</span>` : ''}
            </span>
            <span class="stage-count"><span class="done-num">${b.done}</span>/${b.total} · ${remaining} left</span>
          </div>
          <div class="stage-panel-stats">
            ${ackAllBtn}
            <div class="stage-mini-progress"><div class="stage-mini-progress-fill" style="width:${pct}%"></div></div>
            <span style="font-family:'JetBrains Mono',monospace;font-size:16px;font-weight:700;color:${pctColor};min-width:44px;text-align:right;">${pct}%</span>
          </div>
        </div>
        <div class="stage-task-grid">${b.tasks.slice().sort(sortTasks).map(renderTaskCard).join('')}</div>
      </div>
    `;
  }).join('');
  attachDragHandlers();
}

// Render the swim-lane view when grouping=source and activeSource='all'.
// One panel per source, with the source's icon/photo, task count, and progress %.
function renderAllSources(project) {
  const container = document.getElementById('allStagesView');
  const buckets = getSourceBuckets(project);
  if (buckets.length === 0) {
    container.innerHTML = '<div class="stage-empty">No tasks yet</div>';
    return;
  }
  // Filter out empty buckets to keep the view clean --- only show sources that have tasks
  // (configured-but-empty sources are still selectable via the tab nav above)
  const nonEmpty = buckets.filter(b => b.total > 0);
  if (nonEmpty.length === 0) {
    container.innerHTML = '<div class="stage-empty">No tasks have a source assigned yet</div>';
    return;
  }
  container.innerHTML = nonEmpty.map(b => {
    const label = b.name === 'unsourced' ? '--- No Source ---' : b.name;
    const meta = getSourceMeta(b.name);
    const pct = b.total > 0 ? Math.round((b.done / b.total) * 100) : 0;
    const remaining = b.total - b.done;
    const iconMarkup = (b.name !== 'unsourced' && meta.photo)
      ? `<span class="avatar has-photo" style="width:36px;height:36px;overflow:hidden;padding:0;background:#fff;border:1px solid var(--border);"><img src="${meta.photo}" alt="" style="width:100%;height:100%;object-fit:contain;padding:3px;"></span>`
      : `<span style="font-size:24px;width:36px;height:36px;display:inline-flex;align-items:center;justify-content:center;">${escapeHtml(meta.icon)}</span>`;
    const pctColor = pct === 100 ? 'var(--green)' : pct >= 50 ? 'var(--sbg-navy)' : pct > 0 ? 'var(--yellow)' : 'var(--text-dim)';
    return `
      <div class="stage-panel">
        <div class="stage-panel-header" onclick="selectTab('${escapeHtml(b.name).replace(/'/g, "\\'")}')">
          <div class="stage-panel-title">
            ${iconMarkup}
            <span>${escapeHtml(label)}</span>
            <span class="stage-count"><span class="done-num">${b.done}</span>/${b.total} · ${remaining} left</span>
          </div>
          <div class="stage-panel-stats">
            <div class="stage-mini-progress"><div class="stage-mini-progress-fill" style="width:${pct}%"></div></div>
            <span style="font-family:'JetBrains Mono',monospace;font-size:16px;font-weight:700;color:${pctColor};min-width:44px;text-align:right;">${pct}%</span>
          </div>
        </div>
        <div class="stage-task-grid">${b.tasks.slice().sort(sortTasks).map(renderTaskCard).join('')}</div>
      </div>
    `;
  }).join('');
  attachDragHandlers();
}

function renderTaskCard(t) {
  const due = t.dueDate ? formatDateShort(t.dueDate) : '---';
  const dueClass = getDueClass(t.dueDate, t.status);
  const isOverdue = isTaskOverdue(t);
  const isImminent = !isOverdue && isTaskDueImminent(t);
  const isSoon = !isOverdue && !isImminent && isTaskDueSoon(t);
  // Multi-lead support --- display all Leads. Avatar uses the primary (first)
  // Lead; if there are 2+ Leads the chip shows "Sarah · +1" or "Sarah · Trent"
  // depending on space.
  const allLeads = (typeof getTaskLeads === 'function') ? getTaskLeads(t) : (t.assignee ? [t.assignee] : []);
  const primaryLead = allLeads[0] || '';
  const initials = (primaryLead || '?').split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
  const catShort = t.category.length > 30 ? t.category.slice(0,28)+'...' : t.category;
  const color = primaryLead ? avatarColor(primaryLead) : '#9ba4b0';
  const photo = primaryLead ? getMemberPhoto(primaryLead) : null;
  // Build the name display --- if 2 leads, show both joined with " · "; if 3+,
  // show the primary plus a "+N" badge. Tooltip lists everyone.
  let leadDisplay = '';
  let leadTooltip = '';
  if (allLeads.length === 0) {
    leadDisplay = '<span style="color:var(--text-faint);">Unassigned</span>';
  } else if (allLeads.length === 1) {
    leadDisplay = escapeHtml(allLeads[0]);
    leadTooltip = `Lead: ${allLeads[0]}`;
  } else if (allLeads.length === 2) {
    leadDisplay = `${escapeHtml(allLeads[0])} <span class="co-lead-sep">·</span> ${escapeHtml(allLeads[1])}`;
    leadTooltip = `Co-Leads: ${allLeads.join(', ')}`;
  } else {
    leadDisplay = `${escapeHtml(allLeads[0])} <span class="co-lead-more" title="${escapeAttr(allLeads.slice(1).join(', '))}">+${allLeads.length - 1}</span>`;
    leadTooltip = `Co-Leads: ${allLeads.join(', ')}`;
  }
  const avatarHtml = (allLeads.length > 0)
    ? (photo
        ? `<span class="avatar has-photo" title="${escapeAttr(leadTooltip)}"><img src="${photo}" alt=""></span>${leadDisplay}`
        : `<span class="avatar" style="background:${color};" title="${escapeAttr(leadTooltip)}">${escapeHtml(initials)}</span>${leadDisplay}`)
    : '<span style="color:var(--text-faint);">Unassigned</span>';
  const offsetBadge = typeof t.dayOffset === 'number' ? `<span class="day-offset">D+${t.dayOffset}</span>` : '';

  // Due reminder badge (today / tomorrow / 2 days) --- top right corner
  let dueBadge = '';
  if (!isOverdue && (isImminent || isSoon)) {
    const cls = isImminent ? 'badge-imminent' : 'badge-soon';
    dueBadge = `<span class="due-badge ${cls}">${getDueSoonLabel(t)}</span>`;
  }

  // Support members chip --- shows all support members (primary + additional)
  // Up to 3 inline; "+N more" badge if there are more
  let supportHtml = '';
  const allSupports = getAllSupportMembers(t);
  if (allSupports.length > 0) {
    const visible = allSupports.slice(0, 3);
    const overflow = allSupports.length - visible.length;
    const avatarStack = visible.map(name => {
      const sInitials = name.split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
      const sColor = avatarColor(name);
      const sPhoto = getMemberPhoto(name);
      return sPhoto
        ? `<span class="support-avatar" title="Support: ${escapeHtml(name)}"><img src="${sPhoto}" alt=""></span>`
        : `<span class="support-avatar" title="Support: ${escapeHtml(name)}" style="background:${sColor};">${escapeHtml(sInitials)}</span>`;
    }).join('');
    const tooltip = `Support: ${allSupports.join(', ')}`;
    const labelText = allSupports.length === 1
      ? escapeHtml(allSupports[0])
      : `${allSupports.length} support members`;
    const overflowBadge = overflow > 0 ? `<span class="support-overflow">+${overflow}</span>` : '';
    supportHtml = `<span class="support-chip" title="${escapeHtml(tooltip)}"><span class="support-label">+</span><span class="support-stack">${avatarStack}${overflowBadge}</span><span class="support-text">${labelText}</span></span>`;
  }

  // Recurrence badge --- small 🔁 indicator if this task is part of a recurring series
  let recurrenceBadge = '';
  if (isRecurringTask(t)) {
    const desc = describeRecurrence(t.recurrence);
    const instanceLabel = t.recurrence.instanceNumber && t.recurrence.instanceNumber > 1
      ? ` · Instance #${t.recurrence.instanceNumber}`
      : '';
    recurrenceBadge = `<span class="recurrence-badge" title="${escapeHtml('Recurs: ' + desc + instanceLabel)}">🔁</span>`;
  }

  // Checklist progress chip --- shows "✓ 3/8" plus loud red treatment when required items are still open
  let checklistChip = '';
  const clInfo = getChecklistChipLabel(t);
  if (clInfo) {
    const pct = clInfo.total > 0 ? Math.round((clInfo.done / clInfo.total) * 100) : 0;
    let stateClass = '';
    let icon = '☐';
    let label = `${clInfo.done}/${clInfo.total}`;
    let titleText = `${clInfo.done} of ${clInfo.total} checklist subtasks complete (${pct}%)`;
    if (clInfo.allDone) {
      stateClass = ' cl-chip-done';
      icon = '✓';
    } else if (clInfo.hasRequiredOpen) {
      // LOUD: red + pulse --- required SUBTASKS still open. Icon stays ☐ so the
      // visual reads as a checklist (different from the 📦 deliverable chip).
      stateClass = ' cl-chip-required-open';
      icon = '☐';
      label = `${clInfo.reqLeft} SUBTASK${clInfo.reqLeft === 1 ? '' : 'S'} LEFT`;
      titleText = `${clInfo.reqLeft} of ${clInfo.reqTotal} required SUBTASKS still open --- task cannot be marked Complete until these are done`;
    }
    checklistChip = `<span class="cl-chip${stateClass}" title="${escapeAttr(titleText)}">
      <span class="cl-chip-icon">${icon}</span>
      <span class="cl-chip-count">${escapeHtml(label)}</span>
      <span class="cl-chip-bar"><span class="cl-chip-bar-fill" style="width:${pct}%"></span></span>
    </span>`;
  }

  // Deliverables progress chip --- gold by default, loud red (with 📦 icon
  // and "DELIVERABLES" wording) when required outputs still open. Same red
  // urgency as the subtask chip but distinct icon + word so an assignee
  // reads the chip as "deliverable missing" not "subtask missing".
  let deliverableChip = '';
  const dlvInfo = getDeliverableChipLabel(t);
  if (dlvInfo) {
    const pct = dlvInfo.total > 0 ? Math.round((dlvInfo.done / dlvInfo.total) * 100) : 0;
    let stateClass = '';
    let icon = '📦';
    let label = `${dlvInfo.done}/${dlvInfo.total}`;
    let titleText = `${dlvInfo.done} of ${dlvInfo.total} deliverables complete (${pct}%)`;
    if (dlvInfo.allDone) {
      stateClass = ' dlv-chip-done';
      icon = '✓';
    } else if (dlvInfo.hasRequiredOpen) {
      // LOUD: red + pulse, KEEP 📦 icon so the chip differentiates from the
      // subtask chip at a glance even though both are red.
      stateClass = ' dlv-chip-required-open';
      icon = '📦';
      label = `${dlvInfo.reqLeft} DELIVERABLE${dlvInfo.reqLeft === 1 ? '' : 'S'} LEFT`;
      titleText = `${dlvInfo.reqLeft} of ${dlvInfo.reqTotal} required DELIVERABLES still open --- task cannot be marked Complete until these are submitted`;
    }
    deliverableChip = `<span class="dlv-chip${stateClass}" title="${escapeAttr(titleText)}">
      <span class="dlv-chip-icon">${icon}</span>
      <span class="dlv-chip-count">${escapeHtml(label)}</span>
      <span class="dlv-chip-bar"><span class="dlv-chip-bar-fill" style="width:${pct}%"></span></span>
    </span>`;
  }

  // Best-practice indicator chip --- small red 💡 dot when this task has guidance the assignee should read
  let bestPracticeChip = '';
  if (t.bestPractice && t.bestPractice.trim()) {
    // Show "NEW" tag if popup is enabled and current user (if Lead) hasn't acked yet
    const user = (typeof getCurrentUser === 'function') ? (getCurrentUser() || '') : '';
    const userIsLead = user && ((typeof isTaskLead === 'function')
      ? isTaskLead(t, user)
      : (t.assignee && t.assignee.toLowerCase() === user.toLowerCase()));
    const isMyTaskUnacked = userIsLead
      && t.bestPracticePopupEnabled !== false
      && (!t.bestPracticeAck || !t.bestPracticeAck[user.toLowerCase()]);
    const newTag = isMyTaskUnacked ? ' · NEW' : '';
    bestPracticeChip = `<span class="bp-chip" title="Best-practice notes from the Lead Estimator${newTag ? ' --- you have not acknowledged these yet' : ''}">💡 Tip${newTag}</span>`;
  }

  // Co-Lead completion chip --- shows "🏁 N/M" progress when this is a multi-Lead
  // task with at least one Lead having marked their part complete (and the
  // task isn't already Done). Hidden for single-Lead tasks.
  let leadCompChip = '';
  if (t.status !== 'done'
      && typeof getTaskLeads === 'function'
      && typeof getCompletedLeads === 'function') {
    const _leads = getTaskLeads(t);
    if (_leads.length >= 2) {
      const _completed = getCompletedLeads(t);
      const _allDone = _completed.length === _leads.length;
      // Only render when there's progress to show
      if (_completed.length > 0) {
        const _cls = _allDone ? 'lead-comp-chip lead-comp-chip-done' : 'lead-comp-chip';
        const _title = _allDone
          ? `All ${_leads.length} co-Leads complete (${_completed.join(', ')})`
          : `${_completed.length} of ${_leads.length} co-Leads complete: ${_completed.join(', ')}. Awaiting: ${_leads.filter(n => !_completed.some(c => c.toLowerCase() === n.toLowerCase())).join(', ')}`;
        leadCompChip = `<span class="${_cls}" title="${escapeAttr(_title)}">🏁 ${_completed.length}/${_leads.length}</span>`;
      }
    }
  }

  // Projected hours chip --- shows "⏱ 4h" when the task has an estimate AND
  // the global hours feature is enabled. Hidden when no estimate or feature off.
  let hoursChip = '';
  if (state.hoursEnabled && typeof t.estimatedHours === 'number' && t.estimatedHours > 0) {
    const formattedH = (typeof formatHours === 'function') ? formatHours(t.estimatedHours) : (t.estimatedHours + 'h');
    hoursChip = `<span class="hours-chip" title="Projected effort: ${escapeAttr(formattedH)}">⏱ ${escapeHtml(formattedH)}</span>`;
  }

  // Start By chip --- shows the Start By date with urgency color when set.
  // Only renders when the feature is enabled for this stage AND the task has
  // a Start By date AND the task isn't already done. Color codes by urgency:
  //   red filled (LATE) --- Start By date passed, still not started
  //   gold (DUE SOON)   --- within 2 days of Start By
  //   neutral           --- Start By is set but more than 2 days out
  // Once a task is in-progress or done the Start By has been satisfied so
  // the chip switches to a quiet "✓ started" check; once done it disappears.
  let startByChip = '';
  if (t.startByDate && t.status !== 'done'
      && typeof isStartByEnabledForStage === 'function'
      && isStartByEnabledForStage(t.stage)) {
    const today = new Date();
    const todayStart = new Date(today.getFullYear(), today.getMonth(), today.getDate());
    const sb = new Date(t.startByDate + 'T00:00:00');
    const diffDays = Math.round((sb.getTime() - todayStart.getTime()) / 86400000);
    let chipClass = 'sb-chip';
    let label = '';
    let titleText = '';
    if (t.status === 'in-progress' || t.status === 'blocked' || t.status === 'pending') {
      // Already moved off "not-started" --- Start By has been satisfied
      chipClass += ' sb-chip-satisfied';
      label = `⏰ Started`;
      titleText = `Start By date: ${formatDate(t.startByDate)} --- task has moved off Not Started`;
    } else if (diffDays < 0) {
      chipClass += ' sb-chip-late';
      label = `⏰ ${Math.abs(diffDays)}d LATE START`;
      titleText = `Start By was ${formatDate(t.startByDate)} (${Math.abs(diffDays)} day${Math.abs(diffDays) === 1 ? '' : 's'} ago) --- task still Not Started`;
    } else if (diffDays === 0) {
      chipClass += ' sb-chip-imminent';
      label = `⏰ Start TODAY`;
      titleText = `Start By is today (${formatDate(t.startByDate)})`;
    } else if (diffDays <= 2) {
      chipClass += ' sb-chip-warning';
      label = `⏰ Start in ${diffDays}d`;
      titleText = `Start By: ${formatDate(t.startByDate)} (in ${diffDays} day${diffDays === 1 ? '' : 's'})`;
    } else {
      label = `⏰ Start ${formatDate(t.startByDate)}`;
      titleText = `Start By: ${formatDate(t.startByDate)} (in ${diffDays} days)`;
    }
    startByChip = `<span class="${chipClass}" title="${escapeAttr(titleText)}">${label}</span>`;
  }

  // Ball in Court chip (uses master list's color)
  const bicHtml = t.ballInCourt
    ? `<span class="bic-chip bic-color-${bicColorFor(t.ballInCourt)} bic-${t.ballInCourt.replace(/[^A-Za-z]/g,'')}" title="Ball in Court: ${escapeHtml(t.ballInCourt)}">${escapeHtml(t.ballInCourt)}</span>`
    : '';

  // Source badge --- small chip showing the source's emoji icon or uploaded logo image.
  // Renders next to the assignee row so it's always visible without dominating the card.
  let sourceBadge = '';
  if (t.source && t.source.trim()) {
    const srcOpt = findSourceOption(t.source);
    if (srcOpt) {
      const visual = srcOpt.photo
        ? `<span class="source-badge-img"><img src="${srcOpt.photo}" alt=""></span>`
        : `<span class="source-badge-icon">${escapeHtml(srcOpt.icon || '📥')}</span>`;
      sourceBadge = `<span class="source-badge" title="Source: ${escapeHtml(t.source)}">${visual}<span class="source-badge-name">${escapeHtml(t.source)}</span></span>`;
    } else {
      // Legacy / orphan source --- fallback to plain emoji
      sourceBadge = `<span class="source-badge" title="Source: ${escapeHtml(t.source)} (legacy)"><span class="source-badge-icon">📥</span><span class="source-badge-name">${escapeHtml(t.source)}</span></span>`;
    }
  }

  // NEW badge + Acknowledge button --- shows when a task has an assignee but hasn't been acknowledged
  const needsAck = t.assignee && t.assignee.trim() && !t.acknowledged;
  const newBadge = needsAck
    ? `<span class="new-task-badge" title="This task was newly assigned to ${escapeHtml(t.assignee)} and hasn't been acknowledged yet">NEW</span>`
    : '';
  const ackButton = needsAck
    ? `<button class="task-ack-btn" onclick="acknowledgeTask('${t.id}', event)" title="${escapeHtml(t.assignee)}, click to acknowledge this new task">✓ Acknowledge</button>`
    : '';
  // Lead Estimator override button --- shown only to the Lead when current user isn't the assignee
  let overrideButton = '';
  if (needsAck) {
    const proj = state.projects.find(p => p.id === state.activeProjectId);
    const lead = proj?.leadEstimator?.trim();
    const currentUser = getCurrentUser();
    const isLead = currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();
    const isAssignee = currentUser && t.assignee && currentUser.toLowerCase() === t.assignee.toLowerCase();
    if (isLead && !isAssignee) {
      overrideButton = `<button class="task-override-btn" onclick="overrideAcknowledge('${t.id}', event)" title="Lead override --- acknowledge on behalf of ${escapeHtml(t.assignee)}">⚡ Override</button>`;
    }
  }
  // Audit badge --- shown when the task was acknowledged via override
  const overrideAuditBadge = (t.acknowledged && t.acknowledgedOverrideBy)
    ? `<span class="override-audit-badge" title="Acknowledged via Lead override by ${escapeHtml(t.acknowledgedOverrideBy)}">⚡ OVERRIDE</span>`
    : '';

  const cardClasses = `task-card status-${t.status}${isOverdue ? ' is-overdue' : ''}${isImminent ? ' is-imminent' : ''}${isSoon ? ' is-soon' : ''}${needsAck ? ' needs-ack' : ''}${t.completionRejected ? ' completion-rejected' : ''}${state.bulkSelectionMode ? ' bulk-mode' : ''}${state.bulkSelectionMode && isTaskSelected(t.id) ? ' bulk-selected' : ''}`;
  // Sign-off status footer (only shown on 'done' tasks OR rejected tasks)
  let signOffFooter = '';
  if (t.completionRejected) {
    // Rejected --- show red rejection footer even if status has been reverted
    const rejDate = t.completionRejectedAt
      ? new Date(t.completionRejectedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
      : '';
    const reason = t.completionRejectionReason || 'Rejected';
    const ackedFlag = t.completionRejectionAcknowledged ? '✓' : '⚠';
    signOffFooter = `<div class="task-signoff-footer rejected" title="Completion rejected by ${escapeHtml(t.completionRejectedBy || 'Lead')} --- reason: ${escapeHtml(reason)}${rejDate ? ' on ' + rejDate : ''}${t.completionRejectionAcknowledged ? ' · acknowledged by assignee' : ' · awaiting assignee ack'}">✗ <strong>REJECTED</strong> <span class="rejected-reason-chip">${escapeHtml(reason)}</span>${rejDate ? ` · ${rejDate}` : ''} ${ackedFlag}</div>`;
  } else if (t.status === 'done') {
    if (t.completionAcknowledged && t.completionAcknowledgedBy) {
      const stampDate = t.completionAcknowledgedAt
        ? new Date(t.completionAcknowledgedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
        : '';
      signOffFooter = `<div class="task-signoff-footer signed" title="Signed off by ${escapeHtml(t.completionAcknowledgedBy)} on ${stampDate}">✓ Signed off by ${escapeHtml(t.completionAcknowledgedBy)}${stampDate ? ` · ${stampDate}` : ''}</div>`;
    } else {
      signOffFooter = `<div class="task-signoff-footer pending" title="Awaiting Lead Estimator sign-off">⏳ Awaiting Lead Estimator sign-off</div>`;
    }
  }

  return `
    <div class="${cardClasses}" draggable="${state.bulkSelectionMode ? 'false' : 'true'}" data-task-id="${t.id}" onclick="${state.bulkSelectionMode ? `toggleTaskSelection(event, '${t.id}')` : `openTaskModal(null, '${t.id}')`}">
      ${state.bulkSelectionMode ? `<label class="bulk-checkbox-wrap" onclick="event.stopPropagation();"><input type="checkbox" class="bulk-checkbox" data-task-id="${t.id}" ${isTaskSelected(t.id) ? 'checked' : ''} onchange="toggleTaskSelection(event, '${t.id}')"></label>` : ''}
      ${dueBadge}
      ${newBadge}
      ${t.critical ? '<div class="priority-bar critical" title="Marked as Critical"></div>' : ''}
      <div class="task-card-top">
        <select class="card-status-select status-${t.status}" onclick="event.stopPropagation();" onchange="changeTaskStatusInline(event, '${t.id}', this.value)" title="Change status without opening task">
          <option value="not-started"${t.status==='not-started'?' selected':''}>Not Started</option>
          <option value="in-progress"${t.status==='in-progress'?' selected':''}>In Progress</option>
          <option value="blocked"${t.status==='blocked'?' selected':''}>Blocked</option>
          <option value="pending"${t.status==='pending'?' selected':''}>Pending</option>
          <option value="done"${t.status==='done'?' selected':''}>Complete</option>
        </select>
        <span class="csi-code">${escapeHtml(catShort)}</span>
        ${offsetBadge}
        ${recurrenceBadge}
        ${t.critical ? '<span class="critical-chip" title="Marked as Critical">🔥 CRITICAL</span>' : ''}
        ${checklistChip}
        ${deliverableChip}
        ${bestPracticeChip}
        ${leadCompChip}
        ${hoursChip}
        ${startByChip}
        ${bicHtml}
        ${isOverdue ? '<span class="day-offset" style="background:rgba(255,255,255,0.3);color:#fff;font-weight:700;">OVERDUE</span>' : ''}
      </div>
      <div class="task-title">${escapeHtml(t.title)}</div>
      <div class="task-meta">
        <span class="assignee">${avatarHtml}</span>
        <span class="due-date ${dueClass}">${due}</span>
      </div>
      ${sourceBadge ? `<div class="task-meta task-meta-source" style="margin-top:4px;">${sourceBadge}</div>` : ''}
      ${supportHtml ? `<div class="task-meta" style="margin-top:4px;">${supportHtml}</div>` : ''}
      ${overrideAuditBadge ? `<div class="task-meta" style="margin-top:4px;">${overrideAuditBadge}</div>` : ''}
      ${signOffFooter}
      ${ackButton}
      ${overrideButton}
    </div>
  `;
}

function isTaskOverdue(t) {
  if (!t.dueDate || t.status === 'done') return false;
  return getDaysLeft(t.dueDate) < 0;
}

function isTaskDueImminent(t) {
  // 0 or 1 days out --- more urgent tier
  if (!t.dueDate || t.status === 'done') return false;
  const d = getDaysLeft(t.dueDate);
  return d !== null && d >= 0 && d <= 1;
}

function isTaskDueSoon(t) {
  // Exactly 2 days out --- mutually exclusive with imminent
  if (!t.dueDate || t.status === 'done') return false;
  const d = getDaysLeft(t.dueDate);
  return d === 2;
}

function getDueSoonLabel(t) {
  const d = getDaysLeft(t.dueDate);
  if (d === 0) return '⚠ TODAY';
  if (d === 1) return '⚠ TOMORROW';
  if (d === 2) return '⚠ 2 DAYS';
  return '';
}

function getMemberTitle(name) {
  if (!name) return '';
  const m = state.teamMembers.find(x => x.name === name);
  return m ? m.title : '';
}

// =============================================================
// TABLE VIEW
// =============================================================
function renderTableRow(t, statusLabels) {
  const stage = STAGES.find(s=>s.id===t.stage) || STAGES[0];
  const dueClass = getDueClass(t.dueDate, t.status);
  const isOverdue = isTaskOverdue(t);
  const isImminent = !isOverdue && isTaskDueImminent(t);
  const isSoon = !isOverdue && !isImminent && isTaskDueSoon(t);
  const initials = (t.assignee || '?').split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
  const color = t.assignee ? avatarColor(t.assignee) : '#9ba4b0';
  const photo = t.assignee ? getMemberPhoto(t.assignee) : null;
  const avatarHtml = t.assignee
    ? (photo
        ? `<span class="avatar has-photo"><img src="${photo}" alt=""></span>`
        : `<span class="avatar" style="background:${color};">${escapeHtml(initials)}</span>`)
    : '';
  // Multi-lead text for the assignee cell --- shows "Sarah · Trent" or
  // "Sarah +N" when there are co-Leads.
  const tblLeads = (typeof getTaskLeads === 'function') ? getTaskLeads(t) : (t.assignee ? [t.assignee] : []);
  let tblLeadText = '';
  if (tblLeads.length === 0) tblLeadText = '';
  else if (tblLeads.length === 1) tblLeadText = escapeHtml(tblLeads[0]);
  else if (tblLeads.length === 2) tblLeadText = `${escapeHtml(tblLeads[0])} <span class="co-lead-sep">·</span> ${escapeHtml(tblLeads[1])}`;
  else tblLeadText = `${escapeHtml(tblLeads[0])} <span class="co-lead-more" title="${escapeAttr(tblLeads.slice(1).join(', '))}">+${tblLeads.length - 1}</span>`;

  // Support member cell
  let supportCell = '<span style="color:var(--text-faint);">---</span>';
  if (t.support && t.support.trim()) {
    const sInitials = t.support.split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
    const sColor = avatarColor(t.support);
    const sPhoto = getMemberPhoto(t.support);
    const sAvatar = sPhoto
      ? `<span class="avatar has-photo"><img src="${sPhoto}" alt=""></span>`
      : `<span class="avatar" style="background:${sColor};">${escapeHtml(sInitials)}</span>`;
    supportCell = `<span class="assignee">${sAvatar}${escapeHtml(t.support)}</span>`;
  }

  // Ball in Court cell
  const bicCell = t.ballInCourt
    ? `<span class="bic-chip bic-color-${bicColorFor(t.ballInCourt)} bic-${t.ballInCourt.replace(/[^A-Za-z]/g,'')}">${escapeHtml(t.ballInCourt)}</span>`
    : '<span style="color:var(--text-faint);">---</span>';

  const offsetText = typeof t.dayOffset === 'number' ? `D+${t.dayOffset}` : '---';
  const notesShort = t.notes ? (t.notes.length > 60 ? t.notes.slice(0, 58) + '...' : t.notes) : '';

  // Row tier: overdue > imminent (1d) > soon (2d) > regular
  let rowClass;
  if (isOverdue) rowClass = 'row-overdue';
  else if (isImminent) rowClass = `row-${t.status} row-imminent`;
  else if (isSoon) rowClass = `row-${t.status} row-soon`;
  else rowClass = `row-${t.status}`;

  // Inline due-reminder badge in the status cell
  let dueInline = '';
  if (!isOverdue && (isImminent || isSoon)) {
    const cls = isImminent ? 'badge-imminent' : 'badge-soon';
    dueInline = `<span class="due-inline ${cls}">${getDueSoonLabel(t)}</span>`;
  }
  const baseStatus = statusLabels[t.status] || t.status;
  const statusText = isOverdue ? 'OVERDUE' : baseStatus;

  // Acknowledgment indicators for table view
  const needsAck = t.assignee && t.assignee.trim() && !t.acknowledged;
  const newBadgeTable = needsAck
    ? `<span class="table-new-badge" title="Newly assigned to ${escapeHtml(t.assignee)} --- awaiting acknowledgment">NEW</span>`
    : '';
  const ackBtnTable = needsAck
    ? `<button class="table-ack-btn" onclick="acknowledgeTask('${t.id}', event)" title="${escapeHtml(t.assignee)}, click to acknowledge this new task">✓ Ack</button>`
    : '';
  // Lead Estimator override button --- shown only to Lead when current user isn't the assignee
  let overrideBtnTable = '';
  if (needsAck) {
    const proj = state.projects.find(p => p.id === state.activeProjectId);
    const lead = proj?.leadEstimator?.trim();
    const currentUser = getCurrentUser();
    const isLead = currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();
    const isAssignee = currentUser && t.assignee && currentUser.toLowerCase() === t.assignee.toLowerCase();
    if (isLead && !isAssignee) {
      overrideBtnTable = `<button class="table-override-btn" onclick="overrideAcknowledge('${t.id}', event)" title="Lead override --- ack on behalf of ${escapeHtml(t.assignee)}">⚡</button>`;
    }
  }
  // Override audit badge
  const overrideBadgeTable = (t.acknowledged && t.acknowledgedOverrideBy)
    ? `<span class="override-audit-badge" title="Acknowledged via Lead override by ${escapeHtml(t.acknowledgedOverrideBy)}">⚡</span>`
    : '';
  // ===== Required-item chips for the Table view =====
  // Mirror the Board treatment: loud red + pulse when required SUBTASKS or
  // DELIVERABLES are still open, distinct icon + label so they read as
  // different categories at a glance even when stacked on the same row.
  // Compact `-table` variant hides the progress bar (table cells are tight).
  let clChipTable = '';
  const clInfoTable = getChecklistChipLabel(t);
  if (clInfoTable) {
    let stateClass = '';
    let icon = '☐';
    let label = `${clInfoTable.done}/${clInfoTable.total}`;
    let titleText = `${clInfoTable.done} of ${clInfoTable.total} checklist subtasks complete`;
    if (clInfoTable.allDone) {
      stateClass = ' cl-chip-done';
      icon = '✓';
    } else if (clInfoTable.hasRequiredOpen) {
      stateClass = ' cl-chip-required-open';
      icon = '☐';
      label = `${clInfoTable.reqLeft} SUBTASK${clInfoTable.reqLeft === 1 ? '' : 'S'} LEFT`;
      titleText = `${clInfoTable.reqLeft} of ${clInfoTable.reqTotal} required SUBTASKS still open --- task cannot be marked Complete until these are done`;
    }
    clChipTable = `<span class="cl-chip cl-chip-table${stateClass}" title="${escapeAttr(titleText)}">
      <span class="cl-chip-icon">${icon}</span>
      <span class="cl-chip-count">${escapeHtml(label)}</span>
    </span>`;
  }
  let dlvChipTable = '';
  const dlvInfoTable = getDeliverableChipLabel(t);
  if (dlvInfoTable) {
    let stateClass = '';
    let icon = '📦';
    let label = `${dlvInfoTable.done}/${dlvInfoTable.total}`;
    let titleText = `${dlvInfoTable.done} of ${dlvInfoTable.total} deliverables complete`;
    if (dlvInfoTable.allDone) {
      stateClass = ' dlv-chip-done';
      icon = '✓';
    } else if (dlvInfoTable.hasRequiredOpen) {
      stateClass = ' dlv-chip-required-open';
      icon = '📦';
      label = `${dlvInfoTable.reqLeft} DELIVERABLE${dlvInfoTable.reqLeft === 1 ? '' : 'S'} LEFT`;
      titleText = `${dlvInfoTable.reqLeft} of ${dlvInfoTable.reqTotal} required DELIVERABLES still open --- task cannot be marked Complete until these are submitted`;
    }
    dlvChipTable = `<span class="dlv-chip dlv-chip-table${stateClass}" title="${escapeAttr(titleText)}">
      <span class="dlv-chip-icon">${icon}</span>
      <span class="dlv-chip-count">${escapeHtml(label)}</span>
    </span>`;
  }
  // Best-practice indicator chip --- flags tasks with Lead-authored guidance
  let bpChipTable = '';
  if (t.bestPractice && t.bestPractice.trim()) {
    const tblUser = (typeof getCurrentUser === 'function') ? (getCurrentUser() || '') : '';
    const isMyTaskUnacked = tblUser
      && t.assignee
      && t.assignee.toLowerCase() === tblUser.toLowerCase()
      && t.bestPracticePopupEnabled !== false
      && (!t.bestPracticeAck || !t.bestPracticeAck[tblUser.toLowerCase()]);
    const newTag = isMyTaskUnacked ? ' · NEW' : '';
    bpChipTable = `<span class="bp-chip bp-chip-table" title="Best-practice notes from the Lead Estimator${newTag ? ' --- you have not acknowledged these yet' : ''}">💡 Tip${newTag}</span>`;
  }
  // Sign-off inline indicator for done tasks
  let signOffTable = '';
  if (t.status === 'done') {
    if (t.completionAcknowledged && t.completionAcknowledgedBy) {
      signOffTable = `<span class="table-signoff signed" title="Signed off by ${escapeHtml(t.completionAcknowledgedBy)}">✓ Signed</span>`;
    } else {
      signOffTable = `<span class="table-signoff pending" title="Awaiting Lead Estimator sign-off">⏳ Pending</span>`;
    }
  }

  return `
    <tr class="${rowClass}${needsAck ? ' row-needs-ack' : ''}${state.bulkSelectionMode && isTaskSelected(t.id) ? ' bulk-selected' : ''}" onclick="${state.bulkSelectionMode ? `toggleTaskSelection(event, '${t.id}')` : `openTaskModal(null, '${t.id}')`}">
      ${state.bulkSelectionMode ? `<td class="bulk-cell" onclick="event.stopPropagation();"><input type="checkbox" class="bulk-checkbox" data-task-id="${t.id}" ${isTaskSelected(t.id) ? 'checked' : ''} onchange="toggleTaskSelection(event, '${t.id}')"></td>` : ''}
      <td data-col="status">
        <select class="inline-status-select status-${t.status}" onclick="event.stopPropagation();" onchange="changeTaskStatusInline(event, '${t.id}', this.value)" title="Change status without opening task">
          <option value="not-started"${t.status==='not-started'?' selected':''}>Not Started</option>
          <option value="in-progress"${t.status==='in-progress'?' selected':''}>In Progress</option>
          <option value="blocked"${t.status==='blocked'?' selected':''}>Blocked / RFI</option>
          <option value="pending"${t.status==='pending'?' selected':''}>Pending</option>
          <option value="done"${t.status==='done'?' selected':''}>Complete</option>
        </select>
        ${dueInline}${signOffTable}
      </td>
      <td data-col="task" class="task-title-cell" style="font-weight:600;">${newBadgeTable}${escapeHtml(t.title)}${clChipTable}${dlvChipTable}${bpChipTable}${ackBtnTable}${overrideBtnTable}${overrideBadgeTable}</td>
      <td data-col="stage"><span class="csi-code" style="color:var(--sbg-navy);background:var(--surface-3);">${stage.icon} ${escapeHtml(stage.name)}</span></td>
      <td data-col="assignee">${tblLeads.length > 0 ? `<span class="assignee">${avatarHtml}${tblLeadText}</span>` : '<span style="color:var(--text-faint);">Unassigned</span>'}</td>
      <td data-col="support">${supportCell}</td>
      <td data-col="bic">${bicCell}</td>
      <td data-col="priority">${t.critical ? '<span class="priority-tag critical" title="Marked as Critical">🔥 CRITICAL</span>' : '<span style="color:var(--text-faint);">---</span>'}</td>
      <td data-col="due" class="due-date ${dueClass}">${t.dueDate ? formatDate(t.dueDate) : '---'}</td>
      <td data-col="hours" class="hours-cell">${state.hoursEnabled && typeof t.estimatedHours === 'number' && t.estimatedHours > 0 ? `<span class="hours-cell-val">${escapeHtml(formatHours(t.estimatedHours))}</span>` : '<span style="color:var(--text-faint);">---</span>'}</td>
      <td data-col="offset" class="mono" style="color:var(--text-dim);">${offsetText}</td>
      <td data-col="source">${(() => {
        if (!t.source) return '<span style="color:var(--text-faint);">---</span>';
        const srcOpt = findSourceOption(t.source);
        const visual = srcOpt && srcOpt.photo
          ? `<span class="source-badge-img"><img src="${srcOpt.photo}" alt=""></span>`
          : `<span class="source-badge-icon">${escapeHtml((srcOpt && srcOpt.icon) || '📥')}</span>`;
        return `<span class="source-badge" title="Source: ${escapeHtml(t.source)}">${visual}<span class="source-badge-name">${escapeHtml(t.source)}</span></span>`;
      })()}</td>
      <td data-col="category" style="color:var(--text-dim);font-size:12px;">${escapeHtml(t.category)}</td>
      <td data-col="notes" style="color:var(--text-dim);font-size:12px;" title="${escapeHtml(t.notes || '')}">${escapeHtml(notesShort) || '<span style="color:var(--text-faint);">---</span>'}</td>
    </tr>
  `;
}

function clearTableSort() {
  state.tableSort = { col: null, dir: 'asc' };
  saveState();
  render();
}

function renderTableView(project) {
  const tbody = document.getElementById('tableBody');
  const modeBar = document.getElementById('tableModeBar');
  // Hide/show the Hours column based on whether feature is enabled. We set
  // a body-level data attribute that CSS uses to hide every td[data-col="hours"]
  // and the th in one rule.
  document.body.setAttribute('data-hours-enabled', state.hoursEnabled ? 'true' : 'false');
  const statusLabels = {
    'not-started': 'Not Started',
    'in-progress': 'In Progress',
    'blocked': 'Blocked / RFI',
    'pending': 'Pending',
    'done': 'Complete'
  };

  // Add or remove the bulk-checkbox column header based on selection mode.
  // We do this dynamically so the column appears only when needed.
  const headerRow = document.querySelector('.task-table thead tr');
  if (headerRow) {
    const existingBulkTh = headerRow.querySelector('th.bulk-th');
    if (state.bulkSelectionMode && !existingBulkTh) {
      const th = document.createElement('th');
      th.className = 'bulk-th';
      th.style.width = '32px';
      th.innerHTML = '<input type="checkbox" id="bulkHeaderCheckbox" onchange="bulkHeaderCheckboxToggle(this)" title="Select all visible tasks">';
      headerRow.insertBefore(th, headerRow.firstChild);
    } else if (!state.bulkSelectionMode && existingBulkTh) {
      existingBulkTh.remove();
    }
    // Update the header checkbox to reflect current state (all/some/none selected)
    if (state.bulkSelectionMode) {
      const cb = document.getElementById('bulkHeaderCheckbox');
      if (cb) {
        const visibleTasks = getFilteredTasks(project);
        const allSelected = visibleTasks.length > 0 && visibleTasks.every(t => state.bulkSelectedTaskIds.includes(t.id));
        const noneSelected = state.bulkSelectedTaskIds.length === 0;
        cb.checked = allSelected;
        cb.indeterminate = !allSelected && !noneSelected;
      }
    }
  }

  // Apply column-hide classes based on current grouping mode to reclaim space for Task/Notes.
  //   Group by Stage → hide Stage (redundant, shown in group header) + Offset
  //   Group by Assignee → hide Offset only (Stage still valuable when viewing one person's tasks across stages)
  //   Group by Source → hide Source (redundant, shown in group header) + Offset
  const tableEl = document.querySelector('.task-table');
  if (tableEl) {
    tableEl.classList.remove('hide-stage', 'hide-offset', 'hide-source');
    if (state.grouping === 'stage') {
      tableEl.classList.add('hide-stage', 'hide-offset');
    } else if (state.grouping === 'assignee') {
      tableEl.classList.add('hide-offset');
    } else if (state.grouping === 'source') {
      tableEl.classList.add('hide-source', 'hide-offset');
    }
  }

  // Update sort arrow indicators on all table headers
  document.querySelectorAll('.task-table th.sortable').forEach(th => {
    const col = th.dataset.col;
    const arrow = th.querySelector('.sort-arrow');
    th.classList.remove('sort-active');
    if (arrow) arrow.classList.remove('asc', 'desc');
    if (state.tableSort && state.tableSort.col === col) {
      th.classList.add('sort-active');
      if (arrow) arrow.classList.add(state.tableSort.dir);
    }
  });

  // Determine mode:
  //   - GROUPED: "All Stages" tab active + grouping by stage + no active column sort
  //   - FLAT:   any other case (specific stage selected, grouping by assignee, OR column sort active)
  const isAllStagesStageGroup =
    state.grouping === 'stage' &&
    state.activeStageId === 'all';
  const hasColumnSort = state.tableSort && state.tableSort.col;
  const useGrouped = isAllStagesStageGroup && !hasColumnSort;

  // Render mode bar
  if (modeBar) {
    if (useGrouped) {
      modeBar.innerHTML = `
        <div class="mode-label">📊 Table Mode: <span class="mode-value">Grouped by Stage</span></div>
        <div class="mode-label" style="font-weight:400;text-transform:none;letter-spacing:0;">Click any column header to sort as a flat list</div>
      `;
    } else if (hasColumnSort) {
      const colLabels = {
        status: 'Status', task: 'Task', stage: 'Stage', assignee: 'Assignee',
        support: 'Support', bic: 'Ball in Court', priority: 'Priority',
        due: 'Due Date', offset: 'Offset', source: 'Source',
        category: 'Category', notes: 'Notes'
      };
      const dirLabel = state.tableSort.dir === 'desc' ? 'Descending ▼' : 'Ascending ▲';
      const colLabel = colLabels[state.tableSort.col] || state.tableSort.col;
      modeBar.innerHTML = `
        <div class="mode-label">⇅ Sorted by: <span class="mode-value">${colLabel} · ${dirLabel}</span></div>
        ${isAllStagesStageGroup ? '<button class="mode-btn" onclick="clearTableSort()">⟲ Back to Grouped by Stage</button>' : ''}
      `;
    } else {
      modeBar.innerHTML = '';
    }
  }

  // Get the task set respecting current filter
  const allTasks = getFilteredTasks(project);

  if (allTasks.length === 0) {
    tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;padding:30px;color:var(--text-dim);font-style:italic;">No tasks yet</td></tr>';
    return;
  }

  if (useGrouped) {
    // ========== GROUPED BY STAGE VIEW ==========
    const rows = [];
    STAGES.forEach(stage => {
      const stageTasks = allTasks.filter(t => t.stage === stage.id).sort(sortTasks);
      if (stageTasks.length === 0) return;
      const done = stageTasks.filter(t => t.status === 'done').length;
      const total = stageTasks.length;
      const pct = total > 0 ? Math.round((done / total) * 100) : 0;
      const remaining = total - done;

      // Stage header row --- spans all 12 columns
      rows.push(`
        <tr class="stage-group-header">
          <td colspan="12">
            <div class="sgh-inner">
              <div class="sgh-title">
                <span class="sgh-icon">${stage.icon}</span>
                <span class="sgh-name">${escapeHtml(stage.name)}</span>
                <span class="sgh-count">${done} / ${total} · ${remaining} left</span>
              </div>
              <div class="sgh-progress">
                <div class="sgh-progress-bar"><div class="sgh-progress-fill" style="width:${pct}%"></div></div>
                <span class="sgh-pct">${pct}%</span>
              </div>
            </div>
          </td>
        </tr>
      `);
      // Task rows for this stage
      stageTasks.forEach(t => rows.push(renderTableRow(t, statusLabels)));
    });

    if (rows.length === 0) {
      tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;padding:30px;color:var(--text-dim);font-style:italic;">No tasks yet</td></tr>';
    } else {
      tbody.innerHTML = rows.join('');
    }
  } else {
    // ========== FLAT SORTED VIEW ==========
    const tasks = hasColumnSort
      ? sortTasksByColumn(allTasks, state.tableSort.col, state.tableSort.dir)
      : allTasks.slice().sort(sortTasks);
    tbody.innerHTML = tasks.map(t => renderTableRow(t, statusLabels)).join('');
  }
}

// =============================================================
// CALENDAR VIEW --- Day / Week / 2-Week / Month + assignee filter
// =============================================================
function setCalRange(range) {
  state.calRange = range;
  saveState();
  render();
}
function setCalAssignee(val) {
  state.calAssignee = val;
  saveState();
  render();
}
function calNav(delta) {
  const cursor = new Date(state.calCursor + 'T00:00:00');
  if (state.calRange === 'month') {
    cursor.setMonth(cursor.getMonth() + delta);
  } else if (state.calRange === 'day') {
    cursor.setDate(cursor.getDate() + delta);
  } else if (state.calRange === 'week') {
    cursor.setDate(cursor.getDate() + 7 * delta);
  } else if (state.calRange === '2week') {
    cursor.setDate(cursor.getDate() + 14 * delta);
  }
  state.calCursor = cursor.toISOString().slice(0,10);
  state.calMonth = state.calCursor.slice(0,7);
  saveState();
  render();
}
function calToday() {
  state.calCursor = new Date().toISOString().slice(0,10);
  state.calMonth = state.calCursor.slice(0,7);
  saveState();
  render();
}

function populateCalAssigneeFilter(project) {
  const sel = document.getElementById('calAssigneeSelect');
  if (!sel) return;
  const buckets = getAssigneeBuckets(project);
  sel.innerHTML = '<option value="all">All Team</option>' +
    buckets.map(b => {
      const label = b.name === 'unassigned' ? 'Unassigned' : b.name;
      return `<option value="${escapeHtml(b.name)}" ${state.calAssignee===b.name?'selected':''}>${escapeHtml(label)} (${b.total})</option>`;
    }).join('');
  sel.value = state.calAssignee;
}

function filterCalTasks(project) {
  if (state.calAssignee === 'all') return project.tasks;
  if (state.calAssignee === 'unassigned') return project.tasks.filter(t => !t.assignee || !t.assignee.trim());
  return project.tasks.filter(t => (t.assignee||'').trim() === state.calAssignee);
}

// =============================================================
// SCHEDULE / GANTT VIEW --- bar chart of tasks across bid timeline
// =============================================================

// =============================================================
// LOOK AHEAD VIEW --- Today / 2 Days / 1 Week / 2 Weeks task forecast
// Filterable by project (current or all) and assignee (everyone or specific person).
// Tasks grouped by day, color-coded by status, click-to-edit.
// =============================================================

function setLookAheadWindow(days) {
  state.laWindow = parseInt(days, 10);
  saveState();
  document.querySelectorAll('.la-window-btn').forEach(b => b.classList.toggle('active', parseInt(b.dataset.lawindow, 10) === state.laWindow));
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderLookAheadView(project);
}

function setLookAheadProject(scope) {
  state.laProjectScope = scope;
  saveState();
  // Refresh assignee list since the source set changed
  populateLookAheadAssignees();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderLookAheadView(project);
}

function setLookAheadAssignee(name) {
  state.laAssignee = name;
  saveState();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderLookAheadView(project);
}

function toggleLookAheadOverdue(checked) {
  state.laIncludeOverdue = !!checked;
  saveState();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderLookAheadView(project);
}

function toggleLookAheadHideDone(checked) {
  state.laHideDone = !!checked;
  saveState();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderLookAheadView(project);
}

// Build the assignee dropdown from whichever projects are in scope
function populateLookAheadAssignees() {
  const sel = document.getElementById('laAssigneeSelect');
  if (!sel) return;
  const sourceProjects = getLookAheadSourceProjects();
  const names = new Set();
  let hasUnassigned = false;
  sourceProjects.forEach(p => {
    (p.tasks || []).forEach(t => {
      const a = (t.assignee || '').trim();
      if (a) names.add(a);
      else hasUnassigned = true;
      // Include every support member --- primary + additional
      getAllSupportMembers(t).forEach(s => names.add(s));
    });
  });
  const sortedNames = Array.from(names).sort((a, b) => a.localeCompare(b));
  let opts = '<option value="all">Everyone</option>';
  if (hasUnassigned) opts += '<option value="unassigned">--- Unassigned ---</option>';
  sortedNames.forEach(n => {
    opts += `<option value="${escapeHtml(n)}">${escapeHtml(n)}</option>`;
  });
  sel.innerHTML = opts;
  // Restore selection if still valid
  if (state.laAssignee !== 'all' && state.laAssignee !== 'unassigned' && !sortedNames.includes(state.laAssignee)) {
    state.laAssignee = 'all';
  }
  sel.value = state.laAssignee || 'all';
}

// Returns the array of projects currently in scope based on laProjectScope
function getLookAheadSourceProjects() {
  if (state.laProjectScope === 'all') {
    // Active projects only --- exclude won/lost/no-bid past pursuits
    return (state.projects || []).filter(p => {
      const status = (p.status || '').toLowerCase();
      return status !== 'won' && status !== 'lost' && status !== 'no-bid';
    });
  }
  // Current project only
  const active = state.projects.find(p => p.id === state.activeProjectId);
  return active ? [active] : [];
}

// Returns YYYY-MM-DD for a given Date object using local timezone
function fmtLocalDate(d) {
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

// Build the look ahead data: tasks grouped by date within the window
function buildLookAheadData() {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const todayStr = fmtLocalDate(today);
  const windowDays = state.laWindow || 7;

  // End date is today + (windowDays - 1) days inclusive
  // e.g. window=1 → just today; window=7 → today + next 6 days
  const endDate = new Date(today);
  endDate.setDate(endDate.getDate() + windowDays - 1);
  const endStr = fmtLocalDate(endDate);

  const sourceProjects = getLookAheadSourceProjects();

  // Collect tasks meeting the filter criteria
  const matchingTasks = []; // {project, task, isOverdue, dateBucket}
  sourceProjects.forEach(project => {
    (project.tasks || []).forEach(task => {
      // Hide done tasks if filter is on
      if (state.laHideDone && task.status === 'done') return;

      // Assignee filter
      if (state.laAssignee && state.laAssignee !== 'all') {
        if (state.laAssignee === 'unassigned') {
          if (task.assignee && task.assignee.trim()) return;
        } else {
          const isLead = (task.assignee || '').trim() === state.laAssignee;
          const isSupport = isTaskSupport(task, state.laAssignee);
          if (!isLead && !isSupport) return;
        }
      }

      // Date filter
      if (!task.dueDate) return; // skip tasks without due dates --- they don't fit a "look ahead" timeline

      const isOverdue = task.dueDate < todayStr && task.status !== 'done';
      const inWindow = task.dueDate >= todayStr && task.dueDate <= endStr;

      if (isOverdue && state.laIncludeOverdue) {
        matchingTasks.push({ project, task, isOverdue: true, dateBucket: 'overdue' });
      } else if (inWindow) {
        matchingTasks.push({ project, task, isOverdue: false, dateBucket: task.dueDate });
      }
    });
  });

  // Group by date bucket
  const groups = new Map();
  // Always create overdue bucket first if there are any overdue
  matchingTasks.forEach(item => {
    const key = item.dateBucket;
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(item);
  });

  // Build ordered groups: overdue first (if present), then date buckets in chronological order
  const orderedGroups = [];
  if (groups.has('overdue')) {
    orderedGroups.push({ key: 'overdue', items: groups.get('overdue') });
    groups.delete('overdue');
  }
  // Walk through every day in the window in order
  for (let d = 0; d < windowDays; d++) {
    const date = new Date(today);
    date.setDate(date.getDate() + d);
    const key = fmtLocalDate(date);
    if (groups.has(key)) {
      orderedGroups.push({ key, items: groups.get(key) });
    } else if (d < 7 || d === windowDays - 1) {
      // Show empty days too within the first week or on the final day, so the structure is visible.
      // Skip showing empty days beyond the first week of a 2-week view to reduce noise.
      orderedGroups.push({ key, items: [] });
    }
  }

  return { orderedGroups, totalTasks: matchingTasks.length, windowDays, today, endDate };
}

function renderLookAheadView(project) {
  // Update sub-control button states
  document.querySelectorAll('.la-window-btn').forEach(b => b.classList.toggle('active', parseInt(b.dataset.lawindow, 10) === state.laWindow));
  const projSel = document.getElementById('laProjectSelect');
  if (projSel) projSel.value = state.laProjectScope || 'active';
  const incOver = document.getElementById('laIncludeOverdue');
  if (incOver) incOver.checked = !!state.laIncludeOverdue;
  const hideDone = document.getElementById('laHideDone');
  if (hideDone) hideDone.checked = !!state.laHideDone;

  populateLookAheadAssignees();

  // Title text
  const titleEl = document.getElementById('laTitle');
  if (titleEl) {
    const windowLabel = ({ 1: 'Today', 2: '2-Day', 7: '1-Week', 14: '2-Week' })[state.laWindow] || `${state.laWindow}-Day`;
    const scopeLabel = state.laProjectScope === 'all'
      ? 'All Active Projects'
      : (project ? escapeHtml(project.name) : '(no project selected)');
    const assigneeLabel = state.laAssignee === 'all' ? '' : (state.laAssignee === 'unassigned' ? ' · Unassigned only' : ` · ${escapeHtml(state.laAssignee)}`);
    titleEl.innerHTML = `${windowLabel} Look Ahead · ${scopeLabel}${assigneeLabel}`;
  }

  const data = buildLookAheadData();
  const contentEl = document.getElementById('lookaheadContent');
  const emptyEl = document.getElementById('lookaheadEmpty');
  const summaryEl = document.getElementById('lookaheadSummary');

  // Summary stats panel
  if (summaryEl) {
    const overdueCount = (data.orderedGroups.find(g => g.key === 'overdue')?.items.length) || 0;
    const upcomingCount = data.totalTasks - overdueCount;
    const todayKey = fmtLocalDate(data.today);
    const todayCount = (data.orderedGroups.find(g => g.key === todayKey)?.items.length) || 0;
    summaryEl.innerHTML = `
      <div class="la-summary-row">
        <div class="la-stat ${overdueCount > 0 ? 'la-stat-red' : ''}">
          <div class="la-stat-num">${overdueCount}</div>
          <div class="la-stat-label">Overdue</div>
        </div>
        <div class="la-stat ${todayCount > 0 ? 'la-stat-orange' : ''}">
          <div class="la-stat-num">${todayCount}</div>
          <div class="la-stat-label">Due Today</div>
        </div>
        <div class="la-stat la-stat-navy">
          <div class="la-stat-num">${upcomingCount}</div>
          <div class="la-stat-label">In Window</div>
        </div>
        <div class="la-stat-window">
          <div class="la-window-label">${formatDate(fmtLocalDate(data.today))}</div>
          <div class="la-window-arrow">→</div>
          <div class="la-window-label">${formatDate(fmtLocalDate(data.endDate))}</div>
        </div>
      </div>
    `;
  }

  // Empty state
  if (data.totalTasks === 0) {
    if (contentEl) contentEl.innerHTML = '';
    if (emptyEl) emptyEl.style.display = 'flex';
    return;
  }
  if (emptyEl) emptyEl.style.display = 'none';

  // Build content --- one card per day group
  const todayKey = fmtLocalDate(data.today);
  let html = '';
  data.orderedGroups.forEach(group => {
    if (group.key === 'overdue') {
      html += `
        <div class="la-day-group la-day-overdue">
          <div class="la-day-header">
            <div class="la-day-name">⚠ Overdue</div>
            <div class="la-day-count">${group.items.length} task${group.items.length === 1 ? '' : 's'}</div>
          </div>
          <div class="la-day-tasks">
            ${group.items.map(item => renderLookAheadTaskRow(item)).join('')}
          </div>
        </div>
      `;
      return;
    }

    const dateObj = new Date(group.key + 'T00:00:00');
    const isToday = group.key === todayKey;
    const tomorrowDate = new Date(data.today);
    tomorrowDate.setDate(tomorrowDate.getDate() + 1);
    const isTomorrow = group.key === fmtLocalDate(tomorrowDate);
    const dayName = dateObj.toLocaleDateString('en-US', { weekday: 'long' });
    const monthDay = dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    const isWeekend = dateObj.getDay() === 0 || dateObj.getDay() === 6;

    let dayLabel = `<span class="la-day-name-text">${dayName}</span> <span class="la-day-date">${monthDay}</span>`;
    if (isToday) dayLabel = `<span class="la-day-pill la-pill-today">TODAY</span> ${dayLabel}`;
    else if (isTomorrow) dayLabel = `<span class="la-day-pill la-pill-tomorrow">TOMORROW</span> ${dayLabel}`;

    const groupClass = isToday ? 'la-day-today' : (isTomorrow ? 'la-day-tomorrow' : (isWeekend ? 'la-day-weekend' : ''));

    html += `
      <div class="la-day-group ${groupClass}">
        <div class="la-day-header">
          <div class="la-day-name">${dayLabel}</div>
          <div class="la-day-count">${group.items.length === 0 ? '<span class="la-day-empty-label">No tasks</span>' : `${group.items.length} task${group.items.length === 1 ? '' : 's'}`}</div>
        </div>
        ${group.items.length > 0 ? `<div class="la-day-tasks">${group.items.map(item => renderLookAheadTaskRow(item)).join('')}</div>` : ''}
      </div>
    `;
  });

  if (contentEl) contentEl.innerHTML = html;
}

function renderLookAheadTaskRow(item) {
  const { project, task, isOverdue } = item;
  const stage = STAGES.find(s => s.id === task.stage);
  const stageLabel = stage ? `${stage.icon} ${escapeHtml(stage.name)}` : escapeHtml(task.stage || '');

  // Status pill
  const statusLabels = {
    'not-started': 'Not Started',
    'in-progress': 'In Progress',
    'blocked': 'Blocked',
    'pending': 'Pending',
    'done': 'Complete'
  };
  const statusClass = `la-status-${task.status}`;
  const statusLabel = statusLabels[task.status] || task.status;

  // Assignee chip
  let assigneeChip = '';
  if (task.assignee && task.assignee.trim()) {
    const initials = task.assignee.split(/\s+/).map(x => x[0]).join('').slice(0, 2).toUpperCase();
    const photo = getMemberPhoto(task.assignee);
    const color = avatarColor(task.assignee);
    const avatarMarkup = photo
      ? `<span class="la-avatar"><img src="${photo}" alt=""></span>`
      : `<span class="la-avatar" style="background:${color};">${escapeHtml(initials)}</span>`;
    assigneeChip = `<span class="la-assignee" title="Lead: ${escapeHtml(task.assignee)}">${avatarMarkup}<span class="la-assignee-name">${escapeHtml(task.assignee)}</span></span>`;
  } else {
    assigneeChip = `<span class="la-assignee la-assignee-none">⚠ Unassigned</span>`;
  }

  // Support chip --- show all support members (primary + additional), up to 3 inline
  let supportChip = '';
  const allSupports = getAllSupportMembers(task);
  if (allSupports.length > 0) {
    const visible = allSupports.slice(0, 3);
    const overflow = allSupports.length - visible.length;
    const avatars = visible.map(name => {
      const sInitials = name.split(/\s+/).map(x => x[0]).join('').slice(0, 2).toUpperCase();
      const sPhoto = getMemberPhoto(name);
      const sColor = avatarColor(name);
      return sPhoto
        ? `<span class="la-avatar la-avatar-sm" title="${escapeHtml(name)}"><img src="${sPhoto}" alt=""></span>`
        : `<span class="la-avatar la-avatar-sm" title="${escapeHtml(name)}" style="background:${sColor};">${escapeHtml(sInitials)}</span>`;
    }).join('');
    const overflowBadge = overflow > 0 ? `<span class="la-support-overflow">+${overflow}</span>` : '';
    const tooltip = `Support: ${allSupports.join(', ')}`;
    supportChip = `<span class="la-support" title="${escapeHtml(tooltip)}">+${avatars}${overflowBadge}</span>`;
  }

  // Project chip --- shown when scope is "all" so user can tell which project a task belongs to
  let projectChip = '';
  if (state.laProjectScope === 'all') {
    projectChip = `<span class="la-project-chip" title="${escapeHtml(project.name)}">📁 ${escapeHtml(project.name)}</span>`;
  }

  // Priority indicator
  // Look Ahead priority class --- replaced with critical-first marker since
  // priority tiers were removed in v33. Critical tasks get the red rail;
  // others get a neutral rail.
  const priorityClass = task.critical ? 'la-priority-critical' : 'la-priority-normal';

  // Overdue tag
  const overdueTag = isOverdue ? `<span class="la-overdue-tag">${getOverdueLabel(task.dueDate)}</span>` : '';

  // ===== Required-item chips --- mirror the Board card so unfinished required
  // SUBTASKS and DELIVERABLES stand out on Look Ahead too =====
  let laChecklistChip = '';
  const laClInfo = getChecklistChipLabel(task);
  if (laClInfo) {
    const pct = laClInfo.total > 0 ? Math.round((laClInfo.done / laClInfo.total) * 100) : 0;
    let stateClass = '';
    let icon = '☐';
    let label = `${laClInfo.done}/${laClInfo.total}`;
    let titleText = `${laClInfo.done} of ${laClInfo.total} checklist subtasks complete (${pct}%)`;
    if (laClInfo.allDone) {
      stateClass = ' cl-chip-done';
      icon = '✓';
    } else if (laClInfo.hasRequiredOpen) {
      stateClass = ' cl-chip-required-open';
      icon = '☐';
      label = `${laClInfo.reqLeft} SUBTASK${laClInfo.reqLeft === 1 ? '' : 'S'} LEFT`;
      titleText = `${laClInfo.reqLeft} of ${laClInfo.reqTotal} required SUBTASKS still open --- task cannot be marked Complete until these are done`;
    }
    laChecklistChip = `<span class="cl-chip${stateClass}" title="${escapeAttr(titleText)}">
      <span class="cl-chip-icon">${icon}</span>
      <span class="cl-chip-count">${escapeHtml(label)}</span>
      <span class="cl-chip-bar"><span class="cl-chip-bar-fill" style="width:${pct}%"></span></span>
    </span>`;
  }
  let laDeliverableChip = '';
  const laDlvInfo = getDeliverableChipLabel(task);
  if (laDlvInfo) {
    const pct = laDlvInfo.total > 0 ? Math.round((laDlvInfo.done / laDlvInfo.total) * 100) : 0;
    let stateClass = '';
    let icon = '📦';
    let label = `${laDlvInfo.done}/${laDlvInfo.total}`;
    let titleText = `${laDlvInfo.done} of ${laDlvInfo.total} deliverables complete (${pct}%)`;
    if (laDlvInfo.allDone) {
      stateClass = ' dlv-chip-done';
      icon = '✓';
    } else if (laDlvInfo.hasRequiredOpen) {
      stateClass = ' dlv-chip-required-open';
      icon = '📦';
      label = `${laDlvInfo.reqLeft} DELIVERABLE${laDlvInfo.reqLeft === 1 ? '' : 'S'} LEFT`;
      titleText = `${laDlvInfo.reqLeft} of ${laDlvInfo.reqTotal} required DELIVERABLES still open --- task cannot be marked Complete until these are submitted`;
    }
    laDeliverableChip = `<span class="dlv-chip${stateClass}" title="${escapeAttr(titleText)}">
      <span class="dlv-chip-icon">${icon}</span>
      <span class="dlv-chip-count">${escapeHtml(label)}</span>
      <span class="dlv-chip-bar"><span class="dlv-chip-bar-fill" style="width:${pct}%"></span></span>
    </span>`;
  }
  // Best-practice indicator chip --- flags tasks with Lead-authored guidance
  let laBestPracticeChip = '';
  if (task.bestPractice && task.bestPractice.trim()) {
    const laUser = (typeof getCurrentUser === 'function') ? (getCurrentUser() || '') : '';
    const isMyTaskUnacked = laUser
      && task.assignee
      && task.assignee.toLowerCase() === laUser.toLowerCase()
      && task.bestPracticePopupEnabled !== false
      && (!task.bestPracticeAck || !task.bestPracticeAck[laUser.toLowerCase()]);
    const newTag = isMyTaskUnacked ? ' · NEW' : '';
    laBestPracticeChip = `<span class="bp-chip" title="Best-practice notes from the Lead Estimator${newTag ? ' --- you have not acknowledged these yet' : ''}">💡 Tip${newTag}</span>`;
  }

  // NEW badge on Look Ahead rows when the task is awaiting the assignee's
  // acknowledgment --- same alert language as the Board card.
  let laNewBadge = '';
  let laAckButton = '';
  const laNeedsAck = task.assignee && task.assignee.trim() && !task.acknowledged;
  if (laNeedsAck) {
    laNewBadge = `<span class="la-new-badge" title="This task was newly assigned to ${escapeHtml(task.assignee)} and hasn't been acknowledged yet">NEW</span>`;
    // Only show the inline Ack button if the current user is the assignee
    const laUser2 = (typeof getCurrentUser === 'function') ? (getCurrentUser() || '') : '';
    if (laUser2 && task.assignee.toLowerCase() === laUser2.toLowerCase()) {
      laAckButton = `<button class="la-ack-btn" onclick="event.stopPropagation();laAcknowledgeFromRow('${project.id}','${task.id}')" title="Click to acknowledge this newly-assigned task">✓ Acknowledge</button>`;
    }
  }

  // Hours chip for Look Ahead --- inline cyan pill if feature on AND task has estimate
  let laHoursChip = '';
  if (state.hoursEnabled && typeof task.estimatedHours === 'number' && task.estimatedHours > 0) {
    const fH = (typeof formatHours === 'function') ? formatHours(task.estimatedHours) : (task.estimatedHours + 'h');
    laHoursChip = `<span class="hours-chip" title="Projected effort: ${escapeAttr(fH)}">⏱ ${escapeHtml(fH)}</span>`;
  }

  return `
    <div class="la-task-row ${priorityClass} ${isOverdue ? 'la-task-overdue' : ''} ${laNeedsAck ? 'la-task-needs-ack' : ''}" onclick="jumpToTaskFromLookAhead('${project.id}', '${task.id}')">
      <div class="la-task-priority-bar"></div>
      <div class="la-task-main">
        <div class="la-task-top">
          <span class="la-task-stage">${stageLabel}</span>
          ${projectChip}
          ${overdueTag}
          ${laNewBadge}
        </div>
        <div class="la-task-title">${escapeHtml(task.title)}</div>
        <div class="la-task-meta">
          ${assigneeChip}
          ${supportChip}
          <span class="la-task-status ${statusClass}">${statusLabel}</span>
          ${laChecklistChip}
          ${laDeliverableChip}
          ${laBestPracticeChip}
          ${laHoursChip}
        </div>
        ${laAckButton}
      </div>
    </div>
  `;
}

// Acknowledge a task directly from a Look Ahead row, in place. Does NOT
// switch the active project (the Look Ahead view spans projects); instead
// it operates directly on the target project so the user stays on the
// Look Ahead they're working from. Surfaces the same required-item scope
// confirm as the regular acknowledgeTask.
function laAcknowledgeFromRow(projectId, taskId) {
  const project = state.projects.find(p => p.id === projectId);
  if (!project) return;
  const t = project.tasks.find(x => x.id === taskId);
  if (!t) return;
  // Surface scope of work --- same logic as acknowledgeTask
  const r = getTaskReadiness(t);
  if (r.openCount > 0) {
    const lines = [];
    lines.push(`Acknowledge "${t.title || '(untitled task)'}"?\n`);
    lines.push(`This task has required items you'll be responsible for completing before it can be marked Done:\n`);
    if (r.openChecklist.length > 0) {
      lines.push(`📋 ${r.openChecklist.length} required checklist item${r.openChecklist.length===1?'':'s'}:`);
      r.openChecklist.slice(0, 6).forEach(i => lines.push(`   • ${i.text}`));
      if (r.openChecklist.length > 6) lines.push(`   ... and ${r.openChecklist.length - 6} more`);
      lines.push('');
    }
    if (r.openDeliverables.length > 0) {
      lines.push(`📦 ${r.openDeliverables.length} required deliverable${r.openDeliverables.length===1?'':'s'}:`);
      r.openDeliverables.slice(0, 6).forEach(d => lines.push(`   • ${d.description || d.fileName || '(unnamed)'}`));
      if (r.openDeliverables.length > 6) lines.push(`   ... and ${r.openDeliverables.length - 6} more`);
      lines.push('');
    }
    lines.push(`Open the task to see all details. Continue with acknowledgment?`);
    if (!confirm(lines.join('\n'))) return;
  }
  t.acknowledged = true;
  t.acknowledgedBy = t.assignee || '';
  t.acknowledgedAt = Date.now();
  if (typeof logTaskAcknowledged === 'function') {
    logTaskAcknowledged(project, t, t.acknowledgedBy);
  }
  saveState();
  render();
}

function getOverdueLabel(dueDate) {
  if (!dueDate) return 'OVERDUE';
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const due = new Date(dueDate + 'T00:00:00');
  const days = Math.round((today - due) / 86400000);
  if (days === 0) return 'OVERDUE';
  if (days === 1) return 'OVERDUE · 1 day';
  return `OVERDUE · ${days} days`;
}

function jumpToTaskFromLookAhead(projectId, taskId) {
  // Switch to the project if it's not already active
  if (state.activeProjectId !== projectId) {
    state.activeProjectId = projectId;
    saveState();
  }
  openTaskModal(null, taskId);
}

function setSchedGrouping(group) {
  state.schedGrouping = group;
  saveState();
  document.querySelectorAll('.sched-group-btn').forEach(b => b.classList.toggle('active', b.dataset.schedgroup === group));
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderScheduleView(project);
}

function setSchedZoom(zoom) {
  state.schedZoom = zoom;
  saveState();
  document.querySelectorAll('.sched-zoom-btn').forEach(b => b.classList.toggle('active', b.dataset.schedzoom === zoom));
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderScheduleView(project);
}

function toggleSchedHideDone(checked) {
  state.schedHideDone = !!checked;
  saveState();
  const project = state.projects.find(p => p.id === state.activeProjectId);
  if (project) renderScheduleView(project);
}

// Compute the date range for the schedule chart axis.
// Auto-fit to project's bid window with padding, expanding if any tasks fall outside.
function getSchedDateRange(project, tasks) {
  const dates = [];
  if (project.startDate) dates.push(project.startDate);
  if (project.dueDate) dates.push(project.dueDate);
  tasks.forEach(t => {
    if (t.dueDate) dates.push(t.dueDate);
    // Also include computed start (dueDate - dayOffset) for tasks with offset
    if (t.dueDate && typeof t.dayOffset === 'number' && t.dayOffset > 0 && project.startDate) {
      // Bar starts at project start + (dayOffset - duration) --- which is bid start, basically
      dates.push(project.startDate);
    }
  });
  // Include milestones
  if (Array.isArray(project.milestones)) {
    project.milestones.forEach(m => { if (m.date) dates.push(m.date); });
  }
  if (dates.length === 0) return null;

  const sorted = dates.slice().sort();
  const start = new Date(sorted[0] + 'T00:00:00');
  const end = new Date(sorted[sorted.length - 1] + 'T00:00:00');
  // Pad 3 days on each side
  start.setDate(start.getDate() - 3);
  end.setDate(end.getDate() + 3);
  // Total days span
  const totalDays = Math.max(1, Math.round((end - start) / 86400000) + 1);
  return { start, end, totalDays };
}

// Date diff in whole days (positive if d2 is later than d1)
function daysFromStart(rangeStart, dateStr) {
  if (!dateStr) return 0;
  const d = new Date(dateStr + 'T00:00:00');
  return Math.round((d - rangeStart) / 86400000);
}

// Format a date as M/D for axis tick labels
function fmtTickDate(dateObj) {
  return `${dateObj.getMonth() + 1}/${dateObj.getDate()}`;
}

// Compute task bar positioning. Returns { startDay, endDay, isMilestone }.
// - If task has both dueDate AND a positive dayOffset, draw a bar from (dueDate - dayOffset) to dueDate.
// - If task only has dueDate (no offset or offset 0), draw as 1-day milestone diamond at dueDate.
// - If no dueDate at all, return null (skip rendering).
function getTaskBarBounds(task, rangeStart) {
  if (!task.dueDate) return null;
  const endDay = daysFromStart(rangeStart, task.dueDate);
  if (typeof task.dayOffset === 'number' && task.dayOffset > 0) {
    const startDay = endDay - task.dayOffset;
    return { startDay, endDay, isMilestone: false };
  }
  // Single-day milestone
  return { startDay: endDay, endDay, isMilestone: true };
}

// Get color for a task bar based on status + overdue state
function getSchedTaskColor(task) {
  if (isTaskOverdue(task)) return { fill: 'var(--sbg-red)', text: '#fff', border: '#9a261f' };
  switch (task.status) {
    case 'done':        return { fill: 'rgba(46,125,82,0.85)', text: '#fff', border: 'var(--green)' };
    case 'in-progress': return { fill: 'rgba(10,37,64,0.85)', text: '#fff', border: 'var(--sbg-navy)' };
    case 'blocked':     return { fill: 'rgba(200,50,43,0.85)', text: '#fff', border: 'var(--sbg-red)' };
    case 'pending':     return { fill: 'rgba(123,67,151,0.85)', text: '#fff', border: 'var(--purple)' };
    default:            return { fill: 'rgba(155,164,176,0.7)', text: 'var(--text)', border: 'var(--border-strong)' };
  }
}

// Group tasks by current schedule grouping
function getSchedGroupedTasks(project, tasks) {
  const groups = [];
  if (state.schedGrouping === 'stage') {
    STAGES.forEach(stage => {
      const stageTasks = tasks.filter(t => t.stage === stage.id);
      if (stageTasks.length > 0) {
        groups.push({
          id: stage.id,
          label: stage.name,
          icon: stage.icon,
          color: '#0a2540',
          tasks: stageTasks
        });
      }
    });
    // Catch tasks with stages no longer in the master list
    const orphanTasks = tasks.filter(t => !STAGES.some(s => s.id === t.stage));
    if (orphanTasks.length > 0) {
      groups.push({ id: 'orphan', label: 'Other', icon: '📦', color: '#6b7687', tasks: orphanTasks });
    }
  } else if (state.schedGrouping === 'assignee') {
    const byAssignee = new Map();
    tasks.forEach(t => {
      const key = (t.assignee || '').trim() || 'unassigned';
      if (!byAssignee.has(key)) byAssignee.set(key, []);
      byAssignee.get(key).push(t);
    });
    // Sort assignees alphabetically, unassigned last
    const sortedKeys = Array.from(byAssignee.keys()).sort((a, b) => {
      if (a === 'unassigned') return 1;
      if (b === 'unassigned') return -1;
      return a.localeCompare(b);
    });
    sortedKeys.forEach(name => {
      const isUnassigned = name === 'unassigned';
      groups.push({
        id: name,
        label: isUnassigned ? 'Unassigned' : name,
        icon: '',
        color: isUnassigned ? '#9ba4b0' : avatarColor(name),
        photo: isUnassigned ? null : getMemberPhoto(name),
        initials: isUnassigned ? '?' : name.split(/\s+/).map(x => x[0]).join('').slice(0, 2).toUpperCase(),
        tasks: byAssignee.get(name)
      });
    });
  } else if (state.schedGrouping === 'scope') {
    const byScope = new Map();
    tasks.forEach(t => {
      const key = (t.scopePackage || '').trim() || 'general';
      if (!byScope.has(key)) byScope.set(key, []);
      byScope.get(key).push(t);
    });
    // Sort: general last, others alphabetically
    const sortedKeys = Array.from(byScope.keys()).sort((a, b) => {
      if (a === 'general') return 1;
      if (b === 'general') return -1;
      return a.localeCompare(b);
    });
    sortedKeys.forEach(scopeName => {
      const isGeneral = scopeName === 'general';
      // Find icon/color from any task in the bucket
      const sample = byScope.get(scopeName)[0];
      groups.push({
        id: scopeName,
        label: isGeneral ? 'General (no scope package)' : scopeName,
        icon: isGeneral ? '📋' : (sample?.scopePackageIcon || '📦'),
        color: isGeneral ? '#6b7687' : (sample?.scopePackageColor || '#0a2540'),
        tasks: byScope.get(scopeName)
      });
    });
  }
  return groups;
}

function renderScheduleView(project) {
  const chartEl = document.getElementById('scheduleChart');
  const emptyEl = document.getElementById('scheduleEmpty');
  const titleEl = document.getElementById('schedTitle');
  if (!chartEl) return;

  // Update sub-control button active states
  document.querySelectorAll('.sched-group-btn').forEach(b => b.classList.toggle('active', b.dataset.schedgroup === state.schedGrouping));
  document.querySelectorAll('.sched-zoom-btn').forEach(b => b.classList.toggle('active', b.dataset.schedzoom === state.schedZoom));
  const hideDoneEl = document.getElementById('schedHideDone');
  if (hideDoneEl) hideDoneEl.checked = !!state.schedHideDone;

  // Filter tasks
  let tasks = (project.tasks || []).slice();
  if (state.schedHideDone) tasks = tasks.filter(t => t.status !== 'done');
  // Only render tasks with a due date --- bars need positions on the time axis
  tasks = tasks.filter(t => t.dueDate);

  if (titleEl) {
    const total = (project.tasks || []).length;
    const done = (project.tasks || []).filter(t => t.status === 'done').length;
    titleEl.innerHTML = `${escapeHtml(project.name)} <span class="sched-title-stats">${tasks.length} of ${total} tasks · ${done} complete</span>`;
  }

  if (tasks.length === 0) {
    chartEl.innerHTML = '';
    if (emptyEl) emptyEl.style.display = 'flex';
    return;
  }
  if (emptyEl) emptyEl.style.display = 'none';

  const range = getSchedDateRange(project, tasks);
  if (!range) {
    chartEl.innerHTML = '<div class="schedule-empty"><div class="se-icon">📅</div><h3>No date range available</h3><p>Set a Bid Start and Bid Due Date in Edit Project to see the schedule.</p></div>';
    return;
  }

  // Day cell width based on zoom + total range
  const dayWidthMap = { compact: 18, normal: 28, wide: 44 };
  const rowHeightMap = { compact: 22, normal: 28, wide: 36 };
  const dayWidth = dayWidthMap[state.schedZoom] || 28;
  const rowHeight = rowHeightMap[state.schedZoom] || 28;

  const groups = getSchedGroupedTasks(project, tasks);
  const labelColumnWidth = 220;
  const chartWidth = labelColumnWidth + range.totalDays * dayWidth;

  // Compute key date positions for vertical lines
  const todayStr = new Date().toISOString().slice(0, 10);
  const todayDay = daysFromStart(range.start, todayStr);
  const todayInRange = todayDay >= 0 && todayDay <= range.totalDays;

  const bidStartDay = project.startDate ? daysFromStart(range.start, project.startDate) : null;
  const bidDueDay = project.dueDate ? daysFromStart(range.start, project.dueDate) : null;

  // Milestones --- vertical markers
  const milestoneMarkers = [];
  if (Array.isArray(project.milestones)) {
    project.milestones.forEach(m => {
      if (!m.date) return;
      const type = state.milestoneTypes.find(t => t.id === m.typeId);
      if (!type) return;
      const day = daysFromStart(range.start, m.date);
      if (day < 0 || day > range.totalDays) return;
      milestoneMarkers.push({ day, label: type.name, icon: type.icon || '🎯', color: type.color || '#0a2540' });
    });
  }

  // Build the time-axis header (months + day grid)
  let axisHeader = '';
  let monthBands = '';
  let dayTicks = '';
  let lastMonth = -1;
  let monthStartDay = 0;
  for (let d = 0; d <= range.totalDays; d++) {
    const dt = new Date(range.start.getTime() + d * 86400000);
    const isFirstOfMonth = dt.getDate() === 1 || d === 0;
    const isWeekend = dt.getDay() === 0 || dt.getDay() === 6;
    const cellLeft = labelColumnWidth + d * dayWidth;

    if (lastMonth !== dt.getMonth() && d > 0) {
      // Close previous month band
      const prevDt = new Date(range.start.getTime() + (d - 1) * 86400000);
      const monthLabel = prevDt.toLocaleString('en-US', { month: 'short', year: 'numeric' });
      const bandWidth = (d - monthStartDay) * dayWidth;
      monthBands += `<div class="sched-month-band" style="left:${labelColumnWidth + monthStartDay * dayWidth}px;width:${bandWidth}px;">${monthLabel}</div>`;
      monthStartDay = d;
    }
    lastMonth = dt.getMonth();

    if (d < range.totalDays) {
      dayTicks += `<div class="sched-day-tick${isWeekend ? ' is-weekend' : ''}" style="left:${cellLeft}px;width:${dayWidth}px;"><span>${dt.getDate()}</span></div>`;
    }
  }
  // Close last month band
  if (range.totalDays > monthStartDay) {
    const lastDt = new Date(range.start.getTime() + (range.totalDays - 1) * 86400000);
    const monthLabel = lastDt.toLocaleString('en-US', { month: 'short', year: 'numeric' });
    const bandWidth = (range.totalDays - monthStartDay) * dayWidth;
    monthBands += `<div class="sched-month-band" style="left:${labelColumnWidth + monthStartDay * dayWidth}px;width:${bandWidth}px;">${monthLabel}</div>`;
  }

  axisHeader = `
    <div class="sched-axis" style="width:${chartWidth}px;">
      <div class="sched-axis-corner" style="width:${labelColumnWidth}px;">
        <div class="sched-corner-title">${state.schedGrouping === 'stage' ? 'Stage / Task' : state.schedGrouping === 'assignee' ? 'Assignee / Task' : 'Scope / Task'}</div>
      </div>
      <div class="sched-axis-time" style="left:${labelColumnWidth}px;width:${range.totalDays * dayWidth}px;">
        <div class="sched-month-row">${monthBands}</div>
        <div class="sched-day-row">${dayTicks}</div>
      </div>
    </div>
  `;

  // Vertical line markers (today, bid start, bid due, milestones)
  let verticalLines = '';
  if (todayInRange) {
    verticalLines += `<div class="sched-vline sched-vline-today" style="left:${labelColumnWidth + todayDay * dayWidth + dayWidth / 2}px;" title="Today: ${formatDate(todayStr)}"><span class="vline-label">TODAY</span></div>`;
  }
  if (bidStartDay !== null && bidStartDay >= 0 && bidStartDay <= range.totalDays) {
    verticalLines += `<div class="sched-vline sched-vline-bidstart" style="left:${labelColumnWidth + bidStartDay * dayWidth}px;" title="Bid Start: ${formatDate(project.startDate)}"><span class="vline-label">BID START</span></div>`;
  }
  if (bidDueDay !== null && bidDueDay >= 0 && bidDueDay <= range.totalDays) {
    verticalLines += `<div class="sched-vline sched-vline-biddue" style="left:${labelColumnWidth + bidDueDay * dayWidth + dayWidth}px;" title="Bid Due: ${formatDate(project.dueDate)}"><span class="vline-label">BID DUE</span></div>`;
  }
  milestoneMarkers.forEach(m => {
    verticalLines += `<div class="sched-vline sched-vline-milestone" style="left:${labelColumnWidth + m.day * dayWidth + dayWidth / 2}px;border-color:${m.color};" title="${escapeHtml(m.label)}"><span class="vline-label vline-milestone-label" style="background:${m.color};">${m.icon} ${escapeHtml(m.label)}</span></div>`;
  });

  // Build group rows with tasks
  let groupHtml = '';
  groups.forEach(group => {
    // Group header row
    let groupHeaderLeft;
    if (state.schedGrouping === 'assignee' && group.id !== 'orphan') {
      const av = group.photo
        ? `<span class="sched-group-avatar has-photo"><img src="${group.photo}" alt=""></span>`
        : `<span class="sched-group-avatar" style="background:${group.color};">${escapeHtml(group.initials || '?')}</span>`;
      groupHeaderLeft = `${av}<span class="sched-group-label">${escapeHtml(group.label)}</span><span class="sched-group-count">${group.tasks.length}</span>`;
    } else {
      groupHeaderLeft = `<span class="sched-group-icon" style="background:${group.color};">${group.icon || '📋'}</span><span class="sched-group-label">${escapeHtml(group.label)}</span><span class="sched-group-count">${group.tasks.length}</span>`;
    }

    // Sort tasks within group by computed start day, then by due date
    const sortedTasks = group.tasks.slice().sort((a, b) => {
      const ba = getTaskBarBounds(a, range.start);
      const bb = getTaskBarBounds(b, range.start);
      if (ba && bb) {
        if (ba.startDay !== bb.startDay) return ba.startDay - bb.startDay;
        return ba.endDay - bb.endDay;
      }
      return 0;
    });

    let groupBars = '';
    sortedTasks.forEach(task => {
      const bounds = getTaskBarBounds(task, range.start);
      if (!bounds) return;
      const colors = getSchedTaskColor(task);
      const left = labelColumnWidth + bounds.startDay * dayWidth;
      const width = bounds.isMilestone
        ? Math.max(dayWidth * 0.6, 14)
        : Math.max((bounds.endDay - bounds.startDay + 1) * dayWidth - 2, dayWidth * 0.6);

      // Build tooltip + label
      const dueStr = formatDate(task.dueDate);
      const titleAttr = `${task.title} --- ${dueStr}${task.assignee ? ' · ' + task.assignee : ''}${task.dayOffset ? ' · D+' + task.dayOffset : ''}${isTaskOverdue(task) ? ' · OVERDUE' : ''}`;

      // Check if there's room to show task title inside the bar
      const showLabel = !bounds.isMilestone && width > 80;
      const labelText = showLabel ? `<span class="sched-bar-label">${escapeHtml(task.title.length > 40 ? task.title.slice(0, 38) + '...' : task.title)}</span>` : '';

      // Render the row
      // Each task gets its own row in the group
      const rowLeft = (state.schedGrouping === 'stage') ? '' :
                     (state.schedGrouping === 'assignee') ? '' : '';
      const taskRowLeftLabel = `<div class="sched-task-row-label" style="width:${labelColumnWidth - 12}px;padding-left:24px;" title="${escapeHtml(task.title)}"><span class="strow-icon">${task.dayOffset ? '⫿' : '◆'}</span><span class="strow-title">${escapeHtml(task.title)}</span></div>`;

      groupBars += `
        <div class="sched-task-row" style="height:${rowHeight}px;" onclick="openTaskModal(null, '${task.id}')">
          ${taskRowLeftLabel}
          <div class="sched-task-track" style="left:${labelColumnWidth}px;height:${rowHeight}px;">
            ${bounds.isMilestone
              ? `<div class="sched-milestone-marker" style="left:${(bounds.startDay * dayWidth) + dayWidth / 2 - 7}px;background:${colors.fill};border-color:${colors.border};color:${colors.text};" title="${escapeHtml(titleAttr)}"></div>`
              : `<div class="sched-task-bar" style="left:${bounds.startDay * dayWidth}px;width:${width}px;background:${colors.fill};border-color:${colors.border};color:${colors.text};${task.status === 'done' ? 'opacity:0.7;' : ''}" title="${escapeHtml(titleAttr)}">${labelText}</div>`
            }
          </div>
        </div>
      `;
    });

    groupHtml += `
      <div class="sched-group">
        <div class="sched-group-header" style="height:${rowHeight}px;border-left-color:${group.color};">
          <div class="sched-group-header-label" style="width:${labelColumnWidth}px;">
            ${groupHeaderLeft}
          </div>
          <div class="sched-group-header-track" style="left:${labelColumnWidth}px;height:${rowHeight}px;"></div>
        </div>
        ${groupBars}
      </div>
    `;
  });

  // Final assembly --- chart wrapper holds axis + scrollable content
  chartEl.innerHTML = `
    <div class="sched-scroll-wrap">
      <div class="sched-chart-inner" style="width:${chartWidth}px;">
        ${axisHeader}
        <div class="sched-body">
          ${verticalLines}
          ${groupHtml}
        </div>
      </div>
    </div>
    <div class="sched-legend">
      <span class="sched-legend-item"><span class="legend-bar" style="background:rgba(155,164,176,0.7);"></span>Not Started</span>
      <span class="sched-legend-item"><span class="legend-bar" style="background:rgba(10,37,64,0.85);"></span>In Progress</span>
      <span class="sched-legend-item"><span class="legend-bar" style="background:rgba(200,50,43,0.85);"></span>Blocked</span>
      <span class="sched-legend-item"><span class="legend-bar" style="background:rgba(123,67,151,0.85);"></span>Pending</span>
      <span class="sched-legend-item"><span class="legend-bar" style="background:rgba(46,125,82,0.85);"></span>Complete</span>
      <span class="sched-legend-item"><span class="legend-bar" style="background:var(--sbg-red);"></span>Overdue</span>
      <span class="sched-legend-item legend-divider">|</span>
      <span class="sched-legend-item"><span class="legend-bar legend-bar-thin" style="background:var(--sbg-red);"></span>Today</span>
      <span class="sched-legend-item"><span class="legend-diamond" style="background:rgba(155,164,176,0.7);"></span>Single-day task</span>
      <span class="sched-legend-item"><span class="legend-bar legend-bar-dashed" style="border-color:#c07f00;"></span>Milestone</span>
    </div>
  `;

  // Auto-scroll so today is visible (or bid start if today is before range)
  setTimeout(() => {
    const wrap = chartEl.querySelector('.sched-scroll-wrap');
    if (!wrap) return;
    const scrollTarget = todayInRange ? todayDay : (bidStartDay !== null && bidStartDay >= 0 ? bidStartDay : 0);
    const targetX = labelColumnWidth + scrollTarget * dayWidth - 100;
    wrap.scrollLeft = Math.max(0, targetX);
  }, 50);
}

function renderCalendar(project) {
  populateCalAssigneeFilter(project);
  document.querySelectorAll('.cal-range-btn').forEach(b => b.classList.toggle('active', b.dataset.range === state.calRange));

  const grid = document.getElementById('calendarGrid');
  grid.className = `calendar-grid cal-${state.calRange}-view`;

  const range = state.calRange;
  const cursor = new Date(state.calCursor + 'T00:00:00');
  const todayStr = new Date().toISOString().slice(0,10);
  const titleEl = document.getElementById('calTitle');
  const filteredTasks = filterCalTasks(project);

  if (range === 'month') {
    const y = cursor.getFullYear(), m = cursor.getMonth();
    const monthStart = new Date(y, m, 1);
    titleEl.textContent = monthStart.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
    const gridStart = new Date(monthStart);
    gridStart.setDate(gridStart.getDate() - gridStart.getDay());
    const dow = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    let html = dow.map(d => `<div class="cal-dow">${d}</div>`).join('');
    for (let i = 0; i < 42; i++) {
      const d = new Date(gridStart);
      d.setDate(gridStart.getDate() + i);
      html += renderCalDayCell(d, filteredTasks, project, { otherMonth: d.getMonth() !== m, todayStr, compact: true });
    }
    grid.innerHTML = html;
  }
  else if (range === 'week') {
    const weekStart = new Date(cursor);
    weekStart.setDate(cursor.getDate() - cursor.getDay());
    const weekEnd = new Date(weekStart);
    weekEnd.setDate(weekStart.getDate() + 6);
    titleEl.textContent = `${weekStart.toLocaleDateString('en-US',{month:'short',day:'numeric'})} -- ${weekEnd.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}`;
    const dow = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    let html = dow.map(d => `<div class="cal-dow">${d}</div>`).join('');
    for (let i = 0; i < 7; i++) {
      const d = new Date(weekStart);
      d.setDate(weekStart.getDate() + i);
      html += renderCalDayCell(d, filteredTasks, project, { todayStr, compact: false });
    }
    grid.innerHTML = html;
  }
  else if (range === '2week') {
    const weekStart = new Date(cursor);
    weekStart.setDate(cursor.getDate() - cursor.getDay());
    const weekEnd = new Date(weekStart);
    weekEnd.setDate(weekStart.getDate() + 13);
    titleEl.textContent = `2-Week Look Ahead · ${weekStart.toLocaleDateString('en-US',{month:'short',day:'numeric'})} -- ${weekEnd.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}`;
    const dow = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    let html = dow.map(d => `<div class="cal-dow">${d}</div>`).join('');
    for (let i = 0; i < 14; i++) {
      const d = new Date(weekStart);
      d.setDate(weekStart.getDate() + i);
      html += renderCalDayCell(d, filteredTasks, project, { todayStr, compact: false });
    }
    grid.innerHTML = html;
  }
  else if (range === 'day') {
    titleEl.textContent = cursor.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });
    grid.innerHTML = renderCalDayCell(cursor, filteredTasks, project, { todayStr, compact: false, single: true });
  }
}

function renderCalDayCell(d, tasks, project, opts) {
  const dStr = d.toISOString().slice(0,10);
  const isToday = dStr === opts.todayStr;
  const isBidStart = dStr === project.startDate;
  const isBidDue = dStr === project.dueDate;
  const isWeekend = d.getDay() === 0 || d.getDay() === 6;

  const dayTasks = tasks.filter(t => t.dueDate === dStr);
  dayTasks.sort((a,b) => {
    const pri = {high:0,medium:1,low:2};
    if (pri[a.priority] !== pri[b.priority]) return pri[a.priority] - pri[b.priority];
    return 0;
  });

  const maxVisible = opts.compact ? 4 : (opts.single ? 999 : 8);
  const visible = dayTasks.slice(0, maxVisible);
  const extra = dayTasks.length - maxVisible;

  const classes = ['cal-day'];
  if (opts.otherMonth) classes.push('other-month');
  if (isWeekend) classes.push('weekend');
  if (isToday) classes.push('today');
  if (isBidDue) classes.push('is-bid-date');
  else if (isBidStart) classes.push('is-bid-start');

  const dowLabel = opts.single || !opts.compact ? '' : '';
  const dayNumHtml = opts.single
    ? `<span class="cal-day-num">${d.toLocaleDateString('en-US',{weekday:'long'})}, ${d.toLocaleDateString('en-US',{month:'short',day:'numeric'})}</span>`
    : `<span class="cal-day-num">${d.getDate()}</span>`;

  const eventsHtml = visible.map(t => {
    const classes = ['cal-event', `status-${t.status}`];
    const isOverdueEv = t.status !== 'done' && getDaysLeft(t.dueDate) < 0;
    const isImminentEv = !isOverdueEv && isTaskDueImminent(t);
    const isSoonEv = !isOverdueEv && !isImminentEv && isTaskDueSoon(t);
    if (isOverdueEv) classes.push('overdue-task');
    else if (isImminentEv) classes.push('imminent-task');
    else if (isSoonEv) classes.push('soon-task');

    // Inline due-reminder flag (Today / Tomorrow / 2 Days)
    let dueFlag = '';
    if (!isOverdueEv && (isImminentEv || isSoonEv)) {
      const cls = isImminentEv ? 'badge-imminent' : 'badge-soon';
      dueFlag = `<span class="cal-due-flag ${cls}">${getDueSoonLabel(t)}</span>`;
    }

    const showMeta = !opts.compact;
    const metaParts = [];
    if (showMeta && t.assignee) metaParts.push(escapeHtml(t.assignee));
    if (showMeta && t.support) metaParts.push(`+${escapeHtml(t.support)}`);
    const metaLine = metaParts.length ? `<span class="cal-event-meta">${metaParts.join(' · ')}</span>` : '';
    const bicTag = t.ballInCourt
      ? `<span class="cal-event-bic" title="Ball in Court">🏀 ${escapeHtml(t.ballInCourt)}</span>`
      : '';
    const tooltipParts = [escapeHtml(t.title)];
    if (t.assignee) tooltipParts.push('Lead: ' + escapeHtml(t.assignee));
    if (t.support) tooltipParts.push('Support: ' + escapeHtml(t.support));
    if (t.ballInCourt) tooltipParts.push('Ball in Court: ' + escapeHtml(t.ballInCourt));
    // Acknowledgment indicators for calendar events
    const needsAckCal = t.assignee && t.assignee.trim() && !t.acknowledged;
    if (needsAckCal) classes.push('needs-ack-cal');
    const calNewBadge = needsAckCal
      ? `<span class="cal-new-badge" title="Newly assigned --- click to acknowledge">NEW</span><button class="cal-ack-btn" onclick="event.stopPropagation();acknowledgeTask('${t.id}', event);" title="Click to acknowledge this new task">✓</button>`
      : '';
    // Lead override button on calendar events
    let calOverrideBtn = '';
    if (needsAckCal) {
      const proj = state.projects.find(p => p.id === state.activeProjectId);
      const lead = proj?.leadEstimator?.trim();
      const currentUser = getCurrentUser();
      const isLead = currentUser && lead && currentUser.toLowerCase() === lead.toLowerCase();
      const isAssignee = currentUser && t.assignee && currentUser.toLowerCase() === t.assignee.toLowerCase();
      if (isLead && !isAssignee) {
        calOverrideBtn = `<button class="cal-override-btn" onclick="event.stopPropagation();overrideAcknowledge('${t.id}', event);" title="Lead override --- ack on behalf of ${escapeHtml(t.assignee)}">⚡</button>`;
      }
    }
    // Audit badge
    const calOverrideAudit = (t.acknowledged && t.acknowledgedOverrideBy)
      ? `<span class="cal-signoff-badge" style="background:#4a3c8a;color:#fff;" title="Ack'd via Lead override by ${escapeHtml(t.acknowledgedOverrideBy)}">⚡</span>`
      : '';
    let calSignoffBadge = '';
    if (t.status === 'done') {
      if (t.completionAcknowledged && t.completionAcknowledgedBy) {
        calSignoffBadge = `<span class="cal-signoff-badge signed" title="Signed off by ${escapeHtml(t.completionAcknowledgedBy)}">✓</span>`;
      } else {
        calSignoffBadge = `<span class="cal-signoff-badge pending" title="Awaiting Lead Estimator sign-off">⏳</span>`;
      }
    }

    return `<div class="${classes.join(' ')}" onclick="event.stopPropagation();openTaskModal(null,'${t.id}')" title="${tooltipParts.join(' --- ')}">${calNewBadge}${calOverrideBtn}${calOverrideAudit}${calSignoffBadge}${escapeHtml(t.title)}${dueFlag}${metaLine}${showMeta ? bicTag : ''}</div>`;
  }).join('');

  const moreHtml = extra > 0 ? `<div class="cal-event-more">+ ${extra} more</div>` : '';

  const emptyHtml = (opts.single && dayTasks.length === 0)
    ? '<div class="cal-empty-state">No tasks due this day</div>' : '';

  return `<div class="${classes.join(' ')}">${dayNumHtml}${eventsHtml}${moreHtml}${emptyHtml}</div>`;
}

// =============================================================
// DRAG & DROP
// =============================================================
let draggedTaskId = null;
function attachDragHandlers() {
  document.querySelectorAll('.task-card').forEach(card => {
    card.addEventListener('dragstart', e => {
      draggedTaskId = card.dataset.taskId;
      card.classList.add('dragging');
      e.stopPropagation();
    });
    card.addEventListener('dragend', () => card.classList.remove('dragging'));
  });
  document.querySelectorAll('.column').forEach(col => {
    col.addEventListener('dragover', e => { e.preventDefault(); col.style.background='var(--surface-2)'; });
    col.addEventListener('dragleave', () => { col.style.background=''; });
    col.addEventListener('drop', e => {
      e.preventDefault();
      col.style.background = '';
      const ns = col.dataset.status;
      if (draggedTaskId && ns) updateTaskStatus(draggedTaskId, ns);
      draggedTaskId = null;
    });
  });
}

// =============================================================
// IMPORT / EXPORT
// =============================================================
function exportData() {
  const blob = new Blob([JSON.stringify(state, null, 2)], { type:'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `sbg-precon-bids-${new Date().toISOString().slice(0,10)}.json`;
  a.click();
  URL.revokeObjectURL(url);
}
function importData(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = e => {
    try {
      const data = JSON.parse(e.target.result);
      if (data.projects && Array.isArray(data.projects)) {
        if (confirm(`Import ${data.projects.length} project(s)? Replaces current data.`)) {
          state = { ...state, ...data };
          state.projects.forEach(p => p.tasks.forEach(t => {
            if (!t.stage) t.stage = 'project-setup';
            if (typeof t.dayOffset === 'undefined') t.dayOffset = null;
          }));
          saveState();
          render();
        }
      } else alert('Invalid backup file');
    } catch(err) { alert('Error: '+err.message); }
  };
  reader.readAsText(file);
  event.target.value = '';
}
function clearAllData() {
  if (!confirm('Delete ALL projects and tasks?')) return;
  if (!confirm('Absolutely sure? This cannot be undone.')) return;
  state = {
    projects: [], activeProjectId: null,
    activeStageId: 'all', activeAssignee: 'all',
    grouping: 'stage', viewMode: 'board',
    calMonth: new Date().toISOString().slice(0,7)
  };
  saveState();
  render();
}

// =============================================================
// MASTER TASK TEMPLATE MANAGER
// =============================================================
function openMTTModal() {
  // Ensure active template is synced with masterTasks before rendering
  syncLegacyMasterTasks();
  renderTemplateSelector();
  updateMTTHeader();
  populateMTTStageSelects();
  populateMTTCategorySelect();
  populateMTTSourceSelect();
  document.getElementById('mttFilterStage').value = 'all';
  document.getElementById('mttNewTitle').value = '';
  document.getElementById('mttNewOffset').value = '0';
  document.getElementById('mttNewPriority').value = 'medium';
  // Reset stage-add inputs
  const sIcon = document.getElementById('mttNewStageIcon');
  const sName = document.getElementById('mttNewStageName');
  const sDesc = document.getElementById('mttNewStageDesc');
  if (sIcon) sIcon.value = '';
  if (sName) sName.value = '';
  if (sDesc) sDesc.value = '';
  renderMasterTasks();
  renderStagesList();
  document.getElementById('mttModal').classList.add('active');
}
function populateMTTStageSelects() {
  // Stage dropdown for new-task row
  const newStageEl = document.getElementById('mttNewStage');
  newStageEl.innerHTML = STAGES.map(s => `<option value="${s.id}">${s.icon} ${s.name}</option>`).join('');
  // Filter dropdown
  const filterEl = document.getElementById('mttFilterStage');
  filterEl.innerHTML = '<option value="all">All Stages</option>' +
    STAGES.map(s => `<option value="${s.id}">${s.icon} ${s.name}</option>`).join('');
}
function populateMTTCategorySelect() {
  // Delegates to the unified populator which reads from state.csiDivisions
  populateAllCategorySelects();
}
function populateMTTSourceSelect() {
  const sel = document.getElementById('mttNewSource');
  if (!sel) return;
  const options = ['<option value="">--- None ---</option>'];
  state.sourceOptions.forEach(s => {
    options.push(`<option value="${escapeHtml(s.name)}">${escapeHtml(s.name)}</option>`);
  });
  sel.innerHTML = options.join('');
}
function addMasterTask() {
  const title = document.getElementById('mttNewTitle').value.trim();
  if (!title) { alert('Enter a task title'); return; }
  const task = {
    stage: document.getElementById('mttNewStage').value,
    title,
    category: document.getElementById('mttNewCategory').value,
    source: document.getElementById('mttNewSource').value,
    priority: document.getElementById('mttNewPriority').value,
    offset: parseInt(document.getElementById('mttNewOffset').value) || 0
  };
  state.masterTasks.push(task);
  // Mark active template as updated
  const active = getActiveTemplate();
  if (active) active.updatedAt = Date.now();
  saveState();
  document.getElementById('mttNewTitle').value = '';
  document.getElementById('mttNewOffset').value = '0';
  renderTemplateSelector(); // updates task count in dropdown
  renderMasterTasks();
}
function removeMasterTask(index) {
  if (!confirm('Remove this task from the master template?')) return;
  state.masterTasks.splice(index, 1);
  const active = getActiveTemplate();
  if (active) active.updatedAt = Date.now();
  saveState();
  renderTemplateSelector();
  renderMasterTasks();
}
function updateMasterTaskField(index, field, value) {
  const task = state.masterTasks[index];
  if (!task) return;
  if (field === 'offset') value = parseInt(value) || 0;
  if (field === 'estimatedHours') {
    // Quarter-hour precision; empty → null (no estimate)
    if (value === '' || value === null || value === undefined) {
      value = null;
    } else {
      const n = parseFloat(value);
      value = (isNaN(n) || n <= 0) ? null : Math.round(n * 4) / 4;
    }
  }
  task[field] = value;
  saveState();
}

// ===== TEMPLATE RICH-FIELDS HELPERS =====
// Tracks which template rows are currently expanded. Module-level Set keyed
// by task _index. Survives within the current render cycle; resets when
// modal is closed and reopened.
const mttExpandedRows = new Set();

// Toggle the expanded state of a template row, then re-render the list so
// the details panel appears/disappears beneath the row.
function toggleMTTRowExpand(index) {
  if (mttExpandedRows.has(index)) {
    mttExpandedRows.delete(index);
  } else {
    mttExpandedRows.add(index);
  }
  renderMasterTasks();
}

// Toggle the Critical flag on a master task. Mirrors the project-task toggle
// pattern from v33 --- boolean flip + save + re-render.
function toggleMasterTaskCritical(index) {
  const task = state.masterTasks[index];
  if (!task) return;
  task.critical = !task.critical;
  saveState();
  renderMasterTasks();
}

// ===== Deliverables (array of strings) =====
function addMTTDeliverable(index) {
  const task = state.masterTasks[index];
  if (!task) return;
  if (!Array.isArray(task.deliverables)) task.deliverables = [];
  task.deliverables.push('');
  saveState();
  // Make sure the row stays expanded
  mttExpandedRows.add(index);
  renderMasterTasks();
  // Focus the newly-added input. We need to wait for the next paint.
  setTimeout(() => {
    const rows = document.querySelectorAll(`.mtt-row[data-index="${index}"] .mtt-details-section:nth-of-type(2) .mtt-sublist-input`);
    if (rows.length > 0) rows[rows.length - 1].focus();
  }, 30);
}

function updateMTTDeliverable(index, itemIndex, value) {
  const task = state.masterTasks[index];
  if (!task || !Array.isArray(task.deliverables)) return;
  task.deliverables[itemIndex] = value;
  saveState();
  // No re-render --- blur keeps focus stable; row already shows current text
}

function removeMTTDeliverable(index, itemIndex) {
  const task = state.masterTasks[index];
  if (!task || !Array.isArray(task.deliverables)) return;
  task.deliverables.splice(itemIndex, 1);
  saveState();
  renderMasterTasks();
}

// ===== Checklist (array of {text, required}) =====
function addMTTChecklistItem(index) {
  const task = state.masterTasks[index];
  if (!task) return;
  if (!Array.isArray(task.checklist)) task.checklist = [];
  task.checklist.push({ text: '', required: false });
  saveState();
  mttExpandedRows.add(index);
  renderMasterTasks();
  // Focus the newly-added input
  setTimeout(() => {
    const rows = document.querySelectorAll(`.mtt-row[data-index="${index}"] .mtt-details-section:nth-of-type(3) .mtt-sublist-input`);
    if (rows.length > 0) rows[rows.length - 1].focus();
  }, 30);
}

function updateMTTChecklistText(index, itemIndex, value) {
  const task = state.masterTasks[index];
  if (!task || !Array.isArray(task.checklist)) return;
  let item = task.checklist[itemIndex];
  // Migrate legacy string entries to {text, required:false} object form
  if (typeof item === 'string') {
    item = { text: item, required: false };
    task.checklist[itemIndex] = item;
  }
  if (!item) return;
  item.text = value;
  saveState();
}

function toggleMTTChecklistRequired(index, itemIndex) {
  const task = state.masterTasks[index];
  if (!task || !Array.isArray(task.checklist)) return;
  let item = task.checklist[itemIndex];
  if (typeof item === 'string') {
    item = { text: item, required: false };
    task.checklist[itemIndex] = item;
  }
  if (!item) return;
  item.required = !item.required;
  saveState();
  renderMasterTasks();
}

function removeMTTChecklistItem(index, itemIndex) {
  const task = state.masterTasks[index];
  if (!task || !Array.isArray(task.checklist)) return;
  task.checklist.splice(itemIndex, 1);
  saveState();
  renderMasterTasks();
}
function sortMasterTasks() {
  const stageOrder = {};
  STAGES.forEach((s,i) => stageOrder[s.id] = i);
  state.masterTasks.sort((a,b) => {
    if (stageOrder[a.stage] !== stageOrder[b.stage]) return stageOrder[a.stage] - stageOrder[b.stage];
    return (a.offset||0) - (b.offset||0);
  });
  saveState();
  renderMasterTasks();
}
function resetMasterTasks() {
  if (!confirm('Reset the master task template to the default ~40-task SBG bid workflow? Your current customizations will be lost.')) return;
  state.masterTasks = getDefaultMasterTasks();
  saveState();
  renderMasterTasks();
}

// =============================================================
// STAGE MANAGEMENT --- add / edit / delete / reorder lifecycle stages
// =============================================================

// Generate a slug-style stage id from a display name. Falls back to a unique
// suffix when the name has no usable characters.
function generateStageId(name) {
  let base = (name || '').toLowerCase().trim()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '');
  if (!base) base = 'stage';
  // Ensure uniqueness against existing stages
  let id = base;
  let n = 2;
  while (STAGES.some(s => s.id === id)) {
    id = `${base}-${n}`;
    n++;
  }
  return id;
}

// Count tasks across master template + all projects that use a given stage.
function countTasksUsingStage(stageId) {
  let count = 0;
  (state.masterTasks || []).forEach(t => { if (t.stage === stageId) count++; });
  (state.projects || []).forEach(p => {
    (p.tasks || []).forEach(t => { if (t.stage === stageId) count++; });
  });
  return count;
}

function addStage() {
  const iconInput = document.getElementById('mttNewStageIcon');
  const customInput = document.getElementById('mttNewStageIconCustom');
  const iconBtn = document.getElementById('mttNewStageIconBtn');
  const nameInput = document.getElementById('mttNewStageName');
  const descInput = document.getElementById('mttNewStageDesc');
  const icon = (iconInput.value || '🎯').trim() || '🎯';
  const customDataUrl = customInput ? customInput.value : '';
  const name = (nameInput.value || '').trim();
  const description = (descInput.value || '').trim();
  if (!name) {
    alert('Please enter a stage name.');
    nameInput.focus();
    return;
  }
  const id = generateStageId(name);
  const newStage = { id, name, icon, description };
  if (customDataUrl) newStage.iconCustom = customDataUrl;
  STAGES.push(newStage);
  state.stages = STAGES;
  saveState();
  // Reset the inputs to defaults
  iconInput.value = '🎯';
  if (customInput) customInput.value = '';
  if (iconBtn) iconBtn.textContent = '🎯';
  nameInput.value = '';
  descInput.value = '';
  // Refresh UI everywhere stages appear
  renderStagesList();
  populateStageDropdowns();
  renderMasterTasks();
  if (state.activeProjectId) render();
}

// Open the stage-icon picker for the NEW stage form (no stage id yet).
// This reuses the same picker modal; on Save, instead of writing to a
// stage object we just update the hidden fields + the picker button preview.
function openNewStageIconPicker() {
  // Use a sentinel id so saveStageIconFromPicker knows this is the new-stage flow
  document.getElementById('stageIconPickerStageId').value = '__NEW_STAGE__';
  const currentEmoji = document.getElementById('mttNewStageIcon').value || '🎯';
  const currentCustom = document.getElementById('mttNewStageIconCustom').value || '';
  document.getElementById('stageIconPickerEmoji').value = currentEmoji;
  document.getElementById('stageIconPickerCustom').value = currentCustom;
  const titleEl = document.getElementById('stageIconPickerTitle');
  if (titleEl) titleEl.textContent = 'Pick Icon for New Stage';
  renderStageIconPreview(currentEmoji, currentCustom);
  renderStageIconPalette(currentEmoji);
  const fi = document.getElementById('stageIconUploadInput');
  if (fi) fi.value = '';
  document.getElementById('stageIconPickerModal').classList.add('active');
}

function editStageField(stageId, field, value) {
  const s = STAGES.find(x => x.id === stageId);
  if (!s) return;
  s[field] = value;
  state.stages = STAGES;
  saveState();
  // Re-render any UI that displays stage names/icons
  renderStagesList();
  populateStageDropdowns();
  renderMasterTasks();
  if (state.activeProjectId) render();
}

// =============================================================
// STAGE ICON PICKER --- palette + custom image upload per stage.
// Each stage has two icon fields:
//   stage.icon       --- fallback emoji string, used in dropdowns and inline text
//   stage.iconCustom --- optional data:image/jpeg URL, used in stage manager
//                      and board column headers where space allows
// Custom images are resized to 128px max and JPEG-compressed (same pipeline
// as the v40 template icon system).
// =============================================================

// Curated palette of 60+ emoji icons covering construction/precon stages,
// admin/workflow themes, and general status/progression markers.
const STAGE_ICON_PALETTE = [
  // Stage progression & lifecycle
  '🎯','🚀','📋','📑','📐','📏','✅','🏁','🔍','📤','📥','💼',
  // Construction & site
  '🏢','🏗️','🏛️','🏘️','🏬','🏭','🚧','⚒️','🔨','🛠️','🔧','🧱',
  // Pre-bid / planning
  '📊','📈','📉','📅','🗓️','⏳','⏰','🗂️','📁','📂','📒','📓',
  // Communication & coordination
  '🤝','👥','👷','📞','📧','💬','📢','📡','🔔','📨',
  // Status & priority
  '⭐','🔥','⚡','🚨','💡','✔️','❗','⚠️','🟢','🟡','🔴',
  // Misc useful
  '📌','📎','🏷️','🪧','🔗','🔒','🔓','🎬','🪜'
];

// Open the picker for a given stage id. Stages the current values into the
// hidden inputs so cancel doesn't mutate state.
function openStageIconPickerModal(stageId) {
  const stage = STAGES.find(s => s.id === stageId);
  if (!stage) return;
  document.getElementById('stageIconPickerStageId').value = stageId;
  const currentEmoji = stage.icon || '🎯';
  const currentCustom = stage.iconCustom || '';
  document.getElementById('stageIconPickerEmoji').value = currentEmoji;
  document.getElementById('stageIconPickerCustom').value = currentCustom;
  // Title with the stage name so user knows what they're editing
  const titleEl = document.getElementById('stageIconPickerTitle');
  if (titleEl) titleEl.textContent = `Change Stage Icon --- ${stage.name}`;
  renderStageIconPreview(currentEmoji, currentCustom);
  renderStageIconPalette(currentEmoji);
  // Reset file input so the same file can be re-uploaded if needed
  const fi = document.getElementById('stageIconUploadInput');
  if (fi) fi.value = '';
  document.getElementById('stageIconPickerModal').classList.add('active');
}

// Render the preview tile --- shows the custom image if one's staged, else
// shows the emoji.
function renderStageIconPreview(emoji, customDataUrl) {
  const previewEl = document.getElementById('stageIconPreview');
  const removeBtn = document.getElementById('stageIconRemoveBtn');
  if (!previewEl) return;
  if (customDataUrl && customDataUrl.startsWith('data:image/')) {
    previewEl.innerHTML = `<img src="${customDataUrl}" alt="Custom stage icon">`;
    if (removeBtn) removeBtn.style.display = 'inline-flex';
  } else {
    previewEl.textContent = emoji || '🎯';
    if (removeBtn) removeBtn.style.display = 'none';
  }
}

// Render the emoji palette grid. Highlights the current selection.
function renderStageIconPalette(currentEmoji) {
  const palette = document.getElementById('stageIconPalette');
  if (!palette) return;
  palette.innerHTML = STAGE_ICON_PALETTE.map(icon => `
    <button type="button" class="stage-icon-option ${icon === currentEmoji ? 'selected' : ''}" onclick="pickStageIcon('${escapeAttr(icon)}')" title="Use ${escapeAttr(icon)}">${icon}</button>
  `).join('');
}

// User clicked an emoji --- stage it as the new emoji. Doesn't clear the
// custom image; user has to remove that explicitly. Updates highlight.
function pickStageIcon(emoji) {
  document.getElementById('stageIconPickerEmoji').value = emoji;
  // Update palette highlight
  const palette = document.getElementById('stageIconPalette');
  if (palette) {
    palette.querySelectorAll('.stage-icon-option').forEach(btn => {
      btn.classList.toggle('selected', btn.textContent === emoji);
    });
  }
  // Re-render preview --- if there's a custom image staged, it still shows;
  // otherwise the new emoji takes over
  const customStaged = document.getElementById('stageIconPickerCustom').value;
  renderStageIconPreview(emoji, customStaged);
}

// User clicked Upload --- read → resize → JPEG-compress → stage as custom.
function handleStageIconUpload(event) {
  const file = event.target.files && event.target.files[0];
  if (!file) return;
  if (file.size > 10 * 1024 * 1024) {
    alert('Image is too large (over 10MB). Please pick a smaller file.');
    event.target.value = '';
    return;
  }
  if (!file.type || !file.type.startsWith('image/')) {
    alert('Selected file is not an image. Please pick a JPEG, PNG, WebP, or GIF.');
    event.target.value = '';
    return;
  }
  const reader = new FileReader();
  reader.onerror = function() {
    alert('Could not read the selected file. Please try a different image.');
    event.target.value = '';
  };
  reader.onload = function(e) {
    const img = new Image();
    img.onerror = function() {
      alert('That file could not be decoded as an image. Please try a different file.');
      event.target.value = '';
    };
    img.onload = function() {
      try {
        // Reuse the same resize helper from the v40 template-icon work
        const dataUrl = resizeImageToDataUrl(img, 128, 0.85);
        document.getElementById('stageIconPickerCustom').value = dataUrl;
        const emoji = document.getElementById('stageIconPickerEmoji').value || '🎯';
        renderStageIconPreview(emoji, dataUrl);
      } catch (err) {
        console.error('Stage icon resize failed:', err);
        alert('Could not process that image. Please try a different file.');
      }
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
}

// User clicked Remove --- clear the staged custom image (with confirm).
function removeCustomStageIconInPicker() {
  const current = document.getElementById('stageIconPickerCustom').value;
  if (!current) return;
  if (!confirm('Remove the custom image and revert to the fallback emoji?\n\nYou can re-upload the image later if you change your mind.')) return;
  document.getElementById('stageIconPickerCustom').value = '';
  const emoji = document.getElementById('stageIconPickerEmoji').value || '🎯';
  renderStageIconPreview(emoji, '');
}

// User clicked Save --- commit the staged values to the actual stage object.
// Sentinel '__NEW_STAGE__' means we're configuring the new-stage form's
// icon button, not editing an existing stage.
function saveStageIconFromPicker() {
  const stageId = document.getElementById('stageIconPickerStageId').value;
  const emoji = document.getElementById('stageIconPickerEmoji').value || '🎯';
  const custom = document.getElementById('stageIconPickerCustom').value || '';
  if (stageId === '__NEW_STAGE__') {
    // Staging only --- write to the hidden inputs + update the button visual
    const iconInput = document.getElementById('mttNewStageIcon');
    const customInput = document.getElementById('mttNewStageIconCustom');
    const iconBtn = document.getElementById('mttNewStageIconBtn');
    if (iconInput) iconInput.value = emoji;
    if (customInput) customInput.value = custom;
    if (iconBtn) {
      // Show custom image if one was uploaded; else show emoji
      if (custom && custom.startsWith('data:image/')) {
        iconBtn.innerHTML = `<img src="${custom}" alt="New stage icon">`;
      } else {
        iconBtn.textContent = emoji;
      }
    }
    closeModal('stageIconPickerModal');
    return;
  }
  const stage = STAGES.find(s => s.id === stageId);
  if (!stage) {
    closeModal('stageIconPickerModal');
    return;
  }
  stage.icon = emoji;
  if (custom) {
    stage.iconCustom = custom;
  } else {
    delete stage.iconCustom;
  }
  state.stages = STAGES;
  saveState();
  closeModal('stageIconPickerModal');
  renderStagesList();
  populateStageDropdowns();
  renderMasterTasks();
  if (state.activeProjectId) render();
}

// Render helper --- returns the HTML for a stage's icon, preferring the
// custom image when present, falling back to emoji. Used in stage manager
// rows. Other surfaces (dropdowns, inline text) just use stage.icon directly.
function renderStageIconHtml(stage) {
  if (!stage) return '🎯';
  if (stage.iconCustom && stage.iconCustom.startsWith('data:image/')) {
    return `<img src="${stage.iconCustom}" alt="${escapeAttr(stage.name)} icon">`;
  }
  return escapeHtml(stage.icon || '🎯');
}

function deleteStage(stageId) {
  if (STAGES.length <= 1) {
    alert('Cannot delete --- at least one stage must remain.');
    return;
  }
  const stage = STAGES.find(s => s.id === stageId);
  if (!stage) return;

  const usageCount = countTasksUsingStage(stageId);
  // Build fallback options (all stages except the one being deleted)
  const fallbackChoices = STAGES.filter(s => s.id !== stageId);

  let message = `Delete the "${stage.name}" stage?`;
  if (usageCount > 0) {
    message += `\n\n⚠ ${usageCount} task${usageCount === 1 ? ' is' : 's are'} currently assigned to this stage (in the master template and existing projects).\n\nThose tasks will be reassigned to the fallback stage you choose.`;
  }
  if (!confirm(message)) return;

  let fallbackId = fallbackChoices[0].id;
  if (usageCount > 0) {
    // Build a quick prompt list --- user types the matching name or accepts default
    const promptList = fallbackChoices.map((s, i) => `${i + 1}. ${s.icon} ${s.name}`).join('\n');
    const choice = prompt(`Reassign ${usageCount} task${usageCount === 1 ? '' : 's'} to which stage?\n\n${promptList}\n\nEnter the number (1-${fallbackChoices.length}):`, '1');
    if (choice === null) return; // cancelled
    const idx = parseInt(choice, 10) - 1;
    if (isNaN(idx) || idx < 0 || idx >= fallbackChoices.length) {
      alert('Invalid choice --- deletion cancelled.');
      return;
    }
    fallbackId = fallbackChoices[idx].id;
  }

  // Reassign tasks
  (state.masterTasks || []).forEach(t => { if (t.stage === stageId) t.stage = fallbackId; });
  (state.projects || []).forEach(p => {
    (p.tasks || []).forEach(t => { if (t.stage === stageId) t.stage = fallbackId; });
  });

  // Remove the stage
  const idx = STAGES.findIndex(s => s.id === stageId);
  STAGES.splice(idx, 1);
  state.stages = STAGES;
  saveState();

  // Clear active stage filter if it was pointing to the deleted one
  if (state.activeStageId === stageId) state.activeStageId = 'all';

  renderStagesList();
  populateStageDropdowns();
  renderMasterTasks();
  if (state.activeProjectId) render();
}

function moveStage(stageId, direction) {
  const idx = STAGES.findIndex(s => s.id === stageId);
  if (idx < 0) return;
  const newIdx = idx + direction;
  if (newIdx < 0 || newIdx >= STAGES.length) return;
  [STAGES[idx], STAGES[newIdx]] = [STAGES[newIdx], STAGES[idx]];
  state.stages = STAGES;
  saveState();
  renderStagesList();
  populateStageDropdowns();
  renderMasterTasks();
  if (state.activeProjectId) render();
}

function resetStagesToDefaults() {
  // Check whether any current stages would be removed by the reset
  const defaultIds = DEFAULT_STAGES.map(s => s.id);
  const customStages = STAGES.filter(s => !defaultIds.includes(s.id));
  let warning = 'Reset all stages to the 9 SBG defaults?\n\nDefault stages: ' + DEFAULT_STAGES.map(s => s.icon + ' ' + s.name).join(', ');
  if (customStages.length > 0) {
    warning += `\n\n⚠ ${customStages.length} custom stage${customStages.length === 1 ? '' : 's'} will be removed: ` + customStages.map(s => s.name).join(', ');
    let totalTasks = 0;
    customStages.forEach(s => { totalTasks += countTasksUsingStage(s.id); });
    if (totalTasks > 0) {
      warning += `\n\n⚠ ${totalTasks} task${totalTasks === 1 ? '' : 's'} currently using those custom stages will be reassigned to "Project Setup."`;
    }
  }
  if (!confirm(warning)) return;

  // Reassign any tasks on custom stages to project-setup before removing them
  customStages.forEach(s => {
    (state.masterTasks || []).forEach(t => { if (t.stage === s.id) t.stage = 'project-setup'; });
    (state.projects || []).forEach(p => {
      (p.tasks || []).forEach(t => { if (t.stage === s.id) t.stage = 'project-setup'; });
    });
  });

  STAGES.length = 0;
  DEFAULT_STAGES.forEach(s => STAGES.push({ ...s }));
  state.stages = STAGES;
  saveState();
  renderStagesList();
  populateStageDropdowns();
  renderMasterTasks();
  if (state.activeProjectId) render();
}

function renderStagesList() {
  const list = document.getElementById('mttStagesList');
  const countEl = document.getElementById('mttStagesCount');
  if (!list) return;
  if (countEl) countEl.textContent = `${STAGES.length} stage${STAGES.length === 1 ? '' : 's'}`;
  list.innerHTML = STAGES.map((s, i) => {
    const usage = countTasksUsingStage(s.id);
    return `
      <div class="mtt-stages-row">
        <div class="mtt-stages-order">${i + 1}</div>
        <button type="button" class="stage-icon-btn" onclick="openStageIconPickerModal('${escapeAttr(s.id)}')" title="Click to change icon --- pick from palette or upload an image">${renderStageIconHtml(s)}</button>
        <input type="text" class="mtt-stage-name-input" value="${escapeHtml(s.name)}" onchange="editStageField('${s.id}', 'name', this.value.trim() || 'Untitled')" placeholder="Stage name">
        <input type="text" class="mtt-stage-desc-input" value="${escapeHtml(s.description || '')}" onchange="editStageField('${s.id}', 'description', this.value)" placeholder="Description (shown in tooltips)">
        <span class="mtt-stage-usage" title="${usage} task${usage === 1 ? '' : 's'} use this stage">${usage}</span>
        <div class="mtt-stages-actions">
          <button class="btn btn-sm" onclick="moveStage('${s.id}', -1)" title="Move up" ${i === 0 ? 'disabled' : ''}>▲</button>
          <button class="btn btn-sm" onclick="moveStage('${s.id}', 1)" title="Move down" ${i === STAGES.length - 1 ? 'disabled' : ''}>▼</button>
          <button class="btn btn-sm" style="color:var(--red);" onclick="deleteStage('${s.id}')" title="Delete">✕</button>
        </div>
      </div>
    `;
  }).join('');
}

// Refresh every dropdown that shows a stage list (master template, task modal, filter dropdowns)
function populateStageDropdowns() {
  const opts = STAGES.map(s => `<option value="${s.id}">${s.icon} ${escapeHtml(s.name)}</option>`).join('');
  // Master task add-form stage dropdown
  const newStageEl = document.getElementById('mttNewStage');
  if (newStageEl) {
    const cur = newStageEl.value;
    newStageEl.innerHTML = opts;
    if (cur && STAGES.some(s => s.id === cur)) newStageEl.value = cur;
  }
  // Master task filter dropdown
  const filterEl = document.getElementById('mttFilterStage');
  if (filterEl) {
    const cur = filterEl.value || 'all';
    filterEl.innerHTML = '<option value="all">All Stages</option>' + opts;
    if (cur && (cur === 'all' || STAGES.some(s => s.id === cur))) filterEl.value = cur;
  }
  // Task modal stage dropdown (only if modal exists)
  const taskStageEl = document.getElementById('taskStage');
  if (taskStageEl) {
    const cur = taskStageEl.value;
    taskStageEl.innerHTML = opts;
    if (cur && STAGES.some(s => s.id === cur)) taskStageEl.value = cur;
  }
}
function renderMasterTasks() {
  const list = document.getElementById('mttList');
  const filter = document.getElementById('mttFilterStage').value;
  const countEl = document.getElementById('mttTaskCount');

  if (state.masterTasks.length === 0) {
    list.innerHTML = '<div class="mtt-empty">No tasks in the template --- add your first above, or click Reset to load defaults.</div>';
    countEl.textContent = '0 tasks';
    return;
  }

  // Pull category labels from the master CSI/Division list so edits propagate here too
  const categories = getCSILabelList();

  const filtered = state.masterTasks
    .map((t, idx) => ({ ...t, _index: idx }))
    .filter(t => filter === 'all' || t.stage === filter);

  countEl.textContent = filter === 'all'
    ? `${state.masterTasks.length} tasks total`
    : `${filtered.length} of ${state.masterTasks.length} tasks`;

  if (filtered.length === 0) {
    list.innerHTML = '<div class="mtt-empty">No tasks in this stage. Change the filter or add a new one.</div>';
    return;
  }

  list.innerHTML = filtered.map(t => {
    const stageOptions = STAGES.map(s => `<option value="${s.id}" ${s.id===t.stage?'selected':''}>${s.icon} ${s.name}</option>`).join('');
    // Build category options; if current task category is no longer in master list, keep it as an orphan option so it doesn't get silently changed
    const catList = categories.slice();
    if (t.category && !catList.includes(t.category)) catList.unshift(t.category);
    const catOptions = catList.map(c => `<option value="${escapeHtml(c)}" ${c===t.category?'selected':''}>${escapeHtml(c)}</option>`).join('');
    // Build source options; preserve orphan source if it was deleted
    const sourceNames = getSourceNames().slice();
    if (t.source && !sourceNames.includes(t.source)) sourceNames.unshift(t.source);
    const srcOptions = '<option value="" ' + (!t.source?'selected':'') + '>--- None ---</option>' +
      sourceNames.map(s => `<option value="${escapeHtml(s)}" ${s===t.source?'selected':''}>${escapeHtml(s)}</option>`).join('');
    // Critical button state
    const isCrit = !!t.critical;
    // Hours value --- handle null/0/decimals
    const hoursVal = (typeof t.estimatedHours === 'number' && t.estimatedHours > 0) ? t.estimatedHours : '';
    // Expand state --- tracked in module-level set
    const isExpanded = mttExpandedRows.has(t._index);
    // Richness dot --- show when row has any rich-field content
    const hasTips = t.tips && t.tips.trim();
    const hasDeliv = Array.isArray(t.deliverables) && t.deliverables.length > 0;
    const hasCheck = Array.isArray(t.checklist) && t.checklist.length > 0;
    const showDot = (hasTips || hasDeliv || hasCheck) && !isExpanded;
    return `
      <div class="mtt-row" data-index="${t._index}">
        <div class="mtt-drag" title="Drag to reorder">⋮⋮</div>
        <button class="mtt-expand-btn ${isExpanded ? 'expanded' : ''}" onclick="toggleMTTRowExpand(${t._index})" title="${isExpanded ? 'Collapse' : 'Expand'} rich details">▸</button>
        <input type="text" value="${escapeHtml(t.title)}${showDot ? '' : ''}" onchange="updateMasterTaskField(${t._index}, 'title', this.value)" placeholder="Task title">
        <select onchange="updateMasterTaskField(${t._index}, 'stage', this.value); renderMasterTasks();">${stageOptions}</select>
        <select onchange="updateMasterTaskField(${t._index}, 'category', this.value)">${catOptions}</select>
        <select onchange="updateMasterTaskField(${t._index}, 'source', this.value)">${srcOptions}</select>
        <button class="mtt-critical-btn ${isCrit ? 'active' : ''}" onclick="toggleMasterTaskCritical(${t._index})" title="${isCrit ? 'Critical --- click to unmark' : 'Mark as Critical'}">🔥</button>
        <input type="number" class="mtt-hours-input" value="${hoursVal}" min="0" step="0.25" placeholder="---" onchange="updateMasterTaskField(${t._index}, 'estimatedHours', this.value)" title="Estimated hours (quarter-hour increments)">
        <input type="number" value="${t.offset||0}" onchange="updateMasterTaskField(${t._index}, 'offset', this.value)" title="Days from bid due">
        <button class="mtt-remove-btn" onclick="removeMasterTask(${t._index})" title="Remove">✕</button>
        ${isExpanded ? renderMTTDetailsPanel(t) : ''}
      </div>
    `;
  }).join('');

  attachMTTDragHandlers();
}

// ===== TEMPLATE RICH-FIELDS DETAILS PANEL =====
// Renders the expanded panel beneath a task row showing tips, deliverables list,
// and checklist (with required-flag toggle per item). Inputs use blur-save
// pattern to avoid re-rendering the whole list on every keystroke (which would
// kill focus and erase the user's place).
function renderMTTDetailsPanel(t) {
  const tipsVal = t.tips || '';
  const deliverables = Array.isArray(t.deliverables) ? t.deliverables : [];
  const checklist = Array.isArray(t.checklist) ? t.checklist : [];
  // Deliverables block --- array of strings (simple list)
  let delivHtml = '';
  if (deliverables.length === 0) {
    delivHtml = '<div class="mtt-sublist-empty">No deliverables yet --- click ＋ Add to define what this task should produce.</div>';
  } else {
    delivHtml = '<div class="mtt-sublist">' + deliverables.map((d, i) => `
      <div class="mtt-sublist-row">
        <div class="mtt-sublist-bullet">•</div>
        <input class="mtt-sublist-input" type="text" value="${escapeHtml(d)}" placeholder="Deliverable description" onblur="updateMTTDeliverable(${t._index}, ${i}, this.value)">
        <button class="mtt-sublist-delete" onclick="removeMTTDeliverable(${t._index}, ${i})" title="Remove deliverable">✕</button>
      </div>
    `).join('') + '</div>';
  }
  // Checklist block --- array of {text, required} objects
  let checkHtml = '';
  if (checklist.length === 0) {
    checkHtml = '<div class="mtt-sublist-empty">No checklist items yet --- click ＋ Add to break this task into subtasks.</div>';
  } else {
    checkHtml = '<div class="mtt-sublist">' + checklist.map((c, i) => {
      const text = (typeof c === 'string') ? c : (c.text || '');
      const req = (typeof c === 'object' && c) ? !!c.required : false;
      return `
      <div class="mtt-sublist-row is-checklist">
        <div class="mtt-sublist-bullet">☐</div>
        <input class="mtt-sublist-input" type="text" value="${escapeHtml(text)}" placeholder="Checklist item / subtask" onblur="updateMTTChecklistText(${t._index}, ${i}, this.value)">
        <button class="mtt-required-toggle ${req ? 'active' : ''}" onclick="toggleMTTChecklistRequired(${t._index}, ${i})" title="${req ? 'Required --- must be checked before Complete' : 'Optional --- click to make required'}">${req ? '★ Required' : '☆ Optional'}</button>
        <button class="mtt-sublist-delete" onclick="removeMTTChecklistItem(${t._index}, ${i})" title="Remove item">✕</button>
      </div>
    `;
    }).join('') + '</div>';
  }
  return `
    <div class="mtt-details-panel">
      <div class="mtt-details-panel-header">📝 Rich Details --- defaults copied to project tasks when template is loaded</div>
      <div class="mtt-details-section">
        <label class="mtt-details-label">💡 Tips & Best-Practice Notes <span class="mtt-details-hint">free-text guidance, instructions, references</span></label>
        <textarea class="mtt-tips-textarea" placeholder="e.g. Reference spec section 03 30 00 first. Coordinate with the structural team early. Always upload final to the OneDrive bid folder before Bid Due day." onblur="updateMasterTaskField(${t._index}, 'tips', this.value)">${escapeHtml(tipsVal)}</textarea>

  </div>
  <div class="mtt-details-section">
    <label class="mtt-details-label">📦 Deliverables <span class="mtt-details-hint">what this task produces --- files, documents, sign-offs</span></label>
    ${delivHtml}
    <button class="mtt-sublist-add" onclick="addMTTDeliverable(${t._index})">＋ Add deliverable</button>
  </div>
  <div class="mtt-details-section">
    <label class="mtt-details-label">✅ Checklist / Subtasks <span class="mtt-details-hint">step-by-step items; mark as Required to gate task completion</span></label>
    ${checkHtml}
    <button class="mtt-sublist-add" onclick="addMTTChecklistItem(${t._index})">＋ Add checklist item</button>
  </div>
</div>

`;
}

// Drag-and-drop reordering for master tasks
let mttDragIndex = null;
function attachMTTDragHandlers() {
document.querySelectorAll('.mtt-row').forEach(row => {
const drag = row.querySelector('.mtt-drag');
row.draggable = true;
row.addEventListener('dragstart', e => {
mttDragIndex = parseInt(row.dataset.index);
row.classList.add('dragging');
e.dataTransfer.effectAllowed = 'move';
});
row.addEventListener('dragend', () => row.classList.remove('dragging'));
row.addEventListener('dragover', e => { e.preventDefault(); });
row.addEventListener('drop', e => {
e.preventDefault();
const targetIndex = parseInt(row.dataset.index);
if (mttDragIndex === null || mttDragIndex === targetIndex) return;
const moved = state.masterTasks.splice(mttDragIndex, 1)[0];
state.masterTasks.splice(targetIndex, 0, moved);
saveState();
mttDragIndex = null;
renderMasterTasks();
});
});
}

