// =============================================================
// PROJECTED HOURS SETTINGS MODAL
// =============================================================

// Suggested per-stage default hours --- calibrated for typical commercial GC
// precon work. Used by Reset to Suggested Defaults.
const HOURS_STAGE_SUGGESTED_DEFAULTS = {
'project-setup': 1, 'special-project-task': 2, 'document-review': 4,
'trade-solicitation': 2, 'estimating': 8, 'scope-leveling': 4,
'bid-day-prep': 2, 'bid-day': 1, 'post-bid': 2
};

function openHoursSettingsModal() {
// Sync toggle to current state
const toggle = document.getElementById('hoursEnabledToggle');
if (toggle) toggle.checked = !!state.hoursEnabled;
// Sync stage defaults section visibility
const section = document.getElementById('hoursStageDefaultsSection');
if (section) section.style.display = state.hoursEnabled ? '' : 'none';
// Render the per-stage defaults grid
renderHoursStageDefaults();
document.getElementById('hoursSettingsModal').classList.add('active');
}

// Toggle the firm-level hours feature on/off. When turned on, refresh
// every active surface so the new field/chip/rollup appears. When turned
// off, those surfaces hide cleanly.
function toggleHoursEnabled(checked) {
state.hoursEnabled = !!checked;
saveState();
// Body-level attribute drives CSS visibility for table column
document.body.setAttribute('data-hours-enabled', state.hoursEnabled ? 'true' : 'false');
// Show/hide the stage-defaults section in the settings modal
const section = document.getElementById('hoursStageDefaultsSection');
if (section) section.style.display = state.hoursEnabled ? '' : 'none';
if (state.hoursEnabled) renderHoursStageDefaults();
// Refresh visible surfaces --- task modal field, board chips, project rollup
if (typeof refreshHoursFieldVisibility === 'function') refreshHoursFieldVisibility();
if (typeof render === 'function') render();
}

// Render the per-stage default hours grid in the settings modal.
function renderHoursStageDefaults() {
const grid = document.getElementById('hoursStageDefaultsGrid');
if (!grid) return;
if (typeof STAGES === 'undefined' || !Array.isArray(STAGES)) {
grid.innerHTML = '<div style="color:var(--text-dim);font-size:12px;">Stage list unavailable.</div>';
return;
}
const defaults = state.hoursStageDefaults || {};
grid.innerHTML = STAGES.map(stage => {
const current = (typeof defaults[stage.id] === 'number') ? defaults[stage.id] : '';
return `<div class="hours-stage-row"> <label class="hours-stage-label">${escapeHtml(stage.name)}</label> <input type="number" class="hours-stage-input" min="0" max="40" step="0.25" value="${current}" placeholder="---" onchange="updateHoursStageDefault('${escapeAttr(stage.id)}', this.value)" oninput="updateHoursStageDefault('${escapeAttr(stage.id)}', this.value)" > <span class="hours-stage-unit">h</span> </div>`;
}).join('');
}

// Update a single stage's default. Normalize to quarter-hour, clear if blank.
function updateHoursStageDefault(stageId, value) {
if (!state.hoursStageDefaults || typeof state.hoursStageDefaults !== 'object') {
state.hoursStageDefaults = {};
}
if (value === '' || value === null || value === undefined) {
delete state.hoursStageDefaults[stageId];
} else {
const normalized = (typeof normalizeHours === 'function') ? normalizeHours(value) : parseFloat(value);
if (normalized && normalized > 0) {
state.hoursStageDefaults[stageId] = normalized;
} else {
delete state.hoursStageDefaults[stageId];
}
}
saveState();
}

// Reset stage defaults to the suggested baseline.
function resetHoursStageDefaults() {
if (!confirm('Restore the suggested default hours for every stage? This overwrites any custom values you have set.')) return;
state.hoursStageDefaults = Object.assign({}, HOURS_STAGE_SUGGESTED_DEFAULTS);
saveState();
renderHoursStageDefaults();
}

// Toggle whether a specific stage is always-on (mandatory) for Start By
// regardless of the global flag. Lead-time-critical stages benefit from
// being always-on since missing the start day = missing the deadline.
function toggleStartByAlwaysOn(stageId, checked) {
if (!Array.isArray(state.startByAlwaysOnStages)) state.startByAlwaysOnStages = [];
const idx = state.startByAlwaysOnStages.indexOf(stageId);
if (checked && idx === -1) state.startByAlwaysOnStages.push(stageId);
else if (!checked && idx >= 0) state.startByAlwaysOnStages.splice(idx, 1);
saveState();
renderStartBySettings();
if (typeof render === 'function') render();
}

// Update the per-stage default duration (business days before due).
function setStartByStageDefault(stageId, days) {
if (!state.startByStageDefaults) state.startByStageDefaults = {};
const n = parseInt(days, 10);
state.startByStageDefaults[stageId] = (isNaN(n) || n < 0) ? 2 : n;
saveState();
}

// Render the Start By settings list --- per-stage rows with always-on
// checkbox + default-days input.
function renderStartBySettings() {
const alwaysOnList = document.getElementById('startByAlwaysOnList');
const defaultsList = document.getElementById('startByStageDefaultsList');
if (!alwaysOnList || !defaultsList) return;

const alwaysOn = state.startByAlwaysOnStages || [];
const defaults = state.startByStageDefaults || {};

// Always-on column --- checkboxes per stage
alwaysOnList.innerHTML = STAGES.map(s => {
const checked = alwaysOn.includes(s.id) ? 'checked' : '';
return `<label style="display:flex;align-items:center;gap:8px;cursor:pointer;"> <input type="checkbox" ${checked} onchange="toggleStartByAlwaysOn('${s.id}', this.checked)"> <span style="font-size:13px;">${s.icon} ${escapeHtml(s.name)}</span> </label>`;
}).join('');

// Per-stage defaults
defaultsList.innerHTML = STAGES.map(s => {
const days = (typeof defaults[s.id] === 'number') ? defaults[s.id] : 2;
return `<div style="font-size:13px;">${s.icon} ${escapeHtml(s.name)}</div> <div style="display:flex;align-items:center;gap:6px;"> <input type="number" min="0" max="60" value="${days}" style="width:70px;padding:4px 8px;font-family:'JetBrains Mono',monospace;font-size:12.5px;border:1px solid var(--border);border-radius:3px;" onchange="setStartByStageDefault('${s.id}', this.value)"> <span style="font-size:11px;color:var(--text-dim);">business days</span> </div>`;
}).join('');
}

// Toggle: skip weekends
function toggleSkipWeekends(checked) {
state.skipWeekends = !!checked;
saveState();
invalidateHolidayCache();
// If a project is currently active, offer to reanchor existing tasks so
// their due dates re-snap to the new rules.
maybeOfferReanchorAfterSkipChange('weekends');
}

// Toggle: skip holidays
function toggleSkipHolidays(checked) {
state.skipHolidays = !!checked;
saveState();
invalidateHolidayCache();
maybeOfferReanchorAfterSkipChange('holidays');
}

// When a global skip rule changes, optionally re-snap existing offset-based
// task due dates across all projects so they reflect the new policy.
// Skipped silently if there are no projects with offset-based tasks.
function maybeOfferReanchorAfterSkipChange(which) {
const candidates = state.projects
.map(p => ({ project: p, count: p.tasks.filter(t => typeof t.dayOffset === 'number').length }))
.filter(x => x.count > 0);
if (candidates.length === 0) return;
const total = candidates.reduce((s, c) => s + c.count, 0);
if (!confirm(`${which === 'weekends' ? 'Skip Weekends' : 'Skip Holidays'} setting changed.\n\nReanchor ${total} offset-based task${total === 1 ? '' : 's'} across ${candidates.length} project${candidates.length === 1 ? '' : 's'} so their due dates respect the new rule?\n\n• Existing manually-entered dates will NOT change.\n• Only tasks with a "Days From Bid Start" offset are recalculated.`)) return;
let changedTotal = 0;
candidates.forEach(c => { changedTotal += reanchorProjectTaskDates(c.project); });
saveState();
render();
setTimeout(() => alert(`✓ Reanchored ${changedTotal} task due date${changedTotal === 1 ? '' : 's'} across ${candidates.length} project${candidates.length === 1 ? '' : 's'}.`), 100);
}

// Toggle the "type" radio in the add-holiday form so the right field set shows
function onScheduleNewTypeChange() {
const type = document.getElementById('schedNewHolidayType').value;
document.getElementById('schedNewHolidayRecurringFields').style.display = type === 'recurring' ? '' : 'none';
document.getElementById('schedNewHolidayOneoffFields').style.display = type === 'oneoff' ? '' : 'none';
}

// Add a custom (user-defined) holiday
function addCustomHoliday() {
const name = document.getElementById('schedNewHolidayName').value.trim();
if (!name) { alert('Enter a holiday name.'); return; }
const type = document.getElementById('schedNewHolidayType').value;
const id = 'h_' + Date.now().toString(36) + '_' + Math.floor(Math.random() * 1000);
let entry;
if (type === 'recurring') {
const month = parseInt(document.getElementById('schedNewHolidayMonth').value, 10);
const day = parseInt(document.getElementById('schedNewHolidayDay').value, 10);
if (!month || !day || day < 1 || day > 31) { alert('Pick a valid month and day (1--31).'); return; }
entry = { id, name, recurring: true, month, day, enabled: true, addedAt: Date.now() };
} else {
const date = document.getElementById('schedNewHolidayDate').value;
if (!date) { alert('Pick a date.'); return; }
entry = { id, name, recurring: false, date, enabled: true, addedAt: Date.now() };
}
state.holidays.push(entry);
invalidateHolidayCache();
saveState();
// Reset form
document.getElementById('schedNewHolidayName').value = '';
document.getElementById('schedNewHolidayDay').value = '';
document.getElementById('schedNewHolidayDate').value = '';
renderHolidayList();
}

// Render the holiday list inside the modal, respecting the current filter
function renderHolidayList() {
const container = document.getElementById('schedHolidayList');
const filter = document.getElementById('schedHolidayFilter').value;
const countEl = document.getElementById('schedHolidayCount');
if (!container) return;
const list = (state.holidays || []).slice();
// Sort: enabled first, then by upcoming date (compute next occurrence
// for recurring rules using the current year as a baseline)
const thisYear = new Date().getFullYear();
function nextOcc(h) {
if (!h.recurring) return h.date || '';
if (h.rule) return resolveHolidayRule(h.rule, thisYear) || '';
if (typeof h.month === 'number' && typeof h.day === 'number') {
return `${thisYear}-${String(h.month).padStart(2,'0')}-${String(h.day).padStart(2,'0')}`;
}
return '';
}
list.sort((a, b) => {
const ao = nextOcc(a) || '9999';
const bo = nextOcc(b) || '9999';
return ao < bo ? -1 : (ao > bo ? 1 : 0);
});
// Filter
const filtered = list.filter(h => {
if (filter === 'enabled') return h.enabled !== false;
if (filter === 'disabled') return h.enabled === false;
if (filter === 'recurring') return !!h.recurring;
if (filter === 'oneoff') return !h.recurring;
return true;
});
if (countEl) {
const enabled = list.filter(h => h.enabled !== false).length;
countEl.textContent = `${enabled} enabled · ${list.length} total`;
}
if (filtered.length === 0) {
container.innerHTML = `<div style="padding:24px;text-align:center;color:var(--text-faint);font-style:italic;">No holidays match the current filter.</div>`;
return;
}
container.innerHTML = filtered.map(h => {
const enabled = h.enabled !== false;
const occ = nextOcc(h);
const occStr = occ ? formatDate(occ) : '';
let typeChip;
if (h.recurring) {
if (h.rule) {
typeChip = `<span class="hl-type-chip hl-type-rule">RULE</span>`;
} else {
typeChip = `<span class="hl-type-chip hl-type-recurring">RECURRING</span>`;
}
} else {
typeChip = `<span class="hl-type-chip hl-type-oneoff">ONE-OFF</span>`;
}
const isSeed = (h.id || '').startsWith('us-');
const seedTag = isSeed ? `<span class="hl-seed-tag" title="Federal US holiday seeded by default">SEED</span>` : '';
return `<div class="hl-row ${enabled ? '' : 'hl-disabled'}"> <input type="checkbox" class="hl-toggle" ${enabled ? 'checked' : ''} onchange="toggleHolidayEnabled('${h.id}', this.checked)" title="${enabled ? 'Enabled --- disable to keep on list but ignore' : 'Disabled --- re-enable to skip on calculations'}"> <div class="hl-info"> <div class="hl-name">${escapeHtml(h.name)}${seedTag}</div> <div class="hl-meta">${typeChip}<span class="hl-occ">Next: ${escapeHtml(occStr || '---')}</span></div> </div> <button class="hl-remove-btn" onclick="removeHoliday('${h.id}')" title="Remove this holiday from the list">✕</button> </div>`;
}).join('');
}

function toggleHolidayEnabled(id, enabled) {
const h = state.holidays.find(x => x.id === id);
if (!h) return;
h.enabled = !!enabled;
invalidateHolidayCache();
saveState();
renderHolidayList();
}

function removeHoliday(id) {
const h = state.holidays.find(x => x.id === id);
if (!h) return;
if (!confirm(`Remove "${h.name}" from the holiday list?\n\nIf you only want to ignore it temporarily, uncheck its toggle instead.`)) return;
state.holidays = state.holidays.filter(x => x.id !== id);
invalidateHolidayCache();
saveState();
renderHolidayList();
}

function enableAllHolidays() {
state.holidays.forEach(h => { h.enabled = true; });
invalidateHolidayCache();
saveState();
renderHolidayList();
}

function disableAllHolidays() {
state.holidays.forEach(h => { h.enabled = false; });
invalidateHolidayCache();
saveState();
renderHolidayList();
}

function resetHolidaysToDefault() {
if (!confirm(`Reset the holiday list to the default federal US holidays?\n\nAny custom holidays you've added will be removed. Your toggle states (Skip Weekends / Skip Holidays) are unaffected.`)) return;
state.holidays = getDefaultHolidays();
invalidateHolidayCache();
saveState();
renderHolidayList();
}

function openCSIModal() {
document.getElementById('csiNewCode').value = '';
document.getElementById('csiNewName').value = '';
document.getElementById('csiNewGroup').value = 'csi';
document.getElementById('csiFilterGroup').value = 'all';
renderCSIList();
document.getElementById('csiModal').classList.add('active');
}

function addCSIDivision() {
const code = document.getElementById('csiNewCode').value.trim();
const name = document.getElementById('csiNewName').value.trim();
const group = document.getElementById('csiNewGroup').value;
if (!name) { alert('Enter a category name'); return; }
if (group === 'csi' && !code) {
if (!confirm('CSI Divisions usually have a code (e.g. "23"). Add without a code anyway?')) return;
}
const newDiv = { code: code, name: name, group: group };
// Check duplicates by display label
const newLabel = csiLabel(newDiv);
if (state.csiDivisions.some(d => csiLabel(d).toLowerCase() === newLabel.toLowerCase())) {
alert('That category already exists'); return;
}
state.csiDivisions.push(newDiv);
saveState();
document.getElementById('csiNewCode').value = '';
document.getElementById('csiNewName').value = '';
renderCSIList();
populateAllCategorySelects();
render();
}

function removeCSIDivision(index) {
const div = state.csiDivisions[index];
if (!div) return;
const label = csiLabel(div);
let usage = 0;
state.projects.forEach(p => p.tasks.forEach(t => { if (t.category === label) usage++; }));
state.masterTasks.forEach(t => { if (t.category === label) usage++; });
const msg = usage > 0
? `Remove "${label}" from the list? ${usage} task(s) currently use this category --- they will keep the label but won't appear as a preset option for new tasks.`
: `Remove "${label}" from the list?`;
if (!confirm(msg)) return;
state.csiDivisions.splice(index, 1);
saveState();
renderCSIList();
populateAllCategorySelects();
render();
}

function updateCSIField(index, field, value) {
const div = state.csiDivisions[index];
if (!div) return;
const oldLabel = csiLabel(div);
if (field === 'code') div.code = value.trim();
else if (field === 'name') div.name = value.trim();
else if (field === 'group') div.group = value;
const newLabel = csiLabel(div);
// Propagate rename to existing tasks
if (oldLabel !== newLabel) {
state.projects.forEach(p => p.tasks.forEach(t => {
if (t.category === oldLabel) t.category = newLabel;
}));
state.masterTasks.forEach(t => {
if (t.category === oldLabel) t.category = newLabel;
});
}
saveState();
populateAllCategorySelects();
render();
}

function sortCSIDivisions() {
// General categories first (alphabetical), then CSI (by code ascending)
state.csiDivisions.sort((a,b) => {
if (a.group !== b.group) return a.group === 'general' ? -1 : 1;
if (a.group === 'csi') {
return (a.code || '').localeCompare(b.code || '', undefined, { numeric: true });
}
return a.name.localeCompare(b.name);
});
saveState();
renderCSIList();
populateAllCategorySelects();
}

function resetCSIDivisions() {
if (!confirm('Reset the CSI / Division list to the default MasterFormat set? Your customizations will be lost.')) return;
state.csiDivisions = getDefaultCSIDivisions();
saveState();
renderCSIList();
populateAllCategorySelects();
render();
}

function renderCSIList() {
const list = document.getElementById('csiList');
const filter = document.getElementById('csiFilterGroup').value;
const countEl = document.getElementById('csiCount');

if (state.csiDivisions.length === 0) {
list.innerHTML = '<div style="padding:30px;text-align:center;color:var(--text-faint);font-style:italic;">No categories defined. Add one above or click Reset.</div>';
countEl.textContent = '0 items';
return;
}

const filtered = state.csiDivisions
.map((d, idx) => ({ ...d, _index: idx }))
.filter(d => filter === 'all' || d.group === filter);

countEl.textContent = filter === 'all'
? `${state.csiDivisions.length} items total`
: `${filtered.length} of ${state.csiDivisions.length} items`;

// Group headers + rows
const generalItems = filtered.filter(d => d.group === 'general');
const csiItems = filtered.filter(d => d.group === 'csi');

const buildRow = d => {
const groupOpts = `<option value="general" ${d.group==='general'?'selected':''}>General</option> <option value="csi" ${d.group==='csi'?'selected':''}>CSI Division</option>`;
return `<div style="display:grid;grid-template-columns:70px 1fr 140px auto;gap:8px;align-items:center;padding:7px 12px;border-bottom:1px solid var(--border);background:var(--surface);"> <input type="text" value="${escapeHtml(d.code || '')}" onchange="updateCSIField(${d._index}, 'code', this.value)" placeholder="---" style="padding:5px 7px;font-size:12px;font-family:'JetBrains Mono',monospace;text-align:center;"> <input type="text" value="${escapeHtml(d.name || '')}" onchange="updateCSIField(${d._index}, 'name', this.value)" style="padding:5px 7px;font-size:12px;"> <select onchange="updateCSIField(${d._index}, 'group', this.value); renderCSIList();" style="padding:5px 7px;font-size:12px;">${groupOpts}</select> <button class="mtt-remove-btn" onclick="removeCSIDivision(${d._index})" title="Remove">✕</button> </div>`;
};

let html = '';
if (generalItems.length > 0 && filter !== 'csi') {
html += '<div class="csi-group-header">General Categories</div>';
html += generalItems.map(buildRow).join('');
}
if (csiItems.length > 0 && filter !== 'general') {
html += '<div class="csi-group-header">CSI Divisions (MasterFormat)</div>';
html += csiItems.map(buildRow).join('');
}

list.innerHTML = html || '<div style="padding:30px;text-align:center;color:var(--text-faint);font-style:italic;">No items match the filter.</div>';
}

