function getDefaultBallInCourtOptions() {
return [
{ name: 'Lead', color: 'red' },
{ name: 'Support', color: 'blue' },
{ name: 'Owner', color: 'yellow' },
{ name: 'Architect', color: 'yellow' },
{ name: 'Engineer', color: 'yellow' },
{ name: 'Subcontractor', color: 'purple' },
{ name: 'Vendor', color: 'purple' },
{ name: 'GC / CM', color: 'gray' },
{ name: 'Internal Review', color: 'gray' },
{ name: 'Other', color: 'gray' }
];
}

function populateBICSelect() {
const sel = document.getElementById('taskBallInCourt');
if (!sel) return;
const options = ['<option value="">--- None ---</option>'];
state.ballInCourtOptions.forEach(opt => {
options.push(`<option value="${escapeHtml(opt.name)}">${escapeHtml(opt.name)}</option>`);
});
sel.innerHTML = options.join('');
}

function bicColorFor(name) {
// Prefer the master list's color; fall back to name-based heuristic for legacy values
const match = state.ballInCourtOptions.find(o => o.name === name);
if (match) return match.color;
// Legacy fallback mapping
const n = (name || '').toLowerCase();
if (n.includes('lead')) return 'red';
if (n.includes('support')) return 'blue';
if (n.includes('owner') || n.includes('architect') || n.includes('engineer')) return 'yellow';
if (n.includes('sub') || n.includes('vendor') || n.includes('supplier')) return 'purple';
return 'gray';
}

