function updateBICField(index, field, value) {
const opt = state.ballInCourtOptions[index];
if (!opt) return;
if (field === 'name') {
const newName = value.trim();
if (!newName) return;
// Propagate the rename to all existing tasks
const oldName = opt.name;
if (oldName !== newName) {
state.projects.forEach(p => p.tasks.forEach(t => {
if (t.ballInCourt === oldName) t.ballInCourt = newName;
}));
}
opt.name = newName;
} else {
opt[field] = value;
}
saveState();
render();
}

