// =============================================================
// TABLE COLUMN SORTING
// =============================================================
function setTableSort(col) {
if (state.tableSort.col === col) {
// Toggle direction, or clear if toggling through
state.tableSort.dir = state.tableSort.dir === 'asc' ? 'desc' : 'asc';
} else {
state.tableSort = { col, dir: 'asc' };
}
saveState();
render();
}

function sortTasksByColumn(tasks, col, dir) {
const mult = dir === 'desc' ? -1 : 1;
const cmp = (a, b) => {
let av, bv;
switch (col) {
case 'status':
const statusOrder = {'blocked':0,'in-progress':1,'pending':2,'not-started':3,'done':4};
av = statusOrder[a.status] ?? 99; bv = statusOrder[b.status] ?? 99; break;
case 'task': av = (a.title||'').toLowerCase(); bv = (b.title||'').toLowerCase(); break;
case 'stage':
const stageIndex = {};
STAGES.forEach((s,i) => stageIndex[s.id] = i);
av = stageIndex[a.stage] ?? 99; bv = stageIndex[b.stage] ?? 99; break;
case 'assignee': av = (a.assignee||'zzz').toLowerCase(); bv = (b.assignee||'zzz').toLowerCase(); break;
case 'support': av = (a.support||'zzz').toLowerCase(); bv = (b.support||'zzz').toLowerCase(); break;
case 'bic': av = (a.ballInCourt||'zzz').toLowerCase(); bv = (b.ballInCourt||'zzz').toLowerCase(); break;
case 'priority':
// Critical-first sort: critical tasks (true) sort before non-critical (false)
av = a.critical ? 0 : 1; bv = b.critical ? 0 : 1; break;
case 'due':
av = a.dueDate ? new Date(a.dueDate+'T00:00:00').getTime() : Infinity;
bv = b.dueDate ? new Date(b.dueDate+'T00:00:00').getTime() : Infinity;
break;
case 'hours':
av = (typeof a.estimatedHours === 'number' && a.estimatedHours > 0) ? a.estimatedHours : Infinity;
bv = (typeof b.estimatedHours === 'number' && b.estimatedHours > 0) ? b.estimatedHours : Infinity;
break;
case 'offset':
av = typeof a.dayOffset === 'number' ? a.dayOffset : Infinity;
bv = typeof b.dayOffset === 'number' ? b.dayOffset : Infinity;
break;
case 'source': av = (a.source||'zzz').toLowerCase(); bv = (b.source||'zzz').toLowerCase(); break;
case 'category': av = (a.category||'').toLowerCase(); bv = (b.category||'').toLowerCase(); break;
case 'notes': av = (a.notes||'').toLowerCase(); bv = (b.notes||'').toLowerCase(); break;
default: return 0;
}
if (av < bv) return -1 * mult;
if (av > bv) return 1 * mult;
return 0;
};
return tasks.slice().sort(cmp);
}

