let tourState = {
active: false,
stepIndex: 0,
visibleSteps: [],   // filtered list --- only steps whose target exists
resizeHandler: null,
keyHandler: null
};

// Public entry points ----------------------------------------------------------

// Auto-show welcome modal for genuine first-time users.
// Called from init AFTER loadState() and render() have populated the DOM.
function maybeShowTourWelcome() {
if (!state.tour) return;
if (state.tour.completed || state.tour.dismissed) return;
// Populate dynamic stat numbers
try {
const projEl = document.getElementById('tourWelcomeProjectCount');
const stageEl = document.getElementById('tourWelcomeStageCount');
if (projEl) projEl.textContent = (Array.isArray(state.projects) ? state.projects.length : 0);
if (stageEl) stageEl.textContent = (Array.isArray(state.stages) ? state.stages.length : 0);
} catch(e){}
// Defer slightly so the main render is settled and the modal feels purposeful
setTimeout(() => {
const m = document.getElementById('tourWelcomeModal');
if (m) m.classList.add('active');
}, 350);
}

// User clicked "Skip for now" on the welcome modal --- don't auto-show again,
// but they can still replay via the sidebar button.
function skipOnboardingTour() {
if (!state.tour) state.tour = { completed: false, dismissed: false, lastStep: 0 };
state.tour.dismissed = true;
saveState();
const m = document.getElementById('tourWelcomeModal');
if (m) m.classList.remove('active');
}

// User clicked "Take the tour" --- close welcome, begin the spotlight tour.
function beginOnboardingTour() {
const m = document.getElementById('tourWelcomeModal');
if (m) m.classList.remove('active');
startOnboardingTour();
}

// Replay entry point --- also called from the sidebar "Take the Tour" button.
function startOnboardingTour() {
// Make sure no other modals are stealing focus
document.querySelectorAll('.modal-backdrop.active').forEach(m => m.classList.remove('active'));

// Filter to steps whose target exists (or is null = centered)
tourState.visibleSteps = TOUR_STEPS.filter(s => {
if (!s.selector) return true;
return !!document.querySelector(s.selector);
});

if (tourState.visibleSteps.length === 0) {
alert('Tour content unavailable in this view. Try again from the main board.');
return;
}

tourState.active = true;
tourState.stepIndex = 0;

const overlay = document.getElementById('tourOverlay');
if (overlay) overlay.classList.add('active');

// Wire up resize + key handlers
tourState.resizeHandler = () => positionTourStep();
window.addEventListener('resize', tourState.resizeHandler);
window.addEventListener('scroll', tourState.resizeHandler, true);

tourState.keyHandler = (e) => {
if (!tourState.active) return;
if (e.key === 'Escape') { endOnboardingTour(false); }
else if (e.key === 'ArrowRight' || e.key === 'Enter') { e.preventDefault(); tourNextStep(); }
else if (e.key === 'ArrowLeft') { e.preventDefault(); tourPrevStep(); }
};
document.addEventListener('keydown', tourState.keyHandler);

showTourStep(0);
}

function tourNextStep() {
if (!tourState.active) return;
if (tourState.stepIndex >= tourState.visibleSteps.length - 1) {
endOnboardingTour(true);
return;
}
showTourStep(tourState.stepIndex + 1);
}

function tourPrevStep() {
if (!tourState.active) return;
if (tourState.stepIndex <= 0) return;
showTourStep(tourState.stepIndex - 1);
}

function showTourStep(index) {
tourState.stepIndex = index;
const step = tourState.visibleSteps[index];
if (!step) return;

// Update tooltip content
const titleEl = document.getElementById('tourTooltipTitle');
const bodyEl = document.getElementById('tourTooltipBody');
const stepEl = document.getElementById('tourTooltipStep');
const progressEl = document.getElementById('tourTooltipProgress');
const backBtn = document.getElementById('tourBtnBack');
const nextBtn = document.getElementById('tourBtnNext');

if (titleEl) titleEl.textContent = step.title;
if (bodyEl) bodyEl.innerHTML = step.body;
if (stepEl) stepEl.textContent = `Step ${index + 1} / ${tourState.visibleSteps.length}`;
if (progressEl) progressEl.style.width = `${((index + 1) / tourState.visibleSteps.length) * 100}%`;

// Back button: hidden on first step
if (backBtn) backBtn.style.visibility = (index === 0) ? 'hidden' : 'visible';
// Next button: relabel "Finish" on the last step
if (nextBtn) nextBtn.innerHTML = (index === tourState.visibleSteps.length - 1) ? 'Finish ✓' : 'Next →';

// Persist progress
if (state.tour) { state.tour.lastStep = index; saveState(); }

// Run the optional `before` hook --- used by section-scoped steps to expand
// a collapsed section before the spotlight tries to land on it. The hook
// may return a number of milliseconds to wait before positioning, which
// gives CSS transitions time to settle.
let delay = 0;
if (typeof step.before === 'function') {
try {
const result = step.before();
if (typeof result === 'number' && result > 0) delay = result;
} catch (e) {
console.warn('Tour step `before` hook threw:', e);
}
}

// Position spotlight + tooltip (after any expansion delay)
if (delay > 0) {
setTimeout(positionTourStep, delay);
} else {
positionTourStep();
}
}

function positionTourStep() {
if (!tourState.active) return;
const step = tourState.visibleSteps[tourState.stepIndex];
if (!step) return;

const overlay = document.getElementById('tourOverlay');
const spotlight = document.getElementById('tourSpotlight');
const tooltip = document.getElementById('tourTooltip');
const maskTop = document.getElementById('tourMaskTop');
const maskBottom = document.getElementById('tourMaskBottom');
const maskLeft = document.getElementById('tourMaskLeft');
const maskRight = document.getElementById('tourMaskRight');
if (!overlay || !spotlight || !tooltip) return;

const vw = window.innerWidth;
const vh = window.innerHeight;
const PADDING = 8;

// Centered (no target) --- hide spotlight, full backdrop, center the tooltip
if (!step.selector || step.placement === 'center') {
spotlight.style.display = 'none';
if (maskTop)    { maskTop.style.cssText    = `top:0;left:0;width:100vw;height:100vh;`; }
if (maskBottom) { maskBottom.style.cssText = `display:none;`; }
if (maskLeft)   { maskLeft.style.cssText   = `display:none;`; }
if (maskRight)  { maskRight.style.cssText  = `display:none;`; }
tooltip.setAttribute('data-arrow', 'none');
// Center the tooltip on screen
const rect = tooltip.getBoundingClientRect();
const tw = rect.width || 360;
const th = rect.height || 220;
tooltip.style.left = `${Math.max(16, (vw - tw) / 2)}px`;
tooltip.style.top = `${Math.max(16, (vh - th) / 2)}px`;
return;
}

const target = document.querySelector(step.selector);
if (!target) {
// Should not happen since we filter, but be safe
return;
}

// Scroll target into view if needed
try { target.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'nearest' }); } catch(e){}

const tRect = target.getBoundingClientRect();
const x = tRect.left - PADDING;
const y = tRect.top - PADDING;
const w = tRect.width + PADDING * 2;
const h = tRect.height + PADDING * 2;

// Show spotlight ring around target
spotlight.style.display = 'block';
spotlight.style.left = `${x}px`;
spotlight.style.top = `${y}px`;
spotlight.style.width = `${w}px`;
spotlight.style.height = `${h}px`;

// Four mask panels (top, bottom, left, right of the spotlight rect)
if (maskTop) {
maskTop.style.cssText = `top:0;left:0;width:100vw;height:${Math.max(0, y)}px;`;
}
if (maskBottom) {
maskBottom.style.cssText = `top:${y + h}px;left:0;width:100vw;height:${Math.max(0, vh - (y + h))}px;`;
}
if (maskLeft) {
maskLeft.style.cssText = `top:${y}px;left:0;width:${Math.max(0, x)}px;height:${h}px;`;
}
if (maskRight) {
maskRight.style.cssText = `top:${y}px;left:${x + w}px;width:${Math.max(0, vw - (x + w))}px;height:${h}px;`;
}

// Decide tooltip placement
const ttRect = tooltip.getBoundingClientRect();
const ttW = ttRect.width || 360;
const ttH = ttRect.height || 200;
const GAP = 14;

let placement = step.placement || 'auto';
if (placement === 'auto') {
// Pick the side with the most room
const space = {
bottom: vh - (y + h),
top: y,
right: vw - (x + w),
left: x
};
placement = Object.keys(space).reduce((a, b) => space[a] > space[b] ? a : b);
}

let tx, ty, arrow;
switch (placement) {
case 'top':
tx = x + (w - ttW) / 2;
ty = y - ttH - GAP;
arrow = 'bottom';
break;
case 'left':
tx = x - ttW - GAP;
ty = y + (h - ttH) / 2;
arrow = 'right';
break;
case 'right':
tx = x + w + GAP;
ty = y + (h - ttH) / 2;
arrow = 'left';
break;
case 'bottom':
default:
tx = x + (w - ttW) / 2;
ty = y + h + GAP;
arrow = 'top';
break;
}

// Clamp to viewport
tx = Math.max(12, Math.min(tx, vw - ttW - 12));
ty = Math.max(12, Math.min(ty, vh - ttH - 12));

tooltip.style.left = `${tx}px`;
tooltip.style.top = `${ty}px`;
tooltip.setAttribute('data-arrow', arrow);
}

function endOnboardingTour(completed) {
tourState.active = false;
const overlay = document.getElementById('tourOverlay');
if (overlay) overlay.classList.remove('active');

// Tear down listeners
if (tourState.resizeHandler) {
window.removeEventListener('resize', tourState.resizeHandler);
window.removeEventListener('scroll', tourState.resizeHandler, true);
tourState.resizeHandler = null;
}
if (tourState.keyHandler) {
document.removeEventListener('keydown', tourState.keyHandler);
tourState.keyHandler = null;
}

// Persist outcome
if (!state.tour) state.tour = { completed: false, dismissed: false, lastStep: 0 };
if (completed) {
state.tour.completed = true;
state.tour.dismissed = false;
} else {
state.tour.dismissed = true;
}
saveState();
}

// =============================================================
// INIT
// =============================================================
document.querySelectorAll('.modal-backdrop').forEach(m => {
m.addEventListener('click', e => { if (e.target === m) m.classList.remove('active'); });
});
document.addEventListener('keydown', e => {
if (e.key === 'Escape') document.querySelectorAll('.modal-backdrop.active').forEach(m => m.classList.remove('active'));
});

loadState();
// Body-level attr drives CSS for the hours table column visibility on first paint
document.body.setAttribute('data-hours-enabled', state.hoursEnabled ? 'true' : 'false');
// Always start with sidebar collapsed on every fresh load. The user can
// expand it via the sidebar toggle once they're working; saving state would
// just bring them back to expanded which they didn't want.
state.sidebarCollapsed = true;
renderCompanyLogo();
render();
// Always open Today on fresh load --- overrides any restored view state.
// Hard force: every page open lands on Today regardless of where the user
// was before. If they want the previous project they navigate from Today.
if (typeof openHomeView === 'function') {
openHomeView();
}
maybeShowTourWelcome();

// After the first paint, try to pull the canonical state from the backend.
syncStateFromServer().then(updated => {
  if (updated) {
    document.body.setAttribute('data-hours-enabled', state.hoursEnabled ? 'true' : 'false');
    state.sidebarCollapsed = true;
    renderCompanyLogo();
    render();
    if (typeof openHomeView === 'function') openHomeView();
  }
});
